
// Login/logout visibility guard
function showLoggedOutOnly() {
    document.body.classList.add('logged-out');

    const login = document.getElementById('loginScreen');
    const dash = document.getElementById('appDashboard');
    const clock = document.getElementById('properClockPanel');
    const topNavMenu = document.getElementById('topNavMenu');

    if (login) login.style.display = 'flex';
    if (dash) dash.style.display = 'none';
    if (clock) clock.style.display = 'none';
    if (topNavMenu) topNavMenu.style.display = 'none';

    document.querySelectorAll('.app-module').forEach(m => m.style.display = 'none');
    document.querySelectorAll('.nav-tab').forEach(t => t.style.display = 'none');
}

function showLoggedInApp() {
    document.body.classList.remove('logged-out');

    const login = document.getElementById('loginScreen');
    const dash = document.getElementById('appDashboard');
    const topNavMenu = document.getElementById('topNavMenu');

    if (login) login.style.display = 'none';
    if (dash) dash.style.display = 'block';
    if (topNavMenu) topNavMenu.style.display = 'flex';
}

