function setStaffPhotoPreview(url) {
    const img = document.getElementById('admin_photoPreview');
    if (!img) return;

    const fallback = "data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='160' height='160' viewBox='0 0 160 160'><rect width='160' height='160' rx='80' fill='%23f4f5f7'/><text x='50%' y='54%' text-anchor='middle' font-family='Arial' font-size='48' font-weight='700' fill='%232f3b4f'>T</text></svg>";

    if (url) {
        img.src = url;
        img.style.display = 'block';
        img.onerror = function() {
            this.src = fallback;
        };
    } else {
        img.src = fallback;
        img.style.display = 'block';
    }
}

function previewStaffPhotoUrl() {
    const url = document.getElementById('admin_photoUrl')?.value.trim() || '';
    setStaffPhotoPreview(url);
}

function previewStaffPhotoUpload() {
    const file = document.getElementById('admin_photoFile')?.files?.[0];
    const msg = document.getElementById('admin_photoUploadMsg');

    if (!file) {
        if (msg) msg.innerText = 'No file selected.';
        return;
    }

    if (!file.type.startsWith('image/')) {
        if (msg) {
            msg.innerText = 'Please select an image file.';
            msg.style.color = 'var(--error)';
        }
        return;
    }

    if (file.size > 2 * 1024 * 1024) {
        if (msg) {
            msg.innerText = 'Image is too large. Please use an image under 2MB.';
            msg.style.color = 'var(--error)';
        }
        return;
    }

    const localUrl = URL.createObjectURL(file);
    setStaffPhotoPreview(localUrl);

    if (msg) {
        msg.innerText = 'Preview ready. Click Upload Photo to save it.';
        msg.style.color = '#777';
    }
}

async function uploadStaffPhoto() {
    const email = document.getElementById('admin_newEmail')?.value.trim().toLowerCase() || '';
    const file = document.getElementById('admin_photoFile')?.files?.[0];
    const msg = document.getElementById('admin_photoUploadMsg');

    if (!email) {
        alert('Enter/select the staff email before uploading photo.');
        return;
    }

    if (!file) {
        alert('Choose a photo first.');
        return;
    }

    if (!file.type.startsWith('image/')) {
        alert('Please select a valid image file.');
        return;
    }

    if (file.size > 2 * 1024 * 1024) {
        alert('Image is too large. Please use an image under 2MB.');
        return;
    }

    if (!firebase.storage) {
        alert('Firebase Storage SDK is not loaded. Check index.html.');
        return;
    }

    try {
        if (msg) {
            msg.innerText = 'Uploading photo...';
            msg.style.color = '#777';
        }

        const ext = (file.name.split('.').pop() || 'jpg').toLowerCase().replace(/[^a-z0-9]/g, '');
        const safeEmail = email.replace(/[^a-zA-Z0-9_-]/g, '_');
        const path = `staff_profiles/${safeEmail}/profile_${Date.now()}.${ext}`;

        const ref = firebase.storage().ref().child(path);
        const snapshot = await ref.put(file, {
            contentType: file.type,
            customMetadata: {
                staffEmail: email,
                uploadedBy: currentUserEmail || ''
            }
        });

        const url = await snapshot.ref.getDownloadURL();

        const photoUrlEl = document.getElementById('admin_photoUrl');
        if (photoUrlEl) photoUrlEl.value = url;

        setStaffPhotoPreview(url);

        // Save immediately so the URL is not lost if admin forgets to press Save.
        await db.collection('Users').doc(email).set({
            photoUrl: url,
            photoStoragePath: path,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: currentUserEmail || ''
        }, { merge: true });

        if (msg) {
            msg.innerText = 'Photo uploaded and saved successfully.';
            msg.style.color = 'var(--success)';
        }

        alert('Photo uploaded successfully.');
    } catch (e) {
        console.error('Staff photo upload failed', e);
        if (msg) {
            msg.innerText = 'Upload failed: ' + e.message;
            msg.style.color = 'var(--error)';
        }
        alert('Photo upload failed: ' + e.message);
    }
}

function clearStaffPhotoUpload() {
    const fileEl = document.getElementById('admin_photoFile');
    const urlEl = document.getElementById('admin_photoUrl');
    const msg = document.getElementById('admin_photoUploadMsg');

    if (fileEl) fileEl.value = '';
    if (urlEl) urlEl.value = '';

    setStaffPhotoPreview('');

    if (msg) {
        msg.innerText = 'Photo cleared from form. Press Save to remove URL from profile.';
        msg.style.color = '#777';
    }
}

function renderStaffProfileMiniCard(userData) {
    const card = document.getElementById('staffProfileMiniCard');
    if (!card || !userData) return;

    const nameEl = document.getElementById('staffProfileName');
    const roleEl = document.getElementById('staffProfileRole');
    const imgEl = document.getElementById('staffProfilePhoto');

    const roles = Array.isArray(userData.roles) ? userData.roles : (userData.role ? [userData.role] : []);
    const name = userData.name || currentUserName || 'Staff Member';
    const roleText = roles.join(' | ') || 'Staff';

    if (nameEl) nameEl.innerText = name;
    if (roleEl) roleEl.innerText = roleText;

    if (imgEl) {
        const photoUrl = userData.photoUrl || '';
        if (photoUrl) {
            imgEl.src = photoUrl;
            imgEl.onerror = function() {
                this.src = '';
                this.style.background = '#f3f4f6';
                this.alt = 'Photo unavailable';
            };
        } else {
            imgEl.removeAttribute('src');
            imgEl.style.background = '#f3f4f6';
        }
    }

    card.style.display = 'flex';
}

