// Sales & Promo checkout sync helper
function renderCheckoutPromoNotice(job) {
    const panel = document.getElementById('checkoutPanel');
    if (!panel || !job) return;

    let box = document.getElementById('checkoutPromoNotice');
    if (!box) {
        box = document.createElement('div');
        box.id = 'checkoutPromoNotice';
        box.style.cssText = 'background:#fff8e1; border:1px solid var(--accent); border-radius:8px; padding:12px 14px; margin-bottom:15px; font-size:0.85rem; color:var(--primary);';
        const services = document.getElementById('checkoutServices');
        if (services && services.parentNode && services.parentNode.parentNode) {
            services.parentNode.parentNode.insertAdjacentElement('afterend', box);
        } else {
            panel.insertBefore(box, panel.firstChild);
        }
    }

    if (job.hasPromoApplied || job.promoCode) {
        const original = parseFloat(job.originalTotal || job.grandTotal || 0);
        const discount = parseFloat(job.discountAmount || 0);
        const finalTotal = parseFloat(job.finalTotal || job.grandTotal || 0);
        box.style.display = 'block';
        box.innerHTML = `
            🏷️ <strong>Promo Applied:</strong> ${job.promoCode || ''} ${job.promoName ? '— ' + job.promoName : ''}<br>
            Original: <strong>${original.toFixed(2)} GHC</strong> · Discount: <strong>${discount.toFixed(2)} GHC</strong> · Final: <strong>${finalTotal.toFixed(2)} GHC</strong>
        `;
    } else {
        box.style.display = 'none';
        box.innerHTML = '';
    }
}


async function consumePackageWalletSession(job, jobId) {
    if (!job || !job.packageWalletId || !job.isPackageRedemption) return;

    const walletRef = db.collection('Client_Packages').doc(job.packageWalletId);
    const walletDoc = await walletRef.get();
    if (!walletDoc.exists) {
        console.warn('Package wallet not found:', job.packageWalletId);
        return;
    }

    const wallet = walletDoc.data() || {};
    const remaining = parseInt(wallet.remainingSessions || 0, 10);
    const used = parseInt(wallet.usedSessions || 0, 10);

    if (remaining <= 0) {
        throw new Error('Package wallet has no remaining sessions.');
    }

    await walletRef.set({
        remainingSessions: Math.max(0, remaining - 1),
        usedSessions: used + 1,
        lastUsedAt: firebase.firestore.FieldValue.serverTimestamp(),
        lastUsedBookingId: jobId,
        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
    }, { merge: true });

    await db.collection('Package_Usage').doc(`${job.packageWalletId}_${jobId}`).set({
        walletId: job.packageWalletId,
        packageCode: job.promoCode || job.packageCode || '',
        clientPhone: job.clientPhone || '',
        clientName: job.clientName || '',
        bookingId: jobId,
        jobId: jobId,
        dateString: job.dateString || todayDateStr,
        service: job.bookedService || '',
        sessionsUsed: parseInt(job.packageSessionsUsed || 1, 10),
        remainingAfter: Math.max(0, remaining - 1),
        originalTotal: parseFloat(job.originalTotal || job.grandTotal || 0),
        finalTotal: parseFloat(job.finalTotal || job.grandTotal || 0),
        usedAt: firebase.firestore.FieldValue.serverTimestamp(),
        usedBy: currentUserEmail || ''
    }, { merge: true });
}

async function recordSalesRedemption(job, jobId, paymentMethod) {
    if (!job || !(job.hasPromoApplied || job.promoCode)) return;

    const code = String(job.promoCode || '').trim().toUpperCase();
    if (!code) return;

    const redemptionId = `${jobId}_${code}`;
    const originalTotal = parseFloat(job.originalTotal || job.grandTotal || 0);
    const discountAmount = parseFloat(job.discountAmount || 0);
    const finalTotal = parseFloat(job.finalTotal || job.grandTotal || 0);

    await db.collection('Sales_Redemptions').doc(redemptionId).set({
        code,
        promoCode: code,
        promoName: job.promoName || '',
        promoType: job.promoType || '',
        bookingId: jobId,
        jobId: jobId,
        clientName: job.clientName || '',
        clientPhone: job.clientPhone || '',
        assignedTechEmail: job.assignedTechEmail || '',
        assignedTechName: job.assignedTechName || '',
        dateString: job.dateString || todayDateStr,
        timeString: job.timeString || '',
        originalTotal,
        discountPercent: parseFloat(job.discountPercent || 0),
        discountAmount,
        finalTotal,
        paymentMethod: paymentMethod || '',
        redeemedAt: firebase.firestore.FieldValue.serverTimestamp(),
        redeemedBy: currentUserEmail || '',
        source: 'billing_checkout'
    }, { merge: true });

    try {
        await db.collection('Sales_Promotions').doc(code).set({
            lastRedeemedAt: firebase.firestore.FieldValue.serverTimestamp(),
            lastRedeemedBy: currentUserEmail || '',
            redemptionCount: firebase.firestore.FieldValue.increment(1),
            totalDiscountGiven: firebase.firestore.FieldValue.increment(discountAmount),
            totalFinalRevenue: firebase.firestore.FieldValue.increment(finalTotal)
        }, { merge: true });
    } catch(e) {
        console.warn('Could not update Sales_Promotions redemption counters', e);
    }
}



