window.showError = function(msg) { 
    const el = document.getElementById('errorMsg'); 
    if (!el) { alert(msg); return; }
    el.innerText = msg; 
    el.style.display = 'block'; 
}

async function clockInStaff(email, name, rolesArray) {
    const docId = `${email}_${todayDateStr}`;
    const docRef = db.collection('Attendance').doc(docId);
    const doc = await docRef.get();
    if(!doc.exists) { await docRef.set({ email: email, name: name, roleString: rolesArray.join(','), date: todayDateStr, clockIn: firebase.firestore.FieldValue.serverTimestamp() }); }
}

async function fetchAllTechs() {
    try {
        const snapshot = await db.collection('Users').get();
        allTechs = [];
        
        snapshot.forEach(doc => {
            const data = doc.data();
            const r = Array.isArray(data.roles) ? data.roles : (data.role ? [data.role] : []);
            const safeR = r.map(role => (typeof role === 'string' ? role.toLowerCase() : ''));
            
            const isNormalTech = safeR.some(role => role === 'tech' || role === 'technician');
            const isTestTech = safeR.some(role => role.includes('test tech'));

            if(isNormalTech || isTestTech) { 
                allTechs.push({ 
                    email: doc.id, 
                    name: data.name || "Unknown", 
                    isTest: isTestTech,
                    // visibleToClients defaults to true if not set
                    visibleToClients: data.visibleToClients !== false
                }); 
            }
        });
        
        const select = document.getElementById('sched_techSelect');
        if(select) {
            select.innerHTML = '<option value="" disabled selected>Select Technician...</option>';
            // Staff see ALL techs regardless of visibleToClients
            allTechs.forEach(t => { select.innerHTML += `<option value="${t.email}">${t.name}${t.visibleToClients ? '' : ' 🔒'}</option>`; });
        }
        const reassignSelect = document.getElementById('consultReassignTech');
        const consultReassign = document.getElementById('consultReassign');
        if(reassignSelect) {
            reassignSelect.innerHTML = '<option value="">Reassign to...</option>';
            allTechs.forEach(t => { reassignSelect.innerHTML += `<option value="${t.email}">${t.name}</option>`; });
        }
        if(consultReassign) {
            consultReassign.innerHTML = '<option value="">Reassign to...</option>';
            allTechs.forEach(t => { consultReassign.innerHTML += `<option value="${t.email}">${t.name}</option>`; });
        }
    } catch(e) { console.error("Error fetching techs:", e); }
}

// ==========================================
// DYNAMIC TAX ENGINE
// ==========================================
function startTaxListener() {
    db.collection('Tax_Settings').doc('current_taxes').onSnapshot(doc => {
        liveTaxes = [];
        if(doc.exists && doc.data().rates) {
            liveTaxes = doc.data().rates;
        }
        renderTaxConfigUI();
        updatePreviewToggles();
        // EMERGENCY HF27: do not let live tax-settings snapshots interrupt booking availability.
        // Schedule totals are recalculated by service/counter/date/tech actions instead.
        // This protects generateTimeSlots() during live operations.
    });
}

window.editTax = function(name, rate) {
    document.getElementById('cfgTaxName').value = name;
    document.getElementById('cfgTaxRate').value = rate;
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

window.addTax = async function() {
    const name = document.getElementById('cfgTaxName').value.trim();
    const rate = parseFloat(document.getElementById('cfgTaxRate').value);
    if(!name || isNaN(rate)) { alert("Enter a valid Tax Name and numerical Rate."); return; }

    let currentRates = [...liveTaxes];
    let existingIdx = currentRates.findIndex(t => t.name.toLowerCase() === name.toLowerCase());
    if(existingIdx >= 0) { currentRates[existingIdx].rate = rate; } 
    else { currentRates.push({ name: name, rate: rate }); }

    try {
        await db.collection('Tax_Settings').doc('current_taxes').set({ rates: currentRates }, {merge: true});
        document.getElementById('cfgTaxName').value = '';
        document.getElementById('cfgTaxRate').value = '';
    } catch(e) { alert("Error saving tax: " + e.message); }
}

window.deleteTax = async function(taxName) {
    if(!confirm(`Remove ${taxName} from the system?`)) return;
    let currentRates = liveTaxes.filter(t => t.name !== taxName);
    try {
        await db.collection('Tax_Settings').doc('current_taxes').set({ rates: currentRates }, {merge: true});
    } catch(e) { alert("Error deleting tax: " + e.message); }
}

function renderTaxConfigUI() {
    const listDiv = document.getElementById('taxConfigList');
    if(!listDiv) return;
    if(liveTaxes.length === 0) { listDiv.innerHTML = '<p style="color: #999; font-style: italic;">No taxes currently configured.</p>'; return; }
    
    let html = '';
    liveTaxes.forEach(t => {
        html += `<div style="display:flex; justify-content:space-between; align-items:center; background:white; padding:10px; border:1px solid var(--border); border-radius:4px; margin-bottom:5px;">
            <strong>${t.name}</strong>
            <div style="display:flex; align-items:center; gap:15px;">
                <span style="color:var(--manager); font-weight:bold;">${t.rate}%</span>
                <button class="btn" style="background:var(--primary); padding:4px 10px; width:auto; font-size:0.75rem;" onclick="editTax('${t.name}', ${t.rate})">Edit</button>
                <button class="btn" style="background:var(--error); padding:4px 10px; width:auto; font-size:0.75rem;" onclick="deleteTax('${t.name}')">Remove</button>
            </div>
        </div>`;
    });
    listDiv.innerHTML = html;
}

window.updatePreviewToggles = function() {
    const container = document.getElementById('previewTaxToggles');
    if(!container) return;
    if(liveTaxes.length === 0) {
        container.innerHTML = '<p style="color:#999; font-size:0.8rem; margin:0;">Add a tax above to see toggles here.</p>';
        calculatePreview();
        return;
    }
    let html = '';
    liveTaxes.forEach((t, index) => {
        html += `<label style="font-weight:normal; cursor:pointer; display:flex; align-items:center; gap:8px; margin-bottom:5px;">
                    <input type="checkbox" class="preview-tax-cb" value="${index}" checked onchange="calculatePreview()" style="width:16px; height:16px; accent-color:var(--manager);"> 
                    ${t.name} (${t.rate}%)
                 </label>`;
    });
    container.innerHTML = html;
    calculatePreview();
}

window.calculatePreview = function() {
    let inputPrice = parseFloat(document.getElementById('previewBasePrice').value) || 0;
    let toggleEl = document.querySelector('input[name="tax_inclusive_toggle"]:checked');
    let isInclusive = toggleEl ? toggleEl.value === 'inclusive' : false;

    let taxHtml = '';
    let totalTaxRate = 0;

    document.querySelectorAll('.preview-tax-cb:checked').forEach(cb => {
        let taxObj = liveTaxes[cb.value];
        if(taxObj) { totalTaxRate += taxObj.rate; }
    });

    let basePrice = 0, grandTotal = 0;

    if (isInclusive) {
        grandTotal = inputPrice;
        basePrice = inputPrice / (1 + (totalTaxRate / 100));
    } else {
        basePrice = inputPrice;
        grandTotal = inputPrice * (1 + (totalTaxRate / 100));
    }

    let calculatedTotalTax = 0;

    document.querySelectorAll('.preview-tax-cb:checked').forEach(cb => {
        let taxObj = liveTaxes[cb.value];
        if(taxObj) {
            let amt = basePrice * (taxObj.rate / 100);
            calculatedTotalTax += amt;
            taxHtml += `<div style="display:flex; justify-content:space-between; font-size:0.85rem; color:#777; margin-bottom:3px;"><span>+ ${taxObj.name} (${taxObj.rate}%)</span><span>${amt.toFixed(2)} GHC</span></div>`;
        }
    });

    let baseOut = document.getElementById('prevBaseOut');
    if(baseOut) baseOut.innerText = basePrice.toFixed(2) + ' GHC';

    let breakdownDiv = document.getElementById('prevTaxBreakdown');
    if(breakdownDiv) breakdownDiv.innerHTML = taxHtml;
    
    let totalOut = document.getElementById('prevTotalOut');
    if(totalOut) totalOut.innerText = grandTotal.toFixed(2) + ' GHC';
}

// ==========================================
// DYNAMIC MENU DISPLAY ENGINE 
// ==========================================
function _thEscapeHtml(value) {
    return String(value ?? '').replace(/[&<>'"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[ch]));
}

function _thEscapeJsAttr(value) {
    return String(value ?? '').replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '&quot;').replace(/\n/g, ' ').replace(/\r/g, ' ');
}

function _thNormalizeInputType(value) {
    const t = String(value || 'radio').trim().toLowerCase();
    if (['counter', 'quantity', 'qty', 'number', 'numeric', 'per unit', 'per-unit', 'unit'].includes(t)) return 'counter';
    if (['checkbox', 'multi', 'multiple', 'add-on', 'addon'].includes(t)) return 'checkbox';
    return 'radio';
}

function _thNum(value, fallback = 9999) {
    const n = Number(value);
    return Number.isFinite(n) ? n : fallback;
}


function _thServiceSlug(text) {
    return String(text || '')
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '_')
        .replace(/^_+|_+$/g, '')
        .slice(0, 90) || 'item';
}

function _thServiceSort(a, b) {
    const pa = _thNum(a.priority, 9999);
    const pb = _thNum(b.priority, 9999);
    if (pa !== pb) return pa - pb;
    const ca = String(a.category || '').toUpperCase();
    const cb = String(b.category || '').toUpperCase();
    if (ca !== cb) return ca.localeCompare(cb, undefined, {numeric:true, sensitivity:'base'});
    return String(a.name || '').localeCompare(String(b.name || ''), undefined, {numeric:true, sensitivity:'base'});
}

function _thGetServiceMeta(s) {
    return {
        cat: s.ritualGroup || 'Uncategorized Rituals',
        main: s.category || 'General',
        sub: s.serviceType || 'Main Therapy'
    };
}

function _thGroupByMenuTree(services) {
    const tree = { Hand: {}, Foot: {} };
    services.forEach(s => {
        const deptList = (s.department === 'Both' || s.appliesTo === 'Both') ? ['Hand','Foot'] : [s.department || 'Hand'];
        const ritualKey = s.ritualGroup || 'Uncategorized Rituals';
        const categoryKey = s.category || 'General';
        const serviceTypeKey = s.serviceType || 'Main Therapy';
        const order = _thNum(s.sortOrder, 9999);
        deptList.forEach(dept => {
            if (!tree[dept]) tree[dept] = {};
            if (!tree[dept][ritualKey]) tree[dept][ritualKey] = { desc: s.ritualGroupDescription || '', priority: order, menus: {} };
            const ritualNode = tree[dept][ritualKey];
            if (!ritualNode.desc && s.ritualGroupDescription) ritualNode.desc = s.ritualGroupDescription;
            ritualNode.priority = Math.min(ritualNode.priority, order);
            if (!ritualNode.menus[categoryKey]) ritualNode.menus[categoryKey] = { desc: s.categoryDescription || '', priority: order, subs: {} };
            const categoryNode = ritualNode.menus[categoryKey];
            if (!categoryNode.desc && s.categoryDescription) categoryNode.desc = s.categoryDescription;
            categoryNode.priority = Math.min(categoryNode.priority, order);
            if (!categoryNode.subs[serviceTypeKey]) categoryNode.subs[serviceTypeKey] = { desc: s.serviceTypeDescription || '', priority: order, services: [] };
            const typeNode = categoryNode.subs[serviceTypeKey];
            if (!typeNode.desc && s.serviceTypeDescription) typeNode.desc = s.serviceTypeDescription;
            typeNode.priority = Math.min(typeNode.priority, order);
            typeNode.services.push(s);
        });
    });
    return tree;
}

function _thFormatMoney(value) {
    const n = Number(value);
    if (!Number.isFinite(n) || n <= 0) return 'Consultation';
    return 'GHC' + (Number.isInteger(n) ? String(n) : n.toFixed(2));
}

function _thCleanServiceName(name, subName) {
    let out = String(name || 'Unnamed Service').trim();
    const sub = String(subName || '').trim();
    const removePrefixes = [
        'Acrylic ', 'Sculpt Acrylic ', 'Gel X ', 'BIAB ', 'DuraGel '
    ];
    removePrefixes.forEach(prefix => {
        if (out.toLowerCase().startsWith(prefix.toLowerCase())) out = out.slice(prefix.length).trim();
    });
    if (/^Chrome\s*\/\s*Manicure$/i.test(out)) return 'Chrome / Manicure';
    if (/^BIAB Overlay$/i.test(name || '')) return 'Overlay';
    if (/^DuraGel Full Set$/i.test(name || '')) return 'Full Set';
    return out || String(name || 'Unnamed Service');
}

function _thSubHeaderMeta(subName) {
    const raw = String(subName || '').trim();
    const lower = raw.toLowerCase();
    const map = {
        'finishing indulgences': ['A. Finishing Indulgences', 'Comfort-led upgrades that extend the ritual through massage, warmth, and restoration.'],
        'polish & finish': ['B. Polish & Finish', 'Finishing options that refine the final look with polish, tip work, or chrome expression.'],
        'a1 acrylic': ['Acrylic', 'Classic acrylic enhancement system for durable structure, clean length, and refined shape.'],
        'sculpt acrylic': ['Sculpt Acrylic', 'Advanced sculpted acrylic structure for stronger shape control and an elevated enhancement finish.'],
        'a2 gel x': ['A2. Gel X', 'Lightweight extension system offering flexibility, comfort, and a natural finish.'],
        'a3 biab': ['A3. BIAB', 'Builder gel system focused on strength, natural overlays, and nail health.'],
        'a4 duragel': ['A4. DuraGel', 'High-durability gel system designed for long-lasting strength and structure.'],
        'c1 editorial art': ['Editorial Art', 'Visible design details for refined creative expression per nail.'],
        'c2 couture art': ['Couture Art', 'Custom design direction for clients seeking a bespoke nail art concept.'],
        'd. embellishment drawers': ['D. Embellishment Drawers', 'Dimensional and decorative embellishments that add texture, sparkle, and couture detail.']
    };
    return map[lower] || [raw, ''];
}

function _thRenderSelectableService(s, subName, compact = false) {
    if (s.isActive === false || (s.status && s.status !== 'Active')) return '';
    const type = _thNormalizeInputType(s.inputType || s.selection || 'radio');
    const safeDur = parseInt(s.duration || 0, 10) || 0;
    const safePrc = parseFloat(s.price || 0) || 0;
    const desc = s.desc || s.description || '';
    const tagHtml = (s.tag && s.tag !== 'None') ? `<span class="hl-tag">${_thEscapeHtml(s.tag)}</span>` : '';
    const displayName = _thCleanServiceName(s.displayName || s.name, subName);
    const priceSuffix = (s.pricingType || '').toLowerCase().includes('unit') ? ' / nail' : '';
    const priceHtml = safePrc > 0 ? `${_thFormatMoney(safePrc)}${priceSuffix}` : 'Consultation';

    if (type === 'counter') {
        return `<div class="th-ritual-service th-ritual-counter ${compact ? 'is-simple' : ''}">
            <div class="th-ritual-row"><div><div class="th-ritual-name">${_thEscapeHtml(displayName)} ${tagHtml}</div>${desc ? `<div class="th-ritual-desc">${_thEscapeHtml(desc)}</div>` : ''}</div><div class="th-ritual-price">${_thEscapeHtml(priceHtml)}</div></div>
            <div class="counter-box th-ritual-counter-box"><button type="button" class="btn btn-secondary" style="padding:2px 10px; width:auto;" onclick="event.preventDefault(); event.stopPropagation(); updateCounter('${_thEscapeJsAttr(s.id)}', -1); return false;">-</button><input type="number" id="sched_qty_${_thEscapeHtml(s.id)}" class="sched-service-counter" data-name="${_thEscapeHtml(s.name || '')}" data-duration="${safeDur}" data-price="${safePrc}" value="0" min="0" readonly><button type="button" class="btn btn-secondary" style="padding:2px 10px; width:auto;" onclick="event.preventDefault(); event.stopPropagation(); updateCounter('${_thEscapeJsAttr(s.id)}', 1); return false;">+</button></div>
        </div>`;
    }

    const inputName = type === 'radio' ? `sched_base_${_thServiceSlug(s.category || 'menu')}` : `sched_cb_${s.id}`;
    const inputHtml = type === 'radio'
        ? `<input type="radio" name="${inputName}" class="sched-service-item" id="sched_cb_${s.id}" data-name="${_thEscapeHtml(s.name || '')}" data-duration="${safeDur}" data-price="${safePrc}">`
        : `<input type="checkbox" class="sched-service-item" id="sched_cb_${s.id}" data-name="${_thEscapeHtml(s.name || '')}" data-duration="${safeDur}" data-price="${safePrc}">`;
    return `<div class="service-card th-ritual-service ${compact ? 'is-simple' : ''}" onclick="toggleServiceCard(event, this, '${s.id}', '${type}', '${inputName}')">
        ${inputHtml}
        <label>
            <div class="th-ritual-row"><div><div class="th-ritual-name">${_thEscapeHtml(displayName)} ${tagHtml}</div>${desc ? `<div class="th-ritual-desc">${_thEscapeHtml(desc)}</div>` : ''}</div><div class="th-ritual-price">${_thEscapeHtml(priceHtml)}</div></div>
        </label>
    </div>`;
}

function _thRenderSubmenuBlock(subName, subNode, mode = 'submenu') {
    const [title, defaultDesc] = _thSubHeaderMeta(subName);
    const desc = subNode.desc || defaultDesc;
    let html = `<div class="th-ritual-submenu ${mode === 'system' ? 'is-system' : ''}">`;
    if (mode === 'system') {
        const icon = title.includes('Gel X') ? 'G' : title.includes('BIAB') ? 'B' : title.includes('DuraGel') ? 'D' : title.includes('Acrylic') ? 'A1' : title.includes('Editorial') ? 'C1' : title.includes('Couture') ? 'C2' : '✦';
        html += `<div class="th-ritual-system-head"><div class="th-ritual-icon">${_thEscapeHtml(icon)}</div><div><h4>${_thEscapeHtml(title)}</h4>${desc ? `<p>${_thEscapeHtml(desc)}</p>` : ''}</div></div>`;
    } else {
        html += `<h3>${_thEscapeHtml(title)}</h3>${desc ? `<p class="th-ritual-subdesc">${_thEscapeHtml(desc)}</p>` : ''}`;
    }
    subNode.services.sort(_thServiceSort).forEach(s => { html += _thRenderSelectableService(s, subName, true); });
    html += '</div>';
    return html;
}

function _thRenderPleiades(mainNode) {
    const subs = Object.entries(mainNode.subs).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
    const get = keys => subs.filter(([name]) => keys.some(k => String(name).toLowerCase().includes(k)));
    let html = '<div class="th-ritual-menu-card"><div class="th-ritual-badge">Enhancement Suite</div>';

    const architecture = get(['a1 acrylic', 'sculpt acrylic', 'a2 gel x', 'a3 biab', 'a4 duragel']);
    if (architecture.length) {
        html += `<div class="th-ritual-submenu"><h3>A. Nail Architecture</h3><p class="th-ritual-subdesc">Acrylic, Gel X extensions, brush-on gel, and structural systems designed to enhance form, durability, and aesthetic balance.</p>`;
        architecture.forEach(([subName, subNode]) => { html += _thRenderSubmenuBlock(subName, subNode, 'system'); });
        html += '</div>';
    }

    const polish = get(['polish & finish']);
    polish.forEach(([subName, subNode]) => { html += _thRenderSubmenuBlock(subName, subNode); });

    const design = get(['c1 editorial', 'c2 couture']);
    if (design.length) {
        html += `<div class="th-ritual-submenu"><h3>C. Design Canvas</h3><p class="th-ritual-subdesc">Design enhancement structure for creative nail artistry from minimal editorial detail to couture expression.</p>`;
        design.forEach(([subName, subNode]) => { html += _thRenderSubmenuBlock(subName, subNode, 'system'); });
        html += '</div>';
    }

    const embellish = get(['d. embellishment']);
    embellish.forEach(([subName, subNode]) => { html += _thRenderSubmenuBlock(subName, subNode); });

    const usedNames = new Set([...architecture, ...polish, ...design, ...embellish].map(x => x[0]));
    subs.filter(([name]) => !usedNames.has(name)).forEach(([subName, subNode]) => { html += _thRenderSubmenuBlock(subName, subNode); });
    html += '</div>';
    return html;
}

function _thMainMenuNumber(name, fallback) {
    const n = String(name || '').toLowerCase();
    if (n.includes('hand therapies')) return '1. Hand Therapies & Rituals';
    if (n.includes('luxe add')) return '2. Luxe Add Ons & Upgrades';
    if (n.includes('pleiades')) return '3. Pleiades Studio';
    if (n.includes('repairs')) return '4. Repairs';
    return `${fallback + 1}. ${name}`;
}

function _thRenderBookingMenuFromTree(tree, dept) {
    const cats = Object.entries(tree[dept] || {}).sort((a,b) => {
        const ap = dept === 'Foot' ? Math.min(_thFootCategoryPriority(a[0]), a[1].priority) : a[1].priority;
        const bp = dept === 'Foot' ? Math.min(_thFootCategoryPriority(b[0]), b[1].priority) : b[1].priority;
        return ap - bp || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'});
    });
    if (!cats.length) return '<p style="text-align:center; color:#999; font-style:italic;">No services configured for this department yet.</p>';

    let html = '<div class="th-ritual-menu th-client-menu-tree">';
    cats.forEach(([catName, catNode]) => {
        html += `<div class="th-ritual-reference-note"><strong>${_thEscapeHtml(catName)}</strong>${catNode.desc ? `<span>${_thEscapeHtml(catNode.desc)}</span>` : ''}</div>`;
        const menus = Object.entries(catNode.menus).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
        menus.forEach(([mainName, mainNode], mainIndex) => {
            const open = mainIndex === 0 || String(mainName).toLowerCase().includes('pleiades') ? 'open' : '';
            html += `<details class="th-ritual-main" ${open}><summary><div class="th-ritual-title-block"><strong>${_thEscapeHtml(_thMainMenuNumber(mainName, mainIndex))}</strong>${mainNode.desc ? `<span>${_thEscapeHtml(mainNode.desc)}</span>` : ''}</div><div class="th-ritual-chev">+</div></summary><div class="th-ritual-content">`;
            if (String(mainName).toLowerCase().includes('pleiades')) {
                html += _thRenderPleiades(mainNode);
            } else {
                const subs = Object.entries(mainNode.subs).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
                subs.forEach(([subName, subNode]) => {
                    if (subName === '__services__') {
                        subNode.services.sort(_thServiceSort).forEach(s => { html += _thRenderSelectableService(s, subName, true); });
                    } else {
                        html += _thRenderSubmenuBlock(subName, subNode);
                    }
                });
            }
            html += '</div></details>';
        });
    });
    html += '</div>';
    return html;
}

function _thRenderAdminMenuTree(tree, dept, hasEditAccess) {
    const cats = Object.entries(tree[dept] || {}).sort((a,b) => {
        const ap = dept === 'Foot' ? Math.min(_thFootCategoryPriority(a[0]), a[1].priority) : a[1].priority;
        const bp = dept === 'Foot' ? Math.min(_thFootCategoryPriority(b[0]), b[1].priority) : b[1].priority;
        return ap - bp || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'});
    });
    if (!cats.length) return '<div class="th-menu-empty">No services configured for this department yet.</div>';

    let html = `<div id="admin_dept_${dept}" class="th-menu-admin-tree" style="display:${dept === 'Hand' ? 'block' : 'none'};">`;
    cats.forEach(([catName, catNode], catIndex) => {
        html += `<details class="th-menu-category" ${catIndex === 0 ? 'open' : ''}>
            <summary><div><span class="th-menu-kicker">Category · Priority ${catNode.priority === 9999 ? '—' : catNode.priority}</span><strong>${_thEscapeHtml(catName)}</strong>${catNode.desc ? `<p>${_thEscapeHtml(catNode.desc)}</p>` : `<p class="th-menu-missing">Description needed for client-facing luxury copy.</p>`}</div><span class="th-menu-chevron">⌄</span></summary>`;
        const menus = Object.entries(catNode.menus).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
        menus.forEach(([mainName, mainNode]) => {
            html += `<div class="th-menu-main"><div class="th-menu-main-head"><div><span class="th-menu-kicker">Main Menu · Priority ${mainNode.priority === 9999 ? '—' : mainNode.priority}</span><h4>${_thEscapeHtml(mainName)}</h4>${mainNode.desc ? `<p>${_thEscapeHtml(mainNode.desc)}</p>` : `<p class="th-menu-missing">Main menu description needed.</p>`}</div></div>`;
            const subs = Object.entries(mainNode.subs).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
            subs.forEach(([subName, subNode]) => {
                if (subName !== '__services__') {
                    html += `<div class="th-menu-sub"><span class="th-menu-kicker">Sub Menu · Priority ${subNode.priority === 9999 ? '—' : subNode.priority}</span><h5>${_thEscapeHtml(subName)}</h5>${subNode.desc ? `<p>${_thEscapeHtml(subNode.desc)}</p>` : `<p class="th-menu-missing">Sub menu description needed.</p>`}</div>`;
                }
                html += '<div class="th-menu-service-grid">';
                subNode.services.sort(_thServiceSort).forEach((s, idx) => {
                    const safeDur = parseInt(s.duration || 0, 10) || 0;
                    const safePrc = parseFloat(s.price || 0) || 0;
                    const type = _thNormalizeInputType(s.inputType || s.selection || 'radio');
                    const status = s.status || 'Active';
                    const desc = s.desc || s.description || '';
                    html += `<div class="th-menu-service-card ${status !== 'Active' ? 'is-inactive' : ''}">
                        <div class="th-menu-service-top">
                            <div><span class="th-menu-kicker">Service · Priority ${_thNum(s.priority, idx + 1)}</span><strong>${_thEscapeHtml(s.name || 'Unnamed Service')}</strong></div>
                            <span class="th-menu-status ${status === 'Active' ? 'active' : 'inactive'}">${_thEscapeHtml(status)}</span>
                        </div>
                        ${desc ? `<p class="th-menu-service-desc">${_thEscapeHtml(desc)}</p>` : `<p class="th-menu-missing">Service description needed.</p>`}
                        <div class="th-menu-meta"><span>${safeDur > 0 ? safeDur + ' mins' : 'No duration'}</span><span>${safePrc} GHC</span><span>${type.toUpperCase()}</span></div>
                        ${hasEditAccess ? `<div class="th-menu-actions"><button class="btn btn-secondary" onclick="editMenuService('${s.id}')">Edit</button><button class="btn btn-secondary" onclick="moveMenuServicePriority('${s.id}', -1)">↑ Priority</button><button class="btn btn-secondary" onclick="moveMenuServicePriority('${s.id}', 1)">↓ Priority</button><button class="btn btn-secondary" onclick="toggleMenuServiceActive('${s.id}')">Set Inactive/Active</button><button class="btn" style="background:var(--error);" onclick="deleteMenuService('${s.id}')">Delete Service</button></div>` : ''}
                    </div>`;
                });
                html += '</div>';
            });
            html += '</div>';
        });
        html += '</details>';
    });
    html += '</div>';
    return html;
}


