window.toggleServiceCard = function(event, cardElement, id, type, groupName) {
    event.preventDefault(); 
    const input = document.getElementById('sched_cb_' + id);
    if(!input) return;

    if(type === 'radio') {
        if(input.checked) {
            input.checked = false;
            cardElement.classList.remove('selected');
        } else {
            document.querySelectorAll(`input[name="${groupName}"]`).forEach(r => {
                r.checked = false;
                let card = r.closest('.service-card');
                if (card) card.classList.remove('selected');
            });
            input.checked = true;
            cardElement.classList.add('selected');
        }
    } else {
        input.checked = !input.checked;
        if(input.checked) { cardElement.classList.add('selected'); } else { cardElement.classList.remove('selected'); }
    }
    calculateScheduleTotals();
}

window.updateCounter = function(id, val) {
    const safeId = String(id || '');
    const delta = parseInt(val, 10) || 0;

    // Prefer the counter closest to the clicked button when the delegated handler sets it.
    let input = window.THURAYA_ACTIVE_COUNTER_INPUT || null;

    if (!input) {
        input = document.getElementById('sched_qty_' + safeId);
    }

    // Fallback for unusual IDs or duplicated rendered menu copies.
    if (!input) {
        const all = Array.from(document.querySelectorAll('#sched_serviceMenu .sched-service-counter'));
        input = all.find(el => el.id === ('sched_qty_' + safeId) || el.id.endsWith(safeId));
    }

    // Final fallback: any matching counter anywhere.
    if (!input) {
        const all = Array.from(document.querySelectorAll('.sched-service-counter'));
        input = all.find(el => el.id === ('sched_qty_' + safeId) || el.id.endsWith(safeId));
    }

    if (!input) {
        console.warn('Counter input not found for:', safeId);
        return false;
    }

    let current = parseInt(input.value, 10);
    if (!Number.isFinite(current)) current = 0;

    current += delta;
    if (current < 0) current = 0;

    input.value = String(current);
    input.setAttribute('value', String(current));

    if (typeof calculateScheduleTotals === 'function') {
        calculateScheduleTotals();
    }

    return false;
};

