// THURAYA STAFF FIX: FOH DOB field safety
// Keeps DOB as YYYY-MM-DD for existing Firestore logic, while preventing invalid browser date values.
function th_normalizeDateForInput(value) {
    if (!value) return '';
    const raw = String(value).trim();
    if (!raw) return '';

    // Native date value already valid: YYYY-MM-DD
    const iso = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if (iso) {
        const y = Number(iso[1]);
        if (y >= 1900 && y <= 2099) return raw;
        return '';
    }

    // Support accidental slash formats from previous/manual entries: MM/DD/YYYY or DD/MM/YYYY.
    const slash = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if (slash) {
        const a = Number(slash[1]);
        const b = Number(slash[2]);
        const y = Number(slash[3]);
        if (y < 1900 || y > 2099) return '';

        // Prefer MM/DD/YYYY when first part is a valid month; fall back to DD/MM/YYYY.
        let mm = a, dd = b;
        if (a > 12 && b <= 12) { mm = b; dd = a; }
        if (mm >= 1 && mm <= 12 && dd >= 1 && dd <= 31) {
            return `${String(y).padStart(4,'0')}-${String(mm).padStart(2,'0')}-${String(dd).padStart(2,'0')}`;
        }
    }

    const parsed = new Date(raw);
    if (!isNaN(parsed.getTime())) {
        const y = parsed.getFullYear();
        if (y >= 1900 && y <= 2099) return parsed.toISOString().slice(0, 10);
    }
    return '';
}

function th_wireFOHDOBField() {
    const dob = document.getElementById('f_dob');
    if (!dob || dob.dataset.thDobWired === '1') return;
    dob.dataset.thDobWired = '1';

    // Keep one clean native date field only. It supports typing in supported browsers
    // and still opens the built-in calendar picker.
    dob.setAttribute('type', 'date');
    dob.setAttribute('min', '1900-01-01');
    dob.max = new Date().toISOString().slice(0, 10);

    dob.addEventListener('blur', function(){
        const fixed = th_normalizeDateForInput(this.value);
        if (this.value && fixed) this.value = fixed;
    });
}

