                    let discountAmount = parseFloat(job.discountAmount || 0).toFixed(2);
                    let grandTotal = parseFloat(job.finalTotal || job.grandTotal || job.bookedPrice || 0).toFixed(2);
                    let hasPromo = !!(job.hasPromoApplied || job.promoCode);

                    let taxHtml = '';
