window.myProfile_load = async function() {
    const user = firebase.auth().currentUser;
    if (!user) return;

    const msg = document.getElementById('myProfileMsg');
    if (msg) {
        msg.innerText = 'Loading...';
        msg.style.color = '#777';
    }

    try {
        const email = user.email.toLowerCase();
        const doc = await db.collection('Users').doc(email).get();
        const data = doc.exists ? (doc.data() || {}) : {};

        const roles = Array.isArray(data.roles) ? data.roles : (data.role ? [data.role] : []);
        const setVal = (id, val) => {
            const el = document.getElementById(id);
            if (el) el.value = val || '';
        };
        const setText = (id, val) => {
            const el = document.getElementById(id);
            if (el) el.innerText = val || '';
        };

        setText('myProfileName', data.name || user.displayName || 'Staff Member');
        setText('myProfileRoles', roles.join(' | ') || 'Staff');

        setVal('myProfileFullName', data.name || user.displayName || '');
        setVal('myProfileEmail', email);
        setVal('myProfilePhone', data.phone || '');
        setVal('myProfileStaffId', data.staffId || '');
        setVal('myProfileDateJoined', data.dateJoined || '');
        setVal('myProfileEmergencyName', data.emergencyContactName || '');
        setVal('myProfileEmergencyPhone', data.emergencyContactPhone || '');

        const img = document.getElementById('myProfilePhoto');
        if (img) {
            const url = data.photoUrl || user.photoURL || '';
            if (url) {
                img.src = url;
                img.onerror = function(){ this.removeAttribute('src'); this.style.background = '#f3f4f6'; this.alt = 'No profile photo'; };
            } else {
                img.removeAttribute('src');
                img.style.background = '#f3f4f6';
            }
        }

        if (msg) {
            msg.innerText = '';
        }

        if (typeof sp4_loadMyAttendanceIdentity === 'function') sp4_loadMyAttendanceIdentity();
        if (typeof att42_loadMyAttendanceIntelligence === 'function') att42_loadMyAttendanceIntelligence();
    } catch(e) {
        console.error('My Profile load failed', e);
        if (msg) {
            msg.innerText = 'Could not load profile: ' + e.message;
            msg.style.color = 'var(--error)';
        }
    }
};

window.myProfile_save = async function() {
    const user = firebase.auth().currentUser;
    if (!user) return alert('Please sign in again.');

    const msg = document.getElementById('myProfileMsg');
    if (msg) {
        msg.innerText = 'Saving...';
        msg.style.color = '#777';
    }

    try {
        const email = user.email.toLowerCase();

        await db.collection('Users').doc(email).set({
            phone: document.getElementById('myProfilePhone')?.value.trim() || '',
            emergencyContactName: document.getElementById('myProfileEmergencyName')?.value.trim() || '',
            emergencyContactPhone: document.getElementById('myProfileEmergencyPhone')?.value.trim() || '',
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: email,
            selfUpdatedAt: firebase.firestore.FieldValue.serverTimestamp()
        }, { merge: true });

        if (msg) {
            msg.innerText = 'Profile saved.';
            msg.style.color = 'var(--success)';
        }

        const updated = await db.collection('Users').doc(email).get();
        if (updated.exists && typeof renderStaffProfileMiniCard === 'function') {
            renderStaffProfileMiniCard(updated.data());
        }
    } catch(e) {
        console.error('My Profile save failed', e);
        if (msg) {
            msg.innerText = 'Save failed: ' + e.message;
            msg.style.color = 'var(--error)';
        }
    }
};


