// ── STAFF PROFILE PHASE 4: ATTENDANCE + IDENTITY LINK ─────────────────────
function sp4_today() {
    return typeof todayDateStr !== 'undefined' ? todayDateStr : getLocalDateString();
}

async function sp4_getUserProfile(email) {
    if (!email) return {};
    try {
        const doc = await db.collection('Users').doc(String(email).toLowerCase()).get();
        return doc.exists ? (doc.data() || {}) : {};
    } catch(e) {
        console.warn('Profile lookup failed', email, e);
        return {};
    }
}


function sp4_formatAttendanceTime(value) {
    if (!value) return '—';

    try {
        // Firestore Timestamp
        if (typeof value.toDate === 'function') {
            const d = value.toDate();
            return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        }

        // Raw Firestore-like object: { seconds, nanoseconds }
        if (typeof value === 'object' && value.seconds) {
            const d = new Date(value.seconds * 1000);
            return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        }

        // Already a readable time string
        if (typeof value === 'string') {
            if (value.includes('Timestamp(')) return 'Recorded';
            return value;
        }

        return String(value);
    } catch(e) {
        return 'Recorded';
    }
}

async function sp4_loadMyAttendanceIdentity() {
    const user = firebase.auth().currentUser;
    if (!user) return;

    const statusEl = document.getElementById('myProfileAttendanceStatus');
    const inEl = document.getElementById('myProfileClockIn');
    const outEl = document.getElementById('myProfileClockOut');
    const noteEl = document.getElementById('myProfileAttendanceNote');

    if (!statusEl && !inEl && !outEl) return;

    try {
        const email = user.email.toLowerCase();
        const today = sp4_today();

        let attendance = null;

        // Try common attendance doc patterns safely
        const candidates = [
            `Attendance_${today}_${email}`,
            `${today}_${email}`,
            `${email}_${today}`
        ];

        for (const id of candidates) {
            try {
                const doc = await db.collection('Attendance').doc(id).get();
                if (doc.exists) {
                    attendance = doc.data();
                    break;
                }
            } catch(_) {}
        }

        // Fallback query
        if (!attendance) {
            try {
                const snap = await db.collection('Attendance')
                    .where('email', '==', email)
                    .where('dateString', '==', today)
                    .limit(1)
                    .get();
                if (!snap.empty) attendance = snap.docs[0].data();
            } catch(_) {}
        }

        const rawClockIn = attendance?.clockIn || attendance?.clockInTime || attendance?.timeIn || '';
        const rawClockOut = attendance?.clockOut || attendance?.clockOutTime || attendance?.timeOut || '';
        const clockIn = sp4_formatAttendanceTime(rawClockIn);
        const clockOut = sp4_formatAttendanceTime(rawClockOut);
        const status = attendance?.status || (rawClockIn && !rawClockOut ? 'Clocked In' : (rawClockIn && rawClockOut ? 'Clocked Out' : 'Not Clocked In'));

        if (statusEl) statusEl.innerText = status;
        if (inEl) inEl.innerText = clockIn || '—';
        if (outEl) outEl.innerText = clockOut || '—';

        if (noteEl) {
            noteEl.innerHTML = attendance
                ? `✅ Identity linked to today’s attendance record for <strong>${today}</strong>.`
                : `No attendance record found for today yet.`;
        }
    } catch(e) {
        console.warn('My attendance identity load failed', e);
        if (noteEl) {
            noteEl.innerText = 'Could not load today attendance identity: ' + e.message;
            noteEl.style.color = 'var(--error)';
        }
    }
}

async function sp4_enrichAttendanceRosterPhotos() {
    const containers = [
        document.getElementById('att_rosterList'),
        document.getElementById('fohRosterList')
    ].filter(Boolean);

    if (!containers.length) return;

    try {
        const userSnap = await db.collection('Users').get();
        const profiles = {};
        userSnap.forEach(doc => {
            const d = doc.data() || {};
            profiles[String(doc.id).toLowerCase()] = {
                name: d.name || '',
                photoUrl: d.photoUrl || '',
                staffId: d.staffId || '',
                roles: Array.isArray(d.roles) ? d.roles : (d.role ? [d.role] : [])
            };
        });

        containers.forEach(container => {
            const text = container.innerHTML;
            Object.keys(profiles).forEach(email => {
                const p = profiles[email];
                if (!p.photoUrl) return;

                // Only add one identity legend per visible roster container
                if (!container.querySelector('.sp4-identity-strip')) {
                    const strip = document.createElement('div');
                    strip.className = 'sp4-identity-strip';
                    strip.style.cssText = 'display:flex; gap:10px; flex-wrap:wrap; margin:10px 0 15px; padding:10px; background:#fafafa; border:1px solid var(--border); border-radius:10px;';
                    strip.innerHTML = Object.entries(profiles).slice(0, 20).map(([em, prof]) => `
                        <div style="display:flex; align-items:center; gap:7px; background:#fff; border:1px solid var(--border); border-radius:999px; padding:5px 9px;">
                            <img src="${prof.photoUrl || ''}" onerror="this.style.display='none';" style="width:28px;height:28px;border-radius:50%;object-fit:cover;border:1px solid var(--accent);">
                            <span style="font-size:0.76rem; color:var(--primary); font-weight:700;">${prof.name || em}</span>
                        </div>
                    `).join('');
                    container.prepend(strip);
                }
            });
        });
    } catch(e) {
        console.warn('Attendance roster identity enrichment failed', e);
    }
}

function sp4_patchAttendanceFunctions() {
    if (window.__sp4AttendancePatched) return;

    const patch = (fnName) => {
        if (typeof window[fnName] === 'function') {
            const original = window[fnName];
            window[fnName] = async function(...args) {
                const result = await original.apply(this, args);
                setTimeout(sp4_enrichAttendanceRosterPhotos, 400);
                return result;
            };
        }
    };

    patch('att_loadRoster');
    patch('att_loadDailyRoster');
    patch('loadFOHRoster');
    window.__sp4AttendancePatched = true;
}

function sp4_bootAttendanceIdentity() {
    sp4_patchAttendanceFunctions();

    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === 'function' && !window.__sp4SwitchPatched) {
        window.switchModule = function(moduleId) {
            oldSwitch(moduleId);
            if (moduleId === 'myProfileView') setTimeout(sp4_loadMyAttendanceIdentity, 250);
            if (moduleId === 'attendanceView') setTimeout(sp4_enrichAttendanceRosterPhotos, 600);
        };
        window.__sp4SwitchPatched = true;
    }
}

if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', sp4_bootAttendanceIdentity);
} else {
    sp4_bootAttendanceIdentity();
}

window.sp4_loadMyAttendanceIdentity = sp4_loadMyAttendanceIdentity;
window.sp4_enrichAttendanceRosterPhotos = sp4_enrichAttendanceRosterPhotos;



// ── STAFF PROFILE PHASE 5: PERFORMANCE DASHBOARD ─────────────────────
function perf_today() {
    return typeof todayDateStr !== 'undefined' ? todayDateStr : getLocalDateString();
}

function perf_money(v) {
    const n = Number(parseFloat(v || 0));
    return (Number.isFinite(n) ? n : 0).toFixed(2);
}

function perf_dateAdd(dateStr, days) {
    const d = new Date(dateStr + 'T12:00:00');
    d.setDate(d.getDate() + days);
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}

function perf_monthStart(dateStr) {
    const d = new Date(dateStr + 'T12:00:00');
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-01`;
}

function perf_monthEnd(dateStr) {
    const d = new Date(dateStr + 'T12:00:00');
    return new Date(d.getFullYear(), d.getMonth()+1, 0).toISOString().slice(0,10);
}

function perf_setRange(type) {
    const today = perf_today();
    const start = document.getElementById('perf_start');
    const end = document.getElementById('perf_end');
    const range = document.getElementById('perf_range');
    if (range) range.value = type;
    if (!start || !end) return;

    if (type === 'today') {
        start.value = today;
        end.value = today;
    } else if (type === 'week') {
        start.value = perf_dateAdd(today, -6);
        end.value = today;
    } else if (type === 'month') {
        start.value = perf_monthStart(today);
        end.value = perf_monthEnd(today);
    }
}

function perf_revenue(job) {
    return Number(parseFloat(job.totalGHC || job.finalTotal || job.grandTotal || job.bookedPrice || 0)) || 0;
}

function perf_staffEmail(job) {
    return String(job.assignedTechEmail || job.techEmail || job.staffEmail || 'unassigned').toLowerCase();
}

function perf_staffName(job, profiles) {
    const email = perf_staffEmail(job);
    return job.assignedTechName || job.techName || job.staffName || profiles[email]?.name || 'Unassigned';
}

async function perf_getProfiles() {
    const profiles = {};
    try {
        const snap = await db.collection('Users').get();
        snap.forEach(doc => {
            const d = doc.data() || {};
            profiles[String(doc.id).toLowerCase()] = {
                name: d.name || '',
                photoUrl: d.photoUrl || '',
                staffId: d.staffId || '',
                roles: Array.isArray(d.roles) ? d.roles : (d.role ? [d.role] : [])
            };
        });
    } catch(e) {
        console.warn('Performance profile lookup failed', e);
    }
    return profiles;
}

async function perf_getCommissionRows(start, end) {
    const totals = {};
    try {
        const snap = await db.collection('Commission_Records')
            .where('periodStart', '>=', start)
            .where('periodEnd', '<=', end)
            .get();

        snap.forEach(doc => {
            const d = doc.data() || {};
            const email = String(d.staffEmail || '').toLowerCase();
            if (!email) return;
            totals[email] = (totals[email] || 0) + (Number(parseFloat(d.commissionAmount || 0)) || 0);
        });
    } catch(e) {
        console.warn('Performance commission records unavailable', e);
    }
    return totals;
}

async function perf_loadDashboard() {
    const start = document.getElementById('perf_start')?.value || perf_monthStart(perf_today());
    const end = document.getElementById('perf_end')?.value || perf_today();

    const leaderboard = document.getElementById('perf_leaderboard');
    const detail = document.getElementById('perf_detail');

    if (leaderboard) leaderboard.innerHTML = '<div class="perf-empty">Loading performance...</div>';
    if (detail) detail.innerHTML = '<div class="perf-empty">Loading details...</div>';

    try {
        const profiles = await perf_getProfiles();
        const commissionTotals = await perf_getCommissionRows(start, end);

        let jobs = [];
        try {
            const snap = await db.collection('Active_Jobs')
                .where('status', '==', 'Closed')
                .where('dateString', '>=', start)
                .where('dateString', '<=', end)
                .get();
            snap.forEach(doc => jobs.push({ id: doc.id, ...doc.data() }));
        } catch(e) {
            console.warn('Performance closed jobs query failed', e);
            const snap = await db.collection('Active_Jobs').get();
            snap.forEach(doc => {
                const d = doc.data() || {};
                if (d.status === 'Closed' && d.dateString >= start && d.dateString <= end) jobs.push({ id: doc.id, ...d });
            });
        }

        const stats = {};
        jobs.forEach(job => {
            const email = perf_staffEmail(job);
            const revenue = perf_revenue(job);
            if (!stats[email]) {
                stats[email] = {
                    email,
                    name: perf_staffName(job, profiles),
                    photoUrl: profiles[email]?.photoUrl || '',
                    staffId: profiles[email]?.staffId || '',
                    jobs: 0,
                    revenue: 0,
                    commission: 0,
                    utilization: 0
                };
            }
            stats[email].jobs += 1;
            stats[email].revenue += revenue;
        });

        Object.keys(commissionTotals).forEach(email => {
            if (!stats[email]) {
                stats[email] = {
                    email,
                    name: profiles[email]?.name || email,
                    photoUrl: profiles[email]?.photoUrl || '',
                    staffId: profiles[email]?.staffId || '',
                    jobs: 0,
                    revenue: 0,
                    commission: 0,
                    utilization: 0
                };
            }
            stats[email].commission = commissionTotals[email];
        });

        const rows = Object.values(stats).sort((a,b) => b.revenue - a.revenue);
        const maxRevenue = Math.max(...rows.map(r => r.revenue), 1);
        rows.forEach(r => {
            r.utilization = Math.min(100, Math.round((r.jobs / Math.max(1, jobs.length || 1)) * 100));
        });

        const totalRevenue = rows.reduce((s,r) => s + r.revenue, 0);
        const totalCommission = rows.reduce((s,r) => s + r.commission, 0);

        const setText = (id, val) => { const el = document.getElementById(id); if (el) el.innerText = val; };
        setText('perf_totalRevenue', perf_money(totalRevenue) + ' GHC');
        setText('perf_totalJobs', jobs.length);
        setText('perf_activeStaff', rows.length);
        setText('perf_totalCommission', perf_money(totalCommission) + ' GHC');

        perf_renderLeaderboard(rows, maxRevenue);
        perf_renderDetail(rows);
    } catch(e) {
        console.error('Performance dashboard failed', e);
        if (leaderboard) leaderboard.innerHTML = `<div class="perf-empty">Could not load performance: ${e.message}</div>`;
        if (detail) detail.innerHTML = `<div class="perf-empty">Could not load details.</div>`;
    }
}

function perf_renderLeaderboard(rows, maxRevenue) {
    const el = document.getElementById('perf_leaderboard');
    if (!el) return;

    if (!rows.length) {
        el.innerHTML = '<div class="perf-empty">No closed jobs found for this period.</div>';
        return;
    }

    el.innerHTML = rows.slice(0, 10).map((r, i) => {
        const pct = Math.max(3, Math.round((r.revenue / maxRevenue) * 100));
        return `
            <div class="perf-staff-row">
                <div class="perf-rank">#${i+1}</div>
                <img src="${r.photoUrl || ''}" onerror="this.style.display='none';">
                <div style="flex:1; min-width:0;">
                    <div style="display:flex; justify-content:space-between; gap:10px;">
                        <strong style="color:var(--primary);">${r.name}</strong>
                        <strong style="color:var(--accent);">${perf_money(r.revenue)} GHC</strong>
                    </div>
                    <div style="font-size:0.75rem; color:#777;">${r.jobs} bookings · ${perf_money(r.commission)} GHC commission</div>
                    <div class="perf-bar"><div style="width:${pct}%"></div></div>
                </div>
            </div>
        `;
    }).join('');
}

function perf_renderDetail(rows) {
    const el = document.getElementById('perf_detail');
    if (!el) return;

    if (!rows.length) {
        el.innerHTML = '<div class="perf-empty">No detail records found.</div>';
        return;
    }

    el.innerHTML = `
        <div class="perf-table-wrap">
            <table class="perf-table">
                <thead>
                    <tr>
                        <th>Staff</th>
                        <th>Staff ID</th>
                        <th>Bookings</th>
                        <th>Revenue</th>
                        <th>Commission</th>
                        <th>Utilization</th>
                        <th>Rank</th>
                    </tr>
                </thead>
                <tbody>
                    ${rows.map((r, i) => `
                        <tr>
                            <td>
                                <div style="display:flex; align-items:center; gap:9px;">
                                    <img src="${r.photoUrl || ''}" onerror="this.style.display='none';" style="width:34px;height:34px;border-radius:50%;object-fit:cover;border:1px solid var(--accent);">
                                    <div><strong>${r.name}</strong><br><span style="color:#777;font-size:0.74rem;">${r.email}</span></div>
                                </div>
                            </td>
                            <td>${r.staffId || '—'}</td>
                            <td>${r.jobs}</td>
                            <td><strong>${perf_money(r.revenue)} GHC</strong></td>
                            <td>${perf_money(r.commission)} GHC</td>
                            <td>${r.utilization}%</td>
                            <td>#${i+1}</td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>
        </div>
    `;
}

function perf_boot() {
    const today = perf_today();
    if (document.getElementById('perf_start') && !document.getElementById('perf_start').value) {
        perf_setRange('month');
    }

    const tab = document.getElementById('tabPerformance');
    if (tab) {
        try {
            const roles = typeof currentRoles !== 'undefined' && Array.isArray(currentRoles) ? currentRoles.map(r => String(r).toLowerCase()) : [];
            const canSee = roles.some(r => r.includes('admin') || r.includes('manager'));
            tab.style.display = canSee ? 'flex' : 'none';
        } catch(e) {}
    }
}

window.perf_setRange = perf_setRange;
window.perf_loadDashboard = perf_loadDashboard;

if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', perf_boot);
} else {
    perf_boot();
}



// ── ATTENDANCE PHASE 4.2: INTELLIGENCE LAYER ─────────────────────
function att42_toDate(value) {
    if (!value) return null;
    try {
        if (typeof value.toDate === 'function') return value.toDate();
        if (typeof value === 'object' && value.seconds) return new Date(value.seconds * 1000);
        if (value instanceof Date) return value;
        if (typeof value === 'string') {
            const d = new Date(value);
            return Number.isNaN(d.getTime()) ? null : d;
        }
        return null;
    } catch(e) {
        return null;
    }
}

function att42_formatDuration(ms) {
    if (!ms || ms < 0) return '—';
    const totalMinutes = Math.floor(ms / 60000);
    const h = Math.floor(totalMinutes / 60);
    const m = totalMinutes % 60;
    if (h <= 0) return `${m}m`;
    return `${h}h ${m}m`;
}

function att42_getDeviceType() {
    const ua = navigator.userAgent || '';
    if (/Mobi|Android|iPhone/i.test(ua)) return 'Mobile';
    if (/iPad|Tablet/i.test(ua)) return 'Tablet';
    return 'Web';
}

function att42_getShiftStart() {
    // Default shift start. Later we can move this to Settings/Attendance.
    return '09:00';
}

function att42_isLate(clockInDate, shiftStartHHMM) {
    if (!clockInDate || !shiftStartHHMM) return false;
    const [hh, mm] = shiftStartHHMM.split(':').map(Number);
    const shift = new Date(clockInDate);
    shift.setHours(hh || 9, mm || 0, 0, 0);
    return clockInDate > shift;
}

async function att42_enrichTodayAttendanceRecord() {
    const user = firebase.auth().currentUser;
    if (!user || !db) return;

    const email = user.email.toLowerCase();
    const today = typeof todayDateStr !== 'undefined' ? todayDateStr : getLocalDateString();

    try {
        const snap = await db.collection('Attendance')
            .where('email', '==', email)
            .where('dateString', '==', today)
            .limit(1)
            .get();

        if (snap.empty) return;

        const doc = snap.docs[0];
        const a = doc.data() || {};
        const clockInRaw = a.clockIn || a.clockInTime || a.timeIn || '';
        const clockOutRaw = a.clockOut || a.clockOutTime || a.timeOut || '';
        const clockInDate = att42_toDate(clockInRaw);
        const clockOutDate = att42_toDate(clockOutRaw);
        const shiftStart = a.shiftStart || att42_getShiftStart();

        let durationMinutes = null;
        if (clockInDate && clockOutDate) {
            durationMinutes = Math.max(0, Math.floor((clockOutDate - clockInDate) / 60000));
        }

        const patch = {
            method: a.method || 'app',
            device: a.device || att42_getDeviceType(),
            shiftStart: shiftStart,
            isLate: a.isLate === true ? true : att42_isLate(clockInDate, shiftStart),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };

        if (durationMinutes !== null) {
            patch.workDurationMinutes = durationMinutes;
            patch.workDurationText = att42_formatDuration(durationMinutes * 60000);
        }

        await db.collection('Attendance').doc(doc.id).set(patch, { merge: true });
    } catch(e) {
        console.warn('Attendance intelligence enrichment failed', e);
    }
}

async function att42_loadMyAttendanceIntelligence() {
    const user = firebase.auth().currentUser;
    if (!user || !db) return;

    const durationEl = document.getElementById('myProfileWorkDuration');
    const lateEl = document.getElementById('myProfileLateStatus');
    const methodEl = document.getElementById('myProfileClockMethod');
    if (!durationEl && !lateEl && !methodEl) return;

    const email = user.email.toLowerCase();
    const today = typeof todayDateStr !== 'undefined' ? todayDateStr : getLocalDateString();

    try {
        await att42_enrichTodayAttendanceRecord();

        const snap = await db.collection('Attendance')
            .where('email', '==', email)
            .where('dateString', '==', today)
            .limit(1)
            .get();

        if (snap.empty) {
            if (durationEl) durationEl.innerText = '—';
            if (lateEl) lateEl.innerText = '—';
            if (methodEl) methodEl.innerText = '—';
            return;
        }

        const a = snap.docs[0].data() || {};
        const clockInDate = att42_toDate(a.clockIn || a.clockInTime || a.timeIn || '');
        const clockOutDate = att42_toDate(a.clockOut || a.clockOutTime || a.timeOut || '');

        let durationText = a.workDurationText || '—';
        if (!a.workDurationText && clockInDate && clockOutDate) {
            durationText = att42_formatDuration(clockOutDate - clockInDate);
        } else if (clockInDate && !clockOutDate) {
            durationText = 'In progress';
        }

        if (durationEl) durationEl.innerText = durationText;
        if (lateEl) {
            lateEl.innerText = a.isLate ? 'Late' : (clockInDate ? 'On Time' : '—');
            lateEl.style.color = a.isLate ? 'var(--error)' : 'var(--success)';
        }
        if (methodEl) methodEl.innerText = `${a.method || 'app'} / ${a.device || att42_getDeviceType()}`;
    } catch(e) {
        console.warn('Attendance intelligence load failed', e);
    }
}

function att42_patchClockActions() {
    if (window.__att42Patched) return;

    ['logOut', 'clockOut', 'clockIn', 'signInClockIn'].forEach(fnName => {
        if (typeof window[fnName] === 'function') {
            const original = window[fnName];
            window[fnName] = async function(...args) {
                const result = await original.apply(this, args);
                setTimeout(att42_enrichTodayAttendanceRecord, 600);
                setTimeout(att42_loadMyAttendanceIntelligence, 900);
                return result;
            };
        }
    });

    window.__att42Patched = true;
}

function att42_boot() {
    att42_patchClockActions();
    setTimeout(att42_enrichTodayAttendanceRecord, 1200);
    setTimeout(att42_loadMyAttendanceIntelligence, 1500);
}

if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', att42_boot);
} else {
    att42_boot();
}

if (window.firebase && firebase.auth) {
    firebase.auth().onAuthStateChanged(user => {
        if (user) setTimeout(att42_boot, 1000);
    });
}

window.att42_loadMyAttendanceIntelligence = att42_loadMyAttendanceIntelligence;
window.att42_enrichTodayAttendanceRecord = att42_enrichTodayAttendanceRecord;



// ── ATTENDANCE PHASE 4.3: PROPER CLOCK SYSTEM ─────────────────────
// Login/logout is now separate from attendance.
// Staff must explicitly click Clock In / Clock Out.
function pc43_today() {
    return typeof todayDateStr !== 'undefined' ? todayDateStr : getLocalDateString();
}

function pc43_docId(email) {
    return `${String(email || '').toLowerCase()}_${pc43_today()}`;
}

function pc43_deviceType() {
    const ua = navigator.userAgent || '';
    if (/Mobi|Android|iPhone/i.test(ua)) return 'Mobile';
    if (/iPad|Tablet/i.test(ua)) return 'Tablet';
    return 'Web';
}

function pc43_shiftStart() {
    return '09:00';
}

function pc43_isLate(now, shiftStartHHMM) {
    const [hh, mm] = String(shiftStartHHMM || '09:00').split(':').map(Number);
    const shift = new Date(now);
    shift.setHours(hh || 9, mm || 0, 0, 0);
    return now > shift;
}

function pc43_formatTime(value) {
    try {
        if (!value) return '—';
        let d = null;
        if (typeof value.toDate === 'function') d = value.toDate();
        else if (typeof value === 'object' && value.seconds) d = new Date(value.seconds * 1000);
        else if (value instanceof Date) d = value;
        else return String(value);
        return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch(e) {
        return 'Recorded';
    }
}

function pc43_durationText(clockIn, clockOut) {
    try {
        let s = clockIn?.toDate ? clockIn.toDate() : (clockIn?.seconds ? new Date(clockIn.seconds * 1000) : null);
        let e = clockOut?.toDate ? clockOut.toDate() : (clockOut?.seconds ? new Date(clockOut.seconds * 1000) : null);
        if (!s || !e) return '';
        const mins = Math.max(0, Math.floor((e - s) / 60000));
        const h = Math.floor(mins / 60);
        const m = mins % 60;
        return h ? `${h}h ${m}m` : `${m}m`;
    } catch(_) {
        return '';
    }
}

function pc43_ensureClockPanel() {
    const dashboard = document.getElementById('appDashboard');
    if (!dashboard || document.getElementById('properClockPanel')) return;

    const panel = document.createElement('div');
    panel.id = 'properClockPanel';
    panel.style.cssText = `
        max-width:1180px;
        margin:14px auto 8px;
        background:#fff;
        border:1px solid var(--border);
        border-left:4px solid var(--accent);
        border-radius:14px;
        padding:12px 14px;
        display:none;
        align-items:center;
        justify-content:space-between;
        gap:12px;
        flex-wrap:wrap;
        box-shadow:0 6px 18px rgba(47,59,79,.06);
    `;

    panel.innerHTML = `
        <div style="display:flex; align-items:center; gap:10px; min-width:260px;">
            <div id="pc43StatusDot" style="width:12px;height:12px;border-radius:50%;background:#bbb;"></div>
            <div>
                <div id="pc43StatusText" style="font-weight:900;color:var(--primary);font-size:.9rem;">Attendance not loaded</div>
                <div id="pc43StatusSub" style="color:#666;font-size:.78rem;">Login/logout is separate from attendance.</div>
            </div>
        </div>
        <div style="display:flex; gap:8px; flex-wrap:wrap;">
            <button id="pc43ClockInBtn" class="btn" style="width:auto;padding:8px 14px;font-size:.78rem;background:var(--success);" onclick="pc43_clockIn()">Clock In / Start Shift</button>
            <button id="pc43ClockOutBtn" class="btn btn-secondary" style="width:auto;padding:8px 14px;font-size:.78rem;color:var(--error);border-color:var(--error);" onclick="pc43_clockOut()">Clock Out / End Shift</button>
        </div>
    `;

    const firstModule = dashboard.querySelector('.app-module');
    if (firstModule) dashboard.insertBefore(panel, firstModule);
    else dashboard.prepend(panel);
}

async function pc43_getTodayRecord() {
    const user = firebase.auth().currentUser;
    if (!user) return null;

    const email = user.email.toLowerCase();
    const docRef = db.collection('Attendance').doc(pc43_docId(email));
    const doc = await docRef.get();

    if (doc.exists) return { id: doc.id, ref: docRef, data: doc.data() || {} };

    // Fallback for older record style
    try {
        const snap = await db.collection('Attendance')
            .where('email', '==', email)
            .where('dateString', '==', pc43_today())
            .limit(1)
            .get();
        if (!snap.empty) return { id: snap.docs[0].id, ref: snap.docs[0].ref, data: snap.docs[0].data() || {} };
    } catch(_) {}

    return { id: pc43_docId(email), ref: docRef, data: null };
}

async function pc43_refreshClockPanel() {
    pc43_ensureClockPanel();

    const panel = document.getElementById('properClockPanel');
    const inBtn = document.getElementById('pc43ClockInBtn');
    const outBtn = document.getElementById('pc43ClockOutBtn');
    const txt = document.getElementById('pc43StatusText');
    const sub = document.getElementById('pc43StatusSub');
    const dot = document.getElementById('pc43StatusDot');

    const user = firebase.auth().currentUser;
    if (!panel || !user) {
        if (panel) panel.style.display = 'none';
        return;
    }

    panel.style.display = 'flex';

    try {
        const rec = await pc43_getTodayRecord();
        const a = rec?.data;

        if (!a || !a.clockIn) {
            if (txt) txt.innerText = 'Not clocked in today';
            if (sub) sub.innerText = 'Click Clock In when starting your shift.';
            if (dot) dot.style.background = '#bbb';
            if (inBtn) inBtn.style.display = 'inline-block';
            if (outBtn) outBtn.style.display = 'none';
            return;
        }

        if (a.clockIn && !a.clockOut) {
            if (txt) txt.innerText = 'Clocked In';
            if (sub) sub.innerText = `Since ${pc43_formatTime(a.clockIn)} · ${a.isLate ? 'Late' : 'On time'} · ${a.device || pc43_deviceType()}`;
            if (dot) dot.style.background = 'var(--success)';
            if (inBtn) inBtn.style.display = 'none';
            if (outBtn) outBtn.style.display = 'inline-block';
            return;
        }

        if (a.clockIn && a.clockOut) {
            const dur = a.workDurationText || pc43_durationText(a.clockIn, a.clockOut);
            if (txt) txt.innerText = 'Shift Ended';
            if (sub) sub.innerText = `${pc43_formatTime(a.clockIn)} → ${pc43_formatTime(a.clockOut)}${dur ? ' · ' + dur : ''}`;
            if (dot) dot.style.background = 'var(--error)';
            if (inBtn) inBtn.style.display = 'none';
            if (outBtn) outBtn.style.display = 'none';
        }
    } catch(e) {
        console.warn('Clock panel refresh failed', e);
        if (txt) txt.innerText = 'Attendance unavailable';
        if (sub) sub.innerText = e.message || 'Could not load attendance.';
    }
}

async function pc43_clockIn() {
    const user = firebase.auth().currentUser;
    if (!user) return alert('Please sign in again.');

    const email = user.email.toLowerCase();
    const name = currentUserName || user.displayName || 'Staff Member';
    const roles = Array.isArray(currentRoles) ? currentRoles : [];
    const now = new Date();
    const shiftStart = pc43_shiftStart();

    try {
        const rec = await pc43_getTodayRecord();
        const existing = rec?.data;

        if (existing?.clockIn && !existing?.clockOut) {
            alert('You are already clocked in.');
            await pc43_refreshClockPanel();
            return;
        }

        if (existing?.clockIn && existing?.clockOut) {
            alert('You already completed today’s shift. Ask Admin/Manager if this needs correction.');
            await pc43_refreshClockPanel();
            return;
        }

        await rec.ref.set({
            email,
            name,
            roleString: roles.join(','),
            roles,
            date: pc43_today(),
            dateString: pc43_today(),
            clockIn: firebase.firestore.FieldValue.serverTimestamp(),
            status: 'Clocked In',
            method: 'app',
            device: pc43_deviceType(),
            shiftStart,
            isLate: pc43_isLate(now, shiftStart),
            createdAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        }, { merge: true });

        alert('Clock-in recorded. Have a productive shift.');
        await pc43_refreshClockPanel();
        if (typeof sp4_loadMyAttendanceIdentity === 'function') sp4_loadMyAttendanceIdentity();
        if (typeof att42_loadMyAttendanceIntelligence === 'function') att42_loadMyAttendanceIntelligence();
    } catch(e) {
        console.error('Clock in failed', e);
        alert('Clock in failed: ' + e.message);
    }
}

async function pc43_clockOut() {
    const user = firebase.auth().currentUser;
    if (!user) return alert('Please sign in again.');

    try {
        const rec = await pc43_getTodayRecord();
        const a = rec?.data;

        if (!a || !a.clockIn) {
            alert('You are not clocked in today.');
            await pc43_refreshClockPanel();
            return;
        }

        if (a.clockOut) {
            alert('You have already clocked out today.');
            await pc43_refreshClockPanel();
            return;
        }

        if (!confirm('Clock out and end your shift now?')) return;

        const clockInDate = a.clockIn?.toDate ? a.clockIn.toDate() : (a.clockIn?.seconds ? new Date(a.clockIn.seconds * 1000) : null);
        const now = new Date();
        let durationMinutes = null;
        if (clockInDate) durationMinutes = Math.max(0, Math.floor((now - clockInDate) / 60000));

        const patch = {
            clockOut: firebase.firestore.FieldValue.serverTimestamp(),
            status: 'Clocked Out',
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };

        if (durationMinutes !== null) {
            patch.workDurationMinutes = durationMinutes;
            const h = Math.floor(durationMinutes / 60);
            const m = durationMinutes % 60;
            patch.workDurationText = h ? `${h}h ${m}m` : `${m}m`;
        }

        await rec.ref.set(patch, { merge: true });

        alert('Clock-out recorded.');
        await pc43_refreshClockPanel();
        if (typeof sp4_loadMyAttendanceIdentity === 'function') sp4_loadMyAttendanceIdentity();
        if (typeof att42_loadMyAttendanceIntelligence === 'function') att42_loadMyAttendanceIntelligence();
    } catch(e) {
        console.error('Clock out failed', e);
        alert('Clock out failed: ' + e.message);
    }
}

function pc43_boot() {
    pc43_ensureClockPanel();
    setTimeout(pc43_refreshClockPanel, 900);
    setTimeout(pc43_refreshClockPanel, 2000);
}

if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', pc43_boot);
} else {
    pc43_boot();
}

if (window.firebase && firebase.auth) {
    firebase.auth().onAuthStateChanged(user => {
        if (user) setTimeout(pc43_boot, 900);
    });
}

window.pc43_clockIn = pc43_clockIn;
window.pc43_clockOut = pc43_clockOut;
window.pc43_refreshClockPanel = pc43_refreshClockPanel;


// ============================================================================
// THURAYA PHASE 4.3.6 v4 PATCH
// Fix shift duplication + reliable multi-shift duration
// This patch safely overrides the clock in/out handlers after the main app loads.
// ============================================================================

(function () {
    const TH_V4 = {
        booted: false,
        busy: false
    };

    function thToday() {
        try {
            if (typeof getLocalDateString === "function") return getLocalDateString();
        } catch (e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
    }

    function thEmail() {
        const user = firebase?.auth?.().currentUser;
        return String(user?.email || currentUserEmail || "").toLowerCase().trim();
    }

    function thDocId(email, today) {
        return `${email}_${today}`;
    }

    function thToDate(value) {
        if (!value) return null;
        try {
            if (value instanceof Date) return value;
            if (typeof value.toDate === "function") return value.toDate();
            if (typeof value === "object" && typeof value.seconds === "number") return new Date(value.seconds * 1000);
            if (typeof value === "object" && typeof value._seconds === "number") return new Date(value._seconds * 1000);
            if (typeof value === "number") return new Date(value);
            if (typeof value === "string") {
                const parsed = new Date(value);
                if (!isNaN(parsed.getTime())) return parsed;
            }
        } catch (e) {}
        return null;
    }

    function thTimestamp(date) {
        return firebase.firestore.Timestamp.fromDate(date instanceof Date ? date : new Date(date));
    }

    function thMinutesBetween(start, end) {
        const s = thToDate(start);
        const e = thToDate(end);
        if (!s || !e || e < s) return 0;
        return Math.max(0, Math.floor((e - s) / 60000));
    }

    function thDurationText(totalMinutes) {
        const mins = Math.max(0, parseInt(totalMinutes || 0, 10));
        const h = Math.floor(mins / 60);
        const m = mins % 60;
        return `${h}h ${m}m`;
    }

    function thShiftStart() {
        try {
            if (typeof pc43_shiftStart === "function") return pc43_shiftStart();
        } catch (e) {}
        return "09:00";
    }

    function thIsLate(now, shiftStartHHMM) {
        try {
            if (typeof pc43_isLate === "function") return pc43_isLate(now, shiftStartHHMM);
        } catch (e) {}

        const [hh, mm] = String(shiftStartHHMM || "09:00").split(":").map(Number);
        const shift = new Date(now);
        shift.setHours(hh || 9, mm || 0, 0, 0);
        return now > shift;
    }

    function thDeviceType() {
        try {
            if (typeof pc43_deviceType === "function") return pc43_deviceType();
        } catch (e) {}
        return /Mobi|Android/i.test(navigator.userAgent) ? "Mobile" : "Web";
    }

    function thNormaliseShift(raw, index) {
        if (!raw) return null;

        const start =
            thToDate(raw.in) ||
            thToDate(raw.clockIn) ||
            thToDate(raw.start) ||
            thToDate(raw.startAt) ||
            thToDate(raw.startedAt) ||
            thToDate(raw.clockInTime);

        const end =
            thToDate(raw.out) ||
            thToDate(raw.clockOut) ||
            thToDate(raw.end) ||
            thToDate(raw.endAt) ||
            thToDate(raw.endedAt) ||
            thToDate(raw.clockOutTime);

        if (!start) return null;

        return {
            id: raw.id || raw.shiftId || `shift_${start.getTime()}_${index}`,
            in: thTimestamp(start),
            out: end ? thTimestamp(end) : null,
            startedAt: thTimestamp(start),
            endedAt: end ? thTimestamp(end) : null,
            method: raw.method || "app",
            device: raw.device || thDeviceType()
        };
    }

    function thCleanShifts(attendance) {
        const raw = Array.isArray(attendance?.shifts) ? attendance.shifts : [];
        const map = new Map();

        raw.forEach((shift, index) => {
            const normal = thNormaliseShift(shift, index);
            if (!normal) return;

            const s = thToDate(normal.in);
            const e = thToDate(normal.out);
            const key = `${s ? s.getTime() : "x"}_${e ? e.getTime() : "open"}`;

            // Keep only one open shift. If there are several open shifts, keep the latest.
            if (!e) {
                map.set("OPEN_SHIFT", normal);
            } else {
                map.set(key, normal);
            }
        });

        let cleaned = Array.from(map.values()).sort((a, b) => {
            const ad = thToDate(a.in);
            const bd = thToDate(b.in);
            return (ad ? ad.getTime() : 0) - (bd ? bd.getTime() : 0);
        });

        // Remove zero-length closed shifts.
        cleaned = cleaned.filter(s => {
            if (!s.out) return true;
            return thMinutesBetween(s.in, s.out) > 0;
        });

        // If root-level clockIn/clockOut exists but shifts[] has no closed shift, preserve it.
        if (!cleaned.some(s => s.out) && attendance?.clockIn && attendance?.clockOut) {
            const rootMins = thMinutesBetween(attendance.clockIn, attendance.clockOut);
            if (rootMins > 0) {
                cleaned.push({
                    id: `root_${thToDate(attendance.clockIn).getTime()}`,
                    in: thTimestamp(thToDate(attendance.clockIn)),
                    out: thTimestamp(thToDate(attendance.clockOut)),
                    startedAt: thTimestamp(thToDate(attendance.clockIn)),
                    endedAt: thTimestamp(thToDate(attendance.clockOut)),
                    method: attendance.method || "app",
                    device: attendance.device || thDeviceType()
                });
            }
        }

        return cleaned;
    }

    function thOpenShift(shifts) {
        const open = shifts.filter(s => s && s.in && !s.out);
        return open.length ? open[open.length - 1] : null;
    }

    function thTotalMinutes(shifts) {
        return (shifts || []).reduce((sum, s) => sum + thMinutesBetween(s.in, s.out), 0);
    }

    function thFormatTime(value) {
        try {
            const d = thToDate(value);
            if (!d) return "—";
            return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
        } catch (e) {
            return "—";
        }
    }

    async function thGetRecordRef() {
        const user = firebase?.auth?.().currentUser;
        if (!user) throw new Error("Please sign in again.");

        const email = thEmail();
        const today = thToday();
        if (!email) throw new Error("No user email found.");

        return {
            email,
            today,
            ref: db.collection("Attendance").doc(thDocId(email, today))
        };
    }

    async function thWriteIdentityHours(docId, shifts) {
        const totalMinutes = thTotalMinutes(shifts);
        const text = thDurationText(totalMinutes);

        try {
            await db.collection("Attendance").doc(docId).set({
                totalMinutesWorked: totalMinutes,
                totalHoursWorkedText: text,
                performanceSyncUpdatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge: true });
        } catch (e) {
            console.warn("Could not write total hours fields", e);
        }

        thUpdateHoursDOM(text);
    }

    function thUpdateHoursDOM(text) {
        const ids = [
            "myProfileHoursWorked",
            "attendanceIdentityHoursWorked",
            "myAttendanceHoursWorked",
            "hoursWorked",
            "att_hoursWorked"
        ];

        let found = false;
        ids.forEach(id => {
            const el = document.getElementById(id);
            if (el) {
                el.innerText = text;
                found = true;
            }
        });

        // Fallback for the visible card whose label says HOURS WORKED.
        if (!found) {
            const all = Array.from(document.querySelectorAll("div, section, article"));
            const card = all.find(el => {
                const txt = (el.innerText || "").trim().toUpperCase();
                return txt.startsWith("HOURS WORKED");
            });

            if (card) {
                const children = Array.from(card.querySelectorAll("*"));
                const valueEl = children.reverse().find(el => {
                    const txt = (el.innerText || "").trim();
                    return txt === "—" || txt === "0h 0m" || /^\d+h\s+\d+m$/.test(txt);
                });
                if (valueEl) valueEl.innerText = text;
            }
        }
    }

    async function thRefreshAll() {
        try {
            if (typeof pc43_refreshClockPanel === "function" && pc43_refreshClockPanel !== window.thuraya_refreshClockPanel_v4) {
                await pc43_refreshClockPanel();
            }
        } catch (e) {}

        try {
            if (typeof sp4_loadMyAttendanceIdentity === "function") await sp4_loadMyAttendanceIdentity();
        } catch (e) {}

        try {
            const ctx = await thGetRecordRef();
            const doc = await ctx.ref.get();
            if (!doc.exists) return;
            const shifts = thCleanShifts(doc.data() || []);
            await thWriteIdentityHours(doc.id, shifts);
        } catch (e) {}
    }

    window.thuraya_calculateShiftHours = function (attendance) {
        const shifts = thCleanShifts(attendance || {});
        const mins = thTotalMinutes(shifts);
        return shifts.some(s => s.out) ? thDurationText(mins) : "—";
    };

    window.pc43_clockIn = async function () {
        if (TH_V4.busy) return;
        TH_V4.busy = true;

        try {
            const user = firebase.auth().currentUser;
            if (!user) return alert("Please sign in again.");

            const ctx = await thGetRecordRef();
            const name = currentUserName || user.displayName || "Staff Member";
            const roles = Array.isArray(currentRoles) ? currentRoles : [];
            const now = new Date();
            const shiftStart = thShiftStart();

            await db.runTransaction(async (tx) => {
                const snap = await tx.get(ctx.ref);
                const existing = snap.exists ? (snap.data() || {}) : {};
                let shifts = thCleanShifts(existing);
                const open = thOpenShift(shifts);

                if (open) {
                    throw new Error("You are already clocked in. Please clock out before starting another shift.");
                }

                const newShift = {
                    id: `shift_${now.getTime()}`,
                    in: thTimestamp(now),
                    out: null,
                    startedAt: thTimestamp(now),
                    endedAt: null,
                    method: "app",
                    device: thDeviceType()
                };

                shifts.push(newShift);

                const totalMinutes = thTotalMinutes(shifts);

                tx.set(ctx.ref, {
                    email: ctx.email,
                    name,
                    roleString: roles.join(","),
                    roles,
                    date: ctx.today,
                    dateString: ctx.today,
                    status: "Clocked In",
                    clockIn: thTimestamp(now),
                    clockOut: firebase.firestore.FieldValue.delete(),
                    method: "app",
                    device: thDeviceType(),
                    shiftStart,
                    isLate: thIsLate(now, shiftStart),
                    shifts,
                    shiftCount: shifts.length,
                    totalMinutesWorked: totalMinutes,
                    totalHoursWorkedText: thDurationText(totalMinutes),
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                    createdAt: existing.createdAt || firebase.firestore.FieldValue.serverTimestamp()
                }, { merge: true });
            });

            alert("Clock-in recorded. Have a productive shift.");
            setTimeout(thRefreshAll, 700);
            setTimeout(thRefreshAll, 1800);
        } catch (e) {
            console.error("Clock in failed", e);
            alert(e.message || "Clock in failed.");
        } finally {
            TH_V4.busy = false;
        }
    };

    window.pc43_clockOut = async function () {
        if (TH_V4.busy) return;
        TH_V4.busy = true;

        try {
            const ctx = await thGetRecordRef();
            const now = new Date();

            if (!confirm("Clock out and end your shift now?")) return;

            let finalMinutes = 0;
            let finalText = "0h 0m";

            await db.runTransaction(async (tx) => {
                const snap = await tx.get(ctx.ref);
                if (!snap.exists) throw new Error("You are not clocked in today.");

                const existing = snap.data() || {};
                let shifts = thCleanShifts(existing);
                let open = thOpenShift(shifts);

                // Backward compatibility: existing root clockIn but no open shift.
                if (!open && existing.clockIn && !existing.clockOut) {
                    open = {
                        id: `shift_${thToDate(existing.clockIn)?.getTime() || now.getTime()}`,
                        in: thTimestamp(thToDate(existing.clockIn) || now),
                        out: null,
                        startedAt: thTimestamp(thToDate(existing.clockIn) || now),
                        endedAt: null,
                        method: existing.method || "app",
                        device: existing.device || thDeviceType()
                    };
                    shifts.push(open);
                }

                if (!open) {
                    throw new Error("No active open shift found. You may already be clocked out.");
                }

                shifts = shifts.map(s => {
                    if (s.id === open.id && !s.out) {
                        return {
                            ...s,
                            out: thTimestamp(now),
                            endedAt: thTimestamp(now)
                        };
                    }
                    return s;
                });

                // Clean again after closing to remove duplicates and zero-duration records.
                shifts = thCleanShifts({ shifts });

                finalMinutes = thTotalMinutes(shifts);
                finalText = thDurationText(finalMinutes);

                tx.set(ctx.ref, {
                    status: "Clocked Out",
                    clockOut: thTimestamp(now),
                    shifts,
                    shiftCount: shifts.length,
                    totalMinutesWorked: finalMinutes,
                    totalHoursWorkedText: finalText,
                    workDurationMinutes: finalMinutes,
                    workDurationText: finalText,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                }, { merge: true });
            });

            alert(`Clock-out recorded. Total hours today: ${finalText}`);
            thUpdateHoursDOM(finalText);
            setTimeout(thRefreshAll, 700);
            setTimeout(thRefreshAll, 1800);
        } catch (e) {
            console.error("Clock out failed", e);
            alert(e.message || "Clock out failed.");
        } finally {
            TH_V4.busy = false;
        }
    };

    window.thuraya_fixShiftDuplicatesNow = async function () {
        try {
            const ctx = await thGetRecordRef();
            const doc = await ctx.ref.get();
            if (!doc.exists) return;

            const data = doc.data() || {};
            const shifts = thCleanShifts(data);
            const totalMinutes = thTotalMinutes(shifts);
            const totalText = thDurationText(totalMinutes);
            const open = thOpenShift(shifts);

            await ctx.ref.set({
                shifts,
                shiftCount: shifts.length,
                totalMinutesWorked: totalMinutes,
                totalHoursWorkedText: totalText,
                workDurationMinutes: totalMinutes,
                workDurationText: totalText,
                status: open ? "Clocked In" : (shifts.length ? "Clocked Out" : (data.status || "Not Clocked In")),
                performanceSyncUpdatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge: true });

            thUpdateHoursDOM(totalText);
        } catch (e) {
            console.warn("Shift duplicate cleanup failed", e);
        }
    };

    window.thuraya_refreshClockPanel_v4 = thRefreshAll;

    function bootV4() {
        if (TH_V4.booted) return;
        TH_V4.booted = true;

        setTimeout(window.thuraya_fixShiftDuplicatesNow, 800);
        setTimeout(thRefreshAll, 1200);
        setTimeout(thRefreshAll, 3000);
        setInterval(() => {
            window.thuraya_fixShiftDuplicatesNow?.();
        }, 10000);
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", bootV4);
    } else {
        bootV4();
    }

    if (window.firebase && firebase.auth) {
        firebase.auth().onAuthStateChanged(user => {
            if (user) {
                TH_V4.booted = false;
                setTimeout(bootV4, 1200);
            }
        });
    }
})();

// ============================================================================
// END THURAYA PHASE 4.3.6 v4 PATCH
// ============================================================================


// ============================================================================
// THURAYA PHASE 5.1A PATCH
// Performance Intelligence Calculation Engine
// Metrics: revenue, hours, revenue/hour, revenue bookings, efficiency score
// Safe engine only — no UI replacement yet.
// ============================================================================

(function () {
    const PERF51A = {
        lastRunAt: null,
        cache: []
    };

    function p51_today() {
        try {
            if (typeof getLocalDateString === "function") return getLocalDateString();
        } catch (e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p51_toDate(value) {
        if (!value) return null;
        try {
            if (value instanceof Date) return value;
            if (typeof value.toDate === "function") return value.toDate();
            if (typeof value === "object" && typeof value.seconds === "number") return new Date(value.seconds * 1000);
            if (typeof value === "object" && typeof value._seconds === "number") return new Date(value._seconds * 1000);
            if (typeof value === "number") return new Date(value);
            if (typeof value === "string") {
                const d = new Date(value);
                if (!isNaN(d.getTime())) return d;
            }
        } catch(e) {}
        return null;
    }

    function p51_num(v, fallback = 0) {
        const n = parseFloat(v);
        return isNaN(n) ? fallback : n;
    }

    function p51_minutesFromAttendance(att) {
        if (!att) return 0;

        // Prefer saved clean value from Phase 4.3.6
        const saved = parseInt(att.totalMinutesWorked || att.workDurationMinutes || 0, 10);
        if (saved > 0) return saved;

        // Fallback: calculate from shifts[]
        let mins = 0;
        const shifts = Array.isArray(att.shifts) ? att.shifts : [];

        shifts.forEach(s => {
            const start = p51_toDate(s?.in || s?.clockIn || s?.startedAt || s?.start);
            const end   = p51_toDate(s?.out || s?.clockOut || s?.endedAt || s?.end);

            if (start && end && end >= start) {
                mins += Math.floor((end - start) / 60000);
            }
        });

        // Final fallback: root clock fields
        if (!mins && att.clockIn && att.clockOut) {
            const start = p51_toDate(att.clockIn);
            const end = p51_toDate(att.clockOut);
            if (start && end && end >= start) mins = Math.floor((end - start) / 60000);
        }

        return Math.max(0, mins);
    }

    function p51_revenue(job) {
        if (!job) return 0;

        // Prefer final paid value after promo/package discount
        const candidates = [
            job.finalTotal,
            job.grandTotal,
            job.totalPaid,
            job.amountPaid,
            job.paidAmount,
            job.bookedPrice,
            job.subtotal,
            job.price
        ];

        for (const v of candidates) {
            const n = p51_num(v, -1);
            if (n >= 0) return n;
        }

        return 0;
    }

    function p51_isCompleted(job) {
        const status = String(job?.status || "").toLowerCase().trim();

        return [
            "completed",
            "paid",
            "checked out",
            "checkout complete",
            "closed",
            "done",
            "service completed",
            "ready for payment"
        ].some(s => status.includes(s));
    }

    function p51_staffKeyFromJob(job) {
        const email = String(
            job?.assignedTechEmail ||
            job?.techEmail ||
            job?.staffEmail ||
            job?.email ||
            ""
        ).toLowerCase().trim();

        const name =
            job?.assignedTechName ||
            job?.techName ||
            job?.staffName ||
            job?.name ||
            email ||
            "Unknown Staff";

        return { email, name };
    }

    function p51_makeRange(rangeType) {
        const today = p51_today();
        const now = new Date(today + "T00:00:00");

        if (rangeType === "week") {
            const day = now.getDay(); // Sun=0
            const diff = day === 0 ? 6 : day - 1; // Monday start
            const start = new Date(now);
            start.setDate(now.getDate() - diff);
            return {
                start: start.toISOString().slice(0,10),
                end: today,
                label: "This Week"
            };
        }

        if (rangeType === "month") {
            const start = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,"0")}-01`;
            return { start, end: today, label: "This Month" };
        }

        return { start: today, end: today, label: "Today" };
    }

    async function p51_fetchAttendance(start, end) {
        const map = {};

        try {
            const snap = await db.collection("Attendance")
                .where("date", ">=", start)
                .where("date", "<=", end)
                .get();

            snap.forEach(doc => {
                const a = doc.data() || {};
                const email = String(a.email || doc.id.split("_")[0] || "").toLowerCase().trim();
                if (!email) return;

                if (!map[email]) map[email] = {
                    email,
                    name: a.name || email,
                    minutes: 0,
                    records: 0
                };

                map[email].minutes += p51_minutesFromAttendance(a);
                map[email].records += 1;
                if (a.name) map[email].name = a.name;
            });
        } catch(e) {
            console.warn("Attendance date query failed; trying fallback", e);

            // Fallback for dateString-based records
            try {
                const snap = await db.collection("Attendance")
                    .where("dateString", ">=", start)
                    .where("dateString", "<=", end)
                    .get();

                snap.forEach(doc => {
                    const a = doc.data() || {};
                    const email = String(a.email || doc.id.split("_")[0] || "").toLowerCase().trim();
                    if (!email) return;

                    if (!map[email]) map[email] = {
                        email,
                        name: a.name || email,
                        minutes: 0,
                        records: 0
                    };

                    map[email].minutes += p51_minutesFromAttendance(a);
                    map[email].records += 1;
                    if (a.name) map[email].name = a.name;
                });
            } catch(err) {
                console.warn("Attendance fallback query failed", err);
            }
        }

        return map;
    }

    async function p51_fetchJobs(start, end) {
        let rows = [];

        async function pull(collection) {
            try {
                const snap = await db.collection(collection)
                    .where("dateString", ">=", start)
                    .where("dateString", "<=", end)
                    .get();

                snap.forEach(doc => rows.push({
                    id: doc.id,
                    source: collection,
                    ...(doc.data() || {})
                }));
            } catch(e) {
                console.warn(`Performance job query failed for ${collection}`, e);
            }
        }

        // Active_Jobs normally contains billing and operational status.
        await pull("Active_Jobs");

        // Fallback to Appointments if Active_Jobs has no data in selected range.
        if (!rows.length) await pull("Appointments");

        return rows;
    }

    function p51_score({ revenue, hours, completedBookings, revenuePerHour }) {
        // Conservative score: avoids wild results for tiny test hours.
        const revenueScore = Math.min(50, revenue / 20);             // 1 pt per GHC 20, capped 50
        const bookingScore = Math.min(25, completedBookings * 5);    // 5 pts per completed booking
        const efficiencyScore = Math.min(25, revenuePerHour / 10);   // 1 pt per GHC10/hr, capped 25
        return Math.round((revenueScore + bookingScore + efficiencyScore) * 10) / 10;
    }

    window.thuraya_buildPerformanceMetrics = async function (rangeType = "today") {
        const range = p51_makeRange(rangeType);
        const [attendanceMap, jobs] = await Promise.all([
            p51_fetchAttendance(range.start, range.end),
            p51_fetchJobs(range.start, range.end)
        ]);

        const staff = {};

        // Seed from attendance first so staff with hours but no revenue still show.
        Object.values(attendanceMap).forEach(a => {
            staff[a.email] = {
                email: a.email,
                name: a.name || a.email,
                totalMinutesWorked: a.minutes || 0,
                totalHoursWorked: (a.minutes || 0) / 60,
                totalRevenue: 0,
                completedBookings: 0,
                totalBookings: 0,
                attendanceRecords: a.records || 0,
                jobs: []
            };
        });

        jobs.forEach(job => {
            const k = p51_staffKeyFromJob(job);
            if (!k.email) return;

            if (!staff[k.email]) {
                staff[k.email] = {
                    email: k.email,
                    name: k.name,
                    totalMinutesWorked: 0,
                    totalHoursWorked: 0,
                    totalRevenue: 0,
                    completedBookings: 0,
                    totalBookings: 0,
                    attendanceRecords: 0,
                    jobs: []
                };
            }

            const amount = p51_revenue(job);
            staff[k.email].totalBookings += 1;
            staff[k.email].jobs.push(job);

            if (p51_isCompleted(job)) {
                staff[k.email].completedBookings += 1;
                staff[k.email].totalRevenue += amount;
            }
        });

        const rows = Object.values(staff).map(s => {
            const hours = Math.round((s.totalHoursWorked || 0) * 100) / 100;
            const revenue = Math.round((s.totalRevenue || 0) * 100) / 100;
            const revenuePerHour = hours > 0 ? Math.round((revenue / hours) * 100) / 100 : 0;
            const avgBookingValue = s.completedBookings > 0
                ? Math.round((revenue / s.completedBookings) * 100) / 100
                : 0;

            return {
                range: range.label,
                startDate: range.start,
                endDate: range.end,
                email: s.email,
                name: s.name,
                totalRevenue: revenue,
                totalMinutesWorked: s.totalMinutesWorked,
                totalHoursWorked: hours,
                revenuePerHour,
                completedBookings: s.completedBookings,
                totalBookings: s.totalBookings,
                avgBookingValue,
                attendanceRecords: s.attendanceRecords,
                efficiencyScore: p51_score({
                    revenue,
                    hours,
                    completedBookings: s.completedBookings,
                    revenuePerHour
                })
            };
        }).sort((a, b) => {
            // Rank by efficiency first, then revenue, then bookings.
            return (b.efficiencyScore - a.efficiencyScore) ||
                   (b.totalRevenue - a.totalRevenue) ||
                   (b.completedBookings - a.completedBookings);
        });

        rows.forEach((r, i) => r.rank = i + 1);

        PERF51A.lastRunAt = new Date();
        PERF51A.cache = rows;

        try {
            await p51_saveSnapshot(rows, rangeType, range);
        } catch(e) {
            console.warn("Could not save performance snapshot", e);
        }

        console.log("Phase 5.1A Performance Metrics:", rows);
        return rows;
    };

    async function p51_saveSnapshot(rows, rangeType, range) {
        if (!rows || !rows.length) return;

        const batch = db.batch();

        rows.forEach(row => {
            const id = `${rangeType}_${range.start}_${range.end}_${row.email}`.replace(/[^a-zA-Z0-9@._-]/g, "_");
            const ref = db.collection("Performance_Metrics").doc(id);

            batch.set(ref, {
                ...row,
                rangeType,
                calculatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                source: "Phase_5_1A"
            }, { merge: true });
        });

        await batch.commit();
    }

    // Debug/helper function available in browser console or future UI button.
    window.thuraya_printPerformanceToday = async function () {
        const rows = await window.thuraya_buildPerformanceMetrics("today");
        console.table(rows);
        return rows;
    };

    // Light auto-run after login, but no UI changes yet.
    setTimeout(() => {
        try {
            if (firebase?.auth?.().currentUser) {
                window.thuraya_buildPerformanceMetrics("today");
            }
        } catch(e) {}
    }, 5000);

})();

// ============================================================================
// END THURAYA PHASE 5.1A PATCH
// ============================================================================


// ============================================================================
// THURAYA PHASE 5.1C CLEAN FIX
// Keeps Unified Job Intelligence engine.
// Removes intrusive Performance Dashboard auto-mount from Admin/Reports layout.
// No UI injection. Reports page returns to normal.
// ============================================================================

(function () {
    // Remove any previously injected dashboard blocks if cached code left them on screen.
    function cleanupPerformanceDashboardUI() {
        try {
            document.querySelectorAll(
                "#performanceDashboard51B, #performanceDashboard51B_FIXED, #p51bOpenBtn"
            ).forEach(el => el.remove());
        } catch(e) {}
    }

    cleanupPerformanceDashboardUI();
    setTimeout(cleanupPerformanceDashboardUI, 500);
    setTimeout(cleanupPerformanceDashboardUI, 1500);
    setTimeout(cleanupPerformanceDashboardUI, 3000);

    const P51C_CLEAN = { cache: [], clientCache: [] };

    function c_today() {
        try {
            if (typeof getLocalDateString === "function") return getLocalDateString();
        } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function c_range(type) {
        const today = c_today();
        const now = new Date(today + "T00:00:00");

        if (type === "week") {
            const day = now.getDay();
            const diff = day === 0 ? 6 : day - 1;
            const start = new Date(now);
            start.setDate(now.getDate() - diff);
            return { start: start.toISOString().slice(0,10), end: today, label: "This Week" };
        }

        if (type === "month") {
            return {
                start: `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,"0")}-01`,
                end: today,
                label: "This Month"
            };
        }

        return { start: today, end: today, label: "Today" };
    }

    function c_num(v, fallback = 0) {
        const n = parseFloat(v);
        return isNaN(n) ? fallback : n;
    }

    function c_status(job) {
        return String(job?.status || job?.paymentStatus || job?.billingStatus || job?.jobStatus || "").toLowerCase().trim();
    }

    function c_isCompletedOrPaid(job) {
        const status = c_status(job);

        if (c_num(job?.amountPaid, 0) > 0 || c_num(job?.totalPaid, 0) > 0 || c_num(job?.paidAmount, 0) > 0) return true;
        if (job?.paid === true || job?.isPaid === true || job?.paymentReceived === true) return true;

        const negative = ["cancelled", "canceled", "no show", "noshow", "void", "refunded", "draft"];
        if (negative.some(s => status.includes(s))) return false;

        const positive = [
            "completed", "complete", "paid", "payment received", "checked out",
            "checkout complete", "closed", "done", "finished", "service completed",
            "ready for payment", "ready for checkout", "billed", "invoice paid", "settled"
        ];

        return positive.some(s => status.includes(s));
    }

    function c_revenue(job) {
        const fields = [
            job?.finalTotal, job?.checkoutTotal, job?.totalPaid, job?.amountPaid,
            job?.paidAmount, job?.paymentAmount, job?.grandTotal, job?.totalAmount,
            job?.invoiceTotal, job?.billTotal, job?.billingTotal, job?.total,
            job?.bookedPrice, job?.bookedTotal, job?.subtotal, job?.serviceTotal, job?.price
        ];

        for (const v of fields) {
            const n = c_num(v, -1);
            if (n >= 0) return n;
        }
        return 0;
    }

    function c_staff(job) {
        const email = String(
            job?.assignedTechEmail || job?.techEmail || job?.technicianEmail ||
            job?.staffEmail || job?.workerEmail || job?.email || ""
        ).toLowerCase().trim();

        const name =
            job?.assignedTechName || job?.techName || job?.technicianName ||
            job?.staffName || job?.workerName || job?.name || email || "Unassigned";

        return { email, name };
    }

    function c_client(job) {
        const phone = String(job?.clientPhone || job?.phone || job?.customerPhone || job?.mobile || "").trim();
        const name = job?.clientName || job?.customerName || job?.name || "Unknown Client";
        return { phone, name };
    }

    function c_key(job) {
        return String(
            job?.jobId || job?.bookingId || job?.appointmentId || job?.id ||
            `${job?.source || "src"}_${job?.clientPhone || job?.phone || ""}_${job?.dateString || job?.date || ""}_${job?.timeString || job?.time || ""}_${job?.assignedTechEmail || job?.techEmail || ""}`
        );
    }

    async function c_pull(collection, start, end) {
        const rows = [];

        async function queryField(field) {
            try {
                const snap = await db.collection(collection)
                    .where(field, ">=", start)
                    .where(field, "<=", end)
                    .get();

                snap.forEach(doc => rows.push({
                    id: doc.id,
                    source: collection,
                    ...(doc.data() || {})
                }));
            } catch(e) {}
        }

        await queryField("dateString");
        await queryField("date");

        const map = {};
        rows.forEach(r => map[`${collection}_${r.id}`] = r);
        return Object.values(map);
    }

    async function c_fetchUnifiedJobs(start, end) {
        const collections = ["Active_Jobs", "Appointments", "Sales_Redemptions", "Package_Usage"];
        let all = [];

        for (const col of collections) {
            all = all.concat(await c_pull(col, start, end));
        }

        const map = {};
        all.forEach(job => {
            const key = c_key(job);
            const old = map[key];

            if (!old) {
                map[key] = job;
                return;
            }

            const oldScore = (c_isCompletedOrPaid(old) ? 10 : 0) + (c_revenue(old) > 0 ? 5 : 0);
            const newScore = (c_isCompletedOrPaid(job) ? 10 : 0) + (c_revenue(job) > 0 ? 5 : 0);

            if (newScore >= oldScore) map[key] = { ...old, ...job };
        });

        return Object.values(map);
    }

    function c_toDate(value) {
        if (!value) return null;
        try {
            if (value instanceof Date) return value;
            if (typeof value.toDate === "function") return value.toDate();
            if (typeof value === "object" && typeof value.seconds === "number") return new Date(value.seconds * 1000);
            if (typeof value === "object" && typeof value._seconds === "number") return new Date(value._seconds * 1000);
            if (typeof value === "number") return new Date(value);
            if (typeof value === "string") {
                const d = new Date(value);
                if (!isNaN(d.getTime())) return d;
            }
        } catch(e) {}
        return null;
    }

    function c_minutes(att) {
        const saved = parseInt(att?.totalMinutesWorked || att?.workDurationMinutes || 0, 10);
        if (saved > 0) return saved;

        let mins = 0;
        const shifts = Array.isArray(att?.shifts) ? att.shifts : [];
        shifts.forEach(s => {
            const start = c_toDate(s?.in || s?.startedAt || s?.clockIn);
            const end = c_toDate(s?.out || s?.endedAt || s?.clockOut);
            if (start && end && end >= start) mins += Math.floor((end - start) / 60000);
        });

        if (!mins && att?.clockIn && att?.clockOut) {
            const start = c_toDate(att.clockIn);
            const end = c_toDate(att.clockOut);
            if (start && end && end >= start) mins = Math.floor((end - start) / 60000);
        }

        return Math.max(0, mins);
    }

    async function c_attendance(start, end) {
        const map = {};

        async function queryField(field) {
            try {
                const snap = await db.collection("Attendance")
                    .where(field, ">=", start)
                    .where(field, "<=", end)
                    .get();

                snap.forEach(doc => {
                    const a = doc.data() || {};
                    const email = String(a.email || doc.id.split("_")[0] || "").toLowerCase().trim();
                    if (!email) return;

                    if (!map[email]) {
                        map[email] = { email, name: a.name || email, minutes: 0, records: 0 };
                    }

                    map[email].minutes += c_minutes(a);
                    map[email].records += 1;
                    if (a.name) map[email].name = a.name;
                });
            } catch(e) {}
        }

        await queryField("date");
        await queryField("dateString");

        return map;
    }

    function c_score(revenue, hours, completed, revPerHour) {
        const revenueScore = Math.min(50, revenue / 20);
        const bookingScore = Math.min(25, completed * 5);
        const efficiencyScore = Math.min(25, revPerHour / 10);
        return Math.round((revenueScore + bookingScore + efficiencyScore) * 10) / 10;
    }

    async function c_save(rows, rangeType, range) {
        if (!rows || !rows.length) return;
        const batch = db.batch();

        rows.forEach(row => {
            const id = `${rangeType}_${range.start}_${range.end}_${row.email}`.replace(/[^a-zA-Z0-9@._-]/g, "_");
            batch.set(db.collection("Performance_Metrics").doc(id), {
                ...row,
                rangeType,
                calculatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                source: "Phase_5_1C_Clean_UnifiedJobIntelligence"
            }, { merge: true });
        });

        await batch.commit();
    }

    window.thuraya_fetchUnifiedJobs = async function(rangeType = "today") {
        const range = c_range(rangeType);
        return await c_fetchUnifiedJobs(range.start, range.end);
    };

    window.thuraya_debugUnifiedJobsToday = async function() {
        const jobs = await window.thuraya_fetchUnifiedJobs("today");
        console.table(jobs.map(j => ({
            source: j.source,
            id: j.id,
            status: j.status || j.paymentStatus || j.billingStatus || "",
            client: j.clientName || j.customerName || "",
            staff: j.assignedTechName || j.assignedTechEmail || j.techEmail || "",
            revenue: c_revenue(j),
            counted: c_isCompletedOrPaid(j)
        })));
        return jobs;
    };

    window.thuraya_buildClientIntelMetrics = async function(rangeType = "today") {
        const range = c_range(rangeType);
        const jobs = await c_fetchUnifiedJobs(range.start, range.end);
        const clients = {};

        jobs.forEach(job => {
            const client = c_client(job);
            const key = client.phone || client.name;
            if (!key) return;

            if (!clients[key]) {
                clients[key] = {
                    clientName: client.name,
                    clientPhone: client.phone,
                    visits: 0,
                    completedVisits: 0,
                    totalSpend: 0,
                    lastVisit: "",
                    jobs: []
                };
            }

            clients[key].visits += 1;
            clients[key].jobs.push(job);

            const date = job.dateString || job.date || "";
            if (date && date > clients[key].lastVisit) clients[key].lastVisit = date;

            if (c_isCompletedOrPaid(job)) {
                clients[key].completedVisits += 1;
                clients[key].totalSpend += c_revenue(job);
            }
        });

        const rows = Object.values(clients).map(c => ({
            ...c,
            totalSpend: Math.round(c.totalSpend * 100) / 100,
            avgSpend: c.completedVisits ? Math.round((c.totalSpend / c.completedVisits) * 100) / 100 : 0,
            repeatClient: c.completedVisits > 1
        })).sort((a,b) => b.totalSpend - a.totalSpend || b.completedVisits - a.completedVisits);

        P51C_CLEAN.clientCache = rows;
        console.log("Client Intel Metrics:", rows);
        return rows;
    };

    window.thuraya_buildPerformanceMetrics = async function(rangeType = "today") {
        const range = c_range(rangeType);
        const [attendance, jobs] = await Promise.all([
            c_attendance(range.start, range.end),
            c_fetchUnifiedJobs(range.start, range.end)
        ]);

        const staff = {};

        Object.values(attendance).forEach(a => {
            staff[a.email] = {
                email: a.email,
                name: a.name || a.email,
                totalMinutesWorked: a.minutes || 0,
                totalRevenue: 0,
                completedBookings: 0,
                totalBookings: 0,
                attendanceRecords: a.records || 0
            };
        });

        jobs.forEach(job => {
            const s = c_staff(job);
            if (!s.email) return;

            if (!staff[s.email]) {
                staff[s.email] = {
                    email: s.email,
                    name: s.name || s.email,
                    totalMinutesWorked: 0,
                    totalRevenue: 0,
                    completedBookings: 0,
                    totalBookings: 0,
                    attendanceRecords: 0
                };
            }

            if (s.name) staff[s.email].name = s.name;
            staff[s.email].totalBookings += 1;

            if (c_isCompletedOrPaid(job)) {
                staff[s.email].completedBookings += 1;
                staff[s.email].totalRevenue += c_revenue(job);
            }
        });

        const rows = Object.values(staff).map(s => {
            const hours = Math.round((s.totalMinutesWorked / 60) * 100) / 100;
            const revenue = Math.round(s.totalRevenue * 100) / 100;
            const revenuePerHour = hours > 0 ? Math.round((revenue / hours) * 100) / 100 : 0;
            const avgBookingValue = s.completedBookings ? Math.round((revenue / s.completedBookings) * 100) / 100 : 0;

            return {
                range: range.label,
                startDate: range.start,
                endDate: range.end,
                email: s.email,
                name: s.name,
                totalRevenue: revenue,
                totalMinutesWorked: s.totalMinutesWorked,
                totalHoursWorked: hours,
                revenuePerHour,
                completedBookings: s.completedBookings,
                totalBookings: s.totalBookings,
                avgBookingValue,
                attendanceRecords: s.attendanceRecords,
                efficiencyScore: c_score(revenue, hours, s.completedBookings, revenuePerHour)
            };
        }).sort((a,b) =>
            (b.efficiencyScore - a.efficiencyScore) ||
            (b.totalRevenue - a.totalRevenue) ||
            (b.completedBookings - a.completedBookings) ||
            (b.totalHoursWorked - a.totalHoursWorked)
        );

        rows.forEach((r, i) => r.rank = i + 1);
        P51C_CLEAN.cache = rows;

        try { await c_save(rows, rangeType, range); } catch(e) {
            console.warn("Performance save failed", e);
        }

        console.log("Unified Performance Metrics:", rows);
        console.log("Unified Jobs:", jobs);
        return rows;
    };

})();

// ============================================================================
// END THURAYA PHASE 5.1C CLEAN FIX
// ============================================================================


// ============================================================================
// THURAYA PHASE 5.2 PATCH
// Proper Performance Module Integration
// Adds Performance Intelligence as a proper Reports tile.
// Does NOT auto-mount at top of Admin page.
// Uses existing engine: thuraya_buildPerformanceMetrics()
// ============================================================================

(function () {
    const P52 = {
        mounted: false,
        activeRange: "today"
    };

    function p52_safe(v) {
        return String(v ?? "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;");
    }

    function p52_money(v) {
        const n = parseFloat(v || 0);
        return `${n.toFixed(2)} GHC`;
    }

    function p52_hours(mins, hours) {
        let m = parseInt(mins || 0, 10);
        if (!m && hours) m = Math.round(parseFloat(hours || 0) * 60);
        const h = Math.floor(m / 60);
        const r = m % 60;
        return h > 0 ? `${h}h ${r}m` : `${r}m`;
    }

    function p52_findReportsRoot() {
        const reportsView = document.getElementById("reportsView");
        if (reportsView) return reportsView;

        const all = Array.from(document.querySelectorAll("div, section, main"));
        const root = all.find(el => {
            const txt = (el.innerText || "").toLowerCase();
            return el.offsetParent !== null &&
                txt.includes("upcoming bookings") &&
                txt.includes("daily operations") &&
                txt.includes("tech performance") &&
                txt.includes("client intelligence");
        });

        return root || document.getElementById("appDashboard") || document.body;
    }

    function p52_findTileGrid(root) {
        const candidates = Array.from(root.querySelectorAll("div"));
        let best = null;

        candidates.forEach(el => {
            const txt = (el.innerText || "").toLowerCase();
            const visible = el.offsetParent !== null;

            if (!visible) return;

            const score =
                (txt.includes("upcoming bookings") ? 1 : 0) +
                (txt.includes("daily operations") ? 1 : 0) +
                (txt.includes("weekly / monthly revenue") ? 1 : 0) +
                (txt.includes("tech performance") ? 1 : 0) +
                (txt.includes("client intelligence") ? 1 : 0) +
                (txt.includes("leave & attendance") ? 1 : 0);

            if (score >= 4) {
                if (!best || el.innerText.length < best.innerText.length) best = el;
            }
        });

        return best;
    }

    function p52_makeTile() {
        const tile = document.createElement("div");
        tile.id = "rptPerformanceTile52";
        tile.onclick = () => window.rpt_openPerformance52("today");
        tile.style.cssText = `
            display:flex;
            align-items:center;
            gap:16px;
            padding:18px;
            border:1px solid #e4e4e4;
            border-radius:12px;
            background:#fff;
            cursor:pointer;
            min-height:82px;
            box-shadow:0 4px 14px rgba(0,0,0,0.03);
        `;
        tile.innerHTML = `
            <div style="
                width:48px;height:48px;border-radius:14px;background:#f8f3e8;
                display:flex;align-items:center;justify-content:center;font-size:22px;
            ">📊</div>
            <div>
                <div style="font-weight:800;color:#2f3b52;font-size:1.05rem;">Performance Intelligence</div>
                <div style="color:#666;font-size:0.9rem;margin-top:4px;">Revenue/hour, efficiency and ranking</div>
            </div>
        `;
        return tile;
    }

    function p52_mountTile() {
        const root = p52_findReportsRoot();
        if (!root || document.getElementById("rptPerformanceTile52")) return;

        const grid = p52_findTileGrid(root);
        if (!grid) return;

        const tile = p52_makeTile();

        // Prefer adding beside existing tiles.
        grid.appendChild(tile);

        // Keep grid looking correct.
        if (!grid.style.display) grid.style.display = "grid";
        if (!grid.style.gridTemplateColumns) {
            grid.style.gridTemplateColumns = "repeat(3, minmax(220px, 1fr))";
        }
        grid.style.gap = grid.style.gap || "14px";
    }

    function p52_mountPanel() {
        const root = p52_findReportsRoot();

        let panel = document.getElementById("rptPerformancePanel52");
        if (panel) return panel;

        panel = document.createElement("div");
        panel.id = "rptPerformancePanel52";
        panel.style.cssText = `
            display:none;
            margin:18px 0;
            border:1px solid #e5e5e5;
            border-radius:14px;
            background:#fff;
            padding:20px;
            box-shadow:0 6px 20px rgba(0,0,0,0.04);
        `;

        panel.innerHTML = `
            <div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:14px;">
                <div>
                    <h3 style="margin:0;color:#2f3b52;letter-spacing:1.5px;text-transform:uppercase;">
                        Performance Intelligence
                    </h3>
                    <p style="margin:6px 0 0;color:#666;">
                        Staff productivity based on revenue, revenue jobs and attendance hours.
                    </p>
                </div>
                <div style="display:flex;gap:8px;flex-wrap:wrap;">
                    <button id="p52TodayBtn" class="btn btn-secondary btn-auto" onclick="rpt_openPerformance52('today')">Today</button>
                    <button id="p52WeekBtn" class="btn btn-secondary btn-auto" onclick="rpt_openPerformance52('week')">Week</button>
                    <button id="p52MonthBtn" class="btn btn-secondary btn-auto" onclick="rpt_openPerformance52('month')">Month</button>
                    <button class="btn btn-auto" onclick="rpt_openPerformance52(window.P52_ACTIVE_RANGE || 'today')">Refresh</button>
                    <button class="btn btn-secondary btn-auto" onclick="rpt_closePerformance52()">Close</button>
                </div>
            </div>

            <div id="p52Status" style="color:#777;font-size:0.85rem;margin-bottom:12px;">Ready.</div>

            <div id="p52Cards" style="display:grid;grid-template-columns:repeat(4,minmax(150px,1fr));gap:12px;margin-bottom:16px;"></div>

            <div style="overflow-x:auto;border:1px solid #eee;border-radius:12px;">
                <table style="width:100%;border-collapse:collapse;">
                    <thead>
                        <tr style="background:#f8f8f8;color:#2f3b52;text-transform:uppercase;font-size:0.78rem;letter-spacing:1px;">
                            <th style="padding:12px;text-align:left;">Rank</th>
                            <th style="padding:12px;text-align:left;">Staff</th>
                            <th style="padding:12px;text-align:right;">Revenue</th>
                            <th style="padding:12px;text-align:right;">Hours</th>
                            <th style="padding:12px;text-align:right;">Revenue/Hour</th>
                            <th style="padding:12px;text-align:right;">Revenue Jobs</th>
                            <th style="padding:12px;text-align:right;">Score</th>
                        </tr>
                    </thead>
                    <tbody id="p52Table">
                        <tr><td colspan="7" style="padding:18px;text-align:center;color:#777;">Click Today, Week or Month.</td></tr>
                    </tbody>
                </table>
            </div>

            <div id="p52Insight" style="margin-top:14px;color:#666;font-size:0.9rem;"></div>
        `;

        // Insert panel after tile grid where possible, not at the top of page.
        const grid = p52_findTileGrid(root);
        if (grid && grid.parentNode) {
            grid.parentNode.insertBefore(panel, grid.nextSibling);
        } else {
            root.appendChild(panel);
        }

        return panel;
    }

    function p52_card(label, value, sub, color) {
        return `
            <div style="border:1px solid #e4e4e4;border-radius:12px;padding:14px;background:#fff;">
                <div style="font-size:0.75rem;color:#777;text-transform:uppercase;letter-spacing:1.4px;margin-bottom:8px;">
                    ${label}
                </div>
                <div style="font-size:1.55rem;font-weight:800;color:${color || "#2f3b52"};">
                    ${value}
                </div>
                <div style="font-size:0.82rem;color:#777;margin-top:6px;">${sub || ""}</div>
            </div>
        `;
    }

    function p52_setActive(range) {
        ["Today", "Week", "Month"].forEach(label => {
            const el = document.getElementById(`p52${label}Btn`);
            if (!el) return;
            const active = label.toLowerCase() === range;
            el.style.background = active ? "#2f3b52" : "";
            el.style.color = active ? "#fff" : "";
        });

        const tile = document.getElementById("rptPerformanceTile52");
        if (tile) {
            tile.style.background = "#2f3b52";
            tile.style.color = "#fff";
            tile.querySelectorAll("div").forEach(d => {
                if (d.style && d.style.color) d.style.color = "#fff";
            });
        }
    }

    window.rpt_closePerformance52 = function() {
        const panel = document.getElementById("rptPerformancePanel52");
        if (panel) panel.style.display = "none";

        const tile = document.getElementById("rptPerformanceTile52");
        if (tile) {
            tile.style.background = "#fff";
            tile.style.color = "";
            tile.querySelectorAll("div").forEach(d => {
                if (d.style && d.style.color === "rgb(255, 255, 255)") d.style.color = "";
            });
        }
    };

    window.rpt_openPerformance52 = async function(range = "today") {
        window.P52_ACTIVE_RANGE = range;
        P52.activeRange = range;

        p52_mountTile();
        const panel = p52_mountPanel();
        panel.style.display = "block";
        p52_setActive(range);

        const status = document.getElementById("p52Status");
        const cards = document.getElementById("p52Cards");
        const table = document.getElementById("p52Table");
        const insight = document.getElementById("p52Insight");

        if (status) status.innerText = "Calculating performance metrics...";
        if (table) table.innerHTML = `<tr><td colspan="7" style="padding:18px;text-align:center;color:#777;">Loading...</td></tr>`;

        try {
            if (typeof window.thuraya_buildPerformanceMetrics !== "function") {
                throw new Error("Performance engine not found.");
            }

            const rows = await window.thuraya_buildPerformanceMetrics(range);
            const rangeLabel = rows?.[0]?.range || (range === "week" ? "This Week" : range === "month" ? "This Month" : "Today");

            if (!rows.length) {
                if (status) status.innerText = `No performance data found for ${rangeLabel}.`;
                if (cards) {
                    cards.innerHTML =
                        p52_card("Best Performer", "—", "No revenue jobs yet.") +
                        p52_card("Total Revenue", "0.00 GHC", rangeLabel, "#55a868") +
                        p52_card("Best Efficiency", "—", "No revenue/hour yet.", "#a58d3d") +
                        p52_card("Revenue Jobs", "0", "No revenue jobs.", "#2f3b52");
                }
                if (table) table.innerHTML = `<tr><td colspan="7" style="padding:22px;text-align:center;color:#777;">No records yet.</td></tr>`;
                if (insight) insight.innerHTML = "Tip: complete/paid jobs and attendance hours are required.";
                return;
            }

            const totalRevenue = rows.reduce((s,r) => s + parseFloat(r.totalRevenue || 0), 0);
            const totalCompleted = rows.reduce((s,r) => s + parseInt(r.completedBookings || 0, 10), 0);
            const best = rows[0];
            const highRev = [...rows].sort((a,b) => (b.totalRevenue || 0) - (a.totalRevenue || 0))[0];
            const highEff = [...rows].sort((a,b) => (b.revenuePerHour || 0) - (a.revenuePerHour || 0))[0];

            if (status) status.innerText = `Showing ${rangeLabel} · ${rows.length} staff record(s)`;

            if (cards) {
                cards.innerHTML =
                    p52_card("Best Performer", p52_safe(best.name || "—"), `Score: ${best.efficiencyScore || 0}`, "#2f3b52") +
                    p52_card("Total Revenue", p52_money(totalRevenue), rangeLabel, "#55a868") +
                    p52_card("Highest Revenue", p52_safe(highRev.name || "—"), p52_money(highRev.totalRevenue), "#4b6cb7") +
                    p52_card("Best Efficiency", p52_safe(highEff.name || "—"), `${p52_money(highEff.revenuePerHour)} / hr`, "#a58d3d");
            }

            if (table) {
                table.innerHTML = rows.map(r => {
                    const medal = r.rank === 1 ? "🏆" : r.rank === 2 ? "🥈" : r.rank === 3 ? "🥉" : "";
                    return `
                        <tr style="border-top:1px solid #eee;">
                            <td style="padding:12px;font-weight:800;">${medal} ${r.rank}</td>
                            <td style="padding:12px;">
                                <strong>${p52_safe(r.name)}</strong><br>
                                <span style="font-size:0.78rem;color:#777;">${p52_safe(r.email)}</span>
                            </td>
                            <td style="padding:12px;text-align:right;font-weight:700;">${p52_money(r.totalRevenue)}</td>
                            <td style="padding:12px;text-align:right;">${p52_hours(r.totalMinutesWorked, r.totalHoursWorked)}</td>
                            <td style="padding:12px;text-align:right;font-weight:700;">${p52_money(r.revenuePerHour)}</td>
                            <td style="padding:12px;text-align:right;">${r.completedBookings || 0}</td>
                            <td style="padding:12px;text-align:right;">
                                <span style="display:inline-block;padding:5px 9px;border-radius:999px;background:#f3f4f6;font-weight:800;">
                                    ${r.efficiencyScore || 0}
                                </span>
                            </td>
                        </tr>
                    `;
                }).join("");
            }

            if (insight) {
                insight.innerHTML = `
                    <strong>Insight:</strong> ${p52_safe(best.name)} is ranked #1 for ${rangeLabel}.
                    Revenue jobs: <strong>${totalCompleted}</strong>.
                    Revenue: <strong>${p52_money(totalRevenue)}</strong>.
                `;
            }

        } catch(e) {
            console.error("Phase 5.2 Performance module error", e);
            if (status) status.innerText = "Performance module error.";
            if (table) {
                table.innerHTML = `<tr><td colspan="7" style="padding:18px;text-align:center;color:#c0392b;">${p52_safe(e.message)}</td></tr>`;
            }
        }
    };

    function p52_boot() {
        // Only add tile when Reports content is visible.
        setTimeout(() => {
            const bodyTxt = (document.body.innerText || "").toLowerCase();
            if (bodyTxt.includes("upcoming bookings") && bodyTxt.includes("tech performance")) {
                p52_mountTile();
                p52_mountPanel();
            }
        }, 1000);

        // Hook Reports button/tab click without auto-opening panel.
        document.querySelectorAll("button, label, div, span").forEach(el => {
            const txt = (el.innerText || "").trim().toLowerCase();
            if (txt === "📊 reports" || txt === "reports") {
                el.addEventListener("click", () => {
                    setTimeout(() => {
                        p52_mountTile();
                        p52_mountPanel();
                    }, 700);
                });
            }
        });
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", p52_boot);
    } else {
        p52_boot();
    }

    setTimeout(() => {
        try {
            if (typeof window.switchModule === "function" && !window.switchModule._p52Wrapped) {
                const original = window.switchModule;
                const wrapped = function(moduleId) {
                    const res = original.apply(this, arguments);
                    if (moduleId === "reportsView" || String(moduleId).toLowerCase().includes("report")) {
                        setTimeout(() => {
                            p52_mountTile();
                            p52_mountPanel();
                        }, 700);
                    }
                    return res;
                };
                wrapped._p52Wrapped = true;
                window.switchModule = wrapped;
            }
        } catch(e) {}
    }, 1500);
})();

// ============================================================================
// END THURAYA PHASE 5.2 PATCH
// ============================================================================


// ============================================================================
// THURAYA PHASE 5.2A PATCH
// Revenue-Based Intelligence Fix
// Business rule:
// - If a job has revenue > 0, count it for analytics
// - Exclude cancelled, no-show, void, refunded and draft jobs
// - This fixes Performance Dashboard + Client Intel for booking-driven revenue
// ============================================================================

(function () {
    function rbi_today() {
        try {
            if (typeof getLocalDateString === "function") return getLocalDateString();
        } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function rbi_range(type) {
        const today = rbi_today();
        const now = new Date(today + "T00:00:00");

        if (type === "week") {
            const day = now.getDay();
            const diff = day === 0 ? 6 : day - 1;
            const start = new Date(now);
            start.setDate(now.getDate() - diff);
            return { start: start.toISOString().slice(0,10), end: today, label: "This Week" };
        }

        if (type === "month") {
            return {
                start: `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,"0")}-01`,
                end: today,
                label: "This Month"
            };
        }

        return { start: today, end: today, label: "Today" };
    }

    function rbi_num(v, fallback = 0) {
        const n = parseFloat(v);
        return isNaN(n) ? fallback : n;
    }

    function rbi_status(job) {
        return String(
            job?.status ||
            job?.paymentStatus ||
            job?.billingStatus ||
            job?.jobStatus ||
            ""
        ).toLowerCase().trim();
    }

    function rbi_revenue(job) {
        const fields = [
            job?.finalTotal,
            job?.checkoutTotal,
            job?.totalPaid,
            job?.amountPaid,
            job?.paidAmount,
            job?.paymentAmount,
            job?.grandTotal,
            job?.totalAmount,
            job?.invoiceTotal,
            job?.billTotal,
            job?.billingTotal,
            job?.total,
            job?.bookedPrice,
            job?.bookedTotal,
            job?.subtotal,
            job?.serviceTotal,
            job?.price,
            job?.amount
        ];

        for (const v of fields) {
            const n = rbi_num(v, -1);
            if (n > 0) return n;
        }

        return 0;
    }

    function rbi_isExcluded(job) {
        const status = rbi_status(job);

        const bad = [
            "cancelled",
            "canceled",
            "no show",
            "noshow",
            "void",
            "refunded",
            "refund",
            "draft",
            "deleted"
        ];

        return bad.some(s => status.includes(s));
    }

    function rbi_isRevenueJob(job) {
        return !rbi_isExcluded(job) && rbi_revenue(job) > 0;
    }

    function rbi_staff(job) {
        const email = String(
            job?.assignedTechEmail ||
            job?.techEmail ||
            job?.technicianEmail ||
            job?.staffEmail ||
            job?.workerEmail ||
            job?.email ||
            ""
        ).toLowerCase().trim();

        const name =
            job?.assignedTechName ||
            job?.techName ||
            job?.technicianName ||
            job?.staffName ||
            job?.workerName ||
            job?.name ||
            email ||
            "Unassigned";

        return { email, name };
    }

    function rbi_client(job) {
        const phone = String(job?.clientPhone || job?.phone || job?.customerPhone || job?.mobile || "").trim();
        const name = job?.clientName || job?.customerName || job?.name || "Unknown Client";
        return { phone, name };
    }

    function rbi_key(job) {
        return String(
            job?.jobId ||
            job?.bookingId ||
            job?.appointmentId ||
            job?.id ||
            `${job?.source || "src"}_${job?.clientPhone || job?.phone || ""}_${job?.dateString || job?.date || ""}_${job?.timeString || job?.time || ""}_${job?.assignedTechEmail || job?.techEmail || ""}_${rbi_revenue(job)}`
        );
    }

    async function rbi_pull(collection, start, end) {
        const rows = [];

        async function q(field) {
            try {
                const snap = await db.collection(collection)
                    .where(field, ">=", start)
                    .where(field, "<=", end)
                    .get();

                snap.forEach(doc => {
                    rows.push({
                        id: doc.id,
                        source: collection,
                        ...(doc.data() || {})
                    });
                });
            } catch(e) {}
        }

        await q("dateString");
        await q("date");

        const map = {};
        rows.forEach(r => map[`${collection}_${r.id}`] = r);
        return Object.values(map);
    }

    async function rbi_fetchJobs(start, end) {
        const collections = ["Active_Jobs", "Appointments", "Sales_Redemptions", "Package_Usage"];
        let all = [];

        for (const col of collections) {
            all = all.concat(await rbi_pull(col, start, end));
        }

        const map = {};

        all.forEach(job => {
            const key = rbi_key(job);
            const current = map[key];

            if (!current) {
                map[key] = job;
                return;
            }

            const oldScore = (rbi_isRevenueJob(current) ? 10 : 0) + rbi_revenue(current);
            const newScore = (rbi_isRevenueJob(job) ? 10 : 0) + rbi_revenue(job);

            if (newScore >= oldScore) {
                map[key] = { ...current, ...job };
            }
        });

        return Object.values(map);
    }

    function rbi_toDate(value) {
        if (!value) return null;
        try {
            if (value instanceof Date) return value;
            if (typeof value.toDate === "function") return value.toDate();
            if (typeof value === "object" && typeof value.seconds === "number") return new Date(value.seconds * 1000);
            if (typeof value === "object" && typeof value._seconds === "number") return new Date(value._seconds * 1000);
            if (typeof value === "number") return new Date(value);
            if (typeof value === "string") {
                const d = new Date(value);
                if (!isNaN(d.getTime())) return d;
            }
        } catch(e) {}
        return null;
    }

    function rbi_minutes(att) {
        const saved = parseInt(att?.totalMinutesWorked || att?.workDurationMinutes || 0, 10);
        if (saved > 0) return saved;

        let mins = 0;
        const shifts = Array.isArray(att?.shifts) ? att.shifts : [];
        shifts.forEach(s => {
            const start = rbi_toDate(s?.in || s?.startedAt || s?.clockIn);
            const end = rbi_toDate(s?.out || s?.endedAt || s?.clockOut);
            if (start && end && end >= start) mins += Math.floor((end - start) / 60000);
        });

        if (!mins && att?.clockIn && att?.clockOut) {
            const start = rbi_toDate(att.clockIn);
            const end = rbi_toDate(att.clockOut);
            if (start && end && end >= start) mins = Math.floor((end - start) / 60000);
        }

        return Math.max(0, mins);
    }

    async function rbi_attendance(start, end) {
        const map = {};

        async function q(field) {
            try {
                const snap = await db.collection("Attendance")
                    .where(field, ">=", start)
                    .where(field, "<=", end)
                    .get();

                snap.forEach(doc => {
                    const a = doc.data() || {};
                    const email = String(a.email || doc.id.split("_")[0] || "").toLowerCase().trim();
                    if (!email) return;

                    if (!map[email]) {
                        map[email] = {
                            email,
                            name: a.name || email,
                            minutes: 0,
                            records: 0
                        };
                    }

                    map[email].minutes += rbi_minutes(a);
                    map[email].records += 1;
                    if (a.name) map[email].name = a.name;
                });
            } catch(e) {}
        }

        await q("date");
        await q("dateString");

        return map;
    }

    function rbi_score(revenue, hours, revenueJobs, revPerHour) {
        const revenueScore = Math.min(50, revenue / 20);
        const jobScore = Math.min(25, revenueJobs * 5);
        const efficiencyScore = Math.min(25, revPerHour / 10);
        return Math.round((revenueScore + jobScore + efficiencyScore) * 10) / 10;
    }

    async function rbi_savePerformance(rows, rangeType, range) {
        if (!rows || !rows.length) return;

        const batch = db.batch();

        rows.forEach(row => {
            const id = `${rangeType}_${range.start}_${range.end}_${row.email}`.replace(/[^a-zA-Z0-9@._-]/g, "_");
            batch.set(db.collection("Performance_Metrics").doc(id), {
                ...row,
                metricRule: "RevenueBased",
                rangeType,
                calculatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                source: "Phase_5_2A_RevenueBasedIntelligence"
            }, { merge: true });
        });

        await batch.commit();
    }

    window.thuraya_fetchUnifiedJobs = async function(rangeType = "today") {
        const range = rbi_range(rangeType);
        return await rbi_fetchJobs(range.start, range.end);
    };

    window.thuraya_debugUnifiedJobsToday = async function() {
        const jobs = await window.thuraya_fetchUnifiedJobs("today");
        console.table(jobs.map(j => ({
            source: j.source,
            id: j.id,
            date: j.dateString || j.date || "",
            status: j.status || j.paymentStatus || j.billingStatus || "",
            client: j.clientName || j.customerName || "",
            staff: j.assignedTechName || j.assignedTechEmail || j.techEmail || "",
            revenue: rbi_revenue(j),
            countedAsRevenue: rbi_isRevenueJob(j)
        })));
        return jobs;
    };

    window.thuraya_buildClientIntelMetrics = async function(rangeType = "today") {
        const range = rbi_range(rangeType);
        const jobs = await rbi_fetchJobs(range.start, range.end);
        const clients = {};

        jobs.forEach(job => {
            const client = rbi_client(job);
            const key = client.phone || client.name;
            if (!key) return;

            if (!clients[key]) {
                clients[key] = {
                    clientName: client.name,
                    clientPhone: client.phone,
                    visits: 0,
                    revenueVisits: 0,
                    totalSpend: 0,
                    lastVisit: "",
                    jobs: []
                };
            }

            clients[key].visits += 1;
            clients[key].jobs.push(job);

            const date = job.dateString || job.date || "";
            if (date && date > clients[key].lastVisit) clients[key].lastVisit = date;

            if (rbi_isRevenueJob(job)) {
                clients[key].revenueVisits += 1;
                clients[key].totalSpend += rbi_revenue(job);
            }
        });

        const rows = Object.values(clients).map(c => ({
            ...c,
            completedVisits: c.revenueVisits,
            totalSpend: Math.round(c.totalSpend * 100) / 100,
            avgSpend: c.revenueVisits ? Math.round((c.totalSpend / c.revenueVisits) * 100) / 100 : 0,
            repeatClient: c.revenueVisits > 1
        })).sort((a,b) => b.totalSpend - a.totalSpend || b.revenueVisits - a.revenueVisits);

        console.log("Revenue-Based Client Intel:", rows);
        return rows;
    };

    window.thuraya_buildPerformanceMetrics = async function(rangeType = "today") {
        const range = rbi_range(rangeType);
        const [attendance, jobs] = await Promise.all([
            rbi_attendance(range.start, range.end),
            rbi_fetchJobs(range.start, range.end)
        ]);

        const staff = {};

        Object.values(attendance).forEach(a => {
            staff[a.email] = {
                email: a.email,
                name: a.name || a.email,
                totalMinutesWorked: a.minutes || 0,
                totalRevenue: 0,
                revenueJobs: 0,
                completedBookings: 0,
                totalBookings: 0,
                attendanceRecords: a.records || 0
            };
        });

        jobs.forEach(job => {
            const s = rbi_staff(job);
            if (!s.email) return;

            if (!staff[s.email]) {
                staff[s.email] = {
                    email: s.email,
                    name: s.name || s.email,
                    totalMinutesWorked: 0,
                    totalRevenue: 0,
                    revenueJobs: 0,
                    completedBookings: 0,
                    totalBookings: 0,
                    attendanceRecords: 0
                };
            }

            if (s.name) staff[s.email].name = s.name;
            staff[s.email].totalBookings += 1;

            if (rbi_isRevenueJob(job)) {
                staff[s.email].revenueJobs += 1;
                staff[s.email].completedBookings += 1; // preserved for existing UI column
                staff[s.email].totalRevenue += rbi_revenue(job);
            }
        });

        const rows = Object.values(staff).map(s => {
            const hours = Math.round((s.totalMinutesWorked / 60) * 100) / 100;
            const revenue = Math.round(s.totalRevenue * 100) / 100;
            const revenuePerHour = hours > 0 ? Math.round((revenue / hours) * 100) / 100 : 0;
            const avgBookingValue = s.revenueJobs ? Math.round((revenue / s.revenueJobs) * 100) / 100 : 0;

            return {
                range: range.label,
                startDate: range.start,
                endDate: range.end,
                email: s.email,
                name: s.name,
                totalRevenue: revenue,
                totalMinutesWorked: s.totalMinutesWorked,
                totalHoursWorked: hours,
                revenuePerHour,
                completedBookings: s.completedBookings,
                revenueJobs: s.revenueJobs,
                totalBookings: s.totalBookings,
                avgBookingValue,
                attendanceRecords: s.attendanceRecords,
                efficiencyScore: rbi_score(revenue, hours, s.revenueJobs, revenuePerHour),
                metricRule: "RevenueBased"
            };
        }).sort((a,b) =>
            (b.efficiencyScore - a.efficiencyScore) ||
            (b.totalRevenue - a.totalRevenue) ||
            (b.revenueJobs - a.revenueJobs) ||
            (b.totalHoursWorked - a.totalHoursWorked)
        );

        rows.forEach((r, i) => r.rank = i + 1);

        try { await rbi_savePerformance(rows, rangeType, range); } catch(e) {
            console.warn("Revenue-based performance save failed", e);
        }

        console.log("Revenue-Based Performance Metrics:", rows);
        console.log("Revenue-Based Jobs:", jobs);

        return rows;
    };

    // Refresh performance panel if it is open.
    setTimeout(() => {
        try {
            if (typeof window.rpt_openPerformance52 === "function" && document.getElementById("rptPerformancePanel52")?.style.display !== "none") {
                window.rpt_openPerformance52(window.P52_ACTIVE_RANGE || "month");
            }
        } catch(e) {}
    }, 2500);

})();

