// ============================================================================
// THURAYA PHASE 5.3A PATCH
// Targets Engine
// Adds staff revenue target calculations on top of Performance Intelligence.
// No UI layout changes yet.
// Collections:
// - Performance_Metrics: already used by performance engine
// - Staff_Targets: optional target settings per staff
// ============================================================================

(function () {
    const TARGETS53A = {
        cache: []
    };

    function t53_today() {
        try {
            if (typeof getLocalDateString === "function") return getLocalDateString();
        } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function t53_range(type) {
        const today = t53_today();
        const now = new Date(today + "T00:00:00");

        if (type === "week") {
            const day = now.getDay();
            const diff = day === 0 ? 6 : day - 1;
            const start = new Date(now);
            start.setDate(now.getDate() - diff);
            return { start: start.toISOString().slice(0,10), end: today, label: "This Week", type: "week" };
        }

        if (type === "month") {
            return {
                start: `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,"0")}-01`,
                end: today,
                label: "This Month",
                type: "month"
            };
        }

        return { start: today, end: today, label: "Today", type: "today" };
    }

    function t53_num(v, fallback = 0) {
        const n = parseFloat(v);
        return isNaN(n) ? fallback : n;
    }

    function t53_daysBetweenInclusive(startStr, endStr) {
        try {
            const start = new Date(startStr + "T00:00:00");
            const end = new Date(endStr + "T00:00:00");
            const diff = Math.floor((end - start) / 86400000) + 1;
            return Math.max(1, diff);
        } catch(e) {
            return 1;
        }
    }

    function t53_defaultTarget(range) {
        // Conservative defaults for staging/testing.
        // These can be overridden in Staff_Targets.
        const daily = 500;
        if (range.type === "today") return daily;
        if (range.type === "week") return daily * t53_daysBetweenInclusive(range.start, range.end);
        if (range.type === "month") return daily * t53_daysBetweenInclusive(range.start, range.end);
        return daily;
    }

    async function t53_getStaffTarget(email, range) {
        if (!email) return t53_defaultTarget(range);

        try {
            const ref = db.collection("Staff_Targets").doc(String(email).toLowerCase());
            const doc = await ref.get();

            if (!doc.exists) return t53_defaultTarget(range);

            const d = doc.data() || {};

            if (range.type === "today") {
                return t53_num(d.dailyTarget || d.targetDaily || d.revenueTargetDaily, t53_defaultTarget(range));
            }

            if (range.type === "week") {
                const explicit = t53_num(d.weeklyTarget || d.targetWeekly || d.revenueTargetWeekly, 0);
                if (explicit > 0) return explicit;

                const daily = t53_num(d.dailyTarget || d.targetDaily || d.revenueTargetDaily, 500);
                return daily * t53_daysBetweenInclusive(range.start, range.end);
            }

            if (range.type === "month") {
                const explicit = t53_num(d.monthlyTarget || d.targetMonthly || d.revenueTargetMonthly, 0);
                if (explicit > 0) return explicit;

                const daily = t53_num(d.dailyTarget || d.targetDaily || d.revenueTargetDaily, 500);
                return daily * t53_daysBetweenInclusive(range.start, range.end);
            }

            return t53_defaultTarget(range);

        } catch(e) {
            console.warn("Target lookup failed for", email, e);
            return t53_defaultTarget(range);
        }
    }

    function t53_status(percent) {
        if (percent >= 100) return "Achieved";
        if (percent >= 80) return "On Track";
        if (percent >= 50) return "Watch";
        return "Behind";
    }

    function t53_gap(revenue, target) {
        return Math.max(0, Math.round((target - revenue) * 100) / 100);
    }

    window.thuraya_buildTargetMetrics = async function(rangeType = "today") {
        const range = t53_range(rangeType);

        if (typeof window.thuraya_buildPerformanceMetrics !== "function") {
            throw new Error("Performance engine not found. Build Phase 5.2 first.");
        }

        const performanceRows = await window.thuraya_buildPerformanceMetrics(rangeType);

        const rows = [];

        for (const row of performanceRows) {
            const target = await t53_getStaffTarget(row.email, range);
            const revenue = t53_num(row.totalRevenue, 0);
            const achievementPercent = target > 0
                ? Math.round((revenue / target) * 1000) / 10
                : 0;

            rows.push({
                ...row,
                range: range.label,
                rangeType,
                targetRevenue: Math.round(target * 100) / 100,
                actualRevenue: revenue,
                achievementPercent,
                targetGap: t53_gap(revenue, target),
                targetStatus: t53_status(achievementPercent),
                targetRule: "Staff_Targets_or_Default"
            });
        }

        rows.sort((a,b) =>
            (b.achievementPercent - a.achievementPercent) ||
            (b.actualRevenue - a.actualRevenue) ||
            (b.efficiencyScore - a.efficiencyScore)
        );

        rows.forEach((r, i) => r.targetRank = i + 1);

        TARGETS53A.cache = rows;

        try {
            await t53_saveTargets(rows, rangeType, range);
        } catch(e) {
            console.warn("Target metrics save failed", e);
        }

        console.log("Phase 5.3A Target Metrics:", rows);
        return rows;
    };

    async function t53_saveTargets(rows, rangeType, range) {
        if (!rows || !rows.length) return;

        const batch = db.batch();

        rows.forEach(row => {
            const id = `${rangeType}_${range.start}_${range.end}_${row.email}`.replace(/[^a-zA-Z0-9@._-]/g, "_");
            const ref = db.collection("Target_Metrics").doc(id);

            batch.set(ref, {
                ...row,
                rangeType,
                calculatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                source: "Phase_5_3A_TargetsEngine"
            }, { merge: true });
        });

        await batch.commit();
    }

    window.thuraya_setStaffTarget = async function(email, targets = {}) {
        if (!email) throw new Error("Staff email required.");

        const safeEmail = String(email).toLowerCase().trim();

        const payload = {
            dailyTarget: t53_num(targets.dailyTarget || targets.daily || 0, 0),
            weeklyTarget: t53_num(targets.weeklyTarget || targets.weekly || 0, 0),
            monthlyTarget: t53_num(targets.monthlyTarget || targets.monthly || 0, 0),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: (firebase.auth().currentUser?.email || currentUserEmail || "")
        };

        await db.collection("Staff_Targets").doc(safeEmail).set(payload, { merge: true });

        console.log("Staff target saved:", safeEmail, payload);
        return payload;
    };

    window.thuraya_debugTargetsToday = async function() {
        const rows = await window.thuraya_buildTargetMetrics("today");
        console.table(rows.map(r => ({
            staff: r.name,
            email: r.email,
            revenue: r.actualRevenue,
            target: r.targetRevenue,
            achievement: `${r.achievementPercent}%`,
            gap: r.targetGap,
            status: r.targetStatus
        })));
        return rows;
    };

    // Light auto-run for current day. No UI impact.
    setTimeout(() => {
        try {
            if (firebase?.auth?.().currentUser) {
                window.thuraya_buildTargetMetrics("today");
            }
        } catch(e) {}
    }, 6000);

})();

// ============================================================================
// END THURAYA PHASE 5.3A PATCH
// ============================================================================


// ============================================================================
// THURAYA PHASE 5.3B PATCH
// Targets Dashboard UI
// Adds target vs actual visuals into the existing Performance Intelligence panel.
// Uses Phase 5.3A: thuraya_buildTargetMetrics(rangeType)
// No top-level auto-mount. No Admin layout disruption.
// ============================================================================

(function () {
    function tgSafe(v) {
        return String(v ?? "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;");
    }

    function tgMoney(v) {
        const n = parseFloat(v || 0);
        return `${n.toFixed(2)} GHC`;
    }

    function tgStatusColor(status) {
        const s = String(status || "").toLowerCase();
        if (s.includes("achieved")) return "#55a868";
        if (s.includes("on track")) return "#4b6cb7";
        if (s.includes("watch")) return "#d99a22";
        return "#c0392b";
    }

    function tgProgressBar(percent, status) {
        const p = Math.max(0, Math.min(100, parseFloat(percent || 0)));
        const color = tgStatusColor(status);

        return `
            <div style="width:100%;height:9px;background:#f0f0f0;border-radius:999px;overflow:hidden;margin-top:6px;">
                <div style="width:${p}%;height:100%;background:${color};border-radius:999px;"></div>
            </div>
        `;
    }

    function tgCard(label, value, sub, color) {
        return `
            <div style="border:1px solid #e4e4e4;border-radius:12px;padding:14px;background:#fff;">
                <div style="font-size:0.75rem;color:#777;text-transform:uppercase;letter-spacing:1.4px;margin-bottom:8px;">
                    ${label}
                </div>
                <div style="font-size:1.45rem;font-weight:800;color:${color || "#2f3b52"};">
                    ${value}
                </div>
                <div style="font-size:0.82rem;color:#777;margin-top:6px;">${sub || ""}</div>
            </div>
        `;
    }

    function tgFindPerformancePanel() {
        return document.getElementById("rptPerformancePanel52");
    }

    function tgEnsureSection(panel) {
        let section = document.getElementById("targetsDashboard53B");
        if (section) return section;

        section = document.createElement("div");
        section.id = "targetsDashboard53B";
        section.style.cssText = `
            margin-top:18px;
            border-top:1px solid #eee;
            padding-top:18px;
        `;

        section.innerHTML = `
            <div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:12px;">
                <div>
                    <h3 style="margin:0;color:#2f3b52;letter-spacing:1.5px;text-transform:uppercase;">
                        Target Intelligence
                    </h3>
                    <p style="margin:6px 0 0;color:#666;">
                        Target vs actual revenue, achievement status and revenue gap.
                    </p>
                </div>
                <button class="btn btn-secondary btn-auto" onclick="thuraya_renderTargetsDashboard53B(window.P52_ACTIVE_RANGE || 'today')">
                    Refresh Targets
                </button>
            </div>

            <div id="tg53bStatus" style="font-size:0.85rem;color:#777;margin-bottom:12px;">Ready.</div>
            <div id="tg53bCards" style="display:grid;grid-template-columns:repeat(4,minmax(150px,1fr));gap:12px;margin-bottom:16px;"></div>

            <div style="overflow-x:auto;border:1px solid #eee;border-radius:12px;">
                <table style="width:100%;border-collapse:collapse;">
                    <thead>
                        <tr style="background:#f8f8f8;color:#2f3b52;text-transform:uppercase;font-size:0.78rem;letter-spacing:1px;">
                            <th style="padding:12px;text-align:left;">Rank</th>
                            <th style="padding:12px;text-align:left;">Staff</th>
                            <th style="padding:12px;text-align:right;">Actual</th>
                            <th style="padding:12px;text-align:right;">Target</th>
                            <th style="padding:12px;text-align:right;">Achievement</th>
                            <th style="padding:12px;text-align:right;">Gap</th>
                            <th style="padding:12px;text-align:left;">Status</th>
                        </tr>
                    </thead>
                    <tbody id="tg53bTable">
                        <tr><td colspan="7" style="padding:18px;text-align:center;color:#777;">Open Performance Intelligence to load targets.</td></tr>
                    </tbody>
                </table>
            </div>
        `;

        panel.appendChild(section);
        return section;
    }

    window.thuraya_renderTargetsDashboard53B = async function(rangeType = "today") {
        const panel = tgFindPerformancePanel();
        if (!panel || panel.style.display === "none") return;

        tgEnsureSection(panel);

        const status = document.getElementById("tg53bStatus");
        const cards = document.getElementById("tg53bCards");
        const table = document.getElementById("tg53bTable");

        if (status) status.innerText = "Calculating target metrics...";
        if (table) table.innerHTML = `<tr><td colspan="7" style="padding:18px;text-align:center;color:#777;">Loading...</td></tr>`;

        try {
            if (typeof window.thuraya_buildTargetMetrics !== "function") {
                throw new Error("Targets engine not found. Please apply Phase 5.3A first.");
            }

            const rows = await window.thuraya_buildTargetMetrics(rangeType);
            const rangeLabel = rows?.[0]?.range || (rangeType === "week" ? "This Week" : rangeType === "month" ? "This Month" : "Today");

            if (!rows.length) {
                if (status) status.innerText = `No target data found for ${rangeLabel}.`;
                if (cards) {
                    cards.innerHTML =
                        tgCard("Target Revenue", "0.00 GHC", rangeLabel) +
                        tgCard("Actual Revenue", "0.00 GHC", "No revenue yet", "#55a868") +
                        tgCard("Achievement", "0%", "No staff data", "#c0392b") +
                        tgCard("Target Gap", "0.00 GHC", "No gap data", "#d99a22");
                }
                if (table) {
                    table.innerHTML = `<tr><td colspan="7" style="padding:22px;text-align:center;color:#777;">No target records yet.</td></tr>`;
                }
                return;
            }

            const totalTarget = rows.reduce((s, r) => s + parseFloat(r.targetRevenue || 0), 0);
            const totalActual = rows.reduce((s, r) => s + parseFloat(r.actualRevenue || r.totalRevenue || 0), 0);
            const totalGap = Math.max(0, totalTarget - totalActual);
            const overallAchievement = totalTarget > 0 ? Math.round((totalActual / totalTarget) * 1000) / 10 : 0;

            const achievedCount = rows.filter(r => String(r.targetStatus || "").toLowerCase().includes("achieved")).length;
            const behindCount = rows.filter(r => String(r.targetStatus || "").toLowerCase().includes("behind")).length;

            if (status) {
                status.innerText = `Showing ${rangeLabel} target performance · ${rows.length} staff record(s)`;
            }

            if (cards) {
                cards.innerHTML =
                    tgCard("Target Revenue", tgMoney(totalTarget), rangeLabel, "#2f3b52") +
                    tgCard("Actual Revenue", tgMoney(totalActual), `${overallAchievement}% achieved`, "#55a868") +
                    tgCard("Target Gap", tgMoney(totalGap), "Revenue still needed", "#d99a22") +
                    tgCard("Status", `${achievedCount} Achieved`, `${behindCount} Behind`, achievedCount ? "#55a868" : "#c0392b");
            }

            if (table) {
                table.innerHTML = rows.map(r => {
                    const pct = parseFloat(r.achievementPercent || 0);
                    const statusColor = tgStatusColor(r.targetStatus);
                    const medal = r.targetRank === 1 ? "🏆" : r.targetRank === 2 ? "🥈" : r.targetRank === 3 ? "🥉" : "";

                    return `
                        <tr style="border-top:1px solid #eee;">
                            <td style="padding:12px;font-weight:800;">${medal} ${r.targetRank}</td>
                            <td style="padding:12px;">
                                <strong>${tgSafe(r.name)}</strong><br>
                                <span style="font-size:0.78rem;color:#777;">${tgSafe(r.email)}</span>
                            </td>
                            <td style="padding:12px;text-align:right;font-weight:700;">${tgMoney(r.actualRevenue || r.totalRevenue)}</td>
                            <td style="padding:12px;text-align:right;">${tgMoney(r.targetRevenue)}</td>
                            <td style="padding:12px;text-align:right;min-width:160px;">
                                <strong>${pct}%</strong>
                                ${tgProgressBar(pct, r.targetStatus)}
                            </td>
                            <td style="padding:12px;text-align:right;">${tgMoney(r.targetGap)}</td>
                            <td style="padding:12px;text-align:left;">
                                <span style="display:inline-block;padding:5px 9px;border-radius:999px;background:${statusColor};color:#fff;font-weight:800;font-size:0.8rem;">
                                    ${tgSafe(r.targetStatus)}
                                </span>
                            </td>
                        </tr>
                    `;
                }).join("");
            }

        } catch(e) {
            console.error("Targets dashboard error", e);
            if (status) status.innerText = "Targets dashboard error.";
            if (table) {
                table.innerHTML = `<tr><td colspan="7" style="padding:18px;text-align:center;color:#c0392b;">${tgSafe(e.message)}</td></tr>`;
            }
        }
    };

    // Hook into existing Performance module open function.
    setTimeout(() => {
        try {
            if (typeof window.rpt_openPerformance52 === "function" && !window.rpt_openPerformance52._tg53bWrapped) {
                const old = window.rpt_openPerformance52;
                const wrapped = async function(rangeType = "today") {
                    const result = await old.apply(this, arguments);
                    setTimeout(() => window.thuraya_renderTargetsDashboard53B(rangeType), 500);
                    setTimeout(() => window.thuraya_renderTargetsDashboard53B(rangeType), 1500);
                    return result;
                };
                wrapped._tg53bWrapped = true;
                window.rpt_openPerformance52 = wrapped;
            }
        } catch(e) {}
    }, 1200);

})();

// ============================================================================
// END THURAYA PHASE 5.3B PATCH
