// ============================================================================
// THURAYA PHASE 5.3C PATCH
// Commission Engine
// Adds commission calculations on top of revenue-based Performance Intelligence.
// No UI layout changes yet.
// Collections:
// - Commission_Settings: optional per-staff or default commission configuration
// - Commission_Metrics: calculated commission snapshots
// ============================================================================

(function () {
    const COMM53C = {
        cache: []
    };

    function c53_today() {
        try {
            if (typeof getLocalDateString === "function") return getLocalDateString();
        } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function c53_range(type) {
        const today = c53_today();
        const now = new Date(today + "T00:00:00");

        if (type === "week") {
            const day = now.getDay();
            const diff = day === 0 ? 6 : day - 1;
            const start = new Date(now);
            start.setDate(now.getDate() - diff);
            return { start: start.toISOString().slice(0,10), end: today, label: "This Week", type: "week" };
        }

        if (type === "month") {
            return {
                start: `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,"0")}-01`,
                end: today,
                label: "This Month",
                type: "month"
            };
        }

        return { start: today, end: today, label: "Today", type: "today" };
    }

    function c53_num(v, fallback = 0) {
        const n = parseFloat(v);
        return isNaN(n) ? fallback : n;
    }

    function c53_round(v) {
        return Math.round(c53_num(v, 0) * 100) / 100;
    }

    async function c53_getDefaultSettings() {
        try {
            const doc = await db.collection("Commission_Settings").doc("default").get();
            if (doc.exists) return doc.data() || {};
        } catch(e) {
            console.warn("Default commission settings lookup failed", e);
        }

        return {};
    }

    async function c53_getStaffSettings(email) {
        const defaults = await c53_getDefaultSettings();

        if (!email) {
            return {
                ratePercent: c53_num(defaults.ratePercent || defaults.defaultRatePercent || 10, 10),
                threshold: c53_num(defaults.threshold || defaults.minimumRevenue || 0, 0),
                bonusPercent: c53_num(defaults.bonusPercent || 0, 0),
                bonusThreshold: c53_num(defaults.bonusThreshold || 0, 0),
                source: "default"
            };
        }

        try {
            const safeEmail = String(email).toLowerCase().trim();
            const doc = await db.collection("Commission_Settings").doc(safeEmail).get();

            if (doc.exists) {
                const d = doc.data() || {};
                return {
                    ratePercent: c53_num(d.ratePercent || d.commissionPercent || defaults.ratePercent || defaults.defaultRatePercent || 10, 10),
                    threshold: c53_num(d.threshold || d.minimumRevenue || defaults.threshold || defaults.minimumRevenue || 0, 0),
                    bonusPercent: c53_num(d.bonusPercent || defaults.bonusPercent || 0, 0),
                    bonusThreshold: c53_num(d.bonusThreshold || defaults.bonusThreshold || 0, 0),
                    source: "staff"
                };
            }
        } catch(e) {
            console.warn("Staff commission settings lookup failed", email, e);
        }

        return {
            ratePercent: c53_num(defaults.ratePercent || defaults.defaultRatePercent || 10, 10),
            threshold: c53_num(defaults.threshold || defaults.minimumRevenue || 0, 0),
            bonusPercent: c53_num(defaults.bonusPercent || 0, 0),
            bonusThreshold: c53_num(defaults.bonusThreshold || 0, 0),
            source: "default"
        };
    }

    function c53_calculateCommission(revenue, settings) {
        const rev = c53_num(revenue, 0);
        const threshold = c53_num(settings.threshold, 0);

        const eligibleRevenue = Math.max(0, rev - threshold);
        const baseRate = c53_num(settings.ratePercent, 10);
        const baseCommission = eligibleRevenue * (baseRate / 100);

        let bonusCommission = 0;
        const bonusThreshold = c53_num(settings.bonusThreshold, 0);
        const bonusPercent = c53_num(settings.bonusPercent, 0);

        if (bonusThreshold > 0 && rev >= bonusThreshold && bonusPercent > 0) {
            bonusCommission = rev * (bonusPercent / 100);
        }

        return {
            eligibleRevenue: c53_round(eligibleRevenue),
            baseRatePercent: baseRate,
            baseCommission: c53_round(baseCommission),
            bonusPercent,
            bonusThreshold,
            bonusCommission: c53_round(bonusCommission),
            totalCommission: c53_round(baseCommission + bonusCommission)
        };
    }

    window.thuraya_buildCommissionMetrics = async function(rangeType = "today") {
        const range = c53_range(rangeType);

        if (typeof window.thuraya_buildPerformanceMetrics !== "function") {
            throw new Error("Performance engine not found. Build Phase 5.2 first.");
        }

        const performanceRows = await window.thuraya_buildPerformanceMetrics(rangeType);
        const rows = [];

        for (const row of performanceRows) {
            const settings = await c53_getStaffSettings(row.email);
            const commission = c53_calculateCommission(row.totalRevenue, settings);

            rows.push({
                ...row,
                range: range.label,
                rangeType,
                commissionRatePercent: commission.baseRatePercent,
                commissionThreshold: c53_num(settings.threshold, 0),
                eligibleRevenue: commission.eligibleRevenue,
                baseCommission: commission.baseCommission,
                bonusPercent: commission.bonusPercent,
                bonusThreshold: commission.bonusThreshold,
                bonusCommission: commission.bonusCommission,
                totalCommission: commission.totalCommission,
                commissionSettingsSource: settings.source,
                commissionRule: "RevenueBased"
            });
        }

        rows.sort((a,b) =>
            (b.totalCommission - a.totalCommission) ||
            (b.totalRevenue - a.totalRevenue) ||
            (b.efficiencyScore - a.efficiencyScore)
        );

        rows.forEach((r, i) => r.commissionRank = i + 1);

        COMM53C.cache = rows;

        try {
            await c53_saveCommissionMetrics(rows, rangeType, range);
        } catch(e) {
            console.warn("Commission metrics save failed", e);
        }

        console.log("Phase 5.3C Commission Metrics:", rows);
        return rows;
    };

    async function c53_saveCommissionMetrics(rows, rangeType, range) {
        if (!rows || !rows.length) return;

        const batch = db.batch();

        rows.forEach(row => {
            const id = `${rangeType}_${range.start}_${range.end}_${row.email}`.replace(/[^a-zA-Z0-9@._-]/g, "_");
            const ref = db.collection("Commission_Metrics").doc(id);

            batch.set(ref, {
                ...row,
                rangeType,
                calculatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                source: "Phase_5_3C_CommissionEngine"
            }, { merge: true });
        });

        await batch.commit();
    }

    window.thuraya_setCommissionRate = async function(email, config = {}) {
        const safeEmail = email ? String(email).toLowerCase().trim() : "default";

        const payload = {
            ratePercent: c53_num(config.ratePercent || config.rate || config.commissionPercent || 10, 10),
            threshold: c53_num(config.threshold || config.minimumRevenue || 0, 0),
            bonusPercent: c53_num(config.bonusPercent || 0, 0),
            bonusThreshold: c53_num(config.bonusThreshold || 0, 0),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: (firebase.auth().currentUser?.email || currentUserEmail || "")
        };

        await db.collection("Commission_Settings").doc(safeEmail).set(payload, { merge: true });

        console.log("Commission setting saved:", safeEmail, payload);
        return payload;
    };

    window.thuraya_debugCommissionsToday = async function() {
        const rows = await window.thuraya_buildCommissionMetrics("today");
        console.table(rows.map(r => ({
            rank: r.commissionRank,
            staff: r.name,
            revenue: r.totalRevenue,
            rate: `${r.commissionRatePercent}%`,
            eligibleRevenue: r.eligibleRevenue,
            baseCommission: r.baseCommission,
            bonus: r.bonusCommission,
            totalCommission: r.totalCommission
        })));
        return rows;
    };

    // Light auto-run. No UI impact.
    setTimeout(() => {
        try {
            if (firebase?.auth?.().currentUser) {
                window.thuraya_buildCommissionMetrics("today");
            }
        } catch(e) {}
    }, 7000);

})();

// ============================================================================
// END THURAYA PHASE 5.3C PATCH
// ============================================================================

// ===============================
// PHASE 5.3D – ALERTS / ADVANCED INTELLIGENCE
// ===============================

let alertDataCache = [];

async function ai_loadAdvancedIntelligence() {
    try {
        const today = todayDateStr;

        const [jobsSnap, targetSnap, commissionSnap] = await Promise.all([
            db.collection('Active_Jobs').where('dateString', '==', today).get(),
            db.collection('Staff_Targets').get(),
            db.collection('Commission_Settings').doc('default').get()
        ]);

        let revenueByStaff = {};
        let hoursByStaff = {};

        jobsSnap.forEach(doc => {
            const j = doc.data();
            const email = j.assignedTechEmail;

            const revenue = parseFloat(j.finalTotal || j.grandTotal || 0);
            const duration = parseInt(j.bookedDuration || 0);

            if (!email) return;

            revenueByStaff[email] = (revenueByStaff[email] || 0) + revenue;
            hoursByStaff[email] = (hoursByStaff[email] || 0) + (duration / 60);
        });

        let targets = {};
        targetSnap.forEach(doc => {
            targets[doc.id] = doc.data();
        });

        const commission = commissionSnap.exists ? commissionSnap.data() : {};

        alertDataCache = [];

        Object.keys(revenueByStaff).forEach(email => {

            const revenue = revenueByStaff[email] || 0;
            const hours = hoursByStaff[email] || 1;
            const revenuePerHour = revenue / hours;

            const target = targets[email]?.dailyTarget || 0;
            const progress = target > 0 ? (revenue / target) * 100 : 0;

            let alertLevel = "normal";
            let alertMsg = "";

            if (progress < 60) {
                alertLevel = "danger";
                alertMsg = "At Risk";
            } else if (progress < 90) {
                alertLevel = "warning";
                alertMsg = "Behind Target";
            } else if (progress <= 110) {
                alertLevel = "success";
                alertMsg = "On Track";
            } else {
                alertLevel = "excellent";
                alertMsg = "Exceeding Target";
            }

            const commissionRate = parseFloat(commission.defaultRate || 0.1);
            const estimatedCommission = revenue * commissionRate;

            alertDataCache.push({
                email,
                revenue,
                hours,
                revenuePerHour,
                target,
                progress,
                alertLevel,
                alertMsg,
                estimatedCommission
            });
        });

        ai_renderAlerts();

    } catch (e) {
        console.error("AI Alerts Error:", e);
    }
}

function ai_renderAlerts() {
    const container = document.getElementById('aiAlertsContainer');
    if (!container) return;

    if (alertDataCache.length === 0) {
        container.innerHTML = "<p style='color:#999;'>No alert data.</p>";
        return;
    }

    alertDataCache.sort((a,b) => b.revenue - a.revenue);

    let html = '';

    alertDataCache.forEach(staff => {

        let color = "#ccc";
        if (staff.alertLevel === "danger") color = "#e74c3c";
        if (staff.alertLevel === "warning") color = "#f39c12";
        if (staff.alertLevel === "success") color = "#27ae60";
        if (staff.alertLevel === "excellent") color = "#2ecc71";

        html += `
        <div style="background:white; border-left:5px solid ${color}; padding:12px; margin-bottom:10px; border-radius:8px;">
            <strong>${staff.email}</strong><br>
            Revenue: ${staff.revenue.toFixed(2)} GHC<br>
            Target: ${staff.target} GHC<br>
            Progress: ${staff.progress.toFixed(1)}%<br>
            Rev/Hr: ${staff.revenuePerHour.toFixed(2)}<br>
            Commission: ${staff.estimatedCommission.toFixed(2)}<br>
            <span style="color:${color}; font-weight:bold;">${staff.alertMsg}</span>
        </div>`;
    });

    container.innerHTML = html;
}

// ===============================
// PHASE 5.4 – PREDICTIVE INTELLIGENCE
// ===============================

let predictiveCache = [];

async function ai_loadPredictiveIntelligence() {
    try {
        const today = todayDateStr;

        const [jobsSnap, targetSnap, commissionSnap] = await Promise.all([
            db.collection('Active_Jobs').where('dateString', '==', today).get(),
            db.collection('Staff_Targets').get(),
            db.collection('Commission_Settings').doc('default').get()
        ]);

        let revenueByStaff = {};
        let hoursByStaff = {};

        jobsSnap.forEach(doc => {
            const j = doc.data();
            const email = j.assignedTechEmail;

            const revenue = parseFloat(j.finalTotal || j.grandTotal || 0);
            const duration = parseInt(j.bookedDuration || 0);

            if (!email) return;

            revenueByStaff[email] = (revenueByStaff[email] || 0) + revenue;
            hoursByStaff[email] = (hoursByStaff[email] || 0) + (duration / 60);
        });

        let targets = {};
        targetSnap.forEach(doc => {
            targets[doc.id] = doc.data();
        });

        const commission = commissionSnap.exists ? commissionSnap.data() : {};

        const now = new Date();
        const currentHour = now.getHours() + (now.getMinutes() / 60);
        const workStart = 8;
        const workEnd = 20;

        const elapsed = Math.max(1, currentHour - workStart);
        const totalWorkHours = workEnd - workStart;
        const remainingHours = Math.max(0, totalWorkHours - elapsed);

        predictiveCache = [];

        Object.keys(revenueByStaff).forEach(email => {

            const revenue = revenueByStaff[email] || 0;
            const hours = hoursByStaff[email] || 1;

            const revenuePerHour = revenue / hours;

            const projectedRevenue = revenue + (revenuePerHour * remainingHours);

            const target = targets[email]?.dailyTarget || 0;

            const projectedGap = target - projectedRevenue;

            const commissionRate = parseFloat(commission.defaultRate || 0.1);
            const projectedCommission = projectedRevenue * commissionRate;

            let riskLevel = "safe";
            let riskMsg = "";

            if (projectedRevenue < target * 0.7) {
                riskLevel = "danger";
                riskMsg = "Will Miss Target";
            } else if (projectedRevenue < target) {
                riskLevel = "warning";
                riskMsg = "At Risk";
            } else {
                riskLevel = "success";
                riskMsg = "Will Hit Target";
            }

            predictiveCache.push({
                email,
                revenue,
                projectedRevenue,
                revenuePerHour,
                target,
                projectedGap,
                projectedCommission,
                riskLevel,
                riskMsg
            });
        });

        ai_renderPredictive();

    } catch (e) {
        console.error("Predictive Engine Error:", e);
    }
}

function ai_renderPredictive() {
    const container = document.getElementById('aiPredictiveContainer');
    if (!container) return;

    if (predictiveCache.length === 0) {
        container.innerHTML = "<p style='color:#999;'>No predictive data.</p>";
        return;
    }

    predictiveCache.sort((a,b) => b.projectedRevenue - a.projectedRevenue);

    let html = '';

    predictiveCache.forEach(staff => {

        let color = "#ccc";
        if (staff.riskLevel === "danger") color = "#e74c3c";
        if (staff.riskLevel === "warning") color = "#f39c12";
        if (staff.riskLevel === "success") color = "#27ae60";

        html += `
        <div style="background:white; border-left:5px solid ${color}; padding:12px; margin-bottom:10px; border-radius:8px;">
            <strong>${staff.email}</strong><br>
            Current: ${staff.revenue.toFixed(2)} GHC<br>
            Projected: <strong>${staff.projectedRevenue.toFixed(2)} GHC</strong><br>
            Target: ${staff.target} GHC<br>
            Gap: ${staff.projectedGap.toFixed(2)} GHC<br>
            Rev/Hr: ${staff.revenuePerHour.toFixed(2)}<br>
            Commission (Projected): ${staff.projectedCommission.toFixed(2)}<br>
            <span style="color:${color}; font-weight:bold;">${staff.riskMsg}</span>
        </div>`;
    });

    container.innerHTML = html;
}

