(function () {
    function thurayaLoadIntelligenceDashboard() {
        const alertsBox = document.getElementById('aiAlertsContainer');
        const forecastBox = document.getElementById('aiPredictiveContainer');

        if (!alertsBox && !forecastBox) return;

        if (alertsBox) {
            alertsBox.innerHTML = "<p style='color:#999; padding:10px;'>Loading alerts...</p>";
        }

        if (forecastBox) {
            forecastBox.innerHTML = "<p style='color:#999; padding:10px;'>Loading forecast...</p>";
        }

        setTimeout(() => {
            try {
                if (typeof ai_loadAdvancedIntelligence === 'function') {
                    ai_loadAdvancedIntelligence();
                } else if (alertsBox) {
                    alertsBox.innerHTML = "<p style='color:#999;'>Alerts engine not found.</p>";
                }

                if (typeof ai_loadPredictiveIntelligence === 'function') {
                    ai_loadPredictiveIntelligence();
                } else if (forecastBox) {
                    forecastBox.innerHTML = "<p style='color:#999;'>Forecast engine not found.</p>";
                }
            } catch (e) {
                console.error("Intelligence dashboard failed:", e);
                if (alertsBox) alertsBox.innerHTML = "<p style='color:red;'>Alerts failed to load.</p>";
                if (forecastBox) forecastBox.innerHTML = "<p style='color:red;'>Forecast failed to load.</p>";
            }
        }, 700);
    }

    // Run when Reports tab is clicked/opened
    const oldSwitchModule = window.switchModule;
    window.switchModule = function(moduleId) {
        if (typeof oldSwitchModule === 'function') {
            oldSwitchModule(moduleId);
        }

        if (moduleId === 'intelligenceView') {
            setTimeout(thurayaLoadIntelligenceDashboard, 500);
            setTimeout(thurayaLoadIntelligenceDashboard, 1500);
        }
    };

    // Also run once after page settles
    document.addEventListener('DOMContentLoaded', () => {
        setTimeout(thurayaLoadIntelligenceDashboard, 2500);
    });
})();

// ============================================================================
// THURAYA PHASE 5.4C PATCH
// Intelligence Command Centre: scoped tab + tabbed insights UI
// Safe append-only patch. Keeps the Intelligence dashboard behind its own tab.
// ============================================================================
(function () {
    function i54_num(v) {
        const n = parseFloat(v || 0);
        return isNaN(n) ? 0 : n;
    }

    function i54_today() {
        try { if (typeof getLocalDateString === 'function') return getLocalDateString(); } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    }

    function i54_money(v) {
        return i54_num(v).toFixed(2) + ' GHC';
    }

    function i54_jobRevenue(job) {
        return i54_num(job.finalTotal || job.grandTotal || job.total || job.amountPaid || job.checkoutTotal || job.revenue || 0);
    }

    function i54_isRevenueJob(job) {
        const status = String(job.status || '').toLowerCase();
        if (['cancelled','canceled','void','refunded','no-show','noshow','draft'].some(x => status.includes(x))) return false;
        return i54_jobRevenue(job) > 0 || ['completed','closed','paid'].some(x => status.includes(x));
    }

    window.intel54c_showTab = function(tabName) {
        const safeTab = tabName || 'overview';
        document.querySelectorAll('.intel54c-sub').forEach(el => el.classList.remove('active'));
        const target = document.getElementById('intel54c_' + safeTab);
        if (target) target.classList.add('active');

        if (safeTab === 'alerts') {
            const src = document.getElementById('aiAlertsContainer');
            const dst = document.getElementById('aiAlertsContainerMirror');
            if (src && dst) dst.innerHTML = src.innerHTML || '<div class="intel54c-empty">No alerts loaded yet.</div>';
        }
    };

    async function i54_loadKpis() {
        if (!window.db) return;
        const today = i54_today();
        const revenueEl = document.getElementById('intel54cRevenueToday');
        const bookingsEl = document.getElementById('intel54cBookingsToday');
        const progressEl = document.getElementById('intel54cTargetProgress');
        const commissionEl = document.getElementById('intel54cCommissionForecast');
        const staffEl = document.getElementById('intel54cStaffSnapshot');
        const actionsEl = document.getElementById('intel54cSuggestedActions');

        let jobs = [];
        try {
            const snap = await db.collection('Active_Jobs').where('dateString', '==', today).get();
            snap.forEach(doc => jobs.push({ id: doc.id, ...(doc.data() || {}) }));
        } catch (e) {
            console.warn('5.4C Active_Jobs KPI load failed', e);
        }

        // Fallback to appointments for booking count when no active jobs exist.
        let bookingCount = jobs.length;
        if (!bookingCount) {
            try {
                const apptSnap = await db.collection('Appointments').where('dateString', '==', today).get();
                bookingCount = apptSnap.size || 0;
            } catch(e) {}
        }

        let revenue = 0;
        const byStaff = {};
        jobs.forEach(job => {
            const amount = i54_jobRevenue(job);
            if (i54_isRevenueJob(job)) revenue += amount;
            const email = String(job.assignedTechEmail || job.techEmail || job.technicianEmail || '').toLowerCase();
            const name = job.assignedTechName || job.techName || email || 'Unassigned';
            if (!email && !name) return;
            const key = email || name;
            if (!byStaff[key]) byStaff[key] = { name, email, bookings: 0, revenue: 0 };
            byStaff[key].bookings += 1;
            byStaff[key].revenue += amount;
        });

        let commissionRate = 0.10;
        try {
            const cdoc = await db.collection('Commission_Settings').doc('current').get();
            if (cdoc.exists) commissionRate = i54_num(cdoc.data().defaultRate || cdoc.data().rate || commissionRate);
            if (commissionRate > 1) commissionRate = commissionRate / 100;
        } catch(e) {}

        if (revenueEl) revenueEl.textContent = i54_money(revenue);
        if (bookingsEl) bookingsEl.textContent = String(bookingCount || 0);
        if (commissionEl) commissionEl.textContent = i54_money(revenue * commissionRate);

        // Optional aggregate target if configured in Staff_Targets.
        let targetTotal = 0;
        try {
            const targetSnap = await db.collection('Staff_Targets').get();
            targetSnap.forEach(doc => { targetTotal += i54_num((doc.data() || {}).dailyTarget || 0); });
        } catch(e) {}
        if (progressEl) {
            progressEl.textContent = targetTotal > 0 ? `${Math.min(999, (revenue / targetTotal) * 100).toFixed(0)}%` : 'N/A';
        }

        const staffRows = Object.values(byStaff).sort((a,b) => b.revenue - a.revenue).slice(0, 8);
        if (staffEl) {
            if (!staffRows.length) {
                staffEl.innerHTML = '<div class="intel54c-empty">No staff revenue data yet today.</div>';
            } else {
                staffEl.innerHTML = `<div style="overflow-x:auto;"><table class="breakdown-table"><thead><tr><th>Rank</th><th>Technician</th><th>Bookings</th><th style="text-align:right;">Revenue</th></tr></thead><tbody>${staffRows.map((s,i) => `<tr><td>${i+1}</td><td>${s.name || s.email}</td><td>${s.bookings}</td><td style="text-align:right; font-weight:800;">${i54_money(s.revenue)}</td></tr>`).join('')}</tbody></table></div>`;
            }
        }

        if (actionsEl) {
            const actions = [];
            if (bookingCount === 0) actions.push('No bookings recorded yet today — check schedule visibility and FOH intake.');
            if (targetTotal > 0 && revenue < targetTotal * 0.6) actions.push('Revenue is below 60% of configured target — consider promo follow-up or technician allocation review.');
            if (staffRows.length && staffRows[0].revenue > 0) actions.push(`Top performer today: ${staffRows[0].name || staffRows[0].email} with ${i54_money(staffRows[0].revenue)}.`);
            actionsEl.innerHTML = actions.length ? `<ul style="margin:0; padding-left:18px; color:#444; line-height:1.7;">${actions.map(a => `<li>${a}</li>`).join('')}</ul>` : 'No urgent actions required.';
        }
    }

    window.thurayaLoadIntelligenceDashboard54C = async function() {
        const alertsBox = document.getElementById('aiAlertsContainer');
        const forecastBox = document.getElementById('aiPredictiveContainer');
        const mirrorBox = document.getElementById('aiAlertsContainerMirror');

        if (alertsBox) alertsBox.innerHTML = '<div class="intel54c-empty">Loading alerts...</div>';
        if (forecastBox) forecastBox.innerHTML = '<div class="intel54c-empty">Loading forecast...</div>';
        if (mirrorBox) mirrorBox.innerHTML = '<div class="intel54c-empty">Loading alerts...</div>';

        try { await i54_loadKpis(); } catch(e) { console.warn('5.4C KPI load failed', e); }

        setTimeout(() => {
            try {
                if (typeof ai_loadAdvancedIntelligence === 'function') ai_loadAdvancedIntelligence();
                else if (alertsBox) alertsBox.innerHTML = '<div class="intel54c-empty">Alerts engine not found.</div>';
            } catch(e) {
                console.error('5.4C alerts failed', e);
                if (alertsBox) alertsBox.innerHTML = '<div style="color:var(--error);">Alerts failed to load.</div>';
            }

            try {
                if (typeof ai_loadPredictiveIntelligence === 'function') ai_loadPredictiveIntelligence();
                else if (forecastBox) forecastBox.innerHTML = '<div class="intel54c-empty">Forecast engine not found.</div>';
            } catch(e) {
                console.error('5.4C forecast failed', e);
                if (forecastBox) forecastBox.innerHTML = '<div style="color:var(--error);">Forecast failed to load.</div>';
            }

            setTimeout(() => {
                const src = document.getElementById('aiAlertsContainer');
                const dst = document.getElementById('aiAlertsContainerMirror');
                if (src && dst) dst.innerHTML = src.innerHTML || '<div class="intel54c-empty">No alerts loaded yet.</div>';
            }, 900);
        }, 350);
    };

    function i54_boot() {
        const tab = document.getElementById('tabIntelligence');
        if (tab && (tab.style.display === '' || tab.style.display === 'none')) {
            // Default hidden; auth patch below reveals for Admin/Manager.
            tab.style.display = 'none';
        }

        if (typeof window.switchModule === 'function' && !window.switchModule._i54cWrapped) {
            const original = window.switchModule;
            const wrapped = function(moduleId) {
                const res = original.apply(this, arguments);
                if (moduleId === 'intelligenceView') {
                    setTimeout(window.thurayaLoadIntelligenceDashboard54C, 250);
                    setTimeout(window.thurayaLoadIntelligenceDashboard54C, 1400);
                }
                return res;
            };
            wrapped._i54cWrapped = true;
            window.switchModule = wrapped;
        }
    }

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', i54_boot);
    else i54_boot();

    if (window.firebase && firebase.auth) {
        firebase.auth().onAuthStateChanged(user => {
            setTimeout(() => {
                const tab = document.getElementById('tabIntelligence');
                if (!tab) return;
                // Use the app's real role variable. It is declared as `let currentRoles`,
                // not `window.currentRoles`, so checking only window.currentRoles can hide the tab.
                const roles = Array.isArray(currentRoles) ? currentRoles : [];
                const safeRoles = roles.map(r => String(r || '').toLowerCase());
                const canSee = safeRoles.some(r => r.includes('admin') || r.includes('manager'));
                tab.style.display = canSee ? 'flex' : 'none';
            }, 900);
        });
    }
})();

// ============================================================================
// END THURAYA PHASE 5.4C PATCH
// ============================================================================

// ============================================================================
// THURAYA PHASE 5.4C REAL DATA INTELLIGENCE ENGINE
// Replaces static Intelligence with live Firestore-based KPIs, alerts,
// forecast, staff snapshot, and suggested operational actions.
// Safe append-only override. Requires existing 5.4C Intelligence containers.
// ============================================================================
(function () {
    const INTEL54C_REFRESH_MS = 30000;
    let intel54cRefreshTimer = null;
    let intel54cLastState = null;

    function rd_num(v) {
        const n = parseFloat(v || 0);
        return Number.isFinite(n) ? n : 0;
    }

    function rd_int(v) {
        const n = parseInt(v || 0, 10);
        return Number.isFinite(n) ? n : 0;
    }

    function rd_money(v) {
        return rd_num(v).toFixed(2) + " GHC";
    }

    function rd_today() {
        try { if (typeof getLocalDateString === "function") return getLocalDateString(); } catch (e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function rd_shiftDate(dateString, days) {
        const [y, m, d] = String(dateString || rd_today()).split("-").map(Number);
        const dt = new Date(y || new Date().getFullYear(), (m || 1) - 1, d || 1);
        dt.setDate(dt.getDate() + days);
        return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,"0")}-${String(dt.getDate()).padStart(2,"0")}`;
    }

    function rd_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function rd_status(v) {
        return String(v || "").trim().toLowerCase();
    }

    function rd_jobRevenue(job) {
        return rd_num(
            job.finalTotal ??
            job.grandTotal ??
            job.total ??
            job.amountPaid ??
            job.checkoutTotal ??
            job.totalRevenue ??
            job.revenue ??
            0
        );
    }

    function rd_jobDuration(job) {
        return rd_int(job.bookedDuration ?? job.duration ?? job.totalDuration ?? 0);
    }

    function rd_isClosedRevenue(job) {
        // Phase 5.4D Revenue Alignment:
        // Revenue must match Reports and should only count financially closed jobs.
        // Do NOT count scheduled/arrived/in-progress Active_Jobs merely because they carry a grandTotal.
        const status = rd_status(job.status);
        if (["cancelled", "canceled", "void", "refunded", "no-show", "noshow", "draft"].some(x => status.includes(x))) return false;
        return ["completed", "closed", "paid"].some(x => status.includes(x));
    }

    function rd_apptRevenue(appt) {
        return rd_num(appt.finalTotal ?? appt.grandTotal ?? appt.totalCost ?? appt.total ?? 0);
    }

    function rd_timeBucket(timeString) {
        const h = rd_int(String(timeString || "00:00").split(":")[0]);
        if (h < 12) return "Morning";
        if (h < 17) return "Afternoon";
        return "Evening";
    }

    async function rd_getSnap(collection, field, op, value) {
        try {
            if (!window.db) return [];
            const snap = await db.collection(collection).where(field, op, value).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, ...(doc.data() || {}) }));
            return rows;
        } catch (e) {
            console.warn(`Intelligence query failed: ${collection}`, e);
            return [];
        }
    }

    async function rd_getDateRows(collection, dateString) {
        return await rd_getSnap(collection, "dateString", "==", dateString);
    }

    async function rd_getAttendance(dateString) {
        let rows = await rd_getSnap("Attendance", "date", "==", dateString);
        if (!rows.length) rows = await rd_getSnap("Attendance", "dateString", "==", dateString);
        return rows;
    }

    async function rd_getUsers() {
        try {
            const snap = await db.collection("Users").get();
            const users = [];
            snap.forEach(doc => users.push({ id: doc.id, email: doc.id, ...(doc.data() || {}) }));
            return users;
        } catch (e) {
            console.warn("Users load failed for Intelligence", e);
            return Array.isArray(window.allTechs) ? window.allTechs : [];
        }
    }

    async function rd_getCommissionRate() {
        let commissionRate = 0.10;
        try {
            const cdoc = await db.collection("Commission_Settings").doc("current").get();
            if (cdoc.exists) {
                const d = cdoc.data() || {};
                commissionRate = rd_num(d.defaultRate ?? d.rate ?? d.commissionRate ?? commissionRate);
                if (commissionRate > 1) commissionRate = commissionRate / 100;
            }
        } catch (e) {}
        return commissionRate;
    }

    async function rd_getDailyTarget() {
        let targetTotal = 0;
        try {
            const targetSnap = await db.collection("Staff_Targets").get();
            targetSnap.forEach(doc => {
                const d = doc.data() || {};
                targetTotal += rd_num(d.dailyTarget ?? d.targetDaily ?? d.revenueTargetDaily ?? 0);
            });
        } catch (e) {}
        return targetTotal;
    }

    function rd_staffKey(row) {
        const email = String(row.assignedTechEmail || row.techEmail || row.technicianEmail || row.email || "").toLowerCase();
        const name = row.assignedTechName || row.techName || row.technicianName || row.name || email || "Unassigned";
        return { key: email || name, email, name };
    }

    async function rd_buildState() {
        const today = rd_today();
        const yesterday = rd_shiftDate(today, -1);

        const [
            todayJobs,
            todayAppointments,
            todayAttendance,
            yesterdayJobs,
            users,
            commissionRate,
            targetTotal
        ] = await Promise.all([
            rd_getDateRows("Active_Jobs", today),
            rd_getDateRows("Appointments", today),
            rd_getAttendance(today),
            rd_getDateRows("Active_Jobs", yesterday),
            rd_getUsers(),
            rd_getCommissionRate(),
            rd_getDailyTarget()
        ]);

        let sevenDayRevenue = 0;
        let sevenDayBookings = 0;
        let sevenDayClosedJobs = 0;
        for (let i = 1; i <= 7; i++) {
            const day = rd_shiftDate(today, -i);
            const rows = await rd_getDateRows("Active_Jobs", day);
            rows.forEach(job => {
                if (rd_isClosedRevenue(job)) {
                    sevenDayRevenue += rd_jobRevenue(job);
                    sevenDayClosedJobs += 1;
                }
            });
            const appts = await rd_getDateRows("Appointments", day);
            sevenDayBookings += appts.length || rows.length || 0;
        }

        let revenueToday = 0;
        let yesterdayRevenue = 0;
        const byStaff = {};
        const statusCounts = {};
        const timeBuckets = { Morning: 0, Afternoon: 0, Evening: 0 };

        todayJobs.forEach(job => {
            const amount = rd_jobRevenue(job);
            const status = rd_status(job.status) || "unknown";
            statusCounts[status] = (statusCounts[status] || 0) + 1;

            if (rd_isClosedRevenue(job)) revenueToday += amount;

            const s = rd_staffKey(job);
            if (!byStaff[s.key]) byStaff[s.key] = { name: s.name, email: s.email, jobs: 0, closed: 0, revenue: 0, minutes: 0 };
            byStaff[s.key].jobs += 1;
            byStaff[s.key].minutes += rd_jobDuration(job);
            if (rd_isClosedRevenue(job)) {
                byStaff[s.key].closed += 1;
                byStaff[s.key].revenue += amount;
            }
        });

        yesterdayJobs.forEach(job => {
            if (rd_isClosedRevenue(job)) yesterdayRevenue += rd_jobRevenue(job);
        });

        todayAppointments.forEach(appt => {
            const bucket = rd_timeBucket(appt.timeString || appt.time || appt.startTime);
            timeBuckets[bucket] = (timeBuckets[bucket] || 0) + 1;

            const s = rd_staffKey(appt);
            if (!byStaff[s.key]) byStaff[s.key] = { name: s.name, email: s.email, jobs: 0, closed: 0, revenue: 0, minutes: 0 };
            if (!todayJobs.some(j => j.id === appt.id)) byStaff[s.key].jobs += 1;
        });

        const visibleTechs = users.filter(u => {
            const roles = Array.isArray(u.roles) ? u.roles : (u.role ? [u.role] : []);
            return roles.map(r => String(r).toLowerCase()).some(r => r.includes("tech"));
        });

        const clockedIn = todayAttendance.filter(a => a.clockIn && !a.clockOut);
        const clockedOut = todayAttendance.filter(a => a.clockIn && a.clockOut);
        const attendanceCount = todayAttendance.filter(a => a.clockIn).length;

        const bookingCount = todayAppointments.length || todayJobs.length;
        const openJobs = todayJobs.filter(j => {
            const s = rd_status(j.status);
            return s && !["completed", "closed", "paid", "cancelled", "canceled", "void", "refunded"].some(x => s.includes(x));
        });

        const average7DayRevenue = sevenDayRevenue / 7;
        const average7DayBookings = sevenDayBookings / 7;
        const projectedRevenue = Math.max(revenueToday, average7DayRevenue);
        const revenueChangePct = yesterdayRevenue > 0 ? ((revenueToday - yesterdayRevenue) / yesterdayRevenue) * 100 : null;
        const targetProgress = targetTotal > 0 ? (revenueToday / targetTotal) * 100 : null;

        const peakBucket = Object.entries(timeBuckets).sort((a,b) => b[1] - a[1])[0] || ["N/A", 0];

        return {
            today,
            yesterday,
            revenueToday,
            yesterdayRevenue,
            revenueChangePct,
            bookingCount,
            openJobs,
            todayJobs,
            todayAppointments,
            todayAttendance,
            attendanceCount,
            clockedIn,
            clockedOut,
            visibleTechs,
            byStaff,
            statusCounts,
            timeBuckets,
            peakBucket,
            targetTotal,
            targetProgress,
            commissionRate,
            commissionForecast: revenueToday * commissionRate,
            average7DayRevenue,
            average7DayBookings,
            projectedRevenue,
            sevenDayClosedJobs
        };
    }

    function rd_renderKpis(state) {
        const set = (id, val) => {
            const el = document.getElementById(id);
            if (el) el.textContent = val;
        };
        set("intel54cRevenueToday", rd_money(state.revenueToday));
        set("intel54cBookingsToday", String(state.bookingCount || 0));
        set("intel54cTargetProgress", state.targetProgress === null ? "N/A" : `${Math.min(999, state.targetProgress).toFixed(0)}%`);
        set("intel54cCommissionForecast", rd_money(state.commissionForecast));
    }

    function rd_alertCard(type, title, body, actionText, actionClick) {
        const border = type === "danger" ? "var(--error)" : type === "success" ? "var(--success)" : "var(--accent)";
        const bg = type === "danger" ? "#fff5f5" : type === "success" ? "#f0fff4" : "#fffaf0";
        const btn = actionText ? `<button type="button" class="btn btn-secondary" style="width:auto;padding:6px 12px;font-size:.75rem;margin-top:8px;" ${actionClick ? `onclick="${actionClick}"` : ""}>${rd_escape(actionText)}</button>` : "";
        return `<div style="background:${bg};border:1px solid ${border};border-left:4px solid ${border};border-radius:12px;padding:12px 14px;margin-bottom:10px;">
            <div style="font-weight:900;color:var(--primary);margin-bottom:4px;">${rd_escape(title)}</div>
            <div style="font-size:.84rem;color:#555;line-height:1.5;">${body}</div>
            ${btn}
        </div>`;
    }

    function rd_renderAlerts(state) {
        const alerts = [];

        if (state.bookingCount === 0) {
            alerts.push(rd_alertCard("danger", "No bookings recorded today", "Check FOH booking intake, appointment sync, or whether the team has started operating for the day.", "Open Clients", "switchModule('clientsView')"));
        }

        if (state.targetProgress !== null && state.targetProgress < 60) {
            alerts.push(rd_alertCard("danger", "Revenue below target pace", `Today is at <strong>${state.targetProgress.toFixed(0)}%</strong> of configured daily target. Current revenue is <strong>${rd_money(state.revenueToday)}</strong> against target <strong>${rd_money(state.targetTotal)}</strong>.`, "Open Reports", "switchModule('reportsView')"));
        }

        if (state.revenueChangePct !== null && state.revenueChangePct < -20) {
            alerts.push(rd_alertCard("danger", "Revenue down versus yesterday", `Revenue is <strong>${Math.abs(state.revenueChangePct).toFixed(0)}%</strong> lower than yesterday. Yesterday: <strong>${rd_money(state.yesterdayRevenue)}</strong>. Today: <strong>${rd_money(state.revenueToday)}</strong>.`, "Review Schedule", "switchModule('clientsView')"));
        }

        if (state.openJobs.length > 0) {
            alerts.push(rd_alertCard("warn", "Open jobs still active", `<strong>${state.openJobs.length}</strong> job(s) are still in progress / not closed. FOH should check pending checkout before end of day.`, "Open Active Atelier", "switchModule('activeAteliersView')"));
        }

        if (state.visibleTechs.length > 0 && state.attendanceCount === 0) {
            alerts.push(rd_alertCard("warn", "No technician clock-in detected", "Attendance has no clock-in records yet today. Confirm staff are using the proper Clock In button.", "Open Attendance", "switchModule('attendanceView')"));
        }

        const staffRows = Object.values(state.byStaff);
        const zeroJobTechs = state.visibleTechs.filter(t => {
            const email = String(t.email || t.id || "").toLowerCase();
            return email && !staffRows.some(s => String(s.email || "").toLowerCase() === email && s.jobs > 0);
        });

        if (zeroJobTechs.length >= 2 && state.bookingCount > 0) {
            alerts.push(rd_alertCard("warn", "Possible underutilized technicians", `<strong>${zeroJobTechs.length}</strong> technician(s) have no assigned work yet today. Consider balancing jobs across the team.`, "Open Performance", "switchModule('staffPerformanceView')"));
        }

        if (!alerts.length) {
            alerts.push(rd_alertCard("success", "Operations look stable", "No urgent operational risks detected from today’s live data."));
        }

        const html = alerts.join("");
        const main = document.getElementById("aiAlertsContainer");
        const mirror = document.getElementById("aiAlertsContainerMirror");
        if (main) main.innerHTML = html;
        if (mirror) mirror.innerHTML = html;
    }

    function rd_renderSuggestedActions(state) {
        const actions = [];

        if (state.openJobs.length) actions.push("FOH should close pending jobs before end-of-day reporting.");
        if (state.targetProgress !== null && state.targetProgress < 60) actions.push("Run a same-day client follow-up or promo push to improve revenue pace.");
        if (state.peakBucket[1] > 0) actions.push(`Protect capacity during the <strong>${rd_escape(state.peakBucket[0])}</strong> window — it currently has the highest booking concentration.`);
        if (state.clockedIn.length && state.bookingCount === 0) actions.push("Team is clocked in but bookings are empty — verify schedule data and walk-in registration.");
        if (state.revenueToday > 0) actions.push(`Estimated commission exposure today is <strong>${rd_money(state.commissionForecast)}</strong>.`);
        if (!actions.length) actions.push("No urgent action. Continue monitoring revenue, attendance, and pending checkouts.");

        const box = document.getElementById("intel54cSuggestedActions");
        if (box) {
            box.innerHTML = `<ul style="margin:0;padding-left:18px;color:#444;line-height:1.75;">${actions.map(a => `<li>${a}</li>`).join("")}</ul>`;
        }
    }

    function rd_renderForecast(state) {
        const changeLine = state.revenueChangePct === null
            ? "No yesterday baseline available yet."
            : `${state.revenueChangePct >= 0 ? "Up" : "Down"} ${Math.abs(state.revenueChangePct).toFixed(0)}% versus yesterday.`;

        const targetLine = state.targetProgress === null
            ? "No daily revenue target configured."
            : state.targetProgress >= 100
                ? "Target achieved or exceeded today."
                : `Needs ${rd_money(Math.max(0, state.targetTotal - state.revenueToday))} more to hit today’s target.`;

        const html = `
            <div class="intel54c-kpis" style="margin-top:0;">
                <div class="intel54c-kpi"><span>7-Day Avg Revenue</span><strong>${rd_money(state.average7DayRevenue)}</strong></div>
                <div class="intel54c-kpi"><span>Projected Revenue</span><strong>${rd_money(state.projectedRevenue)}</strong></div>
                <div class="intel54c-kpi"><span>Peak Booking Window</span><strong>${rd_escape(state.peakBucket[0])}</strong></div>
                <div class="intel54c-kpi"><span>Avg Daily Bookings</span><strong>${state.average7DayBookings.toFixed(1)}</strong></div>
            </div>
            <div style="background:#fff;border:1px solid var(--border);border-radius:12px;padding:14px;margin-top:14px;">
                <div style="font-weight:900;color:var(--primary);margin-bottom:8px;">Forecast Notes</div>
                <ul style="margin:0;padding-left:18px;line-height:1.7;color:#444;">
                    <li>${rd_escape(changeLine)}</li>
                    <li>${targetLine}</li>
                    <li>Closed revenue jobs in the last 7 days: <strong>${state.sevenDayClosedJobs}</strong>.</li>
                    <li>Today’s active/pending jobs: <strong>${state.openJobs.length}</strong>.</li>
                </ul>
            </div>
        `;
        const box = document.getElementById("aiPredictiveContainer");
        if (box) box.innerHTML = html;
    }

    function rd_renderStaff(state) {
        const rows = Object.values(state.byStaff)
            .sort((a,b) => (b.revenue - a.revenue) || (b.jobs - a.jobs))
            .slice(0, 12);

        const box = document.getElementById("intel54cStaffSnapshot");
        if (!box) return;

        if (!rows.length) {
            box.innerHTML = `<div class="intel54c-empty">No staff activity data found yet today.</div>`;
            return;
        }

        const maxRevenue = Math.max(...rows.map(r => r.revenue), 1);
        box.innerHTML = `
            <div style="overflow-x:auto;">
                <table class="breakdown-table">
                    <thead>
                        <tr>
                            <th>Rank</th>
                            <th>Technician</th>
                            <th style="text-align:center;">Jobs</th>
                            <th style="text-align:center;">Closed</th>
                            <th style="text-align:right;">Revenue</th>
                            <th>Revenue Share</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${rows.map((s, i) => `
                            <tr>
                                <td>${i + 1}</td>
                                <td><strong>${rd_escape(s.name || s.email || "Unassigned")}</strong></td>
                                <td style="text-align:center;">${s.jobs}</td>
                                <td style="text-align:center;">${s.closed}</td>
                                <td style="text-align:right;font-weight:900;color:var(--success);">${rd_money(s.revenue)}</td>
                                <td>
                                    <div style="height:8px;background:#eee;border-radius:999px;overflow:hidden;">
                                        <div style="height:100%;width:${Math.max(3, (s.revenue / maxRevenue) * 100).toFixed(0)}%;background:var(--accent);"></div>
                                    </div>
                                </td>
                            </tr>
                        `).join("")}
                    </tbody>
                </table>
            </div>
        `;
    }

    async function rd_load() {
        if (!window.db) return;
        const loading = `<div class="intel54c-empty">Loading live intelligence...</div>`;
        ["aiAlertsContainer", "aiAlertsContainerMirror", "aiPredictiveContainer", "intel54cStaffSnapshot", "intel54cSuggestedActions"].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.innerHTML = loading;
        });

        try {
            const state = await rd_buildState();
            intel54cLastState = state;
            rd_renderKpis(state);
            rd_renderAlerts(state);
            rd_renderSuggestedActions(state);
            rd_renderForecast(state);
            rd_renderStaff(state);
        } catch (e) {
            console.error("Phase 5.4C real data intelligence failed", e);
            const msg = `<div style="color:var(--error);padding:12px 0;">Intelligence failed to load live data: ${rd_escape(e.message || e)}</div>`;
            ["aiAlertsContainer", "aiAlertsContainerMirror", "aiPredictiveContainer", "intel54cStaffSnapshot", "intel54cSuggestedActions"].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.innerHTML = msg;
            });
        }
    }

    window.thurayaLoadIntelligenceDashboard54C = rd_load;
    window.thurayaLoadIntelligenceRealData54C = rd_load;

    const previousShowTab = window.intel54c_showTab;
    window.intel54c_showTab = function(tabName) {
        if (typeof previousShowTab === "function") previousShowTab(tabName);
        if (!intel54cLastState) setTimeout(rd_load, 100);
        if (tabName === "alerts" && intel54cLastState) rd_renderAlerts(intel54cLastState);
        if (tabName === "forecast" && intel54cLastState) rd_renderForecast(intel54cLastState);
        if (tabName === "staff" && intel54cLastState) rd_renderStaff(intel54cLastState);
    };

    function rd_startAutoRefresh() {
        if (intel54cRefreshTimer) clearInterval(intel54cRefreshTimer);
        intel54cRefreshTimer = setInterval(() => {
            const active = document.getElementById("nav_intelligence")?.checked ||
                document.getElementById("intelligenceView")?.style.display === "block";
            if (active) rd_load();
        }, INTEL54C_REFRESH_MS);
    }

    if (typeof window.switchModule === "function" && !window.switchModule._intel54cRealDataWrapped) {
        const originalSwitch = window.switchModule;
        const wrappedSwitch = function(moduleId) {
            const result = originalSwitch.apply(this, arguments);
            if (moduleId === "intelligenceView") {
                setTimeout(rd_load, 150);
                rd_startAutoRefresh();
            }
            return result;
        };
        wrappedSwitch._intel54cRealDataWrapped = true;
        window.switchModule = wrappedSwitch;
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", rd_startAutoRefresh);
    } else {
        rd_startAutoRefresh();
    }
})();

// ============================================================================
