console.log("Thuraya Phase 5.4D full revenue-aligned app.js loaded");

// ===== Phase 5.4E Unified Data Reader =====
function rd_matchDate(row, today){
    return (
        row.dateString === today ||
        row.date === today ||
        row.Date === today
    );
}

function rd_flexibleRevenue(row){
    return parseFloat(
        row.finalTotal ||
        row.grandTotal ||
        row.total ||
        row.Revenue ||
        0
    );
}
console.log("Phase 5.4E Unified Data Reader Loaded");

// ============================================================================
// THURAYA PHASE 5.5 CLIENT & REVENUE INTELLIGENCE — FULL HISTORY
// Full-history business intelligence layer.
// - Reads Appointments + Active_Jobs history
// - Supports date/dateString/Date and createdAt fallback
// - Supports clientName/Client, phone/Phone, technician/Technician
// - Builds lifetime client spend, visits, favourite service/tech, frequency
// - Adds revenue history intelligence and service/client/staff rankings
// - Safe append-only override. Does not remove existing modules.
// ============================================================================
(function () {
    const P55_VERSION = "5.5-full-history";
    let p55Cache = null;
    let p55LastLoadedAt = null;

    function p55_num(v) {
        const n = parseFloat(v ?? 0);
        return Number.isFinite(n) ? n : 0;
    }

    function p55_int(v) {
        const n = parseInt(v ?? 0, 10);
        return Number.isFinite(n) ? n : 0;
    }

    function p55_money(v) {
        return p55_num(v).toFixed(2) + " GHC";
    }

    function p55_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function p55_today() {
        try { if (typeof getLocalDateString === "function") return getLocalDateString(); } catch (e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p55_date(row) {
        const direct = row.dateString || row.date || row.Date || row.bookingDate || row.createdDate;
        if (direct) return String(direct).slice(0, 10);
        const ts = row.createdAt || row.closedAt || row.updatedAt || row.completedAt || row.paidAt;
        try {
            if (ts && typeof ts.toDate === "function") {
                const d = ts.toDate();
                return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
            }
        } catch(e) {}
        return "";
    }

    function p55_dateObj(dateString) {
        if (!dateString) return null;
        const parts = String(dateString).slice(0,10).split("-").map(Number);
        if (parts.length !== 3) return null;
        return new Date(parts[0], parts[1] - 1, parts[2]);
    }

    function p55_daysBetween(a, b) {
        const da = p55_dateObj(a), db = p55_dateObj(b);
        if (!da || !db) return null;
        return Math.round((db - da) / 86400000);
    }

    function p55_status(row) {
        return String(row.status || row.Status || "").trim();
    }

    function p55_statusLower(row) {
        return p55_status(row).toLowerCase();
    }

    function p55_isCancelled(row) {
        const s = p55_statusLower(row);
        return ["cancelled", "canceled", "void", "refunded"].some(x => s.includes(x));
    }

    function p55_isNoShow(row) {
        const s = p55_statusLower(row);
        return s.includes("no show") || s.includes("no-show") || s.includes("noshow");
    }

    function p55_isClosed(row) {
        const s = p55_statusLower(row);
        return ["completed", "closed", "paid"].some(x => s.includes(x));
    }

    function p55_revenue(row) {
        if (p55_isCancelled(row) || p55_isNoShow(row)) return 0;
        return p55_num(
            row.finalTotal ??
            row.grandTotal ??
            row.total ??
            row.totalCost ??
            row.amountPaid ??
            row.checkoutTotal ??
            row.totalRevenue ??
            row.revenue ??
            row.Revenue ??
            0
        );
    }

    function p55_clientName(row) {
        return String(row.clientName || row.Client || row.name || row.customerName || "").trim();
    }

    function p55_clientPhone(row) {
        const raw = row.clientPhone || row.Phone || row.phone || row.tel || row.primaryPhone || "";
        return String(raw).replace(/\.0$/, "").trim();
    }

    function p55_tech(row) {
        return String(row.assignedTechName || row.techName || row.technicianName || row.Technician || row.technician || row.assignedTechEmail || "").trim() || "Unassigned";
    }

    function p55_service(row) {
        return String(row.bookedService || row.service || row.Service || row.services || "").trim() || "Unspecified";
    }

    function p55_source(row) {
        return String(row.Source || row.source || "").trim();
    }

    function p55_groupId(row) {
        return String(row.groupId || row.Group_ID || row["Group ID"] || row.groupBookingId || "").trim();
    }

    function p55_groupSize(row) {
        return p55_int(row.groupSize || row["Group Size"] || 1) || 1;
    }

    function p55_keyClient(row) {
        const phone = p55_clientPhone(row);
        const name = p55_clientName(row).toLowerCase();
        return phone || name || "unknown";
    }

    async function p55_getCollection(name, limitCount=800) {
        if (!window.db) return [];
        try {
            const snap = await db.collection(name).limit(limitCount).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, _collection: name, ...(doc.data() || {}) }));
            return rows;
        } catch (e) {
            console.warn("Phase 5.5 could not read collection:", name, e);
            return [];
        }
    }

    async function p55_loadHistory(force=false) {
        const now = Date.now();
        if (!force && p55Cache && p55LastLoadedAt && now - p55LastLoadedAt < 20000) return p55Cache;

        const [appointments, jobs] = await Promise.all([
            p55_getCollection("Appointments", 1000),
            p55_getCollection("Active_Jobs", 1000)
        ]);

        let rows = [...appointments, ...jobs].map(r => {
            const date = p55_date(r);
            return {
                ...r,
                _p55Date: date,
                _p55Revenue: p55_revenue(r),
                _p55RawRevenue: p55_revenue(r),
                _p55ClientName: p55_clientName(r),
                _p55ClientPhone: p55_clientPhone(r),
                _p55Tech: p55_tech(r),
                _p55Service: p55_service(r),
                _p55Status: p55_status(r),
                _p55Source: p55_source(r),
                _p55GroupId: p55_groupId(r),
                _p55GroupSize: p55_groupSize(r),
                _p55ClientKey: p55_keyClient(r),
                _p55RevenueAllocated: false,
                _p55AllocationNote: ""
            };
        }).filter(r => r._p55Date || r._p55ClientName || r._p55ClientPhone || r._p55Revenue);

        // Phase 5.5B Group Revenue Allocation:
        // Some group bookings store total revenue only on the lead payer / checkout record,
        // while other group participants have blank or 0 revenue. This caused Client Intel
        // and Intelligence to under-report group clients. We allocate group revenue fairly
        // across group members for client lifetime value, while marking it as allocated to
        // avoid invisible group revenue gaps.
        const groups = {};
        rows.forEach(r => {
            if (!r._p55GroupId) return;
            if (p55_isCancelled(r) || p55_isNoShow(r)) return;
            if (!groups[r._p55GroupId]) groups[r._p55GroupId] = [];
            groups[r._p55GroupId].push(r);
        });

        Object.entries(groups).forEach(([groupId, members]) => {
            const totalRevenue = members.reduce((sum, r) => sum + p55_num(r._p55RawRevenue), 0);
            const memberCount = Math.max(
                members.length,
                ...members.map(r => p55_int(r._p55GroupSize || 1))
            );

            if (totalRevenue <= 0 || memberCount <= 1) return;

            const perHead = totalRevenue / memberCount;

            members.forEach(r => {
                // If a participant has no direct revenue, assign fair share.
                if (p55_num(r._p55Revenue) <= 0) {
                    r._p55Revenue = perHead;
                    r._p55RevenueAllocated = true;
                    r._p55AllocationNote = `Group ${groupId}: allocated ${perHead.toFixed(2)} GHC from total ${totalRevenue.toFixed(2)} GHC`;
                }
            });

            // If every member already had the full total duplicated, normalize to per-head
            // to prevent over-counting group revenue.
            const allMembersHaveSameTotal = members.length > 1 && members.every(r => Math.abs(p55_num(r._p55RawRevenue) - totalRevenue) < 0.01);
            if (allMembersHaveSameTotal) {
                members.forEach(r => {
                    r._p55Revenue = perHead;
                    r._p55RevenueAllocated = true;
                    r._p55AllocationNote = `Group ${groupId}: normalized duplicated total to per-head ${perHead.toFixed(2)} GHC`;
                });
            }
        });

        p55Cache = {
            version: P55_VERSION,
            rows,
            appointments,
            jobs,
            loadedAt: new Date()
        };
        p55LastLoadedAt = now;
        return p55Cache;
    }

    function p55_countMap(rows, getter) {
        const map = {};
        rows.forEach(r => {
            const k = getter(r);
            if (!k) return;
            map[k] = (map[k] || 0) + 1;
        });
        return map;
    }

    function p55_sumMap(rows, getter) {
        const map = {};
        rows.forEach(r => {
            const k = getter(r);
            if (!k) return;
            map[k] = (map[k] || 0) + r._p55Revenue;
        });
        return map;
    }

    function p55_top(map) {
        const arr = Object.entries(map).sort((a,b) => b[1] - a[1]);
        return arr[0] || ["—", 0];
    }

    function p55_clientStats(rows, query) {
        const q = String(query || "").trim().toLowerCase();
        const clientRows = rows.filter(r => {
            if (!q) return false;
            return String(r._p55ClientName || "").toLowerCase().includes(q) ||
                   String(r._p55ClientPhone || "").toLowerCase().includes(q);
        }).sort((a,b) => String(b._p55Date).localeCompare(String(a._p55Date)));

        const spendRows = clientRows.filter(r => r._p55Revenue > 0 && !p55_isCancelled(r) && !p55_isNoShow(r));
        const totalSpend = spendRows.reduce((s,r) => s + r._p55Revenue, 0);
        const visits = clientRows.filter(r => !p55_isCancelled(r) && !p55_isNoShow(r)).length;
        const avg = visits ? totalSpend / visits : 0;

        const year = new Date().getFullYear();
        const thisYear = spendRows
            .filter(r => String(r._p55Date || "").startsWith(String(year)))
            .reduce((s,r) => s + r._p55Revenue, 0);

        const serviceTop = p55_top(p55_countMap(spendRows, r => r._p55Service));
        const techTop = p55_top(p55_countMap(spendRows, r => r._p55Tech));
        const lastVisit = clientRows[0]?._p55Date || "—";

        let frequency = "—";
        const dates = [...new Set(clientRows.map(r => r._p55Date).filter(Boolean))].sort();
        if (dates.length >= 2) {
            const gaps = [];
            for (let i=1; i<dates.length; i++) {
                const gap = p55_daysBetween(dates[i-1], dates[i]);
                if (gap !== null && gap >= 0) gaps.push(gap);
            }
            if (gaps.length) {
                const avgGap = gaps.reduce((a,b)=>a+b,0) / gaps.length;
                frequency = avgGap < 10 ? "Very frequent" : avgGap < 30 ? "Monthly" : avgGap < 90 ? "Occasional" : "Rare";
            }
        } else if (dates.length === 1) {
            frequency = "New client";
        }

        const primary = clientRows[0] || {};
        return {
            rows: clientRows,
            spendRows,
            name: primary._p55ClientName || query || "Client",
            phone: primary._p55ClientPhone || "",
            visits,
            totalSpend,
            avg,
            thisYear,
            lastVisit,
            favService: serviceTop[0],
            favTech: techTop[0],
            frequency,
            vip: totalSpend >= 1000 || visits >= 5
        };
    }

    function p55_renderClientIntel(stats) {
        const result = document.getElementById("clientIntelResults") || document.getElementById("clientIntelResult") || document.getElementById("ciResults");
        if (!result) return false;

        const rowsHtml = stats.rows.slice(0, 15).map(r => `
            <tr>
                <td>${p55_escape(r._p55Date || "—")}</td>
                <td>${p55_escape(r._p55Service)}</td>
                <td>${p55_escape(r._p55Tech)}</td>
                <td>${p55_escape(r._p55Status || "—")}</td>
                <td style="text-align:right;font-weight:800;color:var(--success);">${p55_money(r._p55Revenue)}${r._p55RevenueAllocated ? '<div style="font-size:.68rem;color:#777;font-weight:600;">Group allocated</div>' : ''}</td>
            </tr>
        `).join("");

        result.innerHTML = `
            <div style="background:var(--primary);color:#fff;border-radius:10px;padding:20px;margin-bottom:20px;">
                <h3 style="margin:0 0 8px;color:#fff;border:none;">${p55_escape(stats.name)} ${stats.vip ? "💎 VIP" : ""}</h3>
                <div style="opacity:.85;">📞 ${p55_escape(stats.phone || "No phone on record")}</div>
            </div>

            <div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-bottom:20px;">
                <div class="metric-card"><div>Total Visits</div><div class="metric-value">${stats.visits}</div></div>
                <div class="metric-card"><div>Total Spend</div><div class="metric-value">${p55_money(stats.totalSpend)}</div></div>
                <div class="metric-card"><div>Avg / Visit</div><div class="metric-value">${p55_money(stats.avg)}</div></div>
                <div class="metric-card"><div>This Year</div><div class="metric-value">${p55_money(stats.thisYear)}</div></div>
                <div class="metric-card"><div>Last Visit</div><div class="metric-value" style="font-size:1rem;">${p55_escape(stats.lastVisit)}</div></div>
                <div class="metric-card"><div>Fav Service</div><div class="metric-value" style="font-size:1rem;">${p55_escape(stats.favService)}</div></div>
                <div class="metric-card"><div>Fav Tech</div><div class="metric-value" style="font-size:1rem;">${p55_escape(stats.favTech)}</div></div>
                <div class="metric-card"><div>Frequency</div><div class="metric-value" style="font-size:1rem;">${p55_escape(stats.frequency)}</div></div>
            </div>

            <div class="module-box" style="border-top:4px solid var(--accent);">
                <h3 style="color:var(--accent);">Visit History</h3>
                ${stats.rows.length ? `
                    <div style="overflow-x:auto;">
                        <table class="breakdown-table">
                            <thead><tr><th>Date</th><th>Service</th><th>Technician</th><th>Status</th><th style="text-align:right;">Revenue</th></tr></thead>
                            <tbody>${rowsHtml}</tbody>
                        </table>
                    </div>
                ` : `<p style="color:#888;font-style:italic;text-align:center;">No visits found.</p>`}
            </div>

            <div class="module-box" style="border-top:4px solid var(--primary);">
                <h3 style="color:var(--primary);">Client Intelligence Notes</h3>
                <ul style="line-height:1.8;color:#444;">
                    <li>${stats.vip ? "High-value/VIP client — consider retention note or package offer." : "Client below VIP threshold — monitor repeat activity."}</li>
                    <li>Preferred service appears to be <strong>${p55_escape(stats.favService)}</strong>.</li>
                    <li>Preferred technician appears to be <strong>${p55_escape(stats.favTech)}</strong>.</li>
                    <li>Recommended action: ${stats.visits <= 1 ? "send first-return offer." : "promote repeat package or loyalty bundle."}</li>
                </ul>
            </div>
        `;
        return true;
    }

    async function p55_searchClientIntel() {
        const input = document.getElementById("clientIntelSearch") ||
                      document.getElementById("clientSearchInput") ||
                      document.getElementById("ciSearch") ||
                      document.querySelector("#clientIntelView input[type='text']");
        const query = input ? input.value.trim() : "";
        if (!query) {
            alert("Enter a client name or phone number.");
            return;
        }
        const result = document.getElementById("clientIntelResults") || document.getElementById("clientIntelResult") || document.getElementById("ciResults");
        if (result) result.innerHTML = `<p style="text-align:center;color:#777;">Loading full client history...</p>`;

        const data = await p55_loadHistory(true);
        const stats = p55_clientStats(data.rows, query);
        if (!p55_renderClientIntel(stats)) {
            console.warn("Phase 5.5: Client Intel result container not found.");
        }
    }

    function p55_businessStats(rows) {
        const clean = rows.filter(r => !p55_isCancelled(r) && !p55_isNoShow(r));
        const revenueRows = clean.filter(r => r._p55Revenue > 0);
        const totalRevenue = revenueRows.reduce((s,r)=>s+r._p55Revenue,0);
        const records = clean.length;
        const groups = new Set(clean.map(r => r._p55GroupId).filter(Boolean));
        const topClients = Object.entries(p55_sumMap(revenueRows, r => r._p55ClientName || r._p55ClientPhone || "Unknown")).sort((a,b)=>b[1]-a[1]).slice(0,5);
        const topServices = Object.entries(p55_sumMap(revenueRows, r => r._p55Service)).sort((a,b)=>b[1]-a[1]).slice(0,5);
        const topTechs = Object.entries(p55_sumMap(revenueRows, r => r._p55Tech)).sort((a,b)=>b[1]-a[1]).slice(0,5);
        const cancelled = rows.filter(p55_isCancelled).length;
        const noShows = rows.filter(p55_isNoShow).length;

        return { clean, revenueRows, totalRevenue, records, groups, topClients, topServices, topTechs, cancelled, noShows };
    }

    function p55_rankList(items, label) {
        if (!items.length) return `<p style="color:#888;font-style:italic;">No ${label} data yet.</p>`;
        return `<ol style="margin:0;padding-left:22px;line-height:1.9;">${items.map(([name, val]) => `<li><strong>${p55_escape(name)}</strong> — ${p55_money(val)}</li>`).join("")}</ol>`;
    }

    async function p55_renderRevenueHistoryPanel() {
        const container = document.getElementById("aiPredictiveContainer") ||
                          document.getElementById("intel54cRevenueHistory") ||
                          document.getElementById("intelligencePanel");
        if (!container) return;

        const data = await p55_loadHistory();
        const stats = p55_businessStats(data.rows);

        const byDate = {};
        stats.revenueRows.forEach(r => {
            const d = r._p55Date || "Unknown";
            byDate[d] = (byDate[d] || 0) + r._p55Revenue;
        });
        const dateRows = Object.entries(byDate).sort((a,b)=>b[0].localeCompare(a[0])).slice(0,10);

        container.innerHTML = `
            <div class="intel54c-kpis" style="margin-top:0;">
                <div class="intel54c-kpi"><span>Total History Revenue</span><strong>${p55_money(stats.totalRevenue)}</strong></div>
                <div class="intel54c-kpi"><span>Total Records</span><strong>${stats.records}</strong></div>
                <div class="intel54c-kpi"><span>Group Bookings</span><strong>${stats.groups.size}</strong></div>
                <div class="intel54c-kpi"><span>Cancelled / No Show</span><strong>${stats.cancelled} / ${stats.noShows}</strong></div>
            </div>

            <div style="display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:14px;margin-top:16px;">
                <div class="module-box"><h3>Top Clients</h3>${p55_rankList(stats.topClients, "client")}</div>
                <div class="module-box"><h3>Top Services</h3>${p55_rankList(stats.topServices, "service")}</div>
                <div class="module-box"><h3>Top Technicians</h3>${p55_rankList(stats.topTechs, "technician")}</div>
            </div>

            <div class="module-box" style="margin-top:16px;">
                <h3>Recent Revenue by Date</h3>
                <div style="overflow-x:auto;">
                    <table class="breakdown-table">
                        <thead><tr><th>Date</th><th style="text-align:right;">Revenue</th></tr></thead>
                        <tbody>
                            ${dateRows.map(([d,v]) => `<tr><td>${p55_escape(d)}</td><td style="text-align:right;font-weight:900;color:var(--success);">${p55_money(v)}</td></tr>`).join("")}
                        </tbody>
                    </table>
                </div>
            </div>
        `;
    }

    async function p55_enhanceOverview() {
        const data = await p55_loadHistory();
        const stats = p55_businessStats(data.rows);

        const actions = document.getElementById("intel54cSuggestedActions");
        if (actions) {
            const topClient = stats.topClients[0];
            const topService = stats.topServices[0];
            const topTech = stats.topTechs[0];
            actions.innerHTML = `
                <ul style="margin:0;padding-left:18px;color:#444;line-height:1.75;">
                    <li>Full-history revenue base: <strong>${p55_money(stats.totalRevenue)}</strong> across <strong>${stats.records}</strong> valid records.</li>
                    ${topClient ? `<li>Client action: protect top client <strong>${p55_escape(topClient[0])}</strong> with loyalty / retention offer.</li>` : ""}
                    ${topService ? `<li>Sales action: promote <strong>${p55_escape(topService[0])}</strong> because it leads historical revenue.</li>` : ""}
                    ${topTech ? `<li>Staff action: benchmark training from <strong>${p55_escape(topTech[0])}</strong>, the strongest revenue contributor.</li>` : ""}
                    <li>Group-booking records detected: <strong>${stats.groups.size}</strong>.</li>
                </ul>
            `;
        }
    }

    // Expose manual functions
    window.thuraya55LoadHistory = p55_loadHistory;
    window.thuraya55SearchClientIntel = p55_searchClientIntel;
    window.thuraya55RenderRevenueHistoryPanel = p55_renderRevenueHistoryPanel;

    // Wrap known Client Intel search functions, if they exist.
    ["searchClientIntel", "clientIntelSearch", "ci_searchClient", "loadClientIntel"].forEach(fn => {
        if (typeof window[fn] === "function" && !window[fn]._p55Wrapped) {
            const old = window[fn];
            const wrapped = async function () {
                try { await old.apply(this, arguments); } catch(e) { console.warn("Original Client Intel function failed", e); }
                try { await p55_searchClientIntel(); } catch(e) { console.error("Phase 5.5 Client Intel failed", e); }
            };
            wrapped._p55Wrapped = true;
            window[fn] = wrapped;
        }
    });

    // Attach click handler to Client Intel search buttons without needing HTML changes.
    function p55_attachClientIntelButton() {
        const view = document.getElementById("clientIntelView");
        if (!view || view._p55Attached) return;
        const buttons = Array.from(view.querySelectorAll("button"));
        const searchBtn = buttons.find(b => String(b.textContent || "").trim().toLowerCase().includes("search"));
        if (searchBtn) {
            searchBtn.addEventListener("click", function () {
                setTimeout(() => p55_searchClientIntel().catch(e => console.error(e)), 200);
            });
            view._p55Attached = true;
        }
    }

    const previousSwitch = window.switchModule;
    if (typeof previousSwitch === "function" && !previousSwitch._p55Wrapped) {
        const wrappedSwitch = function(moduleId) {
            const result = previousSwitch.apply(this, arguments);
            if (moduleId === "clientIntelView") setTimeout(p55_attachClientIntelButton, 250);
            if (moduleId === "intelligenceView") setTimeout(p55_enhanceOverview, 500);
            return result;
        };
        wrappedSwitch._p55Wrapped = true;
        window.switchModule = wrappedSwitch;
    }

    const previousIntelTab = window.intel54c_showTab;
    if (typeof previousIntelTab === "function" && !previousIntelTab._p55Wrapped) {
        const wrappedIntelTab = function(tabName) {
            const result = previousIntelTab.apply(this, arguments);
            if (String(tabName).toLowerCase().includes("forecast") || String(tabName).toLowerCase().includes("revenue")) {
                setTimeout(p55_renderRevenueHistoryPanel, 300);
            }
            if (String(tabName).toLowerCase().includes("overview")) {
                setTimeout(p55_enhanceOverview, 300);
            }
            return result;
        };
        wrappedIntelTab._p55Wrapped = true;
        window.intel54c_showTab = wrappedIntelTab;
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => {
            setTimeout(p55_attachClientIntelButton, 800);
        });
    } else {
        setTimeout(p55_attachClientIntelButton, 800);
    }

    console.log("Thuraya Phase 5.5 Client & Revenue Intelligence loaded");
})();
// ============================================================================
// END THURAYA PHASE 5.5 CLIENT & REVENUE INTELLIGENCE
// ============================================================================

// ============================================================================
// THURAYA PHASE 5.5B FULL BUILD
// Group Revenue Allocation: group checkout revenue is allocated across group
// participants for Client Intel and historical revenue intelligence, while
// preventing duplicated group totals from inflating revenue.
// ============================================================================
console.log("Thuraya Phase 5.5B group revenue allocation app.js loaded");

// ============================================================================
// THURAYA PHASE 5.5C CLIENT INTEL GROUP BOOKING READER
// Fixes Client Intel under-reporting by replacing the old client reader that
// only queried Appointments by clientPhone and only counted Closed/Completed.
// This reader searches Appointments + Active_Jobs by phone OR client name,
// includes valid arrived/paid/closed records with revenue, and allocates group
// checkout revenue to group members.
// ============================================================================
(function () {
    function gci_num(v) {
        const n = parseFloat(v ?? 0);
        return Number.isFinite(n) ? n : 0;
    }

    function gci_int(v) {
        const n = parseInt(v ?? 0, 10);
        return Number.isFinite(n) ? n : 0;
    }

    function gci_money(v) {
        return gci_num(v).toFixed(2) + " GHC";
    }

    function gci_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function gci_date(row) {
        const d = row.dateString || row.date || row.Date || row.bookingDate || row.createdDate || "";
        if (d) return String(d).slice(0, 10);
        const ts = row.createdAt || row.closedAt || row.updatedAt || row.completedAt || row.paidAt;
        try {
            if (ts && typeof ts.toDate === "function") {
                const dt = ts.toDate();
                return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,"0")}-${String(dt.getDate()).padStart(2,"0")}`;
            }
        } catch(e) {}
        return "";
    }

    function gci_status(row) {
        return String(row.status || row.Status || "").trim();
    }

    function gci_statusLower(row) {
        return gci_status(row).toLowerCase();
    }

    function gci_isCancelled(row) {
        const s = gci_statusLower(row);
        return ["cancelled", "canceled", "void", "refunded"].some(x => s.includes(x));
    }

    function gci_isNoShow(row) {
        const s = gci_statusLower(row);
        return s.includes("no show") || s.includes("no-show") || s.includes("noshow");
    }

    function gci_revenue(row) {
        if (gci_isCancelled(row) || gci_isNoShow(row)) return 0;
        return gci_num(
            row.finalTotal ??
            row.grandTotal ??
            row.total ??
            row.totalCost ??
            row.amountPaid ??
            row.checkoutTotal ??
            row.totalRevenue ??
            row.revenue ??
            row.Revenue ??
            0
        );
    }

    function gci_clientName(row) {
        const direct = row.clientName || row.Client || row.name || row.customerName || "";
        if (direct) return String(direct).trim();

        const first = row.Forename || row.forename || row.firstName || "";
        const last  = row.Surname || row.surname || row.lastName || "";
        return `${first} ${last}`.trim();
    }

    function gci_clientPhone(row) {
        const raw = row.clientPhone || row.Phone || row.phone || row.Tel_Number || row.tel || row.primaryPhone || "";
        return String(raw).replace(/\.0$/, "").replace(/\s+/g, "").trim();
    }

    function gci_tech(row) {
        return String(row.assignedTechName || row.techName || row.technicianName || row.Technician || row.technician || row.assignedTechEmail || "").trim() || "Unassigned";
    }

    function gci_service(row) {
        return String(row.bookedService || row.service || row.Service || row.services || "").trim() || "Unspecified";
    }

    function gci_groupId(row) {
        return String(row.groupId || row.groupBookingId || row.Group_ID || row["Group ID"] || "").trim();
    }

    function gci_groupSize(row) {
        return gci_int(row.groupSize || row["Group Size"] || 1) || 1;
    }

    async function gci_getCollection(name, limitCount=1200) {
        try {
            const snap = await db.collection(name).limit(limitCount).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, _collection: name, ...(doc.data() || {}) }));
            return rows;
        } catch (e) {
            console.warn("Phase 5.5C unable to read:", name, e);
            return [];
        }
    }

    async function gci_loadRows() {
        const [appointments, jobs] = await Promise.all([
            gci_getCollection("Appointments"),
            gci_getCollection("Active_Jobs")
        ]);

        let rows = [...appointments, ...jobs].map(r => ({
            ...r,
            _gciDate: gci_date(r),
            _gciRevenue: gci_revenue(r),
            _gciRawRevenue: gci_revenue(r),
            _gciClientName: gci_clientName(r),
            _gciClientPhone: gci_clientPhone(r),
            _gciTech: gci_tech(r),
            _gciService: gci_service(r),
            _gciStatus: gci_status(r),
            _gciGroupId: gci_groupId(r),
            _gciGroupSize: gci_groupSize(r),
            _gciAllocated: false
        }));

        // Allocate group revenue where the group has a paid/lead amount but some members have zero.
        const groups = {};
        rows.forEach(r => {
            if (!r._gciGroupId) return;
            if (gci_isCancelled(r) || gci_isNoShow(r)) return;
            if (!groups[r._gciGroupId]) groups[r._gciGroupId] = [];
            groups[r._gciGroupId].push(r);
        });

        Object.entries(groups).forEach(([gid, members]) => {
            const totalRaw = members.reduce((s, r) => s + gci_num(r._gciRawRevenue), 0);
            const memberCount = Math.max(members.length, ...members.map(r => gci_groupSize(r)));
            if (totalRaw <= 0 || memberCount <= 1) return;

            // If all members already have their individual amount, keep it.
            const zeroMembers = members.filter(r => gci_num(r._gciRevenue) <= 0);
            if (zeroMembers.length > 0) {
                const perHead = totalRaw / memberCount;
                zeroMembers.forEach(r => {
                    r._gciRevenue = perHead;
                    r._gciAllocated = true;
                });
            }

            // If every member appears to carry the exact same full total, normalize.
            const allSame = members.length > 1 && members.every(r => Math.abs(gci_num(r._gciRawRevenue) - totalRaw) < 0.01);
            if (allSame) {
                const perHead = totalRaw / memberCount;
                members.forEach(r => {
                    r._gciRevenue = perHead;
                    r._gciAllocated = true;
                });
            }
        });

        return rows;
    }

    function gci_nameFromClientData(clientData) {
        return `${clientData?.Forename || ""} ${clientData?.Surname || ""}`.trim();
    }

    function gci_matchesClient(row, phone, fullName) {
        const rowPhone = String(row._gciClientPhone || "").replace(/\D/g, "");
        const wantedPhone = String(phone || "").replace(/\D/g, "");
        const rowName = String(row._gciClientName || "").toLowerCase().trim();
        const wantedName = String(fullName || "").toLowerCase().trim();

        if (wantedPhone && rowPhone && (rowPhone.includes(wantedPhone) || wantedPhone.includes(rowPhone))) return true;
        if (wantedName && rowName && (rowName === wantedName || rowName.includes(wantedName) || wantedName.includes(rowName))) return true;
        return false;
    }

    function gci_top(items, getter) {
        const map = {};
        items.forEach(x => {
            const k = getter(x);
            if (!k || k === "Unspecified" || k === "Unassigned") return;
            map[k] = (map[k] || 0) + 1;
        });
        return Object.entries(map).sort((a,b) => b[1] - a[1])[0]?.[0] || "—";
    }

    function gci_fmtDate(dateStr) {
        if (!dateStr) return "—";
        try {
            if (typeof cip_fmtDate === "function") return cip_fmtDate(dateStr);
        } catch(e) {}
        return dateStr;
    }

    async function gci_loadClientData(clientData) {
        const phone = clientData?.Tel_Number || clientData?.clientPhone || clientData?.Phone || "";
        const fullName = gci_nameFromClientData(clientData) || clientData?.clientName || clientData?.Client || "";

        const rows = await gci_loadRows();

        const visits = rows
            .filter(r => gci_matchesClient(r, phone, fullName))
            .filter(r => !gci_isCancelled(r) && !gci_isNoShow(r))
            .sort((a,b) => String(b._gciDate).localeCompare(String(a._gciDate)));

        // Make old cip_filterVisits still work by giving it compatible fields.
        window._cip_allVisits = visits.map(v => ({
            id: v.id,
            dateString: v._gciDate,
            bookedService: v._gciService,
            assignedTechName: v._gciTech,
            bookedDuration: v.bookedDuration || v.duration || 0,
            grandTotal: v._gciRevenue,
            status: v._gciStatus,
            groupId: v._gciGroupId,
            _groupAllocated: v._gciAllocated
        }));

        const spendRows = visits.filter(v => gci_num(v._gciRevenue) > 0);
        const totalVisits = visits.length;
        const totalSpend = spendRows.reduce((s, v) => s + gci_num(v._gciRevenue), 0);
        const avgSpend = totalVisits ? totalSpend / totalVisits : 0;
        const year = String(new Date().getFullYear());
        const thisYearSpend = spendRows
            .filter(v => String(v._gciDate || "").startsWith(year))
            .reduce((s, v) => s + gci_num(v._gciRevenue), 0);
        const lastVisit = visits[0]?._gciDate || null;
        const favService = gci_top(spendRows, v => v._gciService);
        const favTech = gci_top(spendRows, v => v._gciTech);

        let frequency = "—";
        const uniqueDates = [...new Set(visits.map(v => v._gciDate).filter(Boolean))].sort();
        if (uniqueDates.length === 1) frequency = "New";
        if (uniqueDates.length >= 2) {
            const gaps = [];
            for (let i = 1; i < uniqueDates.length; i++) {
                const d1 = new Date(uniqueDates[i-1] + "T12:00:00");
                const d2 = new Date(uniqueDates[i] + "T12:00:00");
                if (!isNaN(d1) && !isNaN(d2)) gaps.push(Math.abs(d2 - d1) / 86400000);
            }
            if (gaps.length) {
                const avgDays = Math.round(gaps.reduce((a,b)=>a+b,0) / gaps.length);
                frequency = avgDays < 30 ? `${avgDays}d` : `${Math.round(avgDays/30)}mo`;
            }
        }

        const setText = (id, value) => {
            const el = document.getElementById(id);
            if (el) el.textContent = value;
        };

        setText("cip_totalVisits", totalVisits);
        setText("cip_totalSpend", gci_money(totalSpend));
        setText("cip_avgSpend", gci_money(avgSpend));
        setText("cip_thisYear", gci_money(thisYearSpend));
        setText("cip_lastVisit", lastVisit ? gci_fmtDate(lastVisit) : "—");
        setText("cip_favService", favService.length > 12 ? favService.slice(0, 12) + "…" : favService);
        setText("cip_favTech", favTech.split(" ")[0] || "—");
        setText("cip_frequency", frequency);

        const vip = document.getElementById("cip_vipBadge");
        if (vip) vip.style.display = (totalVisits >= 5 || totalSpend >= 1000) ? "inline-block" : "none";

        const lapsed = document.getElementById("cip_lapsedBadge");
        if (lapsed && lastVisit) {
            const days = Math.floor((new Date() - new Date(lastVisit + "T12:00:00")) / 86400000);
            lapsed.style.display = days >= 60 ? "inline-block" : "none";
        }

        const yearSel = document.getElementById("cip_yearFilter");
        if (yearSel) {
            const years = [...new Set(visits.map(v => String(v._gciDate || "").slice(0,4)).filter(Boolean))];
            yearSel.innerHTML = '<option value="all">All Years</option>';
            years.forEach(y => yearSel.innerHTML += `<option value="${y}">${y}</option>`);
        }

        gci_renderVisits();

        try {
            const notesDoc = phone ? await db.collection("Client_Notes").doc(phone).get() : null;
            const notes = notesDoc && notesDoc.exists ? (notesDoc.data().notes || "") : "";
            const noteInput = document.getElementById("cip_notesInput");
            if (noteInput) noteInput.value = notes;
            const saved = document.getElementById("cip_notesSaved");
            if (saved) saved.textContent = "";
        } catch(e) {}

        try {
            if (typeof cip_loadLastConsultation === "function") await cip_loadLastConsultation(phone);
        } catch(e) {}

        try {
            if (typeof cip_renderAlerts === "function") cip_renderAlerts(clientData, totalVisits, totalSpend, lastVisit);
        } catch(e) {}

        console.log("Phase 5.5C Client Intel loaded group-aware visits:", totalVisits, totalSpend);
    }

    function gci_renderVisits() {
        const year = document.getElementById("cip_yearFilter")?.value || "all";
        const list = document.getElementById("cip_visitList");
        const visits = (window._cip_allVisits || []).filter(a => {
            return year === "all" || String(a.dateString || "").startsWith(year);
        });

        if (!list) return;
        if (!visits.length) {
            list.innerHTML = '<p style="color:#999; text-align:center; padding:20px; font-style:italic;">No visits found.</p>';
            return;
        }

        list.innerHTML = visits.map(a => {
            const amt = gci_num(a.grandTotal);
            const allocationNote = a._groupAllocated ? '<div style="font-size:.7rem;color:#777;margin-top:2px;">Group revenue allocated</div>' : "";
            const groupNote = a.groupId ? `<div style="font-size:.7rem;color:#777;margin-top:2px;">Group: ${gci_escape(a.groupId)}</div>` : "";
            return `<div style="display:flex; justify-content:space-between; align-items:center; padding:10px 0; border-bottom:1px solid #f1f1f1; flex-wrap:wrap; gap:6px;">
                <div>
                    <strong style="font-size:0.88rem; color:var(--primary);">${gci_fmtDate(a.dateString)}</strong>
                    <p style="margin:2px 0; font-size:0.8rem; color:#555;">💅 ${gci_escape(a.bookedService || "N/A")}</p>
                    <p style="margin:0; font-size:0.78rem; color:#999;">👩‍🔧 ${gci_escape(a.assignedTechName || "Unknown")} · ${gci_escape(a.status || "")}</p>
                    ${groupNote}
                    ${allocationNote}
                </div>
                <div style="text-align:right;">
                    <strong style="color:var(--success); font-size:0.9rem;">${gci_money(amt)}</strong>
                </div>
            </div>`;
        }).join("");
    }

    // Override visit filter to preserve group-aware list.
    window.cip_filterVisits = gci_renderVisits;

    // Override cip_open fully, so we do not rely on old phone-only Closed/Completed query.
    const previousCipOpen = window.cip_open;
    window.cip_open = async function(clientData) {
        window._cip_clientData = clientData;
        window._cip_allVisits = [];

        const resDiv = document.getElementById("cip_searchResults");
        if (resDiv) resDiv.style.display = "none";

        const searchInput = document.getElementById("cip_searchInput");
        if (searchInput) {
            const name = gci_nameFromClientData(clientData);
            searchInput.value = name || clientData?.Tel_Number || "";
        }

        const panel = document.getElementById("cip_panel");
        if (panel) panel.style.display = "block";

        const phone = clientData?.Tel_Number || "";
        const fullName = gci_nameFromClientData(clientData) || "Unknown Client";

        const nameEl = document.getElementById("cip_name");
        const subEl = document.getElementById("cip_sub");
        if (nameEl) nameEl.textContent = fullName;
        if (subEl) subEl.textContent = `📞 ${phone}${clientData?.Email ? "  ·  ✉ " + clientData.Email : ""}`;

        document.querySelectorAll(".cip-tab").forEach(t => t.classList.remove("cip-tab--active"));
        const firstTab = document.querySelector(".cip-tab");
        if (firstTab) firstTab.classList.add("cip-tab--active");
        document.querySelectorAll('[id^="cip_tab_"]').forEach(t => t.style.display = "none");
        const visitsTab = document.getElementById("cip_tab_visits");
        if (visitsTab) visitsTab.style.display = "block";

        ["cip_vipBadge","cip_lapsedBadge","cip_birthdayBadge"].forEach(id => {
            const el = document.getElementById(id);
            if (el) el.style.display = "none";
        });

        if (panel) panel.scrollIntoView({ behavior: "smooth", block: "start" });

        const list = document.getElementById("cip_visitList");
        if (list) list.innerHTML = '<p style="color:#999; font-style:italic; text-align:center; padding:20px;">Loading group-aware visits…</p>';

        await gci_loadClientData(clientData);
    };

    // Enhance manual search: if user types name and clicks search, match Clients first, then history.
    async function gci_searchTypedClient() {
        const input = document.getElementById("cip_searchInput");
        const q = String(input?.value || "").trim();
        if (!q) return;

        let clientData = null;

        try {
            // Prefer existing client cache if available.
            if (Array.isArray(window.allClientsCache) && window.allClientsCache.length) {
                const ql = q.toLowerCase();
                clientData = window.allClientsCache.find(c => {
                    const name = `${c.Forename || ""} ${c.Surname || ""}`.toLowerCase();
                    const phone = String(c.Tel_Number || "");
                    return name.includes(ql) || phone.includes(q);
                }) || null;
            }

            if (!clientData) {
                const rows = await gci_loadRows();
                const ql = q.toLowerCase();
                const match = rows.find(r => String(r._gciClientName || "").toLowerCase().includes(ql) || String(r._gciClientPhone || "").includes(q));
                if (match) {
                    const names = String(match._gciClientName || "").split(" ");
                    clientData = {
                        Forename: names[0] || match._gciClientName || q,
                        Surname: names.slice(1).join(" "),
                        Tel_Number: match._gciClientPhone || ""
                    };
                }
            }

            if (clientData) await window.cip_open(clientData);
        } catch (e) {
            console.error("Phase 5.5C typed client search failed", e);
        }
    }

    function gci_attachSearchButton() {
        const view = document.getElementById("clientIntelView");
        if (!view || view._gciSearchAttached) return;
        const btn = Array.from(view.querySelectorAll("button")).find(b => String(b.textContent || "").toLowerCase().includes("search"));
        if (btn) {
            btn.addEventListener("click", function () {
                setTimeout(gci_searchTypedClient, 250);
            });
            view._gciSearchAttached = true;
        }
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => setTimeout(gci_attachSearchButton, 800));
    } else {
        setTimeout(gci_attachSearchButton, 800);
    }

    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._gciWrapped) {
        const wrapped = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "clientIntelView") setTimeout(gci_attachSearchButton, 300);
            return result;
        };
        wrapped._gciWrapped = true;
        window.switchModule = wrapped;
    }

    console.log("Thuraya Phase 5.5C Client Intel Group Booking Reader loaded");
})();
// ============================================================================
// END THURAYA PHASE 5.5C CLIENT INTEL GROUP BOOKING READER
// ============================================================================

// ============================================================================
// THURAYA PHASE 5.5D CLIENT INTEL UNIVERSAL CLIENT INDEX
// Fixes "only two clients showing" by building Client Intel search results from:
// - Client master cache / Clients collection when available
// - Appointments history
// - Active_Jobs history
// - group booking participants, even if they were never saved as master clients
// ============================================================================
(function () {
    function uci_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function uci_phone(v) {
        return String(v || "").replace(/\.0$/, "").replace(/\D/g, "").trim();
    }

    function uci_nameFromRow(r) {
        const direct = r.clientName || r.Client || r.name || r.customerName || "";
        if (direct) return String(direct).trim();

        const first = r.Forename || r.forename || r.firstName || "";
        const last = r.Surname || r.surname || r.lastName || "";
        return `${first} ${last}`.trim();
    }

    function uci_phoneFromRow(r) {
        return uci_phone(r.clientPhone || r.Phone || r.phone || r.Tel_Number || r.tel || r.primaryPhone || "");
    }

    function uci_key(name, phone) {
        return phone || String(name || "").toLowerCase().trim();
    }

    async function uci_getCollection(name, limitCount=1500) {
        try {
            const snap = await db.collection(name).limit(limitCount).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, ...(doc.data() || {}) }));
            return rows;
        } catch (e) {
            console.warn("Phase 5.5D unable to read collection:", name, e);
            return [];
        }
    }

    async function uci_buildIndex() {
        const clientRows = [];

        // 1) Existing app cache
        if (Array.isArray(window.allClientsCache)) {
            window.allClientsCache.forEach(c => clientRows.push({ ...c, _source: "Clients Cache" }));
        }

        // 2) Firestore master Clients / Client_Master fallback
        const [clients, clientMaster, appointments, jobs] = await Promise.all([
            uci_getCollection("Clients"),
            uci_getCollection("Client_Master"),
            uci_getCollection("Appointments"),
            uci_getCollection("Active_Jobs")
        ]);

        clients.forEach(c => clientRows.push({ ...c, _source: "Clients" }));
        clientMaster.forEach(c => clientRows.push({ ...c, _source: "Client_Master" }));
        appointments.forEach(a => clientRows.push({ ...a, _source: "Appointments" }));
        jobs.forEach(j => clientRows.push({ ...j, _source: "Active_Jobs" }));

        const index = {};
        clientRows.forEach(r => {
            const name = uci_nameFromRow(r);
            const phone = uci_phoneFromRow(r);
            if (!name && !phone) return;

            const key = uci_key(name, phone);
            if (!key) return;

            if (!index[key]) {
                const parts = name.split(" ");
                index[key] = {
                    Forename: r.Forename || r.forename || r.firstName || parts[0] || name || "Unknown",
                    Surname: r.Surname || r.surname || r.lastName || parts.slice(1).join(" ") || "",
                    Tel_Number: phone,
                    Email: r.Email || r.email || "",
                    _sources: new Set(),
                    _matchName: name,
                    _records: 0
                };
            }

            if (name && (!index[key]._matchName || index[key]._matchName.length < name.length)) {
                index[key]._matchName = name;
                const parts = name.split(" ");
                index[key].Forename = parts[0] || name;
                index[key].Surname = parts.slice(1).join(" ");
            }

            if (phone && !index[key].Tel_Number) index[key].Tel_Number = phone;
            if ((r.Email || r.email) && !index[key].Email) index[key].Email = r.Email || r.email;
            index[key]._sources.add(r._source || "History");
            index[key]._records += 1;
        });

        const arr = Object.values(index).map(c => ({
            ...c,
            _sourceList: Array.from(c._sources || []).join(", ")
        }));

        window.THURAYA_UNIVERSAL_CLIENT_INDEX = arr;
        return arr;
    }

    function uci_renderResults(results) {
        const box =
            document.getElementById("cip_searchResults") ||
            document.getElementById("clientIntelSearchResults") ||
            document.querySelector("#clientIntelView .dropdown-results");

        if (!box) return false;

        if (!results.length) {
            box.innerHTML = `<p style="padding:12px;color:#888;">No clients found across Clients, Appointments or Active Jobs.</p>`;
            box.style.display = "block";
            return true;
        }

        box.innerHTML = results.slice(0, 30).map((c, idx) => {
            const name = `${c.Forename || ""} ${c.Surname || ""}`.trim() || c._matchName || "Unknown Client";
            const phone = c.Tel_Number || "";
            const source = c._sourceList || "History";
            return `
                <div class="dropdown-item" style="padding:10px 12px;border-bottom:1px solid #eee;cursor:pointer;"
                     onclick="window.uciOpenUniversalClient(${idx})">
                    <strong>${uci_escape(name)}</strong>
                    <div style="font-size:.78rem;color:#666;">📞 ${uci_escape(phone || "No phone")} · ${uci_escape(source)} · ${c._records || 0} record(s)</div>
                </div>
            `;
        }).join("");

        window.THURAYA_UNIVERSAL_CLIENT_RESULTS = results.slice(0, 30);
        box.style.display = "block";
        return true;
    }

    window.uciOpenUniversalClient = function(idx) {
        const c = (window.THURAYA_UNIVERSAL_CLIENT_RESULTS || [])[idx];
        if (!c) return;
        if (typeof window.cip_open === "function") {
            window.cip_open(c);
        }
        const box =
            document.getElementById("cip_searchResults") ||
            document.getElementById("clientIntelSearchResults") ||
            document.querySelector("#clientIntelView .dropdown-results");
        if (box) box.style.display = "none";
    };

    async function uci_search() {
        const input =
            document.getElementById("cip_searchInput") ||
            document.getElementById("clientIntelSearch") ||
            document.getElementById("clientSearchInput") ||
            document.querySelector("#clientIntelView input[type='text']");

        const q = String(input?.value || "").trim().toLowerCase();
        if (!q) return;

        const idx = await uci_buildIndex();
        const qPhone = uci_phone(q);

        const results = idx.filter(c => {
            const name = `${c.Forename || ""} ${c.Surname || ""} ${c._matchName || ""}`.toLowerCase();
            const phone = uci_phone(c.Tel_Number || "");
            return name.includes(q) || (qPhone && phone.includes(qPhone));
        }).sort((a,b) => (b._records || 0) - (a._records || 0));

        uci_renderResults(results);
    }

    window.thurayaUniversalClientSearch = uci_search;
    window.thurayaBuildUniversalClientIndex = uci_buildIndex;

    function uci_attach() {
        const view = document.getElementById("clientIntelView");
        if (!view || view._uciAttached) return;

        const input =
            document.getElementById("cip_searchInput") ||
            document.getElementById("clientIntelSearch") ||
            document.getElementById("clientSearchInput") ||
            view.querySelector("input[type='text']");

        if (input) {
            input.addEventListener("keyup", function () {
                clearTimeout(window._uciTimer);
                window._uciTimer = setTimeout(uci_search, 250);
            });
        }

        const btn = Array.from(view.querySelectorAll("button")).find(b =>
            String(b.textContent || "").toLowerCase().includes("search")
        );
        if (btn) {
            btn.addEventListener("click", function () {
                setTimeout(uci_search, 100);
            });
        }

        view._uciAttached = true;
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => setTimeout(uci_attach, 800));
    } else {
        setTimeout(uci_attach, 800);
    }

    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._uciWrapped) {
        const wrapped = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "clientIntelView") setTimeout(uci_attach, 300);
            return result;
        };
        wrapped._uciWrapped = true;
        window.switchModule = wrapped;
    }

    console.log("Thuraya Phase 5.5D Universal Client Index loaded");
})();
// ============================================================================
// END THURAYA PHASE 5.5D CLIENT INTEL UNIVERSAL CLIENT INDEX
// ============================================================================

// ============================================================================
// THURAYA PHASE 6 — PREDICTIVE INTELLIGENCE
// Proactive intelligence layer built on existing Appointments + Active_Jobs.
// Adds:
// - Client next-visit / churn risk / VIP signals
// - Revenue trend and low-traffic opportunity signals
// - Service demand trends
// - Staff/FOH smart actions
// Safe append-only override.
// ============================================================================
(function () {
    const P6_VERSION = "6.0-predictive-intelligence";
    let p6Cache = null;
    let p6LastLoadedAt = 0;

    function p6_num(v) {
        const n = parseFloat(v ?? 0);
        return Number.isFinite(n) ? n : 0;
    }

    function p6_int(v) {
        const n = parseInt(v ?? 0, 10);
        return Number.isFinite(n) ? n : 0;
    }

    function p6_money(v) {
        return p6_num(v).toFixed(2) + " GHC";
    }

    function p6_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function p6_today() {
        try { if (typeof getLocalDateString === "function") return getLocalDateString(); } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p6_date(row) {
        const direct = row.dateString || row.date || row.Date || row.bookingDate || row.createdDate || "";
        if (direct) return String(direct).slice(0, 10);

        const ts = row.createdAt || row.closedAt || row.updatedAt || row.completedAt || row.paidAt;
        try {
            if (ts && typeof ts.toDate === "function") {
                const d = ts.toDate();
                return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
            }
        } catch(e) {}
        return "";
    }

    function p6_dateObj(s) {
        if (!s) return null;
        const p = String(s).slice(0,10).split("-").map(Number);
        if (p.length !== 3 || !p[0] || !p[1] || !p[2]) return null;
        return new Date(p[0], p[1]-1, p[2], 12, 0, 0);
    }

    function p6_shift(dateStr, days) {
        const d = p6_dateObj(dateStr) || new Date();
        d.setDate(d.getDate() + days);
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p6_daysBetween(a, b) {
        const da = p6_dateObj(a), db = p6_dateObj(b);
        if (!da || !db) return null;
        return Math.round((db - da) / 86400000);
    }

    function p6_statusLower(row) {
        return String(row.status || row.Status || "").trim().toLowerCase();
    }

    function p6_cancelled(row) {
        const s = p6_statusLower(row);
        return ["cancelled", "canceled", "void", "refunded"].some(x => s.includes(x));
    }

    function p6_noshow(row) {
        const s = p6_statusLower(row);
        return s.includes("no show") || s.includes("no-show") || s.includes("noshow");
    }

    function p6_revenue(row) {
        if (p6_cancelled(row) || p6_noshow(row)) return 0;
        return p6_num(
            row.finalTotal ??
            row.grandTotal ??
            row.total ??
            row.totalCost ??
            row.amountPaid ??
            row.checkoutTotal ??
            row.totalRevenue ??
            row.revenue ??
            row.Revenue ??
            0
        );
    }

    function p6_clientName(row) {
        const direct = row.clientName || row.Client || row.name || row.customerName || "";
        if (direct) return String(direct).trim();
        const first = row.Forename || row.forename || row.firstName || "";
        const last = row.Surname || row.surname || row.lastName || "";
        return `${first} ${last}`.trim();
    }

    function p6_clientPhone(row) {
        return String(row.clientPhone || row.Phone || row.phone || row.Tel_Number || row.tel || row.primaryPhone || "")
            .replace(/\.0$/, "")
            .replace(/\s+/g, "")
            .trim();
    }

    function p6_clientKey(row) {
        return p6_clientPhone(row) || p6_clientName(row).toLowerCase() || "unknown";
    }

    function p6_service(row) {
        return String(row.bookedService || row.service || row.Service || row.services || "Unspecified").trim();
    }

    function p6_tech(row) {
        return String(row.assignedTechName || row.techName || row.technicianName || row.Technician || row.technician || row.assignedTechEmail || "Unassigned").trim();
    }

    function p6_hour(row) {
        const time = String(row.timeString || row.Time || row.time || "00:00");
        const h = p6_int(time.split(":")[0]);
        return Number.isFinite(h) ? h : 0;
    }

    function p6_bucket(row) {
        const h = p6_hour(row);
        if (h < 12) return "Morning";
        if (h < 17) return "Afternoon";
        return "Evening";
    }

    async function p6_getCollection(name, limitCount=1600) {
        try {
            const snap = await db.collection(name).limit(limitCount).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, _collection: name, ...(doc.data() || {}) }));
            return rows;
        } catch(e) {
            console.warn("Phase 6 unable to read:", name, e);
            return [];
        }
    }

    async function p6_loadHistory(force=false) {
        const now = Date.now();
        if (!force && p6Cache && now - p6LastLoadedAt < 20000) return p6Cache;

        const [appointments, jobs] = await Promise.all([
            p6_getCollection("Appointments"),
            p6_getCollection("Active_Jobs")
        ]);

        let rows = [...appointments, ...jobs].map(r => ({
            ...r,
            _p6Date: p6_date(r),
            _p6Revenue: p6_revenue(r),
            _p6ClientName: p6_clientName(r),
            _p6ClientPhone: p6_clientPhone(r),
            _p6ClientKey: p6_clientKey(r),
            _p6Service: p6_service(r),
            _p6Tech: p6_tech(r),
            _p6Bucket: p6_bucket(r)
        })).filter(r => r._p6Date || r._p6ClientName || r._p6Revenue);

        // Group revenue allocation fallback, matching Phase 5.5 behavior.
        const groups = {};
        rows.forEach(r => {
            const gid = r.groupId || r.groupBookingId || r["Group ID"] || "";
            if (!gid || p6_cancelled(r) || p6_noshow(r)) return;
            if (!groups[gid]) groups[gid] = [];
            groups[gid].push(r);
        });

        Object.values(groups).forEach(members => {
            const total = members.reduce((s,r) => s + p6_num(r._p6Revenue), 0);
            const size = Math.max(
                members.length,
                ...members.map(r => p6_int(r.groupSize || r["Group Size"] || 1) || 1)
            );
            if (total <= 0 || size <= 1) return;
            const perHead = total / size;
            members.forEach(r => {
                if (p6_num(r._p6Revenue) <= 0) {
                    r._p6Revenue = perHead;
                    r._p6GroupAllocated = true;
                }
            });
        });

        p6Cache = { rows, appointments, jobs, loadedAt: new Date(), version: P6_VERSION };
        p6LastLoadedAt = now;
        return p6Cache;
    }

    function p6_mapSum(rows, getter) {
        const map = {};
        rows.forEach(r => {
            const k = getter(r);
            if (!k) return;
            map[k] = (map[k] || 0) + p6_num(r._p6Revenue);
        });
        return map;
    }

    function p6_mapCount(rows, getter) {
        const map = {};
        rows.forEach(r => {
            const k = getter(r);
            if (!k) return;
            map[k] = (map[k] || 0) + 1;
        });
        return map;
    }

    function p6_top(map, n=5) {
        return Object.entries(map).sort((a,b) => b[1] - a[1]).slice(0,n);
    }

    function p6_validRevenueRows(rows) {
        return rows.filter(r => !p6_cancelled(r) && !p6_noshow(r) && p6_num(r._p6Revenue) > 0);
    }

    function p6_clientSignals(rows) {
        const today = p6_today();
        const byClient = {};
        p6_validRevenueRows(rows).forEach(r => {
            const key = r._p6ClientKey;
            if (!key || key === "unknown") return;
            if (!byClient[key]) {
                byClient[key] = {
                    key,
                    name: r._p6ClientName || r._p6ClientPhone || "Unknown",
                    phone: r._p6ClientPhone || "",
                    visits: [],
                    spend: 0,
                    services: {},
                    techs: {}
                };
            }
            const c = byClient[key];
            c.visits.push(r._p6Date);
            c.spend += p6_num(r._p6Revenue);
            c.services[r._p6Service] = (c.services[r._p6Service] || 0) + 1;
            c.techs[r._p6Tech] = (c.techs[r._p6Tech] || 0) + 1;
        });

        const clients = Object.values(byClient).map(c => {
            const dates = [...new Set(c.visits.filter(Boolean))].sort();
            const lastVisit = dates[dates.length-1] || "";
            const gaps = [];
            for (let i = 1; i < dates.length; i++) {
                const gap = p6_daysBetween(dates[i-1], dates[i]);
                if (gap !== null && gap >= 0) gaps.push(gap);
            }
            const avgGap = gaps.length ? Math.round(gaps.reduce((a,b)=>a+b,0) / gaps.length) : null;
            const daysSince = lastVisit ? p6_daysBetween(lastVisit, today) : null;
            const predictedNext = avgGap && lastVisit ? p6_shift(lastVisit, avgGap) : "";
            const overdueBy = (avgGap && daysSince !== null) ? daysSince - avgGap : null;

            let risk = "New";
            if (c.spend >= 1000 || dates.length >= 5) risk = "VIP";
            if (avgGap && overdueBy !== null && overdueBy > Math.max(14, avgGap * 0.7)) risk = "Churn Risk";
            else if (avgGap && overdueBy !== null && overdueBy > 0) risk = "Due Soon";
            else if (dates.length >= 3) risk = "Loyal";

            return {
                ...c,
                visitCount: dates.length,
                dates,
                lastVisit,
                avgGap,
                daysSince,
                predictedNext,
                overdueBy,
                avgSpend: dates.length ? c.spend / dates.length : 0,
                favService: p6_top(c.services, 1)[0]?.[0] || "—",
                favTech: p6_top(c.techs, 1)[0]?.[0] || "—",
                risk
            };
        });

        return clients.sort((a,b) => b.spend - a.spend);
    }

    function p6_revenueSignals(rows) {
        const valid = p6_validRevenueRows(rows);
        const today = p6_today();

        const byDate = {};
        valid.forEach(r => {
            const d = r._p6Date || "Unknown";
            byDate[d] = (byDate[d] || 0) + p6_num(r._p6Revenue);
        });

        const last7Dates = Array.from({length:7}, (_,i) => p6_shift(today, -i)).reverse();
        const prev7Dates = Array.from({length:7}, (_,i) => p6_shift(today, -7-i)).reverse();

        const last7 = last7Dates.reduce((s,d)=>s+(byDate[d]||0),0);
        const prev7 = prev7Dates.reduce((s,d)=>s+(byDate[d]||0),0);
        const trendPct = prev7 > 0 ? ((last7 - prev7) / prev7) * 100 : null;

        const byService = p6_mapSum(valid, r => r._p6Service);
        const byTech = p6_mapSum(valid, r => r._p6Tech);
        const byBucket = p6_mapSum(valid, r => r._p6Bucket);
        const byHour = p6_mapCount(valid, r => String(p6_hour(r)).padStart(2,"0") + ":00");

        const topService = p6_top(byService, 1)[0] || ["—", 0];
        const topTech = p6_top(byTech, 1)[0] || ["—", 0];
        const bestBucket = p6_top(byBucket, 1)[0] || ["—", 0];

        const avgDaily = last7 / 7;
        const todayRevenue = byDate[today] || 0;

        return {
            valid,
            totalRevenue: valid.reduce((s,r)=>s+p6_num(r._p6Revenue),0),
            byDate,
            byService,
            byTech,
            byBucket,
            byHour,
            last7,
            prev7,
            trendPct,
            avgDaily,
            todayRevenue,
            topService,
            topTech,
            bestBucket
        };
    }

    function p6_card(title, value, sub="") {
        return `<div class="intel54c-kpi">
            <span>${p6_escape(title)}</span>
            <strong>${p6_escape(value)}</strong>
            ${sub ? `<div style="font-size:.72rem;color:#666;margin-top:6px;line-height:1.4;">${sub}</div>` : ""}
        </div>`;
    }

    function p6_actionCard(type, title, body, button, click) {
        const border = type === "danger" ? "var(--error)" : type === "success" ? "var(--success)" : "var(--accent)";
        const bg = type === "danger" ? "#fff5f5" : type === "success" ? "#f0fff4" : "#fffaf0";
        return `<div style="background:${bg};border:1px solid ${border};border-left:4px solid ${border};border-radius:12px;padding:12px 14px;margin-bottom:10px;">
            <div style="font-weight:900;color:var(--primary);margin-bottom:4px;">${p6_escape(title)}</div>
            <div style="font-size:.84rem;color:#555;line-height:1.5;">${body}</div>
            ${button ? `<button type="button" class="btn btn-secondary" style="width:auto;padding:6px 12px;font-size:.75rem;margin-top:8px;" onclick="${click || ""}">${p6_escape(button)}</button>` : ""}
        </div>`;
    }

    async function p6_renderPredictivePanel(targetId) {
        const data = await p6_loadHistory();
        const clients = p6_clientSignals(data.rows);
        const revenue = p6_revenueSignals(data.rows);

        const churn = clients.filter(c => c.risk === "Churn Risk").slice(0,5);
        const due = clients.filter(c => c.risk === "Due Soon").slice(0,5);
        const vip = clients.filter(c => c.risk === "VIP").slice(0,5);

        const trendText = revenue.trendPct === null
            ? "No prior 7-day baseline"
            : `${revenue.trendPct >= 0 ? "Up" : "Down"} ${Math.abs(revenue.trendPct).toFixed(0)}%`;

        const actions = [];
        if (churn.length) {
            actions.push(p6_actionCard("danger", "Client churn risk detected",
                `<strong>${churn.length}</strong> high-value/repeat client(s) appear overdue. Start with <strong>${p6_escape(churn[0].name)}</strong>${churn[0].predictedNext ? `, expected around <strong>${p6_escape(churn[0].predictedNext)}</strong>` : ""}.`,
                "Open Client Intel", "switchModule('clientIntelView')"));
        }
        if (due.length) {
            actions.push(p6_actionCard("warn", "Clients due for rebooking",
                `<strong>${due.length}</strong> client(s) are due soon. Suggested first outreach: <strong>${p6_escape(due[0].name)}</strong> for <strong>${p6_escape(due[0].favService)}</strong>.`,
                "Open Client Intel", "switchModule('clientIntelView')"));
        }
        if (revenue.trendPct !== null && revenue.trendPct < -15) {
            actions.push(p6_actionCard("danger", "Revenue trend is falling",
                `Last 7 days revenue is <strong>${Math.abs(revenue.trendPct).toFixed(0)}%</strong> below the previous 7 days. Promote <strong>${p6_escape(revenue.topService[0])}</strong> and protect <strong>${p6_escape(revenue.bestBucket[0])}</strong> capacity.`,
                "Open Reports", "switchModule('reportsView')"));
        }
        if (revenue.topService[1] > 0) {
            actions.push(p6_actionCard("success", "Best service opportunity",
                `<strong>${p6_escape(revenue.topService[0])}</strong> is the leading historical revenue driver with <strong>${p6_money(revenue.topService[1])}</strong>. Consider promoting it during low-traffic periods.`,
                "Open Menu", "switchModule('menuView')"));
        }
        if (!actions.length) {
            actions.push(p6_actionCard("success", "Predictive outlook stable",
                "No urgent churn or revenue risk detected. Continue monitoring client frequency and revenue trend.", "", ""));
        }

        const churnRows = churn.map(c => `
            <tr>
                <td><strong>${p6_escape(c.name)}</strong><div style="font-size:.72rem;color:#777;">${p6_escape(c.phone || "")}</div></td>
                <td>${p6_escape(c.lastVisit || "—")}</td>
                <td>${c.avgGap ? c.avgGap + " days" : "—"}</td>
                <td>${p6_escape(c.predictedNext || "—")}</td>
                <td style="text-align:right;font-weight:900;color:var(--success);">${p6_money(c.spend)}</td>
            </tr>
        `).join("");

        const dueRows = due.map(c => `
            <tr>
                <td><strong>${p6_escape(c.name)}</strong></td>
                <td>${p6_escape(c.favService)}</td>
                <td>${p6_escape(c.favTech)}</td>
                <td>${p6_escape(c.predictedNext || "—")}</td>
                <td style="text-align:right;">${p6_money(c.avgSpend)}</td>
            </tr>
        `).join("");

        const serviceRows = p6_top(revenue.byService, 8).map(([name, val]) => `
            <tr><td>${p6_escape(name)}</td><td style="text-align:right;font-weight:900;color:var(--success);">${p6_money(val)}</td></tr>
        `).join("");

        const panelHtml = `
            <div class="module-box" style="border-top:4px solid var(--accent);">
                <h3 style="color:var(--accent);">Phase 6 Predictive Intelligence</h3>
                <p style="font-size:.85rem;color:#666;margin-bottom:16px;">Client behavior, churn risk, revenue trends and next-best actions from full booking history.</p>

                <div class="intel54c-kpis" style="margin-top:0;">
                    ${p6_card("7-Day Trend", trendText, `Last 7 days: ${p6_money(revenue.last7)}`)}
                    ${p6_card("Avg Daily Revenue", p6_money(revenue.avgDaily), `Today: ${p6_money(revenue.todayRevenue)}`)}
                    ${p6_card("Churn Risk Clients", String(churn.length), "Clients overdue vs normal pattern")}
                    ${p6_card("Due Soon Clients", String(due.length), "Rebooking opportunities")}
                </div>
            </div>

            <div class="module-box" style="border-top:4px solid var(--primary);">
                <h3 style="color:var(--primary);">Next-Best Actions</h3>
                ${actions.join("")}
            </div>

            <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start;">
                <div class="module-box">
                    <h3>Churn Risk Watchlist</h3>
                    ${churn.length ? `
                    <div style="overflow-x:auto;">
                        <table class="breakdown-table">
                            <thead><tr><th>Client</th><th>Last Visit</th><th>Avg Gap</th><th>Expected Next</th><th style="text-align:right;">Spend</th></tr></thead>
                            <tbody>${churnRows}</tbody>
                        </table>
                    </div>` : `<p style="color:#888;font-style:italic;">No churn risk detected yet.</p>`}
                </div>

                <div class="module-box">
                    <h3>Due Soon Rebooking List</h3>
                    ${due.length ? `
                    <div style="overflow-x:auto;">
                        <table class="breakdown-table">
                            <thead><tr><th>Client</th><th>Fav Service</th><th>Fav Tech</th><th>Next Visit</th><th style="text-align:right;">Avg Spend</th></tr></thead>
                            <tbody>${dueRows}</tbody>
                        </table>
                    </div>` : `<p style="color:#888;font-style:italic;">No due-soon clients detected yet.</p>`}
                </div>
            </div>

            <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start;margin-top:16px;">
                <div class="module-box">
                    <h3>Revenue Drivers</h3>
                    <div style="overflow-x:auto;">
                        <table class="breakdown-table">
                            <thead><tr><th>Service</th><th style="text-align:right;">Revenue</th></tr></thead>
                            <tbody>${serviceRows || `<tr><td colspan="2">No service revenue yet.</td></tr>`}</tbody>
                        </table>
                    </div>
                </div>

                <div class="module-box">
                    <h3>VIP Protection List</h3>
                    ${vip.length ? `
                        <ul style="line-height:1.8;margin:0;padding-left:18px;">
                            ${vip.map(c => `<li><strong>${p6_escape(c.name)}</strong> — ${p6_money(c.spend)} · ${c.visitCount} visit(s) · Fav: ${p6_escape(c.favService)}</li>`).join("")}
                        </ul>
                    ` : `<p style="color:#888;font-style:italic;">No VIP threshold clients yet.</p>`}
                </div>
            </div>
        `;

        const target = document.getElementById(targetId) ||
                       document.getElementById("aiPredictiveContainer") ||
                       document.getElementById("intelligencePanel");
        if (target) target.innerHTML = panelHtml;

        // Also enrich suggested action area if visible.
        const actionsBox = document.getElementById("intel54cSuggestedActions");
        if (actionsBox) {
            actionsBox.innerHTML = `<ul style="margin:0;padding-left:18px;line-height:1.75;color:#444;">
                ${churn[0] ? `<li>Call or message <strong>${p6_escape(churn[0].name)}</strong>; this client is overdue based on previous visit pattern.</li>` : ""}
                ${due[0] ? `<li>Offer rebooking to <strong>${p6_escape(due[0].name)}</strong> for <strong>${p6_escape(due[0].favService)}</strong>.</li>` : ""}
                <li>Promote <strong>${p6_escape(revenue.topService[0])}</strong>; it leads historical revenue.</li>
                <li>Protect <strong>${p6_escape(revenue.bestBucket[0])}</strong> capacity; it is your strongest revenue window.</li>
            </ul>`;
        }
    }

    async function p6_enhanceClientIntel(clientData) {
        try {
            const data = await p6_loadHistory();
            const clients = p6_clientSignals(data.rows);
            const name = `${clientData?.Forename || ""} ${clientData?.Surname || ""}`.trim().toLowerCase();
            const phone = String(clientData?.Tel_Number || clientData?.phone || "").replace(/\D/g, "");
            const found = clients.find(c => {
                const cPhone = String(c.phone || "").replace(/\D/g, "");
                return (phone && cPhone && (cPhone.includes(phone) || phone.includes(cPhone))) ||
                       (name && String(c.name || "").toLowerCase().includes(name));
            });
            if (!found) return;

            const container = document.getElementById("cip_tab_insights") ||
                              document.getElementById("cip_alerts") ||
                              document.getElementById("cip_panel");
            if (!container) return;

            let box = document.getElementById("cip_predictiveBox");
            if (!box) {
                box = document.createElement("div");
                box.id = "cip_predictiveBox";
                box.className = "module-box";
                box.style.cssText = "border-top:4px solid var(--accent);margin-top:16px;";
                container.appendChild(box);
            }

            box.innerHTML = `
                <h3 style="color:var(--accent);">Predictive Client Signals</h3>
                <div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;">
                    <div class="metric-card"><div>Risk / Segment</div><div class="metric-value" style="font-size:1rem;">${p6_escape(found.risk)}</div></div>
                    <div class="metric-card"><div>Predicted Next</div><div class="metric-value" style="font-size:1rem;">${p6_escape(found.predictedNext || "—")}</div></div>
                    <div class="metric-card"><div>Avg Visit Gap</div><div class="metric-value" style="font-size:1rem;">${found.avgGap ? found.avgGap + "d" : "—"}</div></div>
                    <div class="metric-card"><div>Fav Service</div><div class="metric-value" style="font-size:1rem;">${p6_escape(found.favService)}</div></div>
                </div>
                <ul style="line-height:1.8;color:#444;margin-top:12px;">
                    <li>${found.risk === "Churn Risk" ? "Recommended action: send retention offer or personal follow-up today." : "Recommended action: maintain normal rebooking rhythm."}</li>
                    <li>Suggested upsell: package or add-on connected to <strong>${p6_escape(found.favService)}</strong>.</li>
                    <li>Preferred technician signal: <strong>${p6_escape(found.favTech)}</strong>.</li>
                </ul>
            `;
        } catch(e) {
            console.warn("Phase 6 client predictive enhancement failed", e);
        }
    }

    // Public controls
    window.thurayaPhase6LoadPredictive = function() {
        return p6_renderPredictivePanel("aiPredictiveContainer");
    };
    window.thurayaPhase6Refresh = function() {
        p6Cache = null;
        p6LastLoadedAt = 0;
        return p6_renderPredictivePanel("aiPredictiveContainer");
    };

    // Wrap Intelligence tab switching to replace/enhance Forecast with predictive intelligence.
    const oldIntelTab = window.intel54c_showTab;
    if (typeof oldIntelTab === "function" && !oldIntelTab._p6Wrapped) {
        const wrapped = function(tabName) {
            const result = oldIntelTab.apply(this, arguments);
            const t = String(tabName || "").toLowerCase();
            if (t.includes("forecast") || t.includes("predict") || t.includes("revenue")) {
                setTimeout(() => p6_renderPredictivePanel("aiPredictiveContainer"), 250);
            }
            if (t.includes("overview")) {
                setTimeout(() => p6_renderPredictivePanel("aiPredictiveContainer"), 400);
            }
            return result;
        };
        wrapped._p6Wrapped = true;
        window.intel54c_showTab = wrapped;
    }

    // Wrap main module switching.
    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._p6Wrapped) {
        const wrappedSwitch = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "intelligenceView") {
                setTimeout(() => p6_renderPredictivePanel("aiPredictiveContainer"), 700);
            }
            return result;
        };
        wrappedSwitch._p6Wrapped = true;
        window.switchModule = wrappedSwitch;
    }

    // Wrap client intel open to add predictive client signals.
    const oldCipOpen = window.cip_open;
    if (typeof oldCipOpen === "function" && !oldCipOpen._p6Wrapped) {
        const wrappedCip = async function(clientData) {
            const result = await oldCipOpen.apply(this, arguments);
            setTimeout(() => p6_enhanceClientIntel(clientData), 800);
            return result;
        };
        wrappedCip._p6Wrapped = true;
        window.cip_open = wrappedCip;
    }

    console.log("Thuraya Phase 6 Predictive Intelligence loaded");
})();
// ============================================================================
// END THURAYA PHASE 6 — PREDICTIVE INTELLIGENCE
// ============================================================================

// ============================================================================
// THURAYA PHASE 6.1 — OVERVIEW EMBED + REFRESH BUTTON FIX
// Fixes:
// - Refresh Intelligence button not triggering Phase 6
// - Predictive Intelligence not visible because current UI has no visible tabs
// - Embeds Phase 6 directly into Intelligence Overview under staff snapshot
// ============================================================================
(function () {
    function p61_waitFor(sel, timeoutMs = 5000) {
        return new Promise(resolve => {
            const found = document.querySelector(sel);
            if (found) return resolve(found);

            const start = Date.now();
            const timer = setInterval(() => {
                const el = document.querySelector(sel);
                if (el || Date.now() - start > timeoutMs) {
                    clearInterval(timer);
                    resolve(el || null);
                }
            }, 150);
        });
    }

    function p61_getIntelligenceRoot() {
        return document.getElementById("intelligenceView") ||
               document.getElementById("intelligencePanel") ||
               document.querySelector(".intel54c-shell") ||
               document.querySelector("[id*='intelligence']");
    }

    function p61_ensurePredictiveContainer() {
        let box = document.getElementById("phase6OverviewPredictivePanel");
        if (box) return box;

        const root = p61_getIntelligenceRoot();
        if (!root) return null;

        box = document.createElement("div");
        box.id = "phase6OverviewPredictivePanel";
        box.style.cssText = "margin-top:18px;";

        // Prefer placing after staff snapshot if possible.
        const staffHeader = Array.from(root.querySelectorAll("h3,h4"))
            .find(h => String(h.textContent || "").toLowerCase().includes("staff performance"));
        const staffBox = staffHeader ? staffHeader.closest(".module-box, .intel54c-card, div") : null;

        if (staffBox && staffBox.parentNode) {
            staffBox.parentNode.insertBefore(box, staffBox.nextSibling);
        } else {
            root.appendChild(box);
        }

        return box;
    }

    async function p61_renderOverviewPredictive() {
        const box = p61_ensurePredictiveContainer();
        if (!box) {
            console.warn("Phase 6.1: Intelligence root/container not found yet.");
            return;
        }

        box.innerHTML = `
            <div class="module-box" style="border-top:4px solid var(--accent);">
                <h3 style="color:var(--accent);">🔮 Predictive Intelligence</h3>
                <p style="font-size:.85rem;color:#666;margin-bottom:12px;">Loading client behavior, churn risk and revenue opportunity signals…</p>
                <div class="loading-pulse">Analyzing history…</div>
            </div>
        `;

        try {
            if (typeof window.thurayaPhase6LoadPredictive === "function") {
                await window.thurayaPhase6LoadPredictive();
            }

            // thurayaPhase6LoadPredictive targets aiPredictiveContainer by default.
            // If that container is hidden/missing, render into our visible overview panel.
            if (typeof p6_renderPredictivePanel === "function") {
                await p6_renderPredictivePanel("phase6OverviewPredictivePanel");
            } else if (typeof window.thurayaPhase6Refresh === "function") {
                await window.thurayaPhase6Refresh();
            }

            // If old function rendered elsewhere and our box still has loader, copy/fallback.
            if (box.textContent.includes("Analyzing history")) {
                const alt = document.getElementById("aiPredictiveContainer");
                if (alt && alt.innerHTML.trim()) {
                    box.innerHTML = alt.innerHTML;
                } else {
                    box.innerHTML = `
                        <div class="module-box" style="border-top:4px solid var(--accent);">
                            <h3 style="color:var(--accent);">🔮 Predictive Intelligence</h3>
                            <p style="color:#777;">Predictive module is active, but no prediction container was returned. Use Refresh Intelligence once more after data loads.</p>
                        </div>
                    `;
                }
            }
        } catch (e) {
            console.error("Phase 6.1 predictive overview render failed:", e);
            box.innerHTML = `
                <div class="module-box" style="border-top:4px solid var(--error);">
                    <h3 style="color:var(--error);">Predictive Intelligence Error</h3>
                    <p style="color:#666;">${String(e.message || e)}</p>
                </div>
            `;
        }
    }

    function p61_bindRefreshButton() {
        const root = p61_getIntelligenceRoot() || document;
        const buttons = Array.from(root.querySelectorAll("button"));
        const refreshBtn = buttons.find(b => String(b.textContent || "").toLowerCase().includes("refresh intelligence"));

        if (!refreshBtn || refreshBtn._p61Bound) return;

        refreshBtn.disabled = false;
        refreshBtn.style.pointerEvents = "auto";
        refreshBtn.addEventListener("click", async function (e) {
            e.preventDefault();
            e.stopPropagation();

            const oldText = refreshBtn.textContent;
            refreshBtn.textContent = "Refreshing…";
            refreshBtn.disabled = true;

            try {
                if (typeof window.thurayaLoadIntelligenceRealData54C === "function") {
                    await window.thurayaLoadIntelligenceRealData54C();
                } else if (typeof window.thurayaLoadIntelligenceDashboard54C === "function") {
                    await window.thurayaLoadIntelligenceDashboard54C();
                }

                if (typeof window.thurayaPhase6Refresh === "function") {
                    await window.thurayaPhase6Refresh();
                }

                await p61_renderOverviewPredictive();
            } catch (err) {
                console.error("Refresh Intelligence failed:", err);
            } finally {
                refreshBtn.textContent = oldText || "Refresh Intelligence";
                refreshBtn.disabled = false;
            }
        });

        refreshBtn._p61Bound = true;
        console.log("Phase 6.1: Refresh Intelligence button bound.");
    }

    async function p61_boot() {
        await p61_waitFor("#intelligenceView, #intelligencePanel, .intel54c-shell", 6000);
        p61_bindRefreshButton();

        const active = document.getElementById("intelligenceView")?.style.display === "block" ||
                       document.getElementById("nav_intelligence")?.checked;

        if (active) {
            setTimeout(p61_renderOverviewPredictive, 600);
        }
    }

    // Expose manual command for testing in console.
    window.thurayaPhase61RenderOverview = p61_renderOverviewPredictive;
    window.thurayaPhase61BindRefresh = p61_bindRefreshButton;

    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._p61Wrapped) {
        const wrapped = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "intelligenceView") {
                setTimeout(() => {
                    p61_bindRefreshButton();
                    p61_renderOverviewPredictive();
                }, 700);
            }
            return result;
        };
        wrapped._p61Wrapped = true;
        window.switchModule = wrapped;
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", p61_boot);
    } else {
        setTimeout(p61_boot, 500);
    }

    console.log("Thuraya Phase 6.1 Overview Embed + Refresh Fix loaded");
})();
// ============================================================================
// END THURAYA PHASE 6.1 — OVERVIEW EMBED + REFRESH BUTTON FIX
// ============================================================================

// ============================================================================
// THURAYA PHASE 6.2 — PERSISTENT PREDICTIVE OVERVIEW
// Strong fix for:
// - Predictive panel flashing then disappearing
// - Refresh Intelligence button losing handler after UI re-render
// This module renders independently and survives DOM replacement.
// ============================================================================
(function () {
    const P62_ID = "phase62PredictiveOverview";
    let p62Rendering = false;
    let p62ObserverStarted = false;
    let p62LastRenderAt = 0;

    function p62_num(v) {
        const n = parseFloat(v ?? 0);
        return Number.isFinite(n) ? n : 0;
    }

    function p62_money(v) {
        return p62_num(v).toFixed(2) + " GHC";
    }

    function p62_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function p62_today() {
        try { if (typeof getLocalDateString === "function") return getLocalDateString(); } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p62_date(row) {
        const d = row.dateString || row.date || row.Date || row.bookingDate || "";
        if (d) return String(d).slice(0, 10);
        const ts = row.createdAt || row.closedAt || row.updatedAt || row.completedAt || row.paidAt;
        try {
            if (ts && typeof ts.toDate === "function") {
                const x = ts.toDate();
                return `${x.getFullYear()}-${String(x.getMonth()+1).padStart(2,"0")}-${String(x.getDate()).padStart(2,"0")}`;
            }
        } catch(e) {}
        return "";
    }

    function p62_dateObj(s) {
        if (!s) return null;
        const p = String(s).slice(0,10).split("-").map(Number);
        if (p.length !== 3 || !p[0] || !p[1] || !p[2]) return null;
        return new Date(p[0], p[1]-1, p[2], 12, 0, 0);
    }

    function p62_shift(dateStr, days) {
        const d = p62_dateObj(dateStr) || new Date();
        d.setDate(d.getDate() + days);
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p62_daysBetween(a,b) {
        const da = p62_dateObj(a), db = p62_dateObj(b);
        if (!da || !db) return null;
        return Math.round((db - da) / 86400000);
    }

    function p62_status(row) {
        return String(row.status || row.Status || "").toLowerCase();
    }

    function p62_cancelled(row) {
        const s = p62_status(row);
        return ["cancelled","canceled","void","refunded"].some(x => s.includes(x));
    }

    function p62_noshow(row) {
        const s = p62_status(row);
        return s.includes("no show") || s.includes("no-show") || s.includes("noshow");
    }

    function p62_revenue(row) {
        if (p62_cancelled(row) || p62_noshow(row)) return 0;
        return p62_num(row.finalTotal ?? row.grandTotal ?? row.total ?? row.totalCost ?? row.amountPaid ?? row.checkoutTotal ?? row.totalRevenue ?? row.revenue ?? row.Revenue ?? 0);
    }

    function p62_clientName(row) {
        const direct = row.clientName || row.Client || row.name || row.customerName || "";
        if (direct) return String(direct).trim();
        return `${row.Forename || row.forename || row.firstName || ""} ${row.Surname || row.surname || row.lastName || ""}`.trim();
    }

    function p62_clientPhone(row) {
        return String(row.clientPhone || row.Phone || row.phone || row.Tel_Number || row.tel || row.primaryPhone || "").replace(/\.0$/,"").replace(/\s+/g,"").trim();
    }

    function p62_clientKey(row) {
        return p62_clientPhone(row) || p62_clientName(row).toLowerCase() || "unknown";
    }

    function p62_service(row) {
        return String(row.bookedService || row.service || row.Service || row.services || "Unspecified").trim();
    }

    function p62_tech(row) {
        return String(row.assignedTechName || row.techName || row.technicianName || row.Technician || row.technician || row.assignedTechEmail || "Unassigned").trim();
    }

    function p62_bucket(row) {
        const t = String(row.timeString || row.Time || row.time || "00:00");
        const h = parseInt(t.split(":")[0] || 0, 10);
        if (h < 12) return "Morning";
        if (h < 17) return "Afternoon";
        return "Evening";
    }

    async function p62_get(name) {
        try {
            const snap = await db.collection(name).limit(1800).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, _collection: name, ...(doc.data() || {}) }));
            return rows;
        } catch(e) {
            console.warn("Phase 6.2 read failed:", name, e);
            return [];
        }
    }

    async function p62_loadRows() {
        const [apps, jobs] = await Promise.all([p62_get("Appointments"), p62_get("Active_Jobs")]);
        const rows = [...apps, ...jobs].map(r => ({
            ...r,
            _d: p62_date(r),
            _rev: p62_revenue(r),
            _client: p62_clientName(r),
            _phone: p62_clientPhone(r),
            _key: p62_clientKey(r),
            _service: p62_service(r),
            _tech: p62_tech(r),
            _bucket: p62_bucket(r)
        })).filter(r => r._d || r._client || r._rev);

        // Fair group allocation for participants with zero revenue.
        const groups = {};
        rows.forEach(r => {
            const gid = r.groupId || r.groupBookingId || r["Group ID"] || "";
            if (!gid || p62_cancelled(r) || p62_noshow(r)) return;
            if (!groups[gid]) groups[gid] = [];
            groups[gid].push(r);
        });
        Object.values(groups).forEach(members => {
            const total = members.reduce((s,r)=>s+p62_num(r._rev),0);
            const size = Math.max(members.length, ...members.map(r => parseInt(r.groupSize || r["Group Size"] || 1, 10) || 1));
            if (total > 0 && size > 1) {
                const share = total / size;
                members.forEach(r => {
                    if (p62_num(r._rev) <= 0) {
                        r._rev = share;
                        r._alloc = true;
                    }
                });
            }
        });

        return rows;
    }

    function p62_top(map, n=5) {
        return Object.entries(map).sort((a,b)=>b[1]-a[1]).slice(0,n);
    }

    function p62_signals(rows) {
        const today = p62_today();
        const valid = rows.filter(r => !p62_cancelled(r) && !p62_noshow(r) && p62_num(r._rev) > 0);

        const byDate = {};
        const byService = {};
        const byTech = {};
        const byBucket = {};
        valid.forEach(r => {
            byDate[r._d] = (byDate[r._d] || 0) + p62_num(r._rev);
            byService[r._service] = (byService[r._service] || 0) + p62_num(r._rev);
            byTech[r._tech] = (byTech[r._tech] || 0) + p62_num(r._rev);
            byBucket[r._bucket] = (byBucket[r._bucket] || 0) + p62_num(r._rev);
        });

        const last7 = Array.from({length:7}, (_,i)=>p62_shift(today,-i)).reduce((s,d)=>s+(byDate[d]||0),0);
        const prev7 = Array.from({length:7}, (_,i)=>p62_shift(today,-7-i)).reduce((s,d)=>s+(byDate[d]||0),0);
        const trend = prev7 > 0 ? ((last7 - prev7) / prev7) * 100 : null;

        const clients = {};
        valid.forEach(r => {
            const k = r._key;
            if (!k || k === "unknown") return;
            if (!clients[k]) clients[k] = { name: r._client || r._phone || "Unknown", phone: r._phone || "", spend: 0, visits: [], services: {}, techs: {} };
            clients[k].spend += p62_num(r._rev);
            if (r._d) clients[k].visits.push(r._d);
            clients[k].services[r._service] = (clients[k].services[r._service] || 0) + 1;
            clients[k].techs[r._tech] = (clients[k].techs[r._tech] || 0) + 1;
        });

        const clientList = Object.values(clients).map(c => {
            const dates = [...new Set(c.visits)].sort();
            const last = dates[dates.length-1] || "";
            const gaps = [];
            for (let i=1;i<dates.length;i++) {
                const g = p62_daysBetween(dates[i-1], dates[i]);
                if (g !== null && g >= 0) gaps.push(g);
            }
            const avgGap = gaps.length ? Math.round(gaps.reduce((a,b)=>a+b,0)/gaps.length) : null;
            const daysSince = last ? p62_daysBetween(last, today) : null;
            const next = avgGap && last ? p62_shift(last, avgGap) : "";
            const overdue = avgGap && daysSince !== null ? daysSince - avgGap : null;

            let segment = "New";
            if (c.spend >= 1000 || dates.length >= 5) segment = "VIP";
            if (avgGap && overdue !== null && overdue > Math.max(14, avgGap * 0.7)) segment = "Churn Risk";
            else if (avgGap && overdue !== null && overdue > 0) segment = "Due Soon";
            else if (dates.length >= 3) segment = "Loyal";

            return {
                ...c,
                visitsCount: dates.length,
                last,
                avgGap,
                daysSince,
                next,
                overdue,
                segment,
                favService: p62_top(c.services,1)[0]?.[0] || "—",
                favTech: p62_top(c.techs,1)[0]?.[0] || "—",
                avgSpend: dates.length ? c.spend / dates.length : 0
            };
        }).sort((a,b)=>b.spend-a.spend);

        return {
            valid,
            total: valid.reduce((s,r)=>s+p62_num(r._rev),0),
            todayRevenue: byDate[today] || 0,
            last7,
            prev7,
            trend,
            avgDaily: last7 / 7,
            topService: p62_top(byService,1)[0] || ["—",0],
            topTech: p62_top(byTech,1)[0] || ["—",0],
            bestBucket: p62_top(byBucket,1)[0] || ["—",0],
            churn: clientList.filter(c=>c.segment==="Churn Risk").slice(0,5),
            due: clientList.filter(c=>c.segment==="Due Soon").slice(0,5),
            vip: clientList.filter(c=>c.segment==="VIP").slice(0,5),
            clients: clientList
        };
    }

    function p62_getRoot() {
        return document.getElementById("intelligenceView") ||
               document.getElementById("intelligencePanel") ||
               document.querySelector(".intel54c-shell");
    }

    function p62_findStaffSection(root) {
        const headings = Array.from(root.querySelectorAll("h1,h2,h3,h4,strong"));
        const h = headings.find(x => String(x.textContent || "").toLowerCase().includes("staff performance"));
        return h ? (h.closest(".module-box") || h.closest("div")) : null;
    }

    function p62_ensureBox() {
        const root = p62_getRoot();
        if (!root) return null;

        let box = document.getElementById(P62_ID);
        if (box && document.body.contains(box)) return box;

        box = document.createElement("div");
        box.id = P62_ID;
        box.style.cssText = "margin:18px 0 0 0;";

        const staff = p62_findStaffSection(root);
        if (staff && staff.parentNode) {
            staff.parentNode.insertBefore(box, staff.nextSibling);
        } else {
            root.appendChild(box);
        }
        return box;
    }

    function p62_kpi(title, value, sub="") {
        return `<div class="intel54c-kpi" style="min-height:86px;">
            <span>${p62_escape(title)}</span>
            <strong>${p62_escape(value)}</strong>
            ${sub ? `<div style="font-size:.72rem;color:#666;margin-top:6px;line-height:1.35;">${sub}</div>` : ""}
        </div>`;
    }

    function p62_action(type, title, body) {
        const border = type === "danger" ? "var(--error)" : type === "success" ? "var(--success)" : "var(--accent)";
        const bg = type === "danger" ? "#fff5f5" : type === "success" ? "#f0fff4" : "#fffaf0";
        return `<div style="background:${bg};border:1px solid ${border};border-left:4px solid ${border};border-radius:12px;padding:12px 14px;margin-bottom:10px;">
            <div style="font-weight:900;color:var(--primary);margin-bottom:4px;">${p62_escape(title)}</div>
            <div style="font-size:.84rem;color:#555;line-height:1.5;">${body}</div>
        </div>`;
    }

    async function p62_render(force=false) {
        if (p62Rendering) return;
        const now = Date.now();
        if (!force && now - p62LastRenderAt < 1200) return;

        const box = p62_ensureBox();
        if (!box) return;

        p62Rendering = true;
        p62LastRenderAt = now;

        box.innerHTML = `
            <div class="module-box" style="border-top:4px solid var(--accent);">
                <h3 style="color:var(--accent);">🔮 Predictive Intelligence</h3>
                <p style="font-size:.85rem;color:#666;margin-bottom:12px;">Analyzing full client and revenue history…</p>
                <div class="loading-pulse">Loading predictions…</div>
            </div>
        `;

        try {
            const rows = await p62_loadRows();
            const s = p62_signals(rows);
            const trendText = s.trend === null ? "No baseline" : `${s.trend >= 0 ? "Up" : "Down"} ${Math.abs(s.trend).toFixed(0)}%`;

            const actions = [];
            if (s.churn[0]) {
                actions.push(p62_action("danger", "Client churn risk detected",
                    `<strong>${p62_escape(s.churn[0].name)}</strong> appears overdue. Last visit: <strong>${p62_escape(s.churn[0].last || "—")}</strong>. Expected next visit: <strong>${p62_escape(s.churn[0].next || "—")}</strong>.`));
            }
            if (s.due[0]) {
                actions.push(p62_action("warn", "Rebooking opportunity",
                    `<strong>${p62_escape(s.due[0].name)}</strong> is due soon. Suggested offer: <strong>${p62_escape(s.due[0].favService)}</strong> with <strong>${p62_escape(s.due[0].favTech)}</strong>.`));
            }
            if (s.trend !== null && s.trend < -15) {
                actions.push(p62_action("danger", "Revenue trend needs attention",
                    `Last 7 days are down <strong>${Math.abs(s.trend).toFixed(0)}%</strong> vs the previous 7 days. Promote <strong>${p62_escape(s.topService[0])}</strong>.`));
            }
            actions.push(p62_action("success", "Best revenue opportunity",
                `<strong>${p62_escape(s.topService[0])}</strong> leads historical revenue at <strong>${p62_money(s.topService[1])}</strong>. Strongest time window: <strong>${p62_escape(s.bestBucket[0])}</strong>.`));

            const churnRows = s.churn.map(c => `
                <tr>
                    <td><strong>${p62_escape(c.name)}</strong><div style="font-size:.72rem;color:#777;">${p62_escape(c.phone || "")}</div></td>
                    <td>${p62_escape(c.last || "—")}</td>
                    <td>${c.avgGap ? c.avgGap + "d" : "—"}</td>
                    <td>${p62_escape(c.next || "—")}</td>
                    <td style="text-align:right;font-weight:900;color:var(--success);">${p62_money(c.spend)}</td>
                </tr>`).join("");

            const dueRows = s.due.map(c => `
                <tr>
                    <td><strong>${p62_escape(c.name)}</strong></td>
                    <td>${p62_escape(c.favService)}</td>
                    <td>${p62_escape(c.favTech)}</td>
                    <td>${p62_escape(c.next || "—")}</td>
                    <td style="text-align:right;">${p62_money(c.avgSpend)}</td>
                </tr>`).join("");

            box.innerHTML = `
                <div class="module-box" style="border-top:4px solid var(--accent);">
                    <h3 style="color:var(--accent);">🔮 Predictive Intelligence</h3>
                    <p style="font-size:.85rem;color:#666;margin-bottom:16px;">Client behavior, churn risk, revenue trend and next-best business actions.</p>

                    <div class="intel54c-kpis" style="margin-top:0;">
                        ${p62_kpi("7-Day Trend", trendText, `Last 7 days: ${p62_money(s.last7)}`)}
                        ${p62_kpi("Avg Daily Revenue", p62_money(s.avgDaily), `Today: ${p62_money(s.todayRevenue)}`)}
                        ${p62_kpi("Churn Risk Clients", String(s.churn.length), "Overdue vs normal pattern")}
                        ${p62_kpi("Due Soon Clients", String(s.due.length), "Rebooking opportunities")}
                    </div>
                </div>

                <div class="module-box" style="border-top:4px solid var(--primary);">
                    <h3 style="color:var(--primary);">Next-Best Actions</h3>
                    ${actions.join("")}
                </div>

                <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start;">
                    <div class="module-box">
                        <h3>Churn Risk Watchlist</h3>
                        ${s.churn.length ? `<div style="overflow-x:auto;"><table class="breakdown-table"><thead><tr><th>Client</th><th>Last Visit</th><th>Avg Gap</th><th>Expected Next</th><th style="text-align:right;">Spend</th></tr></thead><tbody>${churnRows}</tbody></table></div>` : `<p style="color:#888;font-style:italic;">No churn risk detected yet.</p>`}
                    </div>

                    <div class="module-box">
                        <h3>Due Soon Rebooking List</h3>
                        ${s.due.length ? `<div style="overflow-x:auto;"><table class="breakdown-table"><thead><tr><th>Client</th><th>Fav Service</th><th>Fav Tech</th><th>Next Visit</th><th style="text-align:right;">Avg Spend</th></tr></thead><tbody>${dueRows}</tbody></table></div>` : `<p style="color:#888;font-style:italic;">No due-soon clients detected yet.</p>`}
                    </div>
                </div>

                <div class="module-box" style="border-top:4px solid var(--accent);margin-top:16px;">
                    <h3 style="color:var(--accent);">Revenue Opportunity Signals</h3>
                    <ul style="line-height:1.8;color:#444;margin:0;padding-left:18px;">
                        <li>Top revenue service: <strong>${p62_escape(s.topService[0])}</strong> — ${p62_money(s.topService[1])}</li>
                        <li>Top technician by revenue: <strong>${p62_escape(s.topTech[0])}</strong> — ${p62_money(s.topTech[1])}</li>
                        <li>Strongest revenue window: <strong>${p62_escape(s.bestBucket[0])}</strong></li>
                        <li>Total history analyzed: <strong>${s.valid.length}</strong> revenue records</li>
                    </ul>
                </div>
            `;
        } catch(e) {
            console.error("Phase 6.2 render failed", e);
            box.innerHTML = `<div class="module-box" style="border-top:4px solid var(--error);"><h3 style="color:var(--error);">Predictive Intelligence Error</h3><p>${p62_escape(e.message || e)}</p></div>`;
        } finally {
            p62Rendering = false;
        }
    }

    function p62_bindRefresh() {
        const root = p62_getRoot() || document;
        const buttons = Array.from(root.querySelectorAll("button"));
        const refreshBtn = buttons.find(b => String(b.textContent || "").toLowerCase().includes("refresh intelligence"));
        if (!refreshBtn) return;

        refreshBtn.disabled = false;
        refreshBtn.style.pointerEvents = "auto";
        refreshBtn.style.cursor = "pointer";

        // Replace old click behavior by using onclick and capture listener.
        refreshBtn.onclick = async function(e) {
            e.preventDefault();
            e.stopPropagation();
            const old = refreshBtn.textContent;
            refreshBtn.textContent = "Refreshing…";
            refreshBtn.disabled = true;

            try {
                if (typeof window.thurayaLoadIntelligenceRealData54C === "function") {
                    await window.thurayaLoadIntelligenceRealData54C();
                } else if (typeof window.thurayaLoadIntelligenceDashboard54C === "function") {
                    await window.thurayaLoadIntelligenceDashboard54C();
                }
                setTimeout(() => {
                    p62_bindRefresh();
                    p62_render(true);
                }, 500);
            } catch(err) {
                console.error("Refresh Intelligence failed", err);
            } finally {
                setTimeout(() => {
                    const b = Array.from((p62_getRoot() || document).querySelectorAll("button")).find(x => String(x.textContent || "").toLowerCase().includes("refresh"));
                    if (b) {
                        b.textContent = old || "Refresh Intelligence";
                        b.disabled = false;
                    }
                }, 900);
            }
        };

        if (!refreshBtn._p62CaptureBound) {
            refreshBtn.addEventListener("click", function(e) {
                // onclick above handles it; this ensures replaced handlers do not swallow.
                if (refreshBtn.disabled) return;
            }, true);
            refreshBtn._p62CaptureBound = true;
        }
    }

    function p62_isIntelligenceVisible() {
        return document.getElementById("nav_intelligence")?.checked ||
               document.getElementById("intelligenceView")?.style.display === "block" ||
               document.getElementById("intelligenceView")?.offsetParent !== null;
    }

    function p62_bootVisible() {
        if (!p62_isIntelligenceVisible()) return;
        p62_bindRefresh();
        setTimeout(() => p62_render(false), 350);
        setTimeout(() => p62_render(true), 1200); // survive existing render overwrite
    }

    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._p62Wrapped) {
        const wrapped = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "intelligenceView") {
                setTimeout(p62_bootVisible, 400);
                setTimeout(p62_bootVisible, 1300);
            }
            return result;
        };
        wrapped._p62Wrapped = true;
        window.switchModule = wrapped;
    }

    function p62_startObserver() {
        if (p62ObserverStarted) return;
        p62ObserverStarted = true;

        const obs = new MutationObserver(() => {
            if (!p62_isIntelligenceVisible()) return;
            clearTimeout(window._p62DomTimer);
            window._p62DomTimer = setTimeout(() => {
                p62_bindRefresh();
                if (!document.getElementById(P62_ID)) p62_render(true);
            }, 250);
        });

        obs.observe(document.body, { childList: true, subtree: true });
    }

    window.thurayaPhase62Render = function() { return p62_render(true); };
    window.thurayaPhase62BindRefresh = p62_bindRefresh;

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => {
            p62_startObserver();
            setTimeout(p62_bootVisible, 1000);
        });
    } else {
        p62_startObserver();
        setTimeout(p62_bootVisible, 1000);
    }

    console.log("Thuraya Phase 6.2 Persistent Predictive Overview loaded");
})();
// ============================================================================
// END THURAYA PHASE 6.2 — PERSISTENT PREDICTIVE OVERVIEW
// ============================================================================

// ============================================================================
// THURAYA PHASE 6.3 — CLEAN MODE
// Final UI stabilization:
// - Prevents duplicate Predictive Intelligence panels
// - Keeps only the persistent embedded overview panel
// - Removes old/hidden predictive containers if they appear
// - Keeps Refresh Intelligence working
// ============================================================================
(function () {
    const KEEP_ID = "phase62PredictiveOverview";

    function p63_isPredictiveHeading(el) {
        const txt = String(el?.textContent || "").trim().toLowerCase();
        return txt.includes("predictive intelligence");
    }

    function p63_panelRootFromHeading(h) {
        return h.closest(".module-box") || h.closest("[id]") || h.parentElement;
    }

    function p63_removeDuplicates() {
        const keep = document.getElementById(KEEP_ID);

        // Remove explicit old containers that may be rendered by earlier Phase 6 code.
        [
            "phase6OverviewPredictivePanel",
            "aiPredictiveContainer"
        ].forEach(id => {
            const el = document.getElementById(id);
            if (el && el.id !== KEEP_ID) {
                // Only clear/remove if it contains predictive content or is hidden legacy forecast area.
                if (String(el.textContent || "").toLowerCase().includes("predictive") || id === "aiPredictiveContainer") {
                    el.remove();
                }
            }
        });

        // Remove duplicate predictive sections by heading, keeping the one inside KEEP_ID.
        const headings = Array.from(document.querySelectorAll("h1,h2,h3,h4,strong"))
            .filter(p63_isPredictiveHeading);

        headings.forEach(h => {
            const panel = p63_panelRootFromHeading(h);
            if (!panel) return;

            if (keep && (panel === keep || keep.contains(panel) || panel.contains(keep))) return;

            // Do not remove Intelligence main panel accidentally; only remove sections with predictive text.
            const panelText = String(panel.textContent || "").toLowerCase();
            if (panelText.includes("predictive intelligence") || panelText.includes("phase 6 predictive intelligence")) {
                panel.remove();
            }
        });

        // If multiple KEEP_ID somehow exist due to DOM cloning, keep first only.
        const allKeep = Array.from(document.querySelectorAll(`#${KEEP_ID}`));
        allKeep.slice(1).forEach(el => el.remove());
    }

    function p63_wrapLegacyRenderers() {
        // Stop older Phase 6 renderers from injecting separate panels.
        if (typeof window.thurayaPhase6LoadPredictive === "function" && !window.thurayaPhase6LoadPredictive._p63Clean) {
            const old = window.thurayaPhase6LoadPredictive;
            const clean = async function () {
                try {
                    // Prefer persistent clean renderer.
                    if (typeof window.thurayaPhase62Render === "function") {
                        await window.thurayaPhase62Render();
                    } else {
                        await old.apply(this, arguments);
                    }
                } finally {
                    setTimeout(p63_removeDuplicates, 150);
                    setTimeout(p63_removeDuplicates, 700);
                }
            };
            clean._p63Clean = true;
            window.thurayaPhase6LoadPredictive = clean;
        }

        if (typeof window.thurayaPhase6Refresh === "function" && !window.thurayaPhase6Refresh._p63Clean) {
            const oldRefresh = window.thurayaPhase6Refresh;
            const cleanRefresh = async function () {
                try {
                    if (typeof window.thurayaPhase62Render === "function") {
                        await window.thurayaPhase62Render();
                    } else {
                        await oldRefresh.apply(this, arguments);
                    }
                } finally {
                    setTimeout(p63_removeDuplicates, 150);
                    setTimeout(p63_removeDuplicates, 700);
                }
            };
            cleanRefresh._p63Clean = true;
            window.thurayaPhase6Refresh = cleanRefresh;
        }
    }

    function p63_cleanLoop() {
        p63_wrapLegacyRenderers();
        p63_removeDuplicates();
    }

    // Hook switchModule to clean after Intelligence is shown.
    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._p63Wrapped) {
        const wrapped = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "intelligenceView") {
                setTimeout(p63_cleanLoop, 500);
                setTimeout(p63_cleanLoop, 1400);
                setTimeout(p63_cleanLoop, 2600);
            }
            return result;
        };
        wrapped._p63Wrapped = true;
        window.switchModule = wrapped;
    }

    // Mutation observer: remove duplicates whenever old renderer redraws.
    let timer = null;
    const obs = new MutationObserver(() => {
        clearTimeout(timer);
        timer = setTimeout(p63_cleanLoop, 250);
    });

    function start() {
        p63_wrapLegacyRenderers();
        p63_cleanLoop();
        try {
            obs.observe(document.body, { childList: true, subtree: true });
        } catch(e) {}
        setTimeout(p63_cleanLoop, 1000);
        setTimeout(p63_cleanLoop, 2500);
    }

    window.thurayaPhase63CleanMode = p63_cleanLoop;

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", start);
    } else {
        setTimeout(start, 400);
    }

    console.log("Thuraya Phase 6.3 Clean Mode loaded");
})();
// ============================================================================
// END THURAYA PHASE 6.3 — CLEAN MODE
// ============================================================================



/* ================================
   THURAYA PHASE 6.3B — HARD LOCK MODE
   ================================ */

// 🔴 Kill old predictive renderer completely
window.thurayaPhase6LoadPredictive = async function () {
    console.log("🚫 Old Predictive Renderer BLOCKED");
};

// 🔴 Kill old refresh hook
window.thurayaPhase6Refresh = async function () {
    console.log("🔄 Clean Refresh Triggered");

    if (typeof window.thurayaPhase62Render === "function") {
        await window.thurayaPhase62Render();
    }

    // extra cleanup safety
    setTimeout(() => {
        document.querySelectorAll("h1,h2,h3,h4").forEach(h => {
            if (h.innerText.includes("PREDICTIVE INTELLIGENCE")) {
                const box = h.closest(".module-box");
                if (box && box.id !== "phase62PredictiveOverview") {
                    box.remove();
                }
            }
        });
    }, 300);
};

// ============================================================================
// THURAYA PHASE 6.4 — AI ACTION LAYER
// Adds practical AI-style business recommendations:
// - Smart upsell suggestions
// - Client retention prompts
// - Best technician / service matching
// - Promo recommendations for slow windows
// - Owner-ready action cards
// Safe append-only layer built on Phase 6.3B stable.
// ============================================================================
(function () {
    const P64_ID = "phase64AiActionLayer";
    let p64Timer = null;

    function p64_num(v) {
        const n = parseFloat(v ?? 0);
        return Number.isFinite(n) ? n : 0;
    }

    function p64_money(v) {
        return p64_num(v).toFixed(2) + " GHC";
    }

    function p64_escape(s) {
        return String(s ?? "").replace(/[&<>"']/g, ch => ({
            "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;"
        }[ch]));
    }

    function p64_today() {
        try { if (typeof getLocalDateString === "function") return getLocalDateString(); } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
    }

    function p64_date(row) {
        const d = row.dateString || row.date || row.Date || row.bookingDate || "";
        if (d) return String(d).slice(0, 10);
        const ts = row.createdAt || row.closedAt || row.updatedAt || row.completedAt || row.paidAt;
        try {
            if (ts && typeof ts.toDate === "function") {
                const x = ts.toDate();
                return `${x.getFullYear()}-${String(x.getMonth()+1).padStart(2,"0")}-${String(x.getDate()).padStart(2,"0")}`;
            }
        } catch(e) {}
        return "";
    }

    function p64_status(row) {
        return String(row.status || row.Status || "").toLowerCase();
    }

    function p64_excluded(row) {
        const s = p64_status(row);
        return ["cancelled", "canceled", "void", "refunded", "no show", "no-show", "noshow"].some(x => s.includes(x));
    }

    function p64_revenue(row) {
        if (p64_excluded(row)) return 0;
        return p64_num(row.finalTotal ?? row.grandTotal ?? row.total ?? row.totalCost ?? row.amountPaid ?? row.checkoutTotal ?? row.totalRevenue ?? row.revenue ?? row.Revenue ?? 0);
    }

    function p64_client(row) {
        const direct = row.clientName || row.Client || row.name || row.customerName || "";
        if (direct) return String(direct).trim();
        return `${row.Forename || row.forename || row.firstName || ""} ${row.Surname || row.surname || row.lastName || ""}`.trim();
    }

    function p64_service(row) {
        return String(row.bookedService || row.service || row.Service || row.services || "Unspecified").trim();
    }

    function p64_tech(row) {
        return String(row.assignedTechName || row.techName || row.technicianName || row.Technician || row.technician || row.assignedTechEmail || "Unassigned").trim();
    }

    function p64_bucket(row) {
        const t = String(row.timeString || row.Time || row.time || "00:00");
        const h = parseInt(t.split(":")[0] || 0, 10);
        if (h < 12) return "Morning";
        if (h < 17) return "Afternoon";
        return "Evening";
    }

    async function p64_get(name) {
        try {
            const snap = await db.collection(name).limit(1800).get();
            const rows = [];
            snap.forEach(doc => rows.push({ id: doc.id, _collection: name, ...(doc.data() || {}) }));
            return rows;
        } catch(e) {
            console.warn("Phase 6.4 read failed:", name, e);
            return [];
        }
    }

    async function p64_loadRows() {
        const [apps, jobs] = await Promise.all([p64_get("Appointments"), p64_get("Active_Jobs")]);
        return [...apps, ...jobs].map(r => ({
            ...r,
            _date: p64_date(r),
            _revenue: p64_revenue(r),
            _client: p64_client(r),
            _service: p64_service(r),
            _tech: p64_tech(r),
            _bucket: p64_bucket(r)
        })).filter(r => r._date || r._client || r._revenue);
    }

    function p64_top(map, n=5) {
        return Object.entries(map).sort((a,b) => b[1] - a[1]).slice(0,n);
    }

    function p64_analyze(rows) {
        const valid = rows.filter(r => !p64_excluded(r) && p64_num(r._revenue) > 0);
        const today = p64_today();

        const serviceRevenue = {};
        const serviceCount = {};
        const techRevenue = {};
        const clientRevenue = {};
        const bucketRevenue = {};
        const todayRows = valid.filter(r => r._date === today);

        valid.forEach(r => {
            serviceRevenue[r._service] = (serviceRevenue[r._service] || 0) + r._revenue;
            serviceCount[r._service] = (serviceCount[r._service] || 0) + 1;
            techRevenue[r._tech] = (techRevenue[r._tech] || 0) + r._revenue;
            clientRevenue[r._client || "Unknown"] = (clientRevenue[r._client || "Unknown"] || 0) + r._revenue;
            bucketRevenue[r._bucket] = (bucketRevenue[r._bucket] || 0) + r._revenue;
        });

        const topService = p64_top(serviceRevenue, 1)[0] || ["—", 0];
        const topTech = p64_top(techRevenue, 1)[0] || ["—", 0];
        const topClient = p64_top(clientRevenue, 1)[0] || ["—", 0];
        const topBucket = p64_top(bucketRevenue, 1)[0] || ["—", 0];

        const todayRevenue = todayRows.reduce((s,r)=>s+r._revenue,0);
        const avgTicket = valid.length ? valid.reduce((s,r)=>s+r._revenue,0) / valid.length : 0;

        const lowServices = p64_top(serviceCount, 10)
            .filter(([name,count]) => count <= 2 && name !== "Unspecified")
            .slice(0,3);

        return {
            valid,
            todayRows,
            topService,
            topTech,
            topClient,
            topBucket,
            todayRevenue,
            avgTicket,
            lowServices,
            totalRevenue: valid.reduce((s,r)=>s+r._revenue,0),
            totalRecords: valid.length
        };
    }

    function p64_root() {
        return document.getElementById("intelligenceView") ||
               document.getElementById("intelligencePanel") ||
               document.querySelector(".intel54c-shell");
    }

    function p64_anchor(root) {
        return document.getElementById("phase62PredictiveOverview") ||
               Array.from(root.querySelectorAll("h1,h2,h3,h4")).find(h => String(h.textContent || "").toLowerCase().includes("predictive intelligence"))?.closest(".module-box") ||
               root;
    }

    function p64_ensureBox() {
        const root = p64_root();
        if (!root) return null;

        let box = document.getElementById(P64_ID);
        if (box && document.body.contains(box)) return box;

        box = document.createElement("div");
        box.id = P64_ID;
        box.style.cssText = "margin:18px 0 0 0;";

        const anchor = p64_anchor(root);
        if (anchor && anchor.parentNode && anchor !== root) {
            anchor.parentNode.insertBefore(box, anchor.nextSibling);
        } else {
            root.appendChild(box);
        }
        return box;
    }

    function p64_card(icon, title, body, action, click) {
        return `
            <div style="background:#fff;border:1px solid var(--border);border-left:4px solid var(--accent);border-radius:14px;padding:14px 16px;box-shadow:0 2px 8px rgba(0,0,0,.04);">
                <div style="font-weight:900;color:var(--primary);font-size:1rem;margin-bottom:6px;">${icon} ${p64_escape(title)}</div>
                <div style="font-size:.86rem;color:#555;line-height:1.55;">${body}</div>
                ${action ? `<button type="button" class="btn btn-secondary" style="width:auto;margin-top:10px;padding:7px 12px;font-size:.75rem;" onclick="${click || ""}">${p64_escape(action)}</button>` : ""}
            </div>
        `;
    }

    async function p64_render() {
        const box = p64_ensureBox();
        if (!box) return;

        box.innerHTML = `
            <div class="module-box" style="border-top:4px solid var(--accent);">
                <h3 style="color:var(--accent);">🤖 AI Action Layer</h3>
                <p style="font-size:.85rem;color:#666;">Generating revenue, retention and service action recommendations…</p>
                <div class="loading-pulse">Analyzing business signals…</div>
            </div>
        `;

        try {
            const rows = await p64_loadRows();
            const s = p64_analyze(rows);

            const upsell = p64_card(
                "💰",
                "Smart Upsell Recommendation",
                `Push <strong>${p64_escape(s.topService[0])}</strong> as the primary upsell. It has generated <strong>${p64_money(s.topService[1])}</strong> historically and remains the strongest revenue driver.`,
                "Open Sales & Promo",
                "switchModule('salesPromoView')"
            );

            const staffing = p64_card(
                "👩‍🔧",
                "Best Technician Signal",
                `<strong>${p64_escape(s.topTech[0])}</strong> is currently the strongest revenue technician with <strong>${p64_money(s.topTech[1])}</strong>. Use this as a benchmark for training, routing and service quality consistency.`,
                "Open HR & Finance",
                "switchModule('hrFinanceView')"
            );

            const retention = p64_card(
                "💎",
                "VIP / Retention Focus",
                `<strong>${p64_escape(s.topClient[0])}</strong> is the top client by revenue at <strong>${p64_money(s.topClient[1])}</strong>. Protect this relationship with a personal retention note, package offer or preferred-tech booking path.`,
                "Open Client Intel",
                "switchModule('clientIntelView')"
            );

            const promo = p64_card(
                "🏷️",
                "Promo Strategy",
                `Strongest revenue window is <strong>${p64_escape(s.topBucket[0])}</strong>. Use promos to fill weaker windows, not your strongest period. Avoid discounting where demand is already active.`,
                "Open Sales & Promo",
                "switchModule('salesPromoView')"
            );

            const menu = p64_card(
                "📋",
                "Menu Optimization",
                s.lowServices.length
                    ? `Low-demand services detected: <strong>${s.lowServices.map(x => p64_escape(x[0])).join(", ")}</strong>. Review pricing, placement or bundling.`
                    : `No obvious low-demand service risk detected. Keep monitoring service mix and package performance.`,
                "Open Service Menu",
                "switchModule('menuView')"
            );

            const owner = p64_card(
                "📈",
                "Owner Summary",
                `History analyzed: <strong>${s.totalRecords}</strong> revenue records, <strong>${p64_money(s.totalRevenue)}</strong> total revenue, average ticket <strong>${p64_money(s.avgTicket)}</strong>. Today’s revenue currently stands at <strong>${p64_money(s.todayRevenue)}</strong>.`,
                "Open Reports",
                "switchModule('reportsView')"
            );

            box.innerHTML = `
                <div class="module-box" style="border-top:4px solid var(--accent);">
                    <h3 style="color:var(--accent);">🤖 AI Action Layer</h3>
                    <p style="font-size:.85rem;color:#666;margin-bottom:16px;">
                        Practical recommendations generated from revenue history, client behavior, service demand and staff performance.
                    </p>

                    <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px;">
                        ${upsell}
                        ${retention}
                        ${staffing}
                        ${promo}
                        ${menu}
                        ${owner}
                    </div>
                </div>
            `;
        } catch(e) {
            console.error("Phase 6.4 AI layer failed", e);
            box.innerHTML = `
                <div class="module-box" style="border-top:4px solid var(--error);">
                    <h3 style="color:var(--error);">AI Action Layer Error</h3>
                    <p>${p64_escape(e.message || e)}</p>
                </div>
            `;
        }
    }

    function p64_visible() {
        return document.getElementById("nav_intelligence")?.checked ||
               document.getElementById("intelligenceView")?.style.display === "block" ||
               document.getElementById("intelligenceView")?.offsetParent !== null;
    }

    function p64_boot() {
        if (!p64_visible()) return;
        clearTimeout(p64Timer);
        p64Timer = setTimeout(p64_render, 800);
    }

    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === "function" && !oldSwitch._p64Wrapped) {
        const wrapped = function(moduleId) {
            const result = oldSwitch.apply(this, arguments);
            if (moduleId === "intelligenceView") {
                setTimeout(p64_boot, 900);
                setTimeout(p64_boot, 1800);
            }
            return result;
        };
        wrapped._p64Wrapped = true;
        window.switchModule = wrapped;
    }

    const obs = new MutationObserver(() => {
        if (!p64_visible()) return;
        clearTimeout(window._p64DomTimer);
        window._p64DomTimer = setTimeout(() => {
            if (!document.getElementById(P64_ID)) p64_render();
        }, 500);
    });

    window.thurayaPhase64Render = p64_render;

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => {
            try { obs.observe(document.body, { childList:true, subtree:true }); } catch(e) {}
            setTimeout(p64_boot, 1200);
        });
    } else {
        try { obs.observe(document.body, { childList:true, subtree:true }); } catch(e) {}
        setTimeout(p64_boot, 1200);
    }

    console.log("Thuraya Phase 6.4 AI Action Layer loaded");
})();
// ============================================================================
// END THURAYA PHASE 6.4 — AI ACTION LAYER
// ============================================================================

// ============================================================================
// THURAYA PHASE 6.5 — ASSISTED ACTIONS
// Turns AI Action Layer buttons into guided execution:
// - Opens target modules safely using switchModule
// - Stores best service / top client / top technician as global action context
// - Attempts to pre-fill relevant search/input fields where available
// - Adds graceful fallbacks if target module IDs differ
// ============================================================================
(function () {
    function a65_log(...args) {
        console.log("[Thuraya 6.5 Assisted Actions]", ...args);
    }

    function a65_text(v) {
        return String(v || "").trim();
    }

    function a65_findButtonByText(text) {
        const t = String(text || "").toLowerCase();
        return Array.from(document.querySelectorAll("button, .nav-btn, label, [role='button']"))
            .find(el => String(el.textContent || "").toLowerCase().includes(t));
    }

    function a65_openModule(possibleIds, possibleButtonTexts = []) {
        const ids = Array.isArray(possibleIds) ? possibleIds : [possibleIds];

        for (const id of ids) {
            if (!id) continue;
            try {
                if (typeof window.switchModule === "function") {
                    window.switchModule(id);
                    a65_log("Opened module via switchModule:", id);
                    return true;
                }
            } catch (e) {
                console.warn("switchModule failed for", id, e);
            }
        }

        for (const txt of possibleButtonTexts) {
            const btn = a65_findButtonByText(txt);
            if (btn) {
                btn.click();
                a65_log("Opened module via button text:", txt);
                return true;
            }
        }

        console.warn("Could not open module:", possibleIds, possibleButtonTexts);
        return false;
    }

    function a65_prefillAny(selectors, value) {
        if (!value) return false;
        for (const sel of selectors) {
            const el = document.querySelector(sel);
            if (el) {
                el.value = value;
                el.dispatchEvent(new Event("input", { bubbles: true }));
                el.dispatchEvent(new Event("change", { bubbles: true }));
                return true;
            }
        }
        return false;
    }

    function a65_clickSearchNearInput(value) {
        const input = document.activeElement;
        if (!input) return;
        const root = input.closest(".module-box, .card, section, div") || document;
        const btn = Array.from(root.querySelectorAll("button"))
            .find(b => String(b.textContent || "").toLowerCase().includes("search"));
        if (btn) setTimeout(() => btn.click(), 250);
    }

    function a65_setContext(ctx = {}) {
        window.ThurayaAIContext = {
            ...(window.ThurayaAIContext || {}),
            ...ctx,
            updatedAt: new Date().toISOString()
        };

        window.bestService = window.ThurayaAIContext.bestService || window.bestService || "";
        window.topClient = window.ThurayaAIContext.topClient || window.topClient || "";
        window.topTech = window.ThurayaAIContext.topTech || window.topTech || "";
        window.topRevenueWindow = window.ThurayaAIContext.topRevenueWindow || window.topRevenueWindow || "";
    }

    window.ThurayaActions = {
        openSalesPromo() {
            const ctx = window.ThurayaAIContext || {};
            const service = ctx.bestService || window.bestService || "";

            a65_openModule(
                ["salesPromoView", "salesPromo", "promoView", "salesView"],
                ["Sales & Promo", "Sales", "Promo"]
            );

            setTimeout(() => {
                a65_prefillAny([
                    "#promo_service",
                    "#promoService",
                    "#salesPromoService",
                    "input[name='promo_service']",
                    "input[placeholder*='service' i]",
                    "input[placeholder*='coupon' i]",
                    "textarea"
                ], service);

                a65_log("Prepared Sales & Promo for service:", service);
            }, 600);
        },

        openClientIntel() {
            const ctx = window.ThurayaAIContext || {};
            const client = ctx.topClient || window.topClient || "";

            a65_openModule(
                ["clientIntelView", "clientIntel", "clientIntelligenceView"],
                ["Client Intel", "Client Intelligence"]
            );

            setTimeout(() => {
                const filled = a65_prefillAny([
                    "#cip_searchInput",
                    "#clientIntelSearch",
                    "#clientSearchInput",
                    "#clientSearch",
                    "input[placeholder*='client' i]",
                    "input[type='search']"
                ], client);

                if (filled) {
                    const input = document.querySelector("#cip_searchInput, #clientIntelSearch, #clientSearchInput, #clientSearch, input[placeholder*='client' i], input[type='search']");
                    if (input) {
                        input.focus();
                        const root = input.closest(".module-box, .card, section, div") || document;
                        const btn = Array.from(root.querySelectorAll("button"))
                            .find(b => String(b.textContent || "").toLowerCase().includes("search"));
                        if (btn) setTimeout(() => btn.click(), 300);
                    }
                }

                a65_log("Prepared Client Intel for:", client);
            }, 700);
        },

        openHRFinance() {
            const ctx = window.ThurayaAIContext || {};
            const tech = ctx.topTech || window.topTech || "";

            a65_openModule(
                ["hrFinanceView", "hrFinance", "financeView"],
                ["HR & Finance", "Finance"]
            );

            setTimeout(() => {
                a65_prefillAny([
                    "#hrSearch",
                    "#staffSearch",
                    "#techSearch",
                    "input[placeholder*='staff' i]",
                    "input[placeholder*='tech' i]",
                    "input[type='search']"
                ], tech);

                a65_log("Prepared HR & Finance for technician:", tech);
            }, 700);
        },

        openServiceMenu() {
            const ctx = window.ThurayaAIContext || {};
            const service = ctx.bestService || window.bestService || "";

            a65_openModule(
                ["menuView", "serviceMenuView", "servicesView"],
                ["Service Menu", "Menu"]
            );

            setTimeout(() => {
                a65_prefillAny([
                    "#menuSearch",
                    "#serviceSearch",
                    "input[placeholder*='service' i]",
                    "input[placeholder*='menu' i]",
                    "input[type='search']"
                ], service);

                // Light visual highlight of matching service text if present.
                const serviceLower = service.toLowerCase();
                if (serviceLower) {
                    Array.from(document.querySelectorAll("td, div, span, p, strong"))
                        .filter(el => String(el.textContent || "").toLowerCase().includes(serviceLower))
                        .slice(0, 5)
                        .forEach(el => {
                            el.style.outline = "2px solid var(--accent)";
                            el.style.borderRadius = "8px";
                            el.style.padding = el.style.padding || "2px";
                            setTimeout(() => { el.style.outline = ""; }, 3500);
                        });
                }

                a65_log("Prepared Service Menu for:", service);
            }, 700);
        },

        openReports() {
            a65_openModule(
                ["reportsView", "reports", "reportsPanel"],
                ["Reports"]
            );
            a65_log("Opened Reports");
        }
    };

    function a65_replaceActionButtons() {
        const layer = document.getElementById("phase64AiActionLayer");
        if (!layer || layer._a65Bound) return;

        const buttonMap = [
            { contains: "open sales", handler: "ThurayaActions.openSalesPromo()" },
            { contains: "open client", handler: "ThurayaActions.openClientIntel()" },
            { contains: "open hr", handler: "ThurayaActions.openHRFinance()" },
            { contains: "open service", handler: "ThurayaActions.openServiceMenu()" },
            { contains: "open reports", handler: "ThurayaActions.openReports()" }
        ];

        Array.from(layer.querySelectorAll("button")).forEach(btn => {
            const txt = String(btn.textContent || "").toLowerCase();
            const match = buttonMap.find(m => txt.includes(m.contains));
            if (match) {
                btn.setAttribute("onclick", match.handler);
                btn.addEventListener("click", function (e) {
                    e.preventDefault();
                    try {
                        Function(match.handler)();
                    } catch (err) {
                        console.error("Assisted action failed:", match.handler, err);
                    }
                });
            }
        });

        layer._a65Bound = true;
        a65_log("AI Action buttons connected");
    }

    function a65_extractContextFromLayer() {
        const layer = document.getElementById("phase64AiActionLayer");
        if (!layer) return;

        const text = layer.textContent || "";

        // Best service: look for "Push X as the primary upsell" or "Top revenue service".
        let bestService = "";
        const pushMatch = text.match(/Push\s+(.+?)\s+as the primary upsell/i);
        if (pushMatch) bestService = pushMatch[1].trim();

        // Top client: "X is the top client by revenue"
        let topClient = "";
        const clientMatch = text.match(/([A-Za-z0-9 .&'-]+)\s+is the top client by revenue/i);
        if (clientMatch) topClient = clientMatch[1].trim();

        // Top tech: "X is currently the strongest revenue technician"
        let topTech = "";
        const techMatch = text.match(/([A-Za-z0-9 .&'-]+)\s+is currently the strongest revenue technician/i);
        if (techMatch) topTech = techMatch[1].trim();

        // Revenue window
        let topRevenueWindow = "";
        const windowMatch = text.match(/Strongest revenue window is\s+([A-Za-z]+)/i);
        if (windowMatch) topRevenueWindow = windowMatch[1].trim();

        a65_setContext({ bestService, topClient, topTech, topRevenueWindow });
    }

    function a65_boot() {
        a65_extractContextFromLayer();
        a65_replaceActionButtons();
    }

    const obs = new MutationObserver(() => {
        clearTimeout(window._a65Timer);
        window._a65Timer = setTimeout(a65_boot, 250);
    });

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => {
            try { obs.observe(document.body, { childList: true, subtree: true }); } catch(e) {}
            setTimeout(a65_boot, 1000);
        });
    } else {
        try { obs.observe(document.body, { childList: true, subtree: true }); } catch(e) {}
        setTimeout(a65_boot, 1000);
    }

    console.log("Thuraya Phase 6.5 Assisted Actions loaded");
})();
// ============================================================================
// END THURAYA PHASE 6.5 — ASSISTED ACTIONS
// ============================================================================

// ============================================================================
// THURAYA PHASE 6.5B — ASSISTED ACTIONS NAVIGATION FIX
// Fixes navigation crash caused by older wrapped switchModule handlers trying
// to access .style on missing DOM elements.
// Strategy:
// - Use visible nav buttons first (most reliable in this custom UI)
// - Fall back to switchModule only when button click is unavailable
// - Catch navigation errors so UI never blanks
// ============================================================================
(function () {
    function n65b_log(...args) {
        console.log("[Thuraya 6.5B Nav Fix]", ...args);
    }

    function n65b_norm(s) {
        return String(s || "").replace(/\s+/g, " ").trim().toLowerCase();
    }

    function n65b_findNavButton(label) {
        const wanted = n65b_norm(label);
        const candidates = Array.from(document.querySelectorAll("button, .nav-btn, .tab-btn, [role='button'], label"))
            .filter(el => {
                const txt = n65b_norm(el.textContent);
                return txt && (txt === wanted || txt.includes(wanted));
            });

        // Prefer visible buttons
        return candidates.find(el => el.offsetParent !== null) || candidates[0] || null;
    }

    function n65b_safeClick(label) {
        const btn = n65b_findNavButton(label);
        if (!btn) return false;

        try {
            btn.click();
            n65b_log("Clicked nav button:", label);
            return true;
        } catch (e) {
            console.warn("Nav click failed:", label, e);
            return false;
        }
    }

    function n65b_safeSwitch(ids) {
        if (typeof window.switchModule !== "function") return false;
        const list = Array.isArray(ids) ? ids : [ids];

        for (const id of list) {
            try {
                window.switchModule(id);
                n65b_log("switchModule success:", id);
                return true;
            } catch (e) {
                console.warn("switchModule failed:", id, e);
            }
        }
        return false;
    }

    function n65b_open(label, ids) {
        // Button click first, because it uses the app's real wiring.
        if (n65b_safeClick(label)) return true;

        // Fallback to module IDs.
        return n65b_safeSwitch(ids);
    }

    function n65b_prefill(selectors, value) {
        if (!value) return;
        for (const sel of selectors) {
            const el = document.querySelector(sel);
            if (el) {
                el.value = value;
                el.dispatchEvent(new Event("input", { bubbles: true }));
                el.dispatchEvent(new Event("change", { bubbles: true }));
                return el;
            }
        }
        return null;
    }

    function n65b_searchClickNear(el) {
        if (!el) return;
        const root = el.closest(".module-box, .card, section, div") || document;
        const btn = Array.from(root.querySelectorAll("button"))
            .find(b => n65b_norm(b.textContent).includes("search"));
        if (btn) setTimeout(() => btn.click(), 250);
    }

    // Override Phase 6.5 actions with crash-safe navigation.
    window.ThurayaActions = {
        openSalesPromo() {
            const ctx = window.ThurayaAIContext || {};
            const service = ctx.bestService || window.bestService || "";

            n65b_open("Sales & Promo", ["salesPromoView", "salesPromo", "promoView", "salesView"]);

            setTimeout(() => {
                n65b_prefill([
                    "#promo_service",
                    "#promoService",
                    "#salesPromoService",
                    "input[name='promo_service']",
                    "input[placeholder*='service' i]",
                    "input[placeholder*='coupon' i]"
                ], service);
                n65b_log("Sales & Promo prepared:", service);
            }, 600);
        },

        openClientIntel() {
            const ctx = window.ThurayaAIContext || {};
            const client = ctx.topClient || window.topClient || "";

            n65b_open("Client Intel", ["clientIntelView", "clientIntel", "clientIntelligenceView"]);

            setTimeout(() => {
                const el = n65b_prefill([
                    "#cip_searchInput",
                    "#clientIntelSearch",
                    "#clientSearchInput",
                    "#clientSearch",
                    "input[placeholder*='client' i]",
                    "input[type='search']"
                ], client);
                if (el) {
                    el.focus();
                    n65b_searchClickNear(el);
                }
                n65b_log("Client Intel prepared:", client);
            }, 700);
        },

        openHRFinance() {
            const ctx = window.ThurayaAIContext || {};
            const tech = ctx.topTech || window.topTech || "";

            n65b_open("HR & Finance", ["hrFinanceView", "hrFinance", "financeView"]);

            setTimeout(() => {
                n65b_prefill([
                    "#hrSearch",
                    "#staffSearch",
                    "#techSearch",
                    "input[placeholder*='staff' i]",
                    "input[placeholder*='tech' i]",
                    "input[type='search']"
                ], tech);
                n65b_log("HR & Finance prepared:", tech);
            }, 700);
        },

        openServiceMenu() {
            const ctx = window.ThurayaAIContext || {};
            const service = ctx.bestService || window.bestService || "";

            n65b_open("Service Menu", ["menuView", "serviceMenuView", "servicesView"]);

            setTimeout(() => {
                n65b_prefill([
                    "#menuSearch",
                    "#serviceSearch",
                    "input[placeholder*='service' i]",
                    "input[placeholder*='menu' i]",
                    "input[type='search']"
                ], service);
                n65b_log("Service Menu prepared:", service);
            }, 700);
        },

        openReports() {
            n65b_open("Reports", ["reportsView", "reports", "reportsPanel"]);
        }
    };

    function n65b_rebindButtons() {
        const layer = document.getElementById("phase64AiActionLayer");
        if (!layer) return;

        const map = [
            ["open sales", "ThurayaActions.openSalesPromo()"],
            ["open client", "ThurayaActions.openClientIntel()"],
            ["open hr", "ThurayaActions.openHRFinance()"],
            ["open service", "ThurayaActions.openServiceMenu()"],
            ["open reports", "ThurayaActions.openReports()"]
        ];

        Array.from(layer.querySelectorAll("button")).forEach(btn => {
            const txt = n65b_norm(btn.textContent);
            const hit = map.find(([k]) => txt.includes(k));
            if (!hit || btn._n65bBound) return;

            btn.onclick = function (e) {
                e.preventDefault();
                e.stopPropagation();
                try {
                    Function(hit[1])();
                } catch (err) {
                    console.error("Assisted action failed:", hit[1], err);
                }
            };
            btn._n65bBound = true;
        });
    }

    const obs = new MutationObserver(() => {
        clearTimeout(window._n65bTimer);
        window._n65bTimer = setTimeout(n65b_rebindButtons, 250);
    });

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => {
            try { obs.observe(document.body, { childList: true, subtree: true }); } catch(e) {}
            setTimeout(n65b_rebindButtons, 1000);
        });
    } else {
        try { obs.observe(document.body, { childList: true, subtree: true }); } catch(e) {}
        setTimeout(n65b_rebindButtons, 1000);
    }

    console.log("Thuraya Phase 6.5B Assisted Actions Navigation Fix loaded");
})();
