// ============================================================================
// THURAYA PHASE 6.5C — ASSISTED ACTIONS POLISH
// Premium UX layer:
// - Shows "AI is preparing..." toast/overlay feedback
// - Auto-searches Client Intel after navigation
// - Prepares Sales & Promo with service + suggested discount context
// - Scrolls and highlights Service Menu matches
// - Adds guided action notes on destination pages
// ============================================================================
(function () {
    const P65C_NOTE_ID = "thurayaActionPrepNote";

    function p65c_norm(s) {
        return String(s || "").replace(/\s+/g, " ").trim();
    }

    function p65c_lower(s) {
        return p65c_norm(s).toLowerCase();
    }

    function p65c_toast(message, type = "info") {
        try {
            if (typeof toast === "function") {
                toast(message, type, 3000);
                return;
            }
        } catch(e) {}

        let box = document.getElementById("thurayaAiToastBox");
        if (!box) {
            box = document.createElement("div");
            box.id = "thurayaAiToastBox";
            box.style.cssText = `
                position:fixed; right:24px; bottom:24px; z-index:999999;
                display:flex; flex-direction:column; gap:8px; max-width:360px;
            `;
            document.body.appendChild(box);
        }

        const colors = {
            info: "#2c3e50",
            success: "#27ae60",
            warning: "#b7950b",
            error: "#c0392b"
        };
        const item = document.createElement("div");
        item.style.cssText = `
            background:${colors[type] || colors.info}; color:white;
            padding:12px 14px; border-radius:12px;
            box-shadow:0 6px 24px rgba(0,0,0,.18);
            font-weight:800; font-size:.85rem; line-height:1.4;
        `;
        item.textContent = message;
        box.appendChild(item);
        setTimeout(() => item.remove(), 3200);
    }

    function p65c_context() {
        return {
            ...(window.ThurayaAIContext || {}),
            bestService: window.ThurayaAIContext?.bestService || window.bestService || "",
            topClient: window.ThurayaAIContext?.topClient || window.topClient || "",
            topTech: window.ThurayaAIContext?.topTech || window.topTech || "",
            topRevenueWindow: window.ThurayaAIContext?.topRevenueWindow || window.topRevenueWindow || ""
        };
    }

    function p65c_note(title, body) {
        const activePanel =
            document.querySelector("#salesPromoView[style*='block'], #clientIntelView[style*='block'], #hrFinanceView[style*='block'], #menuView[style*='block'], #reportsView[style*='block']") ||
            document.querySelector(".module-view:not([style*='display: none'])") ||
            document.querySelector("[id$='View']:not([style*='display: none'])");

        const root = activePanel || document.querySelector("main") || document.body;

        let note = document.getElementById(P65C_NOTE_ID);
        if (note) note.remove();

        note = document.createElement("div");
        note.id = P65C_NOTE_ID;
        note.style.cssText = `
            background:#fffaf0; border:1px solid var(--accent,#b7950b);
            border-left:5px solid var(--accent,#b7950b);
            border-radius:12px; padding:14px 16px; margin:14px 0;
            box-shadow:0 3px 14px rgba(0,0,0,.06);
            color:var(--primary,#2c3e50);
        `;
        note.innerHTML = `
            <strong style="display:block;font-size:1rem;margin-bottom:4px;">🤖 ${title}</strong>
            <div style="font-size:.86rem;color:#555;line-height:1.55;">${body}</div>
        `;

        root.prepend(note);
        note.scrollIntoView({ behavior: "smooth", block: "start" });

        setTimeout(() => {
            if (note && note.parentNode) {
                note.style.transition = "opacity .4s ease";
                note.style.opacity = ".72";
            }
        }, 4500);
    }

    function p65c_prefill(selectors, value) {
        if (!value) return null;
        for (const sel of selectors) {
            const el = document.querySelector(sel);
            if (!el) continue;
            el.value = value;
            el.dispatchEvent(new Event("input", { bubbles: true }));
            el.dispatchEvent(new Event("change", { bubbles: true }));
            return el;
        }
        return null;
    }

    function p65c_clickSearchNear(el) {
        if (!el) return false;
        const root = el.closest(".module-box, .card, section, form, div") || document;
        const btn = Array.from(root.querySelectorAll("button"))
            .find(b => p65c_lower(b.textContent).includes("search"));
        if (btn) {
            setTimeout(() => btn.click(), 350);
            return true;
        }
        return false;
    }

    function p65c_highlightTextMatch(text) {
        const target = p65c_lower(text);
        if (!target) return false;

        const matches = Array.from(document.querySelectorAll("td, th, div, span, p, strong, label"))
            .filter(el => {
                const t = p65c_lower(el.textContent);
                return t && t.includes(target) && el.offsetParent !== null;
            })
            .slice(0, 8);

        if (!matches.length) return false;

        matches.forEach((el, idx) => {
            el.style.outline = "3px solid var(--accent,#b7950b)";
            el.style.outlineOffset = "3px";
            el.style.borderRadius = "8px";
            el.style.background = "rgba(183,149,11,.08)";
            if (idx === 0) el.scrollIntoView({ behavior: "smooth", block: "center" });
            setTimeout(() => {
                el.style.outline = "";
                el.style.outlineOffset = "";
                el.style.background = "";
            }, 5000);
        });

        return true;
    }

    function p65c_suggestDiscount(ctx) {
        const win = p65c_lower(ctx.topRevenueWindow);
        // Do not discount strongest window. Suggest weak-period promo.
        if (win.includes("morning")) return "10% for afternoon/evening slow slots";
        if (win.includes("afternoon")) return "10% for morning/evening slow slots";
        if (win.includes("evening")) return "10% for morning/afternoon slow slots";
        return "10% slow-period promo";
    }

    const previousActions = window.ThurayaActions || {};

    window.ThurayaActions = {
        ...previousActions,

        openSalesPromo() {
            const ctx = p65c_context();
            const service = ctx.bestService || "top service";
            const discount = p65c_suggestDiscount(ctx);

            p65c_toast("Preparing Sales & Promo strategy…", "info");

            try {
                if (previousActions.openSalesPromo) previousActions.openSalesPromo();
                else if (typeof switchModule === "function") switchModule("salesPromoView");
            } catch(e) {
                console.warn("Sales & Promo assisted action navigation failed", e);
            }

            setTimeout(() => {
                p65c_prefill([
                    "#promo_service",
                    "#promoService",
                    "#salesPromoService",
                    "#promoCodeService",
                    "input[name='promo_service']",
                    "input[placeholder*='service' i]",
                    "input[placeholder*='coupon' i]"
                ], service);

                p65c_prefill([
                    "#promoDiscount",
                    "#discountValue",
                    "#promo_value",
                    "input[placeholder*='discount' i]",
                    "input[placeholder*='value' i]"
                ], "10");

                p65c_note(
                    "Sales strategy prepared",
                    `Recommended focus: <strong>${service}</strong>. Suggested offer: <strong>${discount}</strong>. Avoid discounting your strongest revenue window: <strong>${ctx.topRevenueWindow || "current peak period"}</strong>.`
                );

                p65c_highlightTextMatch(service);
                p65c_toast("Sales & Promo prepared.", "success");
            }, 850);
        },

        openClientIntel() {
            const ctx = p65c_context();
            const client = ctx.topClient || "";

            p65c_toast("Loading Client Intelligence…", "info");

            try {
                if (previousActions.openClientIntel) previousActions.openClientIntel();
                else if (typeof switchModule === "function") switchModule("clientIntelView");
            } catch(e) {
                console.warn("Client Intel assisted action navigation failed", e);
            }

            setTimeout(() => {
                const el = p65c_prefill([
                    "#cip_searchInput",
                    "#clientIntelSearch",
                    "#clientSearchInput",
                    "#clientSearch",
                    "input[placeholder*='client' i]",
                    "input[type='search']"
                ], client);

                if (el) {
                    el.focus();
                    p65c_clickSearchNear(el);
                }

                p65c_note(
                    "Client retention action ready",
                    `Focus client: <strong>${client || "top client"}</strong>. Review their visit history and consider a personal retention note, package offer, or preferred-technician rebooking path.`
                );

                p65c_toast("Client Intel prepared.", "success");
            }, 900);
        },

        openHRFinance() {
            const ctx = p65c_context();
            const tech = ctx.topTech || "";

            p65c_toast("Preparing technician performance focus…", "info");

            try {
                if (previousActions.openHRFinance) previousActions.openHRFinance();
                else if (typeof switchModule === "function") switchModule("hrFinanceView");
            } catch(e) {
                console.warn("HR & Finance assisted action navigation failed", e);
            }

            setTimeout(() => {
                const el = p65c_prefill([
                    "#hrSearch",
                    "#staffSearch",
                    "#techSearch",
                    "input[placeholder*='staff' i]",
                    "input[placeholder*='tech' i]",
                    "input[type='search']"
                ], tech);

                if (el) el.focus();
                p65c_highlightTextMatch(tech);

                p65c_note(
                    "Technician signal prepared",
                    `<strong>${tech || "Top technician"}</strong> is the current strongest revenue technician. Use this for coaching benchmarks, premium booking routing, or performance comparison.`
                );

                p65c_toast("HR & Finance prepared.", "success");
            }, 850);
        },

        openServiceMenu() {
            const ctx = p65c_context();
            const service = ctx.bestService || "";

            p65c_toast("Opening service optimization view…", "info");

            try {
                if (previousActions.openServiceMenu) previousActions.openServiceMenu();
                else if (typeof switchModule === "function") switchModule("menuView");
            } catch(e) {
                console.warn("Service Menu assisted action navigation failed", e);
            }

            setTimeout(() => {
                const el = p65c_prefill([
                    "#menuSearch",
                    "#serviceSearch",
                    "input[placeholder*='service' i]",
                    "input[placeholder*='menu' i]",
                    "input[type='search']"
                ], service);

                if (el) el.focus();
                const highlighted = p65c_highlightTextMatch(service);

                p65c_note(
                    "Service optimization prepared",
                    `Review <strong>${service || "your top service"}</strong> for pricing, bundle placement, upsell visibility, and staff delivery consistency.${highlighted ? " The matching service has been highlighted." : ""}`
                );

                p65c_toast("Service Menu prepared.", "success");
            }, 900);
        },

        openReports() {
            p65c_toast("Opening owner report view…", "info");

            try {
                if (previousActions.openReports) previousActions.openReports();
                else if (typeof switchModule === "function") switchModule("reportsView");
            } catch(e) {
                console.warn("Reports assisted action navigation failed", e);
            }

            setTimeout(() => {
                p65c_note(
                    "Owner summary context",
                    "Review revenue records, average ticket, closed jobs, and weekly/monthly trend to validate the AI recommendations."
                );
                p65c_toast("Reports prepared.", "success");
            }, 750);
        }
    };

    function p65c_bindLayerButtons() {
        const layer = document.getElementById("phase64AiActionLayer");
        if (!layer) return;

        const map = [
            ["open sales", "openSalesPromo"],
            ["open client", "openClientIntel"],
            ["open hr", "openHRFinance"],
            ["open service", "openServiceMenu"],
            ["open reports", "openReports"]
        ];

        Array.from(layer.querySelectorAll("button")).forEach(btn => {
            const txt = p65c_lower(btn.textContent);
            const hit = map.find(([needle]) => txt.includes(needle));
            if (!hit || btn._p65cBound) return;

            btn.onclick = function(e) {
                e.preventDefault();
                e.stopPropagation();
                window.ThurayaActions[hit[1]]();
            };
            btn._p65cBound = true;
        });
    }

    const obs = new MutationObserver(() => {
        clearTimeout(window._p65cTimer);
        window._p65cTimer = setTimeout(p65c_bindLayerButtons, 300);
    });

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", () => {
            try { obs.observe(document.body, { childList:true, subtree:true }); } catch(e) {}
            setTimeout(p65c_bindLayerButtons, 1000);
        });
    } else {
        try { obs.observe(document.body, { childList:true, subtree:true }); } catch(e) {}
        setTimeout(p65c_bindLayerButtons, 1000);
    }

    console.log("Thuraya Phase 6.5C Assisted Actions Polish loaded");
})();
// ============================================================================
// END THURAYA PHASE 6.5C — ASSISTED ACTIONS POLISH
