// ============================================================================
// THURAYA CLIENT EXPERIENCE — PHASE 1
// Staff-side CMS for Client App content: Selfcare, Info, Loyalty, Promo.
// Safe append-only module. Requires Firebase Storage SDK already loaded.
// ============================================================================
let cxExperienceListener = null;
let cxExperienceFilter = 'all';
let cxExperienceDocsCache = [];

function cx_safeText(value) {
    return String(value || '').replace(/[&<>"']/g, function (m) {
        return ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#039;' })[m];
    });
}

function cx_formatDate(ts) {
    try {
        if (!ts) return '—';
        const d = typeof ts.toDate === 'function' ? ts.toDate() : new Date(ts);
        return d.toLocaleString();
    } catch(e) { return '—'; }
}

function cx_setMsg(message, isError) {
    const msg = document.getElementById('cx_uploadMsg');
    if (!msg) return;
    msg.innerText = message || '';
    msg.style.color = isError ? 'var(--error)' : '#777';
}

window.setClientExperienceFilter = function(category) {
    cxExperienceFilter = category || 'all';
    document.querySelectorAll('.cx-chip').forEach(btn => {
        btn.classList.toggle('active', btn.getAttribute('data-cx-filter') === cxExperienceFilter);
    });
    renderClientExperienceList();
};

function renderClientExperienceList() {
    const container = document.getElementById('cx_list');
    if (!container) return;

    const docs = cxExperienceDocsCache.filter(d => cxExperienceFilter === 'all' || d.category === cxExperienceFilter);
    if (!docs.length) {
        container.innerHTML = '<div class="cx-empty">No documents found for this section.</div>';
        return;
    }

    container.innerHTML = docs.map(d => {
        const statusClass = d.visibleToClient === false ? 'hidden' : 'active';
        const statusText = d.visibleToClient === false ? 'Hidden' : 'Visible';
        const fileName = d.fileName || 'Uploaded file';
        const fileType = d.fileType || d.contentType || '';
        const category = (d.category || 'info').toUpperCase();
        return `
            <div class="cx-doc">
                <div>
                    <div class="cx-doc-title">${cx_safeText(d.title)} <span class="cx-status ${statusClass}">${statusText}</span></div>
                    <div class="cx-doc-meta">
                        ${category} · ${cx_safeText(fileName)}${fileType ? ' · ' + cx_safeText(fileType) : ''}<br>
                        ${d.description ? cx_safeText(d.description) + '<br>' : ''}
                        Updated: ${cx_formatDate(d.updatedAt || d.createdAt)} · By: ${cx_safeText(d.updatedBy || d.createdBy || '—')}
                    </div>
                </div>
                <div class="cx-doc-actions">
                    <button type="button" class="btn btn-secondary cx-btn-small" onclick="window.open('${d.fileUrl || '#'}','_blank')">View</button>
                    <button type="button" class="btn btn-secondary cx-btn-small" onclick="toggleClientExperienceVisibility('${d.id}', ${d.visibleToClient === false})">${d.visibleToClient === false ? 'Show' : 'Hide'}</button>
                    <button type="button" class="btn cx-btn-small" style="background:var(--error);" onclick="archiveClientExperience('${d.id}')">Archive</button>
                </div>
            </div>`;
    }).join('');
}

window.loadClientExperience = function(forceRefresh) {
    const container = document.getElementById('cx_list');
    if (!container && !forceRefresh) return;

    if (cxExperienceListener && !forceRefresh) {
        renderClientExperienceList();
        return;
    }

    if (cxExperienceListener && forceRefresh) {
        try { cxExperienceListener(); } catch(e) {}
        cxExperienceListener = null;
    }

    if (!window.db) {
        if (container) container.innerHTML = '<div class="cx-empty">Database is not ready yet.</div>';
        return;
    }

    if (container) container.innerHTML = '<div class="cx-empty">Loading client experience library...</div>';

    cxExperienceListener = db.collection('Client_Experience')
        .where('archived', '!=', true)
        .onSnapshot(snapshot => {
            cxExperienceDocsCache = [];
            snapshot.forEach(doc => cxExperienceDocsCache.push({ id: doc.id, ...doc.data() }));
            cxExperienceDocsCache.sort((a, b) => {
                const ad = a.updatedAt?.toMillis ? a.updatedAt.toMillis() : (a.createdAt?.toMillis ? a.createdAt.toMillis() : 0);
                const bd = b.updatedAt?.toMillis ? b.updatedAt.toMillis() : (b.createdAt?.toMillis ? b.createdAt.toMillis() : 0);
                return bd - ad;
            });
            renderClientExperienceList();
        }, error => {
            console.error('Client Experience listener failed', error);
            if (container) container.innerHTML = `<div class="cx-empty" style="color:var(--error);">Could not load documents: ${cx_safeText(error.message)}</div>`;
        });
};

window.uploadClientExperience = async function() {
    const fileEl = document.getElementById('cx_file');
    const titleEl = document.getElementById('cx_title');
    const descEl = document.getElementById('cx_description');
    const catEl = document.getElementById('cx_category');
    const visibleEl = document.getElementById('cx_visible');
    const externalUrlEl = document.getElementById('cx_externalUrl');

    const file = fileEl?.files?.[0];
    const externalUrl = (externalUrlEl?.value || '').trim();
    const title = (titleEl?.value || '').trim();
    const description = (descEl?.value || '').trim();
    const category = catEl?.value || 'info';
    const visibleToClient = visibleEl ? visibleEl.checked : true;

    if (!title) {
        alert('Enter a document title.');
        return;
    }

    if (!file && !externalUrl) {
        alert('Choose a PDF/image file OR paste a document link.');
        return;
    }

    const uploadBtn = document.querySelector('button[onclick="uploadClientExperience()"]');

    try {
        if (uploadBtn) {
            uploadBtn.disabled = true;
            uploadBtn.innerText = externalUrl && !file ? 'SAVING LINK...' : 'UPLOADING...';
        }

        let fileUrl = externalUrl;
        let storagePath = '';
        let fileName = '';
        let fileType = 'external-link';
        let fileSize = 0;
        let sourceType = externalUrl && !file ? 'external_link' : 'firebase_storage';

        if (externalUrl && !file) {
            if (!/^https?:\/\//i.test(externalUrl)) {
                throw new Error('Document link must start with http:// or https://');
            }

            cx_setMsg('Saving document link...', false);

        } else {
            const maxSize = 10 * 1024 * 1024;
            if (file.size > maxSize) {
                throw new Error('File is too large. Please keep uploads under 10MB, or paste a public document link instead.');
            }

            if (!firebase.storage) {
                throw new Error('Firebase Storage SDK is not loaded. Paste a public document link instead.');
            }

            cx_setMsg('Preparing upload...', false);

            try {
                firebase.storage().setMaxUploadRetryTime(600000);
                firebase.storage().setMaxOperationRetryTime(600000);
            } catch(e) {}

            const ext = (file.name.split('.').pop() || 'file').toLowerCase().replace(/[^a-z0-9]/g, '');
            const safeTitle = title.toLowerCase()
                .replace(/[^a-z0-9]+/g, '_')
                .replace(/^_+|_+$/g, '')
                .slice(0, 60) || 'document';

            const safeFileName = file.name
                .toLowerCase()
                .replace(/[^a-z0-9._-]+/g, '_')
                .slice(0, 90);

            const path = `client_experience/${category}/${safeTitle}_${Date.now()}_${safeFileName || ('file.' + ext)}`;
            const ref = firebase.storage().ref().child(path);

            const metadata = {
                contentType: file.type || (ext === 'pdf' ? 'application/pdf' : 'application/octet-stream'),
                customMetadata: {
                    category,
                    title,
                    uploadedBy: currentUserEmail || '',
                    originalName: file.name || ''
                }
            };

            const uploadTask = ref.put(file, metadata);

            const snapshot = await new Promise((resolve, reject) => {
                uploadTask.on(
                    'state_changed',
                    snap => {
                        const pct = snap.totalBytes ? Math.round((snap.bytesTransferred / snap.totalBytes) * 100) : 0;
                        cx_setMsg(`Uploading document... ${pct}%`, false);
                    },
                    error => reject(error),
                    () => resolve(uploadTask.snapshot)
                );
            });

            cx_setMsg('Finalizing upload...', false);

            fileUrl = await snapshot.ref.getDownloadURL();
            storagePath = path;
            fileName = file.name || '';
            fileType = file.type || '';
            fileSize = file.size || 0;
        }

        await db.collection('Client_Experience').add({
            title,
            description,
            category,
            fileUrl,
            storagePath,
            fileName,
            fileType,
            fileSize,
            sourceType,
            visibleToClient,
            archived: false,
            createdAt: firebase.firestore.FieldValue.serverTimestamp(),
            createdBy: currentUserEmail || '',
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: currentUserEmail || ''
        });

        if (titleEl) titleEl.value = '';
        if (descEl) descEl.value = '';
        if (fileEl) fileEl.value = '';
        if (externalUrlEl) externalUrlEl.value = '';
        if (visibleEl) visibleEl.checked = true;

        cx_setMsg(sourceType === 'external_link' ? 'Document link saved successfully.' : 'Document uploaded successfully.', false);
        if (typeof setClientExperienceFilter === 'function') setClientExperienceFilter(category);
        if (typeof loadClientExperience === 'function') loadClientExperience();

    } catch (e) {
        console.error('Client Experience save/upload failed', e);

        let friendly = e.message || String(e);
        if (e.code === 'storage/retry-limit-exceeded') {
            friendly = 'Firebase Storage upload timed out. Use the Document Link field as a fallback, or compress the PDF and try again.';
        } else if (e.code === 'storage/unauthorized') {
            friendly = 'Upload blocked by Firebase Storage rules. Use Document Link fallback or check Storage permissions.';
        } else if (e.code === 'storage/canceled') {
            friendly = 'Upload was cancelled.';
        }

        cx_setMsg('Upload failed: ' + friendly, true);
        alert('Upload failed: ' + friendly);

    } finally {
        if (uploadBtn) {
            uploadBtn.disabled = false;
            uploadBtn.innerText = 'UPLOAD DOCUMENT';
        }
    }
};

window.toggleClientExperienceVisibility = async function(id, currentlyHidden) {
    if (!id) return;
    try {
        await db.collection('Client_Experience').doc(id).set({
            visibleToClient: currentlyHidden,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: currentUserEmail || ''
        }, { merge:true });
    } catch(e) {
        console.error('Visibility update failed', e);
        alert('Could not update visibility: ' + e.message);
    }
};

window.archiveClientExperience = async function(id) {
    if (!id) return;
    if (!confirm('Archive this client experience document? It will be hidden from the library and client app.')) return;
    try {
        await db.collection('Client_Experience').doc(id).set({
            archived: true,
            visibleToClient: false,
            archivedAt: firebase.firestore.FieldValue.serverTimestamp(),
            archivedBy: currentUserEmail || '',
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: currentUserEmail || ''
        }, { merge:true });
    } catch(e) {
        console.error('Archive failed', e);
        alert('Could not archive document: ' + e.message);
    }
};

// Ensure opening the new module starts the listener even when switchModule is wrapped by other patches.
(function patchClientExperienceSwitch(){
    const oldSwitch = window.switchModule;
    if (typeof oldSwitch === 'function' && !window.__cxSwitchPatched) {
        window.switchModule = function(moduleId) {
            oldSwitch(moduleId);
            if (moduleId === 'clientExperienceView') setTimeout(() => loadClientExperience(), 100);
        };
        window.__cxSwitchPatched = true;
    }
})();



document.addEventListener('DOMContentLoaded', () => {
    try { setStaffPhotoPreview(''); } catch(e) {}
});



function setAdminDOBField(data) {
    const el = document.getElementById('admin_dateOfBirth');
    if (el) el.value = (data && data.dateOfBirth) ? data.dateOfBirth : '';
}



function getNextBirthdayInfo(dateOfBirth) {
    if (!dateOfBirth) return null;

    const today = new Date();
    const dob = new Date(dateOfBirth + 'T00:00:00');
    if (isNaN(dob.getTime())) return null;

    const next = new Date(today.getFullYear(), dob.getMonth(), dob.getDate());
    if (next < new Date(today.getFullYear(), today.getMonth(), today.getDate())) {
        next.setFullYear(today.getFullYear() + 1);
    }

    const diffDays = Math.ceil((next - new Date(today.getFullYear(), today.getMonth(), today.getDate())) / (1000 * 60 * 60 * 24));
    return {
        nextBirthday: next.toISOString().slice(0, 10),
        daysUntil: diffDays
    };
}




