// THURAYA STAFF — BILLING COMPLETED JOBS TAB
// Safe UI helper: separates Pending Checkouts from Completed Jobs.
// ============================================================
window.th_showBillingTab = function(tab){
    const pendingPane = document.getElementById('thBillingPendingPane');
    const completedPane = document.getElementById('thBillingCompletedPane');
    const pendingTab = document.getElementById('thBillingPendingTab');
    const completedTab = document.getElementById('thBillingCompletedTab');
    const showCompleted = tab === 'completed';

    if (pendingPane) pendingPane.style.display = showCompleted ? 'none' : '';
    if (completedPane) completedPane.style.display = showCompleted ? '' : 'none';

    pendingTab?.classList.toggle('active', !showCompleted);
    completedTab?.classList.toggle('active', showCompleted);

    if (showCompleted && typeof th_startReceiptHistoryListener === 'function') {
        setTimeout(() => th_startReceiptHistoryListener(false), 80);
    }
};

document.addEventListener('DOMContentLoaded', function(){
    setTimeout(() => {
        if (document.getElementById('thBillingPendingPane')) th_showBillingTab('pending');
    }, 500);
});
