// ============================================================
// THURAYA STAFF — RECEIPT REPRINT LAYER
// Reprint/resend closed-job receipts using the same stable receipt ref.
// Safe: does not change checkout accounting or job status.
// ============================================================
let th_receiptHistoryUnsub = null;

function th_receiptPayloadFromJob(job){
    const id = job.id || job.jobId || '';
    return {
        method: job.paymentMethod || job.paymentStatus || 'Paid',
        jobId: id,
        reference: job.receiptRef || th_receiptRef(id),
        isGroup: job.isGroupBooking === true || !!job.groupId,
        groupCount: job.groupSize || 1,
        clientName: job.clientName || job.recipientName || 'Client',
        clientEmail: job.clientEmail || job.bookedByEmail || job.email || '',
        clientPhone: job.clientPhone || job.phone || job.recipientPhone || job.Tel_Number || job.tel || job.clientTel || job.bookedByPhone || '',
        services: job.bookedService || job.services || '—',
        techName: job.assignedTechName || job.techName || '—',
        dateString: job.dateString || '',
        timeString: job.timeString || '',
        duration: job.bookedDuration || '',
        total: job.totalGHC || job.finalTotal || job.grandTotal || job.amountDue || job.bookedPrice || 0,
        subtotalText: (job.bookedPrice ? th_receiptMoney(job.bookedPrice) + ' GHC' : ''),
        taxHtml: '',
        jobs: [],
        closedBy: job.closedBy || job.receiptGeneratedBy || currentUserEmail || '',
        generatedAt: (job.receiptGeneratedAt && job.receiptGeneratedAt.toDate) ? job.receiptGeneratedAt.toDate() : (job.closedAt && job.closedAt.toDate ? job.closedAt.toDate() : new Date())
    };
}

window.th_reprintReceipt = function(jobId){
    if (!jobId) { alert('Receipt job reference missing.'); return; }
    db.collection('Active_Jobs').doc(jobId).get().then(doc => {
        if (!doc.exists) { alert('Receipt record not found.'); return; }
        const payload = th_receiptPayloadFromJob({ id: doc.id, ...doc.data() });
        const receiptWindow = window.open('', '_blank', 'width=460,height=760');
        if (!receiptWindow) { alert('Popup blocked. Please allow popups to reprint receipt.'); return; }
        receiptWindow.document.open();
        receiptWindow.document.write(th_receiptBuildHtml(payload));
        receiptWindow.document.close();
        receiptWindow.focus();
    }).catch(e => alert('Could not reprint receipt: ' + e.message));
};

window.th_whatsappReceipt = function(jobId){
    db.collection('Active_Jobs').doc(jobId).get().then(doc => {
        if (!doc.exists) { alert('Receipt record not found.'); return; }
        const payload = th_receiptPayloadFromJob({ id: doc.id, ...doc.data() });
        window.open(th_receiptWhatsAppUrl(payload), '_blank');
    }).catch(e => alert('Could not open WhatsApp receipt: ' + e.message));
};

window.th_emailReceipt = function(jobId){
    db.collection('Active_Jobs').doc(jobId).get().then(doc => {
        if (!doc.exists) { alert('Receipt record not found.'); return; }
        const payload = th_receiptPayloadFromJob({ id: doc.id, ...doc.data() });
        window.location.href = th_receiptMailto(payload);
    }).catch(e => alert('Could not open email receipt: ' + e.message));
};

function th_receiptHistoryCard(job){
    const payload = th_receiptPayloadFromJob(job);
    const div = document.createElement('div');
    div.className = 'th-receipt-history-card';
    div.innerHTML = `
        <div class="th-receipt-history-main">
            <div class="th-receipt-ref">${th_receiptSafe(payload.reference)}</div>
            <strong>${th_receiptSafe(payload.clientName)}</strong>
            <span>${th_receiptSafe(payload.services)}</span>
            <small>${th_receiptDate(payload.dateString)} · ${th_receiptTime(payload.timeString)} · ${th_receiptMoney(payload.total)} GHC</small>
        </div>
        <div class="th-receipt-history-actions">
            <button type="button" onclick="th_reprintReceipt('${th_receiptSafe(job.id)}')">Reprint</button>
            <button type="button" onclick="th_whatsappReceipt('${th_receiptSafe(job.id)}')">WhatsApp</button>
            <button type="button" onclick="th_emailReceipt('${th_receiptSafe(job.id)}')">Email</button>
        </div>`;
    return div;
}

window.th_startReceiptHistoryListener = function(forceRefresh){
    const lists = Array.from(document.querySelectorAll('.thReceiptHistoryList, #thReceiptHistoryList, #thReceiptHistoryListMain'));
    if (!lists.length) return;
    if (th_receiptHistoryUnsub && forceRefresh !== true) return;
    if (th_receiptHistoryUnsub && forceRefresh === true) { try { th_receiptHistoryUnsub(); } catch(e){} th_receiptHistoryUnsub = null; }

    const setLists = (html) => lists.forEach(list => { list.innerHTML = html; });
    const renderJobs = (jobs) => {
        lists.forEach(list => {
            list.innerHTML = '';
            jobs.slice(0, 25).forEach(job => list.appendChild(th_receiptHistoryCard(job)));
        });
    };

    setLists('<p style="color:#666;font-size:0.85rem;">Loading receipt history...</p>');
    try {
        th_receiptHistoryUnsub = db.collection('Active_Jobs')
            .where('status', '==', 'Closed')
            .limit(50)
            .onSnapshot(snap => {
                if (snap.empty) {
                    setLists('<p style="color:#999; font-style:italic;">No closed receipts found yet.</p>');
                    return;
                }
                const jobs = [];
                snap.forEach(doc => jobs.push({ id: doc.id, ...doc.data() }));
                jobs.sort((a,b) => {
                    const at = a.closedAt?.toMillis ? a.closedAt.toMillis() : 0;
                    const bt = b.closedAt?.toMillis ? b.closedAt.toMillis() : 0;
                    return bt - at;
                });
                renderJobs(jobs);
            }, err => {
                setLists(`<p style="color:var(--danger,#c0392b);font-size:0.85rem;">Could not load receipt history: ${th_receiptSafe(err.message)}</p>`);
            });
    } catch(e) {
        setLists(`<p style="color:var(--danger,#c0392b);font-size:0.85rem;">Receipt history unavailable: ${th_receiptSafe(e.message)}</p>`);
    }
};

// Start the reprint list when Billing is opened or after app load.
document.addEventListener('click', function(e){
    if (e.target && e.target.closest && (e.target.closest('[onclick*="subView_Billing"]') || e.target.closest('[onclick*="Billing"]'))) {
        setTimeout(() => th_startReceiptHistoryListener(false), 350);
    }
});
document.addEventListener('DOMContentLoaded', function(){
    setTimeout(() => th_startReceiptHistoryListener(false), 1200);
});
