// END THURAYA STAFF — RECEIPT REPRINT LAYER
// ============================================================


// ============================================================
// THURAYA STAFF — COMPLETED JOBS ROLE ACCESS CONTROL
// Access allowed only for FOH, Manager, and Admin.
// Safe: UI + action guards only. Does not change receipt/accounting data.
// ============================================================
(function(){
    const allowedRoleKeywords = ['admin', 'manager', 'foh', 'front desk', 'front-of-house', 'front of house'];

    window.th_canAccessCompletedJobs = function(){
        const roles = Array.isArray(window.currentRoles) ? window.currentRoles : (Array.isArray(currentRoles) ? currentRoles : []);
        const roleText = roles.map(r => String(r || '').toLowerCase()).join(' ');
        return allowedRoleKeywords.some(k => roleText.includes(k));
    };

    window.th_applyCompletedJobsAccessUI = function(){
        const allowed = window.th_canAccessCompletedJobs();
        const completedTab = document.getElementById('thBillingCompletedTab');
        const completedPane = document.getElementById('thBillingCompletedPane');
        const pendingTab = document.getElementById('thBillingPendingTab');
        const pendingPane = document.getElementById('thBillingPendingPane');

        if (completedTab) {
            completedTab.style.display = allowed ? '' : 'none';
            completedTab.setAttribute('aria-hidden', allowed ? 'false' : 'true');
        }

        if (!allowed && completedPane && completedPane.style.display !== 'none') {
            completedPane.style.display = 'none';
            pendingPane && (pendingPane.style.display = '');
            pendingTab && pendingTab.classList.add('active');
            completedTab && completedTab.classList.remove('active');
        }

        const list = document.getElementById('thReceiptHistoryList');
        if (!allowed && list) {
            list.innerHTML = '<div class="th-rbac-denied"><strong>Restricted access</strong><span>Completed Jobs and receipt history are available to FOH, Manager, and Admin roles only.</span></div>';
        }
    };

    const originalShowBillingTab = window.th_showBillingTab;
    window.th_showBillingTab = function(tab){
        window.th_applyCompletedJobsAccessUI();
        if (tab === 'completed' && !window.th_canAccessCompletedJobs()) {
            alert('Completed Jobs is restricted to FOH, Manager, and Admin.');
            if (typeof originalShowBillingTab === 'function') return originalShowBillingTab('pending');
            return;
        }
        if (typeof originalShowBillingTab === 'function') return originalShowBillingTab(tab);
    };

    const originalStartReceiptHistory = window.th_startReceiptHistoryListener;
    window.th_startReceiptHistoryListener = function(forceRefresh){
        window.th_applyCompletedJobsAccessUI();
        if (!window.th_canAccessCompletedJobs()) return;
        if (typeof originalStartReceiptHistory === 'function') return originalStartReceiptHistory(forceRefresh);
    };

    const originalReprintReceipt = window.th_reprintReceipt;
    window.th_reprintReceipt = function(jobId){
        if (!window.th_canAccessCompletedJobs()) { alert('Receipt reprint is restricted to FOH, Manager, and Admin.'); return; }
        if (typeof originalReprintReceipt === 'function') return originalReprintReceipt(jobId);
    };

    const originalWhatsappReceipt = window.th_whatsappReceipt;
    window.th_whatsappReceipt = function(jobId){
        if (!window.th_canAccessCompletedJobs()) { alert('Receipt sharing is restricted to FOH, Manager, and Admin.'); return; }
        if (typeof originalWhatsappReceipt === 'function') return originalWhatsappReceipt(jobId);
    };

    const originalEmailReceipt = window.th_emailReceipt;
    window.th_emailReceipt = function(jobId){
        if (!window.th_canAccessCompletedJobs()) { alert('Receipt sharing is restricted to FOH, Manager, and Admin.'); return; }
        if (typeof originalEmailReceipt === 'function') return originalEmailReceipt(jobId);
    };

    document.addEventListener('DOMContentLoaded', function(){
        setTimeout(window.th_applyCompletedJobsAccessUI, 600);
        setTimeout(window.th_applyCompletedJobsAccessUI, 1800);
        setTimeout(window.th_applyCompletedJobsAccessUI, 3500);
    });

    document.addEventListener('click', function(e){
        if (e.target && e.target.closest && e.target.closest('#subView_Billing, #thBillingCompletedTab')) {
            setTimeout(window.th_applyCompletedJobsAccessUI, 100);
        }
    });
})();
// ============================================================
// END THURAYA STAFF — COMPLETED JOBS ROLE ACCESS CONTROL
// ============================================================


// ============================================================
// THURAYA STAFF — COMPLETED JOBS MAIN NAV VISIBILITY FIX
// Shows Completed Jobs as a top-level tab for FOH, Manager and Admin.
// ============================================================
(function(){
    function th_completedJobsNavAllowed(){
        return typeof window.th_canAccessCompletedJobs === 'function' && window.th_canAccessCompletedJobs();
    }

    function th_updateCompletedJobsTopNav(){
        const tab = document.getElementById('tabCompletedJobsMain');
        if (!tab) return;
        const allowed = th_completedJobsNavAllowed();
        tab.style.display = allowed ? '' : 'none';
        tab.setAttribute('aria-hidden', allowed ? 'false' : 'true');
    }

    window.th_updateCompletedJobsTopNav = th_updateCompletedJobsTopNav;

    const previousSwitchModuleForCompletedJobs = window.switchModule;
    window.switchModule = function(moduleId){
        if (moduleId === 'completedJobsView') {
            th_updateCompletedJobsTopNav();
            if (!th_completedJobsNavAllowed()) {
                alert('Completed Jobs is restricted to FOH, Manager, and Admin.');
                const clientNav = document.getElementById('nav_clients');
                if (clientNav) clientNav.checked = true;
                return previousSwitchModuleForCompletedJobs.call(this, 'clientsView');
            }
            const result = previousSwitchModuleForCompletedJobs.call(this, moduleId);
            setTimeout(() => th_startReceiptHistoryListener(false), 120);
            return result;
        }
        return previousSwitchModuleForCompletedJobs.call(this, moduleId);
    };

    document.addEventListener('DOMContentLoaded', function(){
        setTimeout(th_updateCompletedJobsTopNav, 600);
        setTimeout(th_updateCompletedJobsTopNav, 1800);
        setTimeout(th_updateCompletedJobsTopNav, 3500);
    });
})();
// ============================================================
// END THURAYA STAFF — COMPLETED JOBS MAIN NAV VISIBILITY FIX
// ============================================================


// ============================================================
// THURAYA STAFF — COMPLETED JOBS TOP NAV HARD FIX
// Guarantees top-level Completed Jobs tab is visible for FOH, Manager and Admin.
// ============================================================
(function(){
    function thRoleText(){
        let roles = [];
        try { if (Array.isArray(window.currentRoles)) roles = roles.concat(window.currentRoles); } catch(e) {}
        try { if (Array.isArray(currentRoles)) roles = roles.concat(currentRoles); } catch(e) {}
        const roleDisplay = document.getElementById('userRoleDisplay')?.innerText || '';
        const badgeDisplay = document.querySelector('.role-tag')?.innerText || '';
        return (roles.join(' ') + ' ' + roleDisplay + ' ' + badgeDisplay).toLowerCase();
    }

    window.th_canAccessCompletedJobs = function(){
        const roleText = thRoleText();
        return roleText.includes('admin') || roleText.includes('manager') || roleText.includes('foh') || roleText.includes('front of house') || roleText.includes('front desk');
    };

    function thForceCompletedJobsTab(){
        const tab = document.getElementById('tabCompletedJobsMain');
        const nav = document.getElementById('topNavMenu');
        if (!tab || !nav) return;

        if (window.th_canAccessCompletedJobs()) {
            tab.style.setProperty('display', 'flex', 'important');
            tab.removeAttribute('aria-hidden');
            // Keep it near Clients & Booking.
            const clientsTab = document.getElementById('tabClients');
            if (clientsTab && clientsTab.nextElementSibling !== tab) {
                clientsTab.insertAdjacentElement('afterend', tab);
            }
        } else {
            tab.style.setProperty('display', 'none', 'important');
            tab.setAttribute('aria-hidden', 'true');
        }
    }

    window.thForceCompletedJobsTab = thForceCompletedJobsTab;

    const previousSwitchModuleCompletedJobsHardFix = window.switchModule;
    window.switchModule = function(moduleId){
        thForceCompletedJobsTab();
        if (moduleId === 'completedJobsView' && !window.th_canAccessCompletedJobs()) {
            alert('Completed Jobs is restricted to FOH, Manager, and Admin.');
            return previousSwitchModuleCompletedJobsHardFix.call(this, 'clientsView');
        }
        const result = previousSwitchModuleCompletedJobsHardFix.call(this, moduleId);
        if (moduleId === 'completedJobsView') {
            setTimeout(function(){
                if (typeof window.th_startReceiptHistoryListener === 'function') window.th_startReceiptHistoryListener(true);
            }, 150);
        }
        setTimeout(thForceCompletedJobsTab, 50);
        return result;
    };

    document.addEventListener('DOMContentLoaded', function(){
        [300, 800, 1500, 3000, 5000].forEach(ms => setTimeout(thForceCompletedJobsTab, ms));
    });

    // Re-apply after login async role rendering.
    setInterval(thForceCompletedJobsTab, 1200);
})();
// ============================================================
// END THURAYA STAFF — COMPLETED JOBS TOP NAV HARD FIX
// ============================================================


