// ============================================================
// GO-LIVE TEST DATA CLEANUP TOOL — Admin Only
// Added for controlled pre-launch cleanup.
// Does NOT touch Menu_Settings_V2, Users, Tax_Settings, Commission_Rules,
// Staff_Schedules, Client_Experience, or configuration records.
// ============================================================
(function(){
    if (window.THURAYA_GOLIVE_CLEANUP_TOOL_LOADED) return;
    window.THURAYA_GOLIVE_CLEANUP_TOOL_LOADED = true;

    const CLEANUP_COLLECTIONS = [
        "Appointments",
        "Active_Jobs",
        "Clients",
        "Attendance",
        "Commission_Metrics",
        "Performance_Metrics",
        "Target_Metrics",
        "Sales_Redemptions",
        "Package_Usage"
    ];

    const TEST_WORDS = [
        "test",
        "demo",
        "dummy",
        "sample",
        "aaa",
        "asdf",
        "qwerty",
        "fake"
    ];

    function th_isAdminForCleanup() {
        try {
            const roles = Array.isArray(window.currentRoles) ? window.currentRoles : (typeof currentRoles !== "undefined" ? currentRoles : []);
            return roles.some(r => String(r || "").toLowerCase().includes("admin"));
        } catch(e) {
            return false;
        }
    }

    function th_safeText(value) {
        if (value === null || value === undefined) return "";
        if (typeof value === "object") {
            try { return JSON.stringify(value); } catch(e) { return ""; }
        }
        return String(value);
    }

    function th_testPhoneLike(value) {
        const digits = th_safeText(value).replace(/\D/g, "");
        if (!digits) return false;
        return (
            /^0+$/.test(digits) ||
            /^1+$/.test(digits) ||
            /^123456/.test(digits) ||
            digits === "1234567890" ||
            digits === "0000000000" ||
            digits === "1111111111" ||
            digits === "9999999999"
        );
    }

    function th_recordLooksLikeTestData(data, docId) {
        const fieldsToCheck = [
            docId,
            data.clientName,
            data.name,
            data.Forename,
            data.Surname,
            data.Email,
            data.email,
            data.bookedBy,
            data.fohCreator,
            data.assignedTechName,
            data.assignedTechEmail,
            data.createdBy,
            data.updatedBy,
            data.promoCode,
            data.code
        ];

        const phoneFields = [
            data.clientPhone,
            data.Tel_Number,
            data.Tel_Number_Alt,
            data.phone,
            data.mobile
        ];

        const joined = fieldsToCheck.map(th_safeText).join(" ").toLowerCase();

        if (TEST_WORDS.some(word => joined.includes(word))) return true;
        if (phoneFields.some(th_testPhoneLike)) return true;

        return false;
    }

    function th_cleanupStatus(message, isError) {
        let box = document.getElementById("thGoLiveCleanupStatus");
        if (!box) {
            box = document.createElement("div");
            box.id = "thGoLiveCleanupStatus";
            box.style.cssText = "position:fixed;right:18px;bottom:18px;z-index:999999;background:#fff;border:1px solid #d9d2c3;border-radius:16px;box-shadow:0 18px 48px rgba(0,0,0,.18);padding:14px 16px;max-width:360px;font-size:13px;color:#2f3746;";
            document.body.appendChild(box);
        }
        box.innerHTML = message;
        box.style.borderColor = isError ? "#c0392b" : "#b59e4b";
    }

    async function th_scanCleanupCandidates() {
        const dbRef = (window.db || (typeof db !== "undefined" ? db : null));
        if (!dbRef) throw new Error("Firestore is not available.");

        const summary = {};
        const candidates = [];

        for (const collectionName of CLEANUP_COLLECTIONS) {
            const snap = await dbRef.collection(collectionName).get();
            let count = 0;

            snap.forEach(doc => {
                const data = doc.data() || {};
                if (th_recordLooksLikeTestData(data, doc.id)) {
                    count++;
                    candidates.push({
                        collectionName,
                        id: doc.id,
                        ref: doc.ref,
                        data
                    });
                }
            });

            summary[collectionName] = count;
        }

        return { summary, candidates };
    }

    async function th_archiveAndDeleteCandidates(candidates) {
        const dbRef = (window.db || (typeof db !== "undefined" ? db : null));
        if (!dbRef) throw new Error("Firestore is not available.");

        const cleanupId = "cleanup_" + new Date().toISOString().replace(/[:.]/g, "-");
        const archiveRoot = dbRef.collection("GoLive_Cleanup_Archive").doc(cleanupId);
        const userEmail = window.currentUserEmail || (typeof currentUserEmail !== "undefined" ? currentUserEmail : "");

        await archiveRoot.set({
            cleanupId,
            type: "test-data-cleanup",
            createdAt: firebase.firestore.FieldValue.serverTimestamp(),
            createdBy: userEmail || "",
            totalRecords: candidates.length,
            collections: CLEANUP_COLLECTIONS,
            note: "Pre-go-live cleanup archive. Configuration collections were not touched."
        }, { merge: true });

        let processed = 0;
        const chunkSize = 350;

        for (let i = 0; i < candidates.length; i += chunkSize) {
            const chunk = candidates.slice(i, i + chunkSize);
            const batch = dbRef.batch();

            chunk.forEach(item => {
                const archiveRef = archiveRoot.collection(item.collectionName).doc(item.id);
                batch.set(archiveRef, {
                    originalCollection: item.collectionName,
                    originalId: item.id,
                    archivedAt: firebase.firestore.FieldValue.serverTimestamp(),
                    archivedBy: userEmail || "",
                    data: item.data
                }, { merge: true });

                batch.delete(item.ref);
            });

            await batch.commit();
            processed += chunk.length;
            th_cleanupStatus(`Cleaning test data...<br><strong>${processed}</strong> / ${candidates.length} records processed.`);
        }

        return cleanupId;
    }

    window.runGoLiveCleanupPreview = async function() {
        if (!th_isAdminForCleanup()) {
            alert("Go-Live Cleanup is available to Admin only.");
            return;
        }

        const proceed = confirm(
            "Go-Live Cleanup Preview\n\n" +
            "This will scan operational collections for obvious TEST records only.\n\n" +
            "It will NOT touch Menu_Settings_V2, Users, Tax_Settings, Commission_Rules, Staff_Schedules, or Client_Experience.\n\n" +
            "Continue?"
        );
        if (!proceed) return;

        try {
            th_cleanupStatus("Scanning for test data candidates...");
            const { summary, candidates } = await th_scanCleanupCandidates();

            const lines = Object.entries(summary)
                .filter(([_, count]) => count > 0)
                .map(([name, count]) => `${name}: ${count}`)
                .join("\n");

            if (!candidates.length) {
                th_cleanupStatus("No obvious test records found. Nothing cleaned.");
                alert("No obvious test records found.");
                return;
            }

            const confirmText =
                "Go-Live Cleanup Found:\n\n" +
                (lines || "No collection counts available") +
                "\n\nTotal: " + candidates.length +
                "\n\nThese records will be archived first, then removed from live collections.\n\n" +
                "Type CLEAN in the next prompt to proceed.";

            alert(confirmText);

            const typed = prompt("Type CLEAN to archive and remove the listed test records:");
            if (typed !== "CLEAN") {
                th_cleanupStatus("Cleanup cancelled. No records were changed.");
                return;
            }

            th_cleanupStatus("Archiving and removing test data...");
            const cleanupId = await th_archiveAndDeleteCandidates(candidates);

            th_cleanupStatus(`Go-Live cleanup complete.<br><strong>${candidates.length}</strong> test records archived and removed.<br><small>Archive ID: ${cleanupId}</small>`);
            alert(`Cleanup complete.\n\n${candidates.length} test records archived and removed.\n\nArchive ID:\n${cleanupId}`);
        } catch (e) {
            console.error("Go-Live cleanup failed:", e);
            th_cleanupStatus("Cleanup failed: " + (e.message || e), true);
            alert("Cleanup failed: " + (e.message || e));
        }
    };

    function th_mountCleanupButton() {
        if (!th_isAdminForCleanup()) return;
        if (document.getElementById("thGoLiveCleanupBtn")) return;

        const btn = document.createElement("button");
        btn.id = "thGoLiveCleanupBtn";
        btn.type = "button";
        btn.innerText = "Go-Live Cleanup";
        btn.onclick = window.runGoLiveCleanupPreview;
        btn.style.cssText = "position:fixed;right:18px;bottom:18px;z-index:999998;background:#111;color:#fff;border:1px solid #b59e4b;border-radius:999px;padding:12px 18px;font-weight:900;letter-spacing:.08em;text-transform:uppercase;box-shadow:0 16px 42px rgba(0,0,0,.22);cursor:pointer;";

        document.body.appendChild(btn);
    }

    document.addEventListener("DOMContentLoaded", () => {
        setInterval(th_mountCleanupButton, 2500);
    });

    // Also try after late auth role loading.
    setInterval(th_mountCleanupButton, 4000);
})();

// ============================================================
// FINAL STABILIZATION — MENU SETTINGS V2 SINGLE SOURCE OF TRUTH
// Collection: Menu_Settings_V2
// Purpose: stop legacy Menu_Settings_V2 contamination while preserving booking/totals logic.
// ============================================================
const THURAYA_MENU_V2_COLLECTION = 'Menu_Settings_V2';
let thurayaMenuV2Listener = null;

function _thMenuV2Status(value) {
    const raw = String(value || 'active').trim().toLowerCase();
    if (raw === 'deleted' || raw === 'archived' || raw === 'remove' || raw === 'removed') return 'deleted';
    if (raw === 'inactive' || raw === 'disabled' || raw === 'off') return 'inactive';
    return 'active';
}

function _thMenuV2Input(value) {
    const t = String(value || 'radio').trim().toLowerCase();
    if (['counter','quantity','qty','per_nail','per unit','per-unit','unit'].includes(t)) return 'counter';
    if (['checkbox','addon','add-on','multi','multiple'].includes(t)) return 'checkbox';
    return 'radio';
}

function _thMenuV2Pricing(value, inputType) {
    const t = String(value || '').trim().toLowerCase();
    if (t.includes('consult')) return 'consultation';
    if (t.includes('per_nail') || t.includes('per nail') || t.includes('unit')) return 'per_nail';
    if (inputType === 'counter') return 'per_nail';
    return 'fixed';
}

function _thMenuV2ServiceType(value, inputType) {
    const raw = String(value || '').trim();
    const t = raw.toLowerCase().replace(/[\s-]+/g, '_');
    const map = {
        standard: 'Main Therapy',
        main: 'Main Therapy',
        main_therapy: 'Main Therapy',
        therapy: 'Main Therapy',
        addon: 'Add-on',
        add_on: 'Add-on',
        optional_add_on: 'Add-on',
        upgrade: 'Add-on',
        structure: 'Structure',
        finish: 'Finish',
        polish_finish: 'Finish',
        quantity: 'Quantity',
        quantity_based_enhancement: 'Quantity',
        counter: 'Quantity',
        consultation: 'Consultation',
        consultation_based_service: 'Consultation',
        repair: 'Repair',
        repairs: 'Repair'
    };
    if (map[t]) return map[t];
    if (raw) return raw;
    if (inputType === 'counter') return 'Quantity';
    if (inputType === 'checkbox') return 'Add-on';
    return 'Main Therapy';
}


// HF30 — Menu Settings department guard
// Keeps Hand and Foot Menu Settings clean even when older records carry the wrong
// department/appliesTo value. This is display/read normalization only; it does
// not rewrite Firestore records or touch booking availability.
function _thMenuV2NormalizeDepartment(value) {
    const raw = String(value || '').trim().toLowerCase();
    if (raw.includes('both')) return 'Both';
    if (raw.includes('foot') || raw.includes('feet') || raw.includes('pedicure')) return 'Foot';
    if (raw.includes('hand') || raw.includes('manicure')) return 'Hand';
    return '';
}

function _thMenuV2DepartmentFromContent(raw = {}) {
    const text = [
        raw.ritualGroup, raw.category, raw.serviceType, raw.serviceName,
        raw.ritualGroupDescription, raw.categoryDescription,
        raw.serviceTypeDescription, raw.serviceDescription
    ].map(v => String(v || '').toLowerCase()).join(' ');

    const footHints = /(\bfoot\b|\bfeet\b|pedicure|toe|toes|heel|heels|callus|sole|soles|medi[-\s]?cleanse|reflexology|footbath|foot\s*therapy)/i.test(text);
    const handHints = /(\bhand\b|\bhands\b|\barm\b|\barms\b|manicure|fingertip|finger|fingers|acrylic|gel\s*x|biab|duragel|nail\s*architecture|sculpt\s*acrylic)/i.test(text);

    if (footHints && !handHints) return 'Foot';
    if (handHints && !footHints) return 'Hand';
    return '';
}

function _thMenuV2ResolveDepartment(raw = {}) {
    const explicit = _thMenuV2NormalizeDepartment(raw.department || raw.appliesTo || raw.dept || raw.departmentName);
    const inferred = _thMenuV2DepartmentFromContent(raw);

    // If old/test records say Both but the content is clearly one-sided, keep them out
    // of the wrong tab. Example: arm/manicure/acrylic records should not show in Foot.
    if (explicit === 'Both' && inferred) return inferred;

    // If an old record is tagged Foot but its content is clearly Hand-only, or vice versa,
    // prefer the content so the live hierarchy stays clean.
    if (explicit && inferred && explicit !== inferred) return inferred;

    return explicit || inferred || 'Hand';
}


// HF32 — Canonical menu taxonomy + de-dup guard.
// Keeps Foot Therapy aligned with the PDF reference and prevents repeated rows
// when old V2 records, imported records, or fallback-shaped records carry the same service.
function _thLooseKey(value) {
    return String(value || '')
        .trim()
        .toLowerCase()
        .replace(/&/g, 'and')
        .replace(/[^a-z0-9]+/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
}

function _thCompactKey(value) {
    return _thLooseKey(value).replace(/\s+/g, '');
}


// HF33 — Foot Therapy category priority order.
// Display/read-only normalization only. It keeps the Foot Therapy menu in the
// same ritual sequence as the approved PDF reference without rewriting Firestore.
function _thFootCategoryPriority(value) {
    const k = _thLooseKey(value);
    if (k.includes('foundation ritual')) return 10;
    if (k.includes('urban express')) return 20;
    if (k.includes('medi cleanse') || k.includes('medi cleanse series')) return 30;
    if (k.includes('finishing indulgence')) return 40;
    if (k.includes('polish finish')) return 50;
    if (k.includes('editorial nail art') || k.includes('editorial art')) return 60;
    // Keep old/imported generic add-on buckets visible, but never above the official ritual suite.
    if (k.includes('add on') || k.includes('addon') || k.includes('upgrade') || k.includes('luxe add')) return 70;
    return 999;
}

function _thApplyFootCategoryPriority(rec) {
    if (!rec || rec.department !== 'Foot') return rec;
    const label = rec.ritualGroup || rec.category || '';
    const priority = _thFootCategoryPriority(label);
    if (priority !== 999) {
        rec.sortOrder = priority;
        rec.priority = priority;
        rec.categoryPriority = priority;
        rec.mainPriority = priority;
        // Keep service ordering under the category using the service's own original order when present.
        rec.subPriority = _thNum(rec.rawSortOrder ?? rec.serviceSortOrder ?? rec.subPriority ?? rec.sortOrder, priority);
    }
    return rec;
}

function _thMenuV2CanonicalFoot(raw = {}) {
    const text = [
        raw.ritualGroup, raw.category, raw.serviceType, raw.serviceName,
        raw.serviceDescription
    ].map(v => String(v || '')).join(' ');
    const key = _thLooseKey(text);
    const nameKey = _thLooseKey(raw.serviceName || raw.name);

    const foundationNames = ['silk skin ritual', 'the refinement indulgence', 'refinement indulgence', 'rituel jeunesse teen ritual', 'rituel jeunesse'];
    const urbanNames = ['rapid reboot', 'l essential foot reset men', 'essential foot reset men', 'l essential foot reset', 'essential foot reset'];
    const mediNames = ['heel harmony peel'];
    const finishingNames = ['paraffin restoration mask', 'hot stone foot therapy'];
    const polishNames = ['classic lacquer finish', 'gel couture finish', 'french tips', 'chrome ombre finish', 'chrome ombré finish', 'chrome finish', 'ombre finish'];
    const artNames = ['simple art', 'detailed art', 'full custom design', 'atelier customisation', 'atelier customisation nail art'];

    const containsAny = (arr) => arr.some(x => key.includes(x) || nameKey === x);

    if (containsAny(foundationNames) || key.includes('foundation ritual')) return {
        ritualGroup: 'Foundation Rituals',
        ritualGroupDescription: 'Bare, clean, essential care.',
        category: 'Foundation Rituals',
        categoryDescription: 'Bare, clean, essential care.'
    };
    if (containsAny(urbanNames) || key.includes('urban express')) return {
        ritualGroup: 'Urban Express Rituals',
        ritualGroupDescription: 'Dry, efficient, precision care.',
        category: 'Urban Express Rituals',
        categoryDescription: 'Dry, efficient, precision care.'
    };
    if (containsAny(mediNames) || key.includes('medi cleanse') || key.includes('callus') || key.includes('heel')) return {
        ritualGroup: 'The Medi-Cleanse Series',
        ritualGroupDescription: 'Targeted treatment and repair.',
        category: 'The Medi-Cleanse Series',
        categoryDescription: 'Targeted treatment and repair.'
    };
    if (containsAny(finishingNames) || key.includes('finishing indulgence') || key.includes('luxury add on')) return {
        ritualGroup: 'Finishing Indulgences',
        ritualGroupDescription: 'Luxury add-on rituals available as enhancements to any pedicure ritual.',
        category: 'Finishing Indulgences',
        categoryDescription: 'Luxury add-on rituals available as enhancements to any pedicure ritual.'
    };
    if (containsAny(polishNames) || key.includes('polish finish') || key.includes('couture enhancement')) return {
        ritualGroup: 'Polish & Finish',
        ritualGroupDescription: 'Final polish and couture finishing enhancements.',
        category: 'Polish & Finish',
        categoryDescription: 'Final polish and couture finishing enhancements.'
    };
    if (containsAny(artNames) || key.includes('editorial nail art') || key.includes('nail art')) return {
        ritualGroup: 'Editorial Nail Art',
        ritualGroupDescription: 'Atelier customisation nail art available following consultation.',
        category: 'Editorial Nail Art',
        categoryDescription: 'Atelier customisation nail art available following consultation.'
    };
    return null;
}

function _thMenuV2CanonicalizeRecord(id, raw = {}) {
    const rec = _thMenuV2ToLegacyShape(id, raw);
    if (rec.department === 'Foot') {
        const foot = _thMenuV2CanonicalFoot(raw);
        if (foot) {
            rec.ritualGroup = foot.ritualGroup;
            rec.ritualGroupDescription = rec.ritualGroupDescription || foot.ritualGroupDescription;
            rec.ritualGroup = foot.ritualGroup;
            rec.ritualGroupDescription = rec.ritualGroupDescription || foot.ritualGroupDescription;
            rec.category = foot.category;
            rec.categoryDescription = rec.categoryDescription || foot.categoryDescription;
        }
    }
    // Keep service type stable for add-ons/finishes/quantity items even when old imports are vague.
    const serviceText = _thLooseKey([rec.serviceName, rec.ritualGroup, rec.category].join(' '));
    if (/simple art|detailed art|full custom design|french tips|chrome|ombre|ombré/.test(serviceText)) {
        rec.inputType = rec.selection = 'counter';
        rec.pricingModel = 'per_nail';
        rec.pricingType = 'Per Unit';
        rec.serviceType = rec.serviceType || 'Quantity';
    }
    if (/paraffin|hot stone|gel couture finish|classic lacquer finish/.test(serviceText)) {
        rec.inputType = rec.inputType === 'counter' ? 'counter' : 'checkbox';
        rec.selection = rec.inputType === 'counter' ? 'Counter' : 'Multi';
        rec.serviceType = rec.serviceType || 'Add-on';
    }
    return _thApplyFootCategoryPriority(rec);
}

function _thMenuV2DedupServices(services) {
    const seen = new Map();
    const ordered = [];
    services.forEach(s => {
        const key = [
            s.department,
            s.ritualGroup,
            s.category,
            s.serviceType,
            s.serviceName
        ].map(_thCompactKey).join('|');
        const current = seen.get(key);
        if (!current) {
            seen.set(key, s);
            ordered.push(s);
            return;
        }
        // Prefer active records, then richer descriptions, then lower sort order.
        const curScore = (_thMenuV2Status(current.status) === 'active' ? 1000 : 0) + String(current.desc || current.description || '').length - _thNum(current.sortOrder ?? current.priority, 9999) / 1000;
        const newScore = (_thMenuV2Status(s.status) === 'active' ? 1000 : 0) + String(s.desc || s.description || '').length - _thNum(s.sortOrder ?? s.priority, 9999) / 1000;
        if (newScore > curScore) {
            const idx = ordered.indexOf(current);
            if (idx >= 0) ordered[idx] = s;
            seen.set(key, s);
        }
    });
    return ordered;
}

function _thMenuV2ToLegacyShape(id, raw) {
    // HF40: V2-only clean shape. Do not read or emit legacy schema fields
    //.
    const inputType = _thMenuV2Input(raw.inputType);
    const pricingModel = _thMenuV2Pricing(raw.pricingModel, inputType);
    const status = _thMenuV2Status(raw.status);
    const department = _thMenuV2NormalizeDepartment(raw.department || raw.appliesTo) || 'Hand';
    const ritualGroup = String(raw.ritualGroup || '').trim() || 'Uncategorized Rituals';
    const ritualGroupDescription = String(raw.ritualGroupDescription || '').trim();
    const category = String(raw.category || '').trim() || 'General';
    const categoryDescription = String(raw.categoryDescription || '').trim();
    const serviceType = _thMenuV2ServiceType(raw.serviceType, inputType);
    const serviceTypeDescription = String(raw.serviceTypeDescription || '').trim();
    const serviceName = String(raw.serviceName || '').trim() || 'Unnamed Service';
    const serviceDescription = String(raw.serviceDescription || '').trim();
    const sortOrder = _thNum(raw.sortOrder, 9999);
    const price = parseFloat(raw.price || 0) || 0;
    const duration = parseInt(raw.duration || 0, 10) || 0;

    return {
        id,
        _source: THURAYA_MENU_V2_COLLECTION,
        department,
        ritualGroup,
        ritualGroupDescription,
        category,
        categoryDescription,
        serviceType,
        serviceTypeDescription,
        serviceName,
        serviceDescription,
        price,
        duration,
        inputType,
        pricingModel,
        sortOrder,
        rawSortOrder: sortOrder,
        status,
        isActive: status === 'active',
        tag: raw.tag || 'None',
        updatedAt: raw.updatedAt || null,
        updatedBy: raw.updatedBy || ''
    };
}

// HF40: Clean V2 tree builder only. No legacy menu aliases.
function _thGetServiceMeta(s) {
    return {
        cat: s.ritualGroup || 'Uncategorized Rituals',
        main: s.category || 'General',
        sub: s.serviceType || 'Main Therapy'
    };
}

function _thGroupByMenuTree(services) {
    const tree = { Hand: {}, Foot: {} };
    services.forEach(s => {
        const deptList = (s.department === 'Both' || s.appliesTo === 'Both') ? ['Hand','Foot'] : [s.department || 'Hand'];
        const ritualKey = s.ritualGroup || 'Uncategorized Rituals';
        const categoryKey = s.category || 'General';
        const serviceTypeKey = s.serviceType || 'Main Therapy';
        const order = _thNum(s.sortOrder, 9999);
        deptList.forEach(dept => {
            if (!tree[dept]) tree[dept] = {};
            if (!tree[dept][ritualKey]) {
                tree[dept][ritualKey] = {
                    desc: s.ritualGroupDescription || '',
                    priority: order,
                    menus: {}
                };
            }
            const ritualNode = tree[dept][ritualKey];
            if (!ritualNode.desc && s.ritualGroupDescription) ritualNode.desc = s.ritualGroupDescription;
            ritualNode.priority = Math.min(ritualNode.priority, order);

            if (!ritualNode.menus[categoryKey]) {
                ritualNode.menus[categoryKey] = {
                    desc: s.categoryDescription || '',
                    priority: order,
                    subs: {}
                };
            }
            const categoryNode = ritualNode.menus[categoryKey];
            if (!categoryNode.desc && s.categoryDescription) categoryNode.desc = s.categoryDescription;
            categoryNode.priority = Math.min(categoryNode.priority, order);

            if (!categoryNode.subs[serviceTypeKey]) {
                categoryNode.subs[serviceTypeKey] = {
                    desc: s.serviceTypeDescription || '',
                    priority: order,
                    services: []
                };
            }
            const typeNode = categoryNode.subs[serviceTypeKey];
            if (!typeNode.desc && s.serviceTypeDescription) typeNode.desc = s.serviceTypeDescription;
            typeNode.priority = Math.min(typeNode.priority, order);
            typeNode.services.push(s);
        });
    });
    return tree;
}

// Override sorting to prioritize V2 sortOrder cleanly.
function _thServiceSort(a, b) {
    const pa = _thNum(a.sortOrder ?? a.priority, 9999);
    const pb = _thNum(b.sortOrder ?? b.priority, 9999);
    if (pa !== pb) return pa - pb;
    return String(a.serviceName || '').localeCompare(String(b.serviceName || ''), undefined, {numeric:true, sensitivity:'base'});
}

// Override selectable service render to accept active/inactive lowercase safely.
function _thRenderSelectableService(s, subName, compact = false) {
    const active = _thMenuV2Status(s.status) === 'active' && s.isActive !== false;
    if (!active) return '';
    const type = _thNormalizeInputType(s.inputType || s.selection || 'radio');
    const safeDur = parseInt(s.duration || 0, 10) || 0;
    const safePrc = parseFloat(s.price || 0) || 0;
    const desc = s.serviceDescription || '';
    const tagHtml = (s.tag && s.tag !== 'None') ? `<span class="hl-tag">${_thEscapeHtml(s.tag)}</span>` : '';
    const displayName = _thCleanServiceName(s.displayName || s.serviceName, subName);
    const priceSuffix = (String(s.pricingType || s.pricingModel || '').toLowerCase().includes('unit') || String(s.pricingModel || '').toLowerCase().includes('per_nail')) ? ' / nail' : '';
    const priceHtml = safePrc > 0 ? `${_thFormatMoney(safePrc)}${priceSuffix}` : 'Consultation';

    if (type === 'counter') {
        return `<div class="th-ritual-service th-ritual-counter ${compact ? 'is-simple' : ''}" data-service-id="${_thEscapeHtml(s.id)}">
            <div class="th-ritual-row"><div><div class="th-ritual-name">${_thEscapeHtml(displayName)} ${tagHtml}</div>${desc ? `<div class="th-ritual-desc">${_thEscapeHtml(desc)}</div>` : ''}</div><div class="th-ritual-price">${_thEscapeHtml(priceHtml)}</div></div>
            <div class="counter-box th-ritual-counter-box"><button type="button" class="btn btn-secondary" style="padding:2px 10px; width:auto;" onclick="event.preventDefault(); event.stopPropagation(); updateCounter('${_thEscapeJsAttr(s.id)}', -1); return false;">-</button><input type="number" id="sched_qty_${_thEscapeHtml(s.id)}" class="sched-service-counter" data-name="${_thEscapeHtml(s.serviceName || '')}" data-duration="${safeDur}" data-price="${safePrc}" value="0" min="0" readonly><button type="button" class="btn btn-secondary" style="padding:2px 10px; width:auto;" onclick="event.preventDefault(); event.stopPropagation(); updateCounter('${_thEscapeJsAttr(s.id)}', 1); return false;">+</button></div>
        </div>`;
    }

    const inputName = type === 'radio' ? `sched_base_${_thServiceSlug(s.ritualGroup || 'menu')}` : `sched_cb_${s.id}`;
    const inputHtml = type === 'radio'
        ? `<input type="radio" name="${inputName}" class="sched-service-item" id="sched_cb_${s.id}" data-name="${_thEscapeHtml(s.serviceName || '')}" data-duration="${safeDur}" data-price="${safePrc}">`
        : `<input type="checkbox" class="sched-service-item" id="sched_cb_${s.id}" data-name="${_thEscapeHtml(s.serviceName || '')}" data-duration="${safeDur}" data-price="${safePrc}">`;
    return `<div class="service-card th-ritual-service ${compact ? 'is-simple' : ''}" onclick="toggleServiceCard(event, this, '${s.id}', '${type}', '${inputName}')">
        ${inputHtml}
        <label>
            <div class="th-ritual-row"><div><div class="th-ritual-name">${_thEscapeHtml(displayName)} ${tagHtml}</div>${desc ? `<div class="th-ritual-desc">${_thEscapeHtml(desc)}</div>` : ''}</div><div class="th-ritual-price">${_thEscapeHtml(priceHtml)}</div></div>
        </label>
    </div>`;
}

// Override Menu Settings admin card so inactive V2 records remain visible/manageable.
function _thRenderAdminMenuTree(tree, dept, hasEditAccess) {
    const cats = Object.entries(tree[dept] || {}).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
    if (!cats.length) return `<div id="admin_dept_${dept}" class="th-menu-admin-tree" style="display:${dept === 'Hand' ? 'block' : 'none'};"><div class="th-menu-empty">No V2 services configured for this department yet.</div></div>`;

    let html = `<div id="admin_dept_${dept}" class="th-menu-admin-tree" style="display:${dept === 'Hand' ? 'block' : 'none'};">`;
    cats.forEach(([catName, catNode], catIndex) => {
        html += `<details class="th-menu-category" ${catIndex === 0 ? 'open' : ''}>
            <summary><div><span class="th-menu-kicker">Ritual Group · V2</span><strong>${_thEscapeHtml(catName)}</strong>${catNode.desc ? `<p>${_thEscapeHtml(catNode.desc)}</p>` : `<p class="th-menu-missing">Ritual Group Description required.</p>`}</div><span class="th-menu-chevron">⌄</span></summary>`;
        const menus = Object.entries(catNode.menus).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
        menus.forEach(([mainName, mainNode]) => {
            html += `<div class="th-menu-main"><div class="th-menu-main-head"><div><span class="th-menu-kicker">Category</span><h4>${_thEscapeHtml(mainName)}</h4>${mainNode.desc ? `<p>${_thEscapeHtml(mainNode.desc)}</p>` : `<p class="th-menu-missing">Category Description required.</p>`}</div></div>`;
            const subs = Object.entries(mainNode.subs).sort((a,b) => a[1].priority - b[1].priority || a[0].localeCompare(b[0], undefined, {numeric:true, sensitivity:'base'}));
            subs.forEach(([subName, subNode]) => {
                if (subName !== '__services__') {
                    html += `<div class="th-menu-sub"><span class="th-menu-kicker">Service Type</span><h5>${_thEscapeHtml(subName)}</h5>${subNode.desc ? `<p>${_thEscapeHtml(subNode.desc)}</p>` : `<p class="th-menu-missing">Service Type Description required.</p>`}</div>`;
                }
                html += '<div class="th-menu-service-grid">';
                subNode.services.sort(_thServiceSort).forEach((s, idx) => {
                    const safeDur = parseInt(s.duration || 0, 10) || 0;
                    const safePrc = parseFloat(s.price || 0) || 0;
                    const type = _thNormalizeInputType(s.inputType || s.selection || 'radio');
                    const isActive = _thMenuV2Status(s.status) === 'active' && s.isActive !== false;
                    const desc = s.serviceDescription || '';
                    html += `<div class="th-menu-service-card ${!isActive ? 'is-inactive' : ''}">
                        <div class="th-menu-service-top">
                            <div><span class="th-menu-kicker">Service · Sort ${_thNum(s.sortOrder ?? s.priority, idx + 1)}</span><strong>${_thEscapeHtml(s.name || s.serviceName || 'Unnamed Service')}</strong></div>
                            <span class="th-menu-status ${isActive ? 'active' : 'inactive'}">${isActive ? 'active' : 'inactive'}</span>
                        </div>
                        ${desc ? `<p class="th-menu-service-desc">${_thEscapeHtml(desc)}</p>` : `<p class="th-menu-missing">Service Description required.</p>`}
                        <div class="th-menu-meta"><span>${_thEscapeHtml(dept)}</span><span>${safeDur > 0 ? safeDur + ' mins' : 'No duration'}</span><span>${safePrc} GHC</span><span>${type.toUpperCase()}</span><span>${_thEscapeHtml(s.pricingModel || s.pricingType || 'fixed')}</span></div>
                        ${hasEditAccess ? `<div class="th-menu-actions"><button class="btn btn-secondary" onclick="editMenuService('${s.id}')">Edit</button><button class="btn btn-secondary" onclick="moveMenuServicePriority('${s.id}', -1)">↑ Sort</button><button class="btn btn-secondary" onclick="moveMenuServicePriority('${s.id}', 1)">↓ Sort</button><button class="btn btn-secondary" onclick="toggleMenuServiceActive('${s.id}')">${isActive ? 'Set Inactive' : 'Set Active'}</button><button class="btn" style="background:var(--error);" onclick="deleteMenuService('${s.id}')">Delete Service</button></div>` : ''}
                    </div>`;
                });
                html += '</div>';
            });
            html += '</div>';
        });
        html += '</details>';
    });
    html += '</div>';
    return html;
}

// V2 live menu: booking/read-only use active only; Menu Settings shows active + inactive.
function fetchLiveMenu(hasEditAccess) {
    if (hasEditAccess) {
        const seedBtn = document.getElementById('seedMenuBtnContainer');
        if (seedBtn) seedBtn.style.display = 'block';
    }

    if (thurayaMenuV2Listener) { try { thurayaMenuV2Listener(); } catch(e) {} thurayaMenuV2Listener = null; }

    thurayaMenuV2Listener = db.collection(THURAYA_MENU_V2_COLLECTION).onSnapshot(snap => {
        const menuContainer = document.getElementById('sched_serviceMenu');
        const adminList = document.getElementById('menuManagerList');
        const readOnlyList = document.getElementById('menuViewReadOnly');

        let allServices = [];
        snap.forEach(doc => allServices.push(_thMenuV2CanonicalizeRecord(doc.id, doc.data() || {})));
        // HF48: deleted services are hidden from Menu Settings, Live Menu, and Booking.
        // They remain in Firestore only as a temporary audit trail for safe go-live cleanup.
        allServices = _thMenuV2DedupServices(allServices).filter(s => _thMenuV2Status(s.status) !== 'deleted' && s.deleted !== true);
        allServices.sort(_thServiceSort);
        const activeServices = _thMenuV2DedupServices(allServices.filter(s => _thMenuV2Status(s.status) === 'active' && s.isActive !== false));
        allMenuServicesCache = activeServices;

        const uSel = document.getElementById('consultUpsellSelect');
        if (uSel) {
            uSel.innerHTML = '<option value="">Select a service or add-on...</option>';
            activeServices.forEach(s => { uSel.innerHTML += `<option value="${s.id}">${_thEscapeHtml(s.name)} (${s.price} GHC)</option>`; });
        }

        if (!allServices.length) {
            const emptyMsg = '<p style="text-align:center; color:#999; font-style:italic;">No V2 services configured yet. Use Menu Settings to create clean records.</p>';
            if (adminList) adminList.innerHTML = '<div class="th-menu-empty">Menu_Settings_V2 is empty. Create the first clean service above.</div>';
            if (menuContainer) menuContainer.innerHTML = emptyMsg;
            if (readOnlyList) readOnlyList.innerHTML = emptyMsg;
            return;
        }

        const bookingTree = _thGroupByMenuTree(activeServices);
        const adminTree = _thGroupByMenuTree(allServices);
        const bookingHtml = `<div id="menu_dept_Hand" style="display:block;">${_thRenderBookingMenuFromTree(bookingTree, 'Hand')}</div><div id="menu_dept_Foot" style="display:none;">${_thRenderBookingMenuFromTree(bookingTree, 'Foot')}</div>`;
        const adminHtml = _thRenderAdminMenuTree(adminTree, 'Hand', hasEditAccess) + _thRenderAdminMenuTree(adminTree, 'Foot', hasEditAccess);

        if (adminList) adminList.innerHTML = adminHtml;
        if (menuContainer) menuContainer.innerHTML = bookingHtml;
        if (readOnlyList) readOnlyList.innerHTML = bookingHtml.replace(/id="menu_dept_/g, 'id="menu_view_dept_').replace(/name="sched_base_/g, 'name="view_base_');
    }, error => {
        console.error(error);
        const menuContainer = document.getElementById('sched_serviceMenu');
        if (menuContainer) menuContainer.innerHTML = `<p style="color:red;">Error loading Menu_Settings_V2: ${error.message}</p>`;
    });
}

function thurayaMenuV2ApplyServiceBehavior() {
    const rawType = document.getElementById('adv_type')?.value || 'main_therapy';
    const type = String(rawType).toLowerCase().replace(/[\s-]+/g, '_');
    const selection = document.getElementById('adv_selection');
    const pricing = document.getElementById('adv_pricing_type');
    const desc = document.getElementById('adv_service_type_desc');

    if (type === 'quantity' || type === 'counter') {
        if (selection) selection.value = 'counter';
        if (pricing) pricing.value = 'per_nail';
        if (desc && !desc.value) desc.value = 'Repeatable quantity enhancement such as per nail or per finger; clients/staff use + and - counters.';
    } else if (type === 'addon' || type === 'add_on' || type === 'finish') {
        if (selection) selection.value = 'checkbox';
        if (pricing && pricing.value === 'per_nail') pricing.value = 'fixed';
        if (desc && !desc.value) desc.value = type === 'finish' ? 'Finishing option applied after structure or grooming to elevate the final aesthetic.' : 'Optional enhancement added alongside a base ritual or enhancement service.';
    } else if (type === 'consultation') {
        if (selection) selection.value = 'checkbox';
        if (pricing) pricing.value = 'consultation';
        if (desc && !desc.value) desc.value = 'Consultation-based service where design, duration, and final price are confirmed by staff.';
    } else if (type === 'repair') {
        if (selection) selection.value = 'checkbox';
        if (pricing && pricing.value === 'per_nail') pricing.value = 'fixed';
        if (desc && !desc.value) desc.value = 'Corrective or maintenance service used to repair, remove, or refresh nail work.';
    } else {
        // main_therapy and structure are primary bookable services.
        if (selection) selection.value = 'radio';
        if (pricing && pricing.value === 'per_nail') pricing.value = 'fixed';
        if (desc && !desc.value) desc.value = type === 'structure' ? 'Primary structural enhancement service for nail form, strength, length, or overlay.' : 'Primary bookable service selected as part of the client ritual.';
    }
}
window.thurayaMenuV2ApplyServiceBehavior = thurayaMenuV2ApplyServiceBehavior;

