window.addNewMenuServiceAdv = async function() {
    const department = document.getElementById('adv_applies_to')?.value || 'Hand';
    const ritualGroup = document.getElementById('adv_main_menu')?.value || '';
    const ritualGroupDescription = document.getElementById('adv_main_desc')?.value.trim() || '';
    const category = document.getElementById('adv_sub_menu')?.value || '';
    const categoryDescription = document.getElementById('adv_sub_desc')?.value.trim() || '';
    const serviceType = document.getElementById('adv_type')?.value || 'standard';
    const serviceTypeDescription = document.getElementById('adv_service_type_desc')?.value.trim() || '';
    const serviceName = document.getElementById('adv_name')?.value.trim() || '';
    const serviceDescription = document.getElementById('adv_desc')?.value.trim() || '';
    const price = parseFloat(document.getElementById('adv_price')?.value || '0');
    const duration = parseInt(document.getElementById('adv_duration')?.value || '0', 10);
    const inputType = _thMenuV2Input(document.getElementById('adv_selection')?.value || 'radio');
    const pricingModel = _thMenuV2Pricing(document.getElementById('adv_pricing_type')?.value || 'fixed', inputType);
    const sortOrder = parseInt(document.getElementById('adv_priority')?.value || '999', 10);
    const status = _thMenuV2Status(document.getElementById('adv_status')?.value || 'active');

    if (!ritualGroup) { alert('Select a Ritual Group.'); return; }
    if (!ritualGroupDescription) { alert('Ritual Group Description is required.'); return; }
    if (!category) { alert('Select a Category.'); return; }
    if (!categoryDescription) { alert('Category Description is required.'); return; }
    if (!serviceType) { alert('Select a Service Type.'); return; }
    if (!serviceTypeDescription) { alert('Service Type Description is required.'); return; }
    if (!serviceName) { alert('Service Name is required.'); return; }
    if (!serviceDescription) { alert('Service Description is required.'); return; }
    if (!Number.isFinite(price) || price < 0) { alert('Enter a valid price.'); return; }
    if (!Number.isFinite(duration) || duration < 0) { alert('Enter a valid duration.'); return; }
    if (!Number.isFinite(sortOrder) || sortOrder < 1) { alert('Enter a valid Sort Order.'); return; }

    const payload = {
        department,
        ritualGroup,
        ritualGroupDescription,
        category,
        categoryDescription,
        serviceType,
        serviceTypeDescription,
        serviceName,
        serviceDescription,
        price,
        duration,
        inputType,
        pricingModel,
        sortOrder,
        status,
        isActive: status === 'active',
        updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
        updatedBy: currentUserEmail || ''
    };

    try {
        if (_editingServiceId) {
            await db.collection(THURAYA_MENU_V2_COLLECTION).doc(_editingServiceId).set(payload, { merge: true });
            alert(`"${serviceName}" updated in Menu_Settings_V2.`);
        } else {
            await db.collection(THURAYA_MENU_V2_COLLECTION).add({ ...payload, createdAt: firebase.firestore.FieldValue.serverTimestamp(), createdBy: currentUserEmail || '' });
            alert('Clean V2 service saved.');
        }
        clearAdvForm();
    } catch (e) {
        alert('Error saving V2 service: ' + e.message);
    }
};

