window.toggleMenuServiceActive = async function(id) {
    if (!id) { alert('Missing V2 service ID.'); return; }
    try {
        const ref = db.collection(THURAYA_MENU_V2_COLLECTION).doc(id);
        const doc = await ref.get();
        if (!doc.exists) { alert('V2 service not found.'); return; }
        const current = _thMenuV2Status(doc.data().status);
        if (current === 'deleted') { alert('This service has already been deleted.'); return; }
        const next = current === 'active' ? 'inactive' : 'active';
        const label = next === 'inactive' ? 'hide from booking' : 'restore to booking';
        if (!confirm(`Set this service to ${next} and ${label}?`)) return;
        await ref.set({
            status: next,
            isActive: next === 'active',
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: currentUserEmail || ''
        }, { merge: true });
        alert(`Service set to ${next}.`);
    } catch(e) {
        alert('Error updating V2 status: ' + e.message);
    }
};

window.deleteMenuService = async function(id) {
    if (!id) { alert('Missing V2 service ID.'); return; }
    try {
        const ref = db.collection(THURAYA_MENU_V2_COLLECTION).doc(id);
        const doc = await ref.get();
        if (!doc.exists) { alert('V2 service not found.'); return; }
        const data = doc.data() || {};
        const name = data.serviceName || data.name || 'this service';
        if (!confirm(`Delete "${name}" from the live menu?

This will immediately remove it from Menu Settings, Live Menu, and Booking selection. The record is soft-deleted for safety.`)) return;
        await ref.set({
            status: 'deleted',
            isActive: false,
            deleted: true,
            deletedAt: firebase.firestore.FieldValue.serverTimestamp(),
            deletedBy: currentUserEmail || '',
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedBy: currentUserEmail || ''
        }, { merge: true });
        alert('Service deleted from the active menu.');
    } catch(e) {
        alert('Error deleting V2 service: ' + e.message);
    }
};

window.moveMenuServicePriority = async function(id, direction) {
    try {
        const ref = db.collection(THURAYA_MENU_V2_COLLECTION).doc(id);
        const doc = await ref.get();
        if (!doc.exists) return;
        const current = _thNum(doc.data().sortOrder, 100);
        const next = Math.max(1, current + direction);
        await ref.set({ sortOrder: next, updatedAt: firebase.firestore.FieldValue.serverTimestamp(), updatedBy: currentUserEmail || '' }, { merge: true });
    } catch(e) { alert('Error updating V2 sort order: ' + e.message); }
};

