/* ============================================================
   THURAYA STAFF — GO-LIVE HOTFIX 8
   Purpose: unlock consultation action buttons when a tech opens
   a service ticket. Prevents stale "Reassigning..." / "Processing..."
   disabled states from blocking Save & Start Service.
   No booking renderer / availability / checkout architecture changes.
   ============================================================ */
(function(){
    if (window.__TH_SERVICE_START_UNLOCK_HF8__) return;
    window.__TH_SERVICE_START_UNLOCK_HF8__ = true;

    function q(id){ return document.getElementById(id); }

    function resetBusyButton(btn, fallbackText){
        if (!btn) return;
        btn.disabled = false;
        btn.style.opacity = '1';
        btn.style.pointerEvents = '';
        if (fallbackText) btn.innerText = fallbackText;
        if (btn.dataset && btn.dataset.originalText) delete btn.dataset.originalText;
    }

    function unlockConsultationActions(){
        try {
            const saveBtn = q('btnConsultSaveStart');
            const addBtn = q('btnConsultAddUpsell');
            const reqBtn = q('btnConsultReqReschedule');
            const reassBtn = q('btnConsultReassign');
            const reassSel = q('consultReassignTech');

            const job = window.currentConsultJobData || currentConsultJobData || {};
            const saveText = job && job.status === 'In Progress' ? 'Update Record' : 'Save & Start Service';

            resetBusyButton(saveBtn, saveText);
            resetBusyButton(addBtn, 'Add To Ticket');
            resetBusyButton(reqBtn, 'Reschedule / Cancel');

            if (reassBtn) {
                reassBtn.innerText = 'Reassign';
                reassBtn.disabled = !(reassSel && reassSel.value);
                reassBtn.style.opacity = (reassSel && reassSel.value) ? '1' : '0.55';
                reassBtn.style.pointerEvents = '';
                if (reassBtn.dataset && reassBtn.dataset.originalText) delete reassBtn.dataset.originalText;
            }
        } catch(e) {
            console.warn('Consult action unlock skipped:', e);
        }
    }

    window.thUnlockConsultationActions = unlockConsultationActions;

    const oldOpen = window.openConsultation;
    if (typeof oldOpen === 'function') {
        window.openConsultation = async function(){
            const result = await oldOpen.apply(this, arguments);
            setTimeout(unlockConsultationActions, 0);
            setTimeout(unlockConsultationActions, 180);
            return result;
        };
        window.openConsult = window.openConsultation;
    }

    const oldClose = window.closeConsultation;
    if (typeof oldClose === 'function') {
        window.closeConsultation = function(){
            unlockConsultationActions();
            return oldClose.apply(this, arguments);
        };
        window.closeConsult = window.closeConsultation;
    }

    document.addEventListener('change', function(e){
        if (e.target && e.target.id === 'consultReassignTech') unlockConsultationActions();
    }, true);

    document.addEventListener('click', function(e){
        const saveBtn = e.target && e.target.closest && e.target.closest('#btnConsultSaveStart');
        if (saveBtn && saveBtn.disabled && currentConsultJobId) {
            e.preventDefault();
            unlockConsultationActions();
        }
    }, true);
})();
/* === END THURAYA STAFF — GO-LIVE HOTFIX 8 === */

/* ============================================================
   THURAYA STAFF — GO-LIVE HOTFIX 9
   Expected Today Quick Edit V3
   Purpose: replace full booking wizard edit with safe same-day edit
   modal, including service dropdown from Menu_Settings_V2 and live
   slot availability. Updates existing Appointment only; does not
   create Active_Jobs or recreate bookings.
   ============================================================ */
(function(){
    if (window.__TH_EXPECTED_TODAY_QUICK_EDIT_V3__) return;
    window.__TH_EXPECTED_TODAY_QUICK_EDIT_V3__ = true;

    const MENU_COLLECTION = (typeof THURAYA_MENU_V2_COLLECTION !== 'undefined') ? THURAYA_MENU_V2_COLLECTION : 'Menu_Settings_V2';
    const OPEN = '09:00';
    const CLOSE = '21:30';
    const STEP = 30;
    let activeAppointmentId = null;
    let activeAppointmentData = null;
    let serviceCache = [];
    let saving = false;

    function q(id){ return document.getElementById(id); }
    function esc(v){ return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
    function today(){ return (typeof todayDateStr !== 'undefined' && todayDateStr) ? todayDateStr : new Date().toISOString().slice(0,10); }
    function num(v, fallback=0){ const n = Number(String(v ?? '').replace(/,/g,'')); return Number.isFinite(n) ? n : fallback; }
    function mins(t){ const [h,m]=String(t||'00:00').split(':').map(x=>parseInt(x,10)||0); return h*60+m; }
    function fmtMins(m){ return `${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`; }
    function fmt12(t){ const [hRaw,mRaw]=String(t||'00:00').split(':'); let h=parseInt(hRaw,10)||0; const m=String(mRaw||'00').padStart(2,'0'); const ap=h>=12?'PM':'AM'; h=h%12||12; return `${h}:${m} ${ap}`; }
    function activeStatus(s){ return String(s || 'Active').trim().toLowerCase() !== 'inactive'; }
    function serviceName(s){ return s.name || s.serviceName || s.displayName || 'Unnamed Service'; }
    function serviceDuration(s){ return num(s.duration || s.durationMins || s.minutes, 0); }
    function servicePrice(s){ return num(s.price, 0); }
    function serviceSort(a,b){
        const pa = num(a.sortOrder ?? a.priority, 9999), pb = num(b.sortOrder ?? b.priority, 9999);
        if (pa !== pb) return pa - pb;
        return serviceName(a).localeCompare(serviceName(b), undefined, {numeric:true, sensitivity:'base'});
    }
    function techList(){
        try {
            const src = (typeof allTechs !== 'undefined' && Array.isArray(allTechs)) ? allTechs : [];
            return src.filter(t => t && t.email && t.name);
        } catch(e) { return []; }
    }
    function selectedTechName(email){
        const t = techList().find(x => String(x.email).toLowerCase() === String(email).toLowerCase());
        return t ? t.name : (activeAppointmentData?.assignedTechName || '');
    }

    async function ensureServices(){
        const existing = (typeof allMenuServicesCache !== 'undefined' && Array.isArray(allMenuServicesCache)) ? allMenuServicesCache : [];
        if (existing.length) {
            serviceCache = existing.filter(s => activeStatus(s.status) && s.isActive !== false).sort(serviceSort);
            return serviceCache;
        }
        try {
            const snap = await db.collection(MENU_COLLECTION).get();
            serviceCache = [];
            snap.forEach(doc => serviceCache.push({id: doc.id, ...(doc.data() || {})}));
            serviceCache = serviceCache.filter(s => activeStatus(s.status) && s.isActive !== false).sort(serviceSort);
            try { allMenuServicesCache = serviceCache; } catch(e) {}
        } catch(e) {
            console.warn('Quick edit service menu load skipped:', e);
            serviceCache = [];
        }
        return serviceCache;
    }

    function ensureModal(){
        let modal = q('thExpectedQuickEditModalV3');
        if (modal) return modal;
        modal = document.createElement('div');
        modal.id = 'thExpectedQuickEditModalV3';
        modal.style.cssText = 'display:none;position:fixed;inset:0;z-index:999999;background:rgba(0,0,0,.58);align-items:center;justify-content:center;padding:18px;';
        modal.innerHTML = `
            <div style="width:min(1060px,96vw);max-height:92vh;overflow:auto;background:#fff;border-radius:28px;box-shadow:0 30px 90px rgba(0,0,0,.32);border:1px solid #ded8cc;">
                <div style="background:#111;color:#fff;padding:28px 34px;border-radius:28px 28px 0 0;">
                    <div style="letter-spacing:.22em;text-transform:uppercase;font-weight:900;font-size:1rem;opacity:.82;">Expected Today · Quick Edit</div>
                    <p style="margin:22px 0 0;color:#ddd;font-size:1rem;line-height:1.55;">Update this appointment only. It will not recreate the booking or create an Active Job.</p>
                </div>
                <div style="padding:30px 34px;">
                    <div id="thQeContext" style="border:1px solid #e5ddcf;border-radius:22px;padding:18px 22px;margin-bottom:24px;background:#fffdf8;display:grid;grid-template-columns:1fr auto;gap:18px;align-items:start;"></div>

                    <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px;margin-bottom:18px;">
                        <label style="display:block;font-weight:900;color:#111;">Date
                            <input id="thQeDate" type="date" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                        </label>
                        <label style="display:block;font-weight:900;color:#111;">Technician
                            <select id="thQeTech" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;background:#fff;"></select>
                        </label>
                    </div>

                    <div style="margin:8px 0 18px;">
                        <div style="display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:8px;">
                            <strong style="font-size:1rem;color:#111;">Available Time Slots</strong>
                            <span id="thQeSlotHint" style="font-size:.84rem;color:#777;">Choose date, technician and duration.</span>
                        </div>
                        <input id="thQeTime" type="hidden">
                        <div id="thQeSlots" style="border:1px dashed #ddd4c3;border-radius:18px;padding:14px;min-height:62px;background:#fffdf8;"></div>
                    </div>

                    <label style="display:block;font-weight:900;color:#111;margin-bottom:18px;">Select Service from Menu_Settings_V2
                        <select id="thQeService" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;background:#fff;"></select>
                        <small style="display:block;margin-top:8px;color:#777;font-weight:700;">Selecting a service updates service name, duration and amount. Keep manual text only for urgent same-day corrections.</small>
                    </label>

                    <label style="display:block;font-weight:900;color:#111;margin-bottom:18px;">Selected Services / Manual Fallback
                        <textarea id="thQeServicesText" rows="4" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;resize:vertical;"></textarea>
                    </label>

                    <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px;margin-bottom:18px;">
                        <label style="display:block;font-weight:900;color:#111;">Duration / mins
                            <input id="thQeDuration" type="number" min="0" step="5" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                        </label>
                        <label style="display:block;font-weight:900;color:#111;">Amount / GHC
                            <input id="thQeAmount" type="number" min="0" step="0.01" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                        </label>
                    </div>

                    <label style="display:block;font-weight:900;color:#111;margin-bottom:20px;">Internal Edit Note
                        <textarea id="thQeNote" rows="3" placeholder="Optional reason for this same-day edit..." style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;resize:vertical;"></textarea>
                    </label>

                    <div id="thQeMsg" style="display:none;margin-bottom:16px;padding:12px 14px;border-radius:12px;font-weight:800;"></div>
                    <div style="border-top:1px solid #eee3d4;padding-top:22px;display:flex;justify-content:flex-end;gap:14px;flex-wrap:wrap;">
                        <button type="button" id="thQeCancel" class="btn btn-secondary" style="width:auto;padding:12px 28px;border-radius:999px;">Cancel</button>
                        <button type="button" id="thQeSave" class="btn" style="width:auto;padding:12px 30px;border-radius:999px;background:#111;color:#fff;">Save Appointment Edit</button>
                    </div>
                </div>
            </div>`;
        document.body.appendChild(modal);
        q('thQeCancel').addEventListener('click', closeModal);
        q('thQeSave').addEventListener('click', saveEdit);
        q('thQeDate').addEventListener('change', renderSlots);
        q('thQeTech').addEventListener('change', renderSlots);
        q('thQeDuration').addEventListener('input', () => { clearSelectedTime(); renderSlots(); });
        q('thQeService').addEventListener('change', applySelectedService);
        modal.addEventListener('click', e => { if (e.target === modal) closeModal(); });
        return modal;
    }

    function setMsg(text, type){
        const box = q('thQeMsg'); if (!box) return;
        if (!text) { box.style.display='none'; box.textContent=''; return; }
        box.textContent = text;
        box.style.display = 'block';
        box.style.color = type === 'error' ? '#8a1f1f' : '#1f5f2b';
        box.style.background = type === 'error' ? '#fff0f0' : '#effaf0';
        box.style.border = type === 'error' ? '1px solid #f0c1c1' : '1px solid #bee3c2';
    }

    function closeModal(){
        const modal = q('thExpectedQuickEditModalV3');
        if (modal) modal.style.display = 'none';
        activeAppointmentId = null;
        activeAppointmentData = null;
        saving = false;
    }

    function renderContext(appt){
        const box = q('thQeContext'); if (!box) return;
        box.innerHTML = `
            <div>
                <div style="letter-spacing:.18em;text-transform:uppercase;color:#81772f;font-weight:900;font-size:.82rem;margin-bottom:10px;">Client</div>
                <div style="font-weight:1000;font-size:1.25rem;color:#111;">${esc(appt.clientName || 'Unknown Client')}</div>
                <div style="color:#666;margin-top:8px;">${esc(appt.clientPhone || '')}</div>
            </div>
            <div style="text-align:right;color:#555;">
                <div style="letter-spacing:.18em;text-transform:uppercase;color:#81772f;font-weight:900;font-size:.82rem;margin-bottom:10px;">Booking Context</div>
                <div>${appt.groupId ? `Group ID: <strong>${esc(appt.groupId)}</strong> · ` : ''}${appt.isGroupBooking ? `Group Size: <strong>${esc(appt.groupSize || 1)}</strong>` : 'Individual booking'}</div>
                <div style="margin-top:8px;">Status: <strong>${esc(appt.status || 'Scheduled')}</strong></div>
            </div>`;
    }

    function populateTechs(appt){
        const sel = q('thQeTech'); if (!sel) return;
        const list = techList();
        const existingEmail = appt.assignedTechEmail || '';
        const existingName = appt.assignedTechName || 'Current technician';
        sel.innerHTML = '<option value="">Select technician...</option>';
        if (existingEmail && !list.some(t => String(t.email).toLowerCase() === String(existingEmail).toLowerCase())) {
            sel.innerHTML += `<option value="${esc(existingEmail)}">${esc(existingName)}</option>`;
        }
        list.forEach(t => sel.innerHTML += `<option value="${esc(t.email)}">${esc(t.name)}</option>`);
        sel.value = existingEmail;
    }

    async function populateServices(appt){
        const sel = q('thQeService'); if (!sel) return;
        const list = await ensureServices();
        sel.innerHTML = '<option value="">Keep current / manual text</option>';
        const current = String(appt.bookedService || '').split(',')[0].trim().toLowerCase();
        let selectedId = '';
        list.forEach(s => {
            const name = serviceName(s);
            const label = `${name} — ${serviceDuration(s)} mins · ${servicePrice(s).toFixed(2)} GHC`;
            sel.innerHTML += `<option value="${esc(s.id)}">${esc(label)}</option>`;
            if (!selectedId && current && name.trim().toLowerCase() === current) selectedId = s.id;
        });
        if (selectedId) sel.value = selectedId;
    }

    function applySelectedService(){
        const id = q('thQeService')?.value || '';
        if (!id) return;
        const s = serviceCache.find(x => String(x.id) === String(id));
        if (!s) return;
        const name = serviceName(s);
        const dur = serviceDuration(s);
        const price = servicePrice(s);
        if (q('thQeServicesText')) q('thQeServicesText').value = name;
        if (q('thQeDuration')) q('thQeDuration').value = dur || '';
        if (q('thQeAmount')) q('thQeAmount').value = price ? price.toFixed(2) : '0';
        clearSelectedTime();
        renderSlots();
    }

    function clearSelectedTime(){
        const t = q('thQeTime'); if (t) t.value = '';
    }

    async function busyMap(date){
        const busy = new Map();
        const add = (email, start, duration) => {
            if (!email || !start) return;
            const s = mins(start); const d = Math.max(15, parseInt(duration || '0',10) || 60);
            if (!busy.has(email)) busy.set(email, []);
            busy.get(email).push([s, s + d]);
        };
        try {
            const snap = await db.collection('Appointments').where('dateString','==',date).get();
            snap.forEach(doc => {
                if (doc.id === activeAppointmentId) return;
                const a = doc.data() || {};
                if (['Cancelled','No Show','Closed'].includes(a.status)) return;
                add(a.assignedTechEmail, a.timeString, a.bookedDuration);
            });
        } catch(e) { console.warn('Quick edit appointment availability skipped:', e); }
        try {
            const snap = await db.collection('Active_Jobs').where('dateString','==',date).get();
            snap.forEach(doc => {
                const j = doc.data() || {};
                if (!['Waiting','In Progress'].includes(j.status)) return;
                add(j.assignedTechEmail, j.timeString || j.startTime || OPEN, j.bookedDuration);
            });
        } catch(e) { console.warn('Quick edit floor availability skipped:', e); }
        return busy;
    }

    function isFree(email,start,duration,busy){
        const end = start + duration;
        return !(busy.get(email) || []).some(([s,e]) => start < e && end > s);
    }

    async function renderSlots(){
        const box = q('thQeSlots');
        const hint = q('thQeSlotHint');
        if (!box) return;
        clearSelectedTime();
        const date = q('thQeDate')?.value || '';
        const techEmail = q('thQeTech')?.value || '';
        const duration = Math.max(15, parseInt(q('thQeDuration')?.value || '0',10) || parseInt(activeAppointmentData?.bookedDuration || '60',10) || 60);
        if (hint) hint.textContent = `${duration} mins service window`;
        if (!date || !techEmail) { box.innerHTML = '<div style="color:#777;font-weight:800;">Choose date and technician to see available slots.</div>'; return; }
        if (date < today()) { box.innerHTML = '<div style="color:#9a2222;font-weight:900;">Past dates are not available for same-day edit.</div>'; return; }
        box.innerHTML = '<div style="color:#777;font-weight:800;">Checking availability…</div>';
        const busy = await busyMap(date);
        const rows = [];
        const current = new Date();
        const nowMins = current.getHours() * 60 + current.getMinutes();
        const currentTime = String(activeAppointmentData?.timeString || '');
        for (let t = mins(OPEN); t + duration <= mins(CLOSE); t += STEP) {
            if (date === today() && t <= nowMins + 5 && fmtMins(t) !== currentTime) continue;
            if (!isFree(techEmail, t, duration, busy)) continue;
            const time = fmtMins(t);
            const selected = time === currentTime ? 'selected' : '';
            rows.push(`<button type="button" class="th-qe-slot ${selected}" data-time="${esc(time)}" style="border:1px solid ${selected ? '#111' : '#d7d1c6'};background:${selected ? '#111' : '#fff'};color:${selected ? '#fff' : '#111'};border-radius:999px;padding:10px 14px;font-weight:900;cursor:pointer;">${esc(fmt12(time))}</button>`);
        }
        if (!rows.length) { box.innerHTML = '<div style="color:#9a2222;font-weight:900;">No free slots found for this technician. Try another time, date, or technician.</div>'; return; }
        box.innerHTML = `<div style="display:flex;flex-wrap:wrap;gap:10px;">${rows.join('')}</div>`;
        const match = box.querySelector('.th-qe-slot.selected') || null;
        if (match && q('thQeTime')) q('thQeTime').value = match.getAttribute('data-time') || '';
        box.querySelectorAll('.th-qe-slot').forEach(btn => btn.addEventListener('click', function(){
            box.querySelectorAll('.th-qe-slot').forEach(b => { b.classList.remove('selected'); b.style.background='#fff'; b.style.color='#111'; b.style.borderColor='#d7d1c6'; });
            this.classList.add('selected'); this.style.background='#111'; this.style.color='#fff'; this.style.borderColor='#111';
            if (q('thQeTime')) q('thQeTime').value = this.getAttribute('data-time') || '';
        }));
    }

    async function openQuickEdit(id){
        try {
            activeAppointmentId = id;
            setMsg('', '');
            const doc = await db.collection('Appointments').doc(id).get();
            if (!doc.exists) { alert('Appointment not found.'); return; }
            const appt = { id: doc.id, ...(doc.data() || {}) };
            if (appt.status && String(appt.status).toLowerCase() !== 'scheduled' && String(appt.status).toLowerCase() !== 'action required') {
                alert('This appointment has already moved beyond pre-check-in. Manage changes through Consultation / Active Job / Checkout.');
                return;
            }
            activeAppointmentData = appt;
            const modal = ensureModal();
            renderContext(appt);
            populateTechs(appt);
            if (q('thQeDate')) q('thQeDate').value = appt.dateString || today();
            if (q('thQeTime')) q('thQeTime').value = appt.timeString || '';
            if (q('thQeServicesText')) q('thQeServicesText').value = appt.bookedService || '';
            if (q('thQeDuration')) q('thQeDuration').value = parseInt(appt.bookedDuration || '0',10) || '';
            if (q('thQeAmount')) q('thQeAmount').value = num(appt.grandTotal || appt.bookedPrice, 0).toFixed(2);
            if (q('thQeNote')) q('thQeNote').value = '';
            await populateServices(appt);
            modal.style.display = 'flex';
            await renderSlots();
        } catch(e) {
            console.error(e);
            alert('Error opening quick edit: ' + e.message);
        }
    }

    async function saveEdit(){
        if (saving || !activeAppointmentId || !activeAppointmentData) return;
        const date = q('thQeDate')?.value || '';
        const time = q('thQeTime')?.value || '';
        const techEmail = q('thQeTech')?.value || '';
        const techName = selectedTechName(techEmail);
        const services = (q('thQeServicesText')?.value || '').trim();
        const duration = parseInt(q('thQeDuration')?.value || '0',10) || 0;
        const amount = num(q('thQeAmount')?.value, NaN);
        const note = (q('thQeNote')?.value || '').trim();
        if (!date || !time || !techEmail || !services || !duration || !Number.isFinite(amount)) {
            setMsg('Please select date, available slot, technician, service, duration and amount before saving.', 'error');
            return;
        }
        saving = true;
        const btn = q('thQeSave'); if (btn) { btn.disabled = true; btn.textContent = 'Saving...'; }
        try {
            await db.collection('Appointments').doc(activeAppointmentId).set({
                dateString: date,
                timeString: time,
                assignedTechEmail: techEmail,
                assignedTechName: techName,
                bookedService: services,
                bookedDuration: String(duration),
                bookedPrice: amount,
                grandTotal: amount,
                sameDayEditNote: note,
                sameDayEditedAt: firebase.firestore.FieldValue.serverTimestamp(),
                sameDayEditedBy: (typeof currentUserEmail !== 'undefined' ? currentUserEmail : ''),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge: true });
            setMsg('Appointment updated successfully.', 'success');
            setTimeout(closeModal, 500);
        } catch(e) {
            console.error(e);
            setMsg('Save failed: ' + e.message, 'error');
        } finally {
            saving = false;
            if (btn) { btn.disabled = false; btn.textContent = 'Save Appointment Edit'; }
        }
    }

    window.editAppointment = function(id){ openQuickEdit(id); };
    window.thOpenExpectedTodayQuickEdit = openQuickEdit;
})();
/* === END THURAYA STAFF — GO-LIVE HOTFIX 9 === */

/* ============================================================
   THURAYA STAFF — GO-LIVE HOTFIX 10
   Expected Today Quick Edit V4
   Purpose: preserve V3 safe quick-edit behavior while allowing FOH
   to add more services/add-ons from Menu_Settings_V2 without running
   the full booking wizard. Updates Appointment only; does not create
   Active_Jobs and does not alter consultation/reassign/checkout flows.
   ============================================================ */
(function(){
    if (window.__TH_EXPECTED_TODAY_QUICK_EDIT_V4__) return;
    window.__TH_EXPECTED_TODAY_QUICK_EDIT_V4__ = true;

    const MENU_COLLECTION = 'Menu_Settings_V2';
    const OPEN = '09:00';
    const CLOSE = '21:30';
    const STEP = 30;

    let activeAppointmentId = null;
    let activeAppointmentData = null;
    let serviceCache = [];
    let selectedItems = [];
    let saving = false;

    function q(id){ return document.getElementById(id); }
    function esc(v){ return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
    function today(){ return (typeof todayDateStr !== 'undefined' && todayDateStr) ? todayDateStr : new Date().toISOString().slice(0,10); }
    function num(v, fallback=0){ const n = Number(String(v ?? '').replace(/,/g,'')); return Number.isFinite(n) ? n : fallback; }
    function mins(t){ const [h,m]=String(t||'00:00').split(':').map(x=>parseInt(x,10)||0); return h*60+m; }
    function fmtMins(m){ return `${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`; }
    function fmt12(t){ const [hRaw,mRaw]=String(t||'00:00').split(':'); let h=parseInt(hRaw,10)||0; const m=String(mRaw||'00').padStart(2,'0'); const ap=h>=12?'PM':'AM'; h=h%12||12; return `${h}:${m} ${ap}`; }
    function statusActive(s){ return String(s || 'active').trim().toLowerCase() !== 'inactive'; }
    function svcName(s){ return s.serviceName || s.name || s.displayName || 'Unnamed Service'; }
    function svcDuration(s){ return num(s.duration || s.durationMins || s.minutes, 0); }
    function svcPrice(s){ return num(s.price ?? s.unitPrice, 0); }
    function svcSort(a,b){
        const pa = num(a.sortOrder ?? a.priority, 9999), pb = num(b.sortOrder ?? b.priority, 9999);
        if (pa !== pb) return pa - pb;
        return svcName(a).localeCompare(svcName(b), undefined, {numeric:true, sensitivity:'base'});
    }
    function svcLabel(s){
        const dept = s.department || s.appliesTo || '';
        const group = s.ritualGroup || s.category || '';
        const category = s.category && s.category !== group ? s.category : (s.serviceType || '');
        const bits = [dept, group, category].filter(Boolean).join(' · ');
        return `${svcName(s)} — ${svcDuration(s)} mins · ${svcPrice(s).toFixed(2)} GHC${bits ? ' · ' + bits : ''}`;
    }
    function techList(){
        try {
            const src = (typeof allTechs !== 'undefined' && Array.isArray(allTechs)) ? allTechs : [];
            return src.filter(t => t && t.email && t.name);
        } catch(e) { return []; }
    }
    function selectedTechName(email){
        const t = techList().find(x => String(x.email).toLowerCase() === String(email).toLowerCase());
        return t ? t.name : (activeAppointmentData?.assignedTechName || '');
    }

    async function loadV2Services(){
        try {
            const snap = await db.collection(MENU_COLLECTION).get();
            const rows = [];
            snap.forEach(doc => {
                const raw = doc.data() || {};
                let normalized;
                if (typeof _thMenuV2ToLegacyShape === 'function') normalized = _thMenuV2ToLegacyShape(doc.id, raw);
                else normalized = { id: doc.id, ...raw };
                rows.push(normalized);
            });
            serviceCache = rows.filter(s => statusActive(s.status) && s.isActive !== false).sort(svcSort);
            try { allMenuServicesCache = serviceCache; } catch(e) {}
        } catch(e) {
            console.warn('Quick Edit V4 Menu_Settings_V2 load failed:', e);
            serviceCache = [];
        }
        return serviceCache;
    }

    function ensureModal(){
        let modal = q('thExpectedQuickEditModalV4');
        if (modal) return modal;
        modal = document.createElement('div');
        modal.id = 'thExpectedQuickEditModalV4';
        modal.style.cssText = 'display:none;position:fixed;inset:0;z-index:1000000;background:rgba(0,0,0,.62);align-items:center;justify-content:center;padding:18px;';
        modal.innerHTML = `
            <div style="width:min(1100px,96vw);max-height:92vh;overflow:auto;background:#fff;border-radius:28px;box-shadow:0 30px 90px rgba(0,0,0,.34);border:1px solid #ded8cc;">
                <div style="background:#111;color:#fff;padding:28px 34px;border-radius:28px 28px 0 0;">
                    <div style="letter-spacing:.22em;text-transform:uppercase;font-weight:900;font-size:1rem;opacity:.82;">Expected Today · Quick Edit V4</div>
                    <p style="margin:18px 0 0;color:#ddd;font-size:1rem;line-height:1.55;">Add services or add-ons from Menu_Settings_V2. This updates the existing appointment only and keeps check-in safe.</p>
                </div>
                <div style="padding:30px 34px;">
                    <div id="thQeV4Context" style="border:1px solid #e5ddcf;border-radius:22px;padding:18px 22px;margin-bottom:24px;background:#fffdf8;display:grid;grid-template-columns:1fr auto;gap:18px;align-items:start;"></div>

                    <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px;margin-bottom:18px;">
                        <label style="display:block;font-weight:900;color:#111;">Date
                            <input id="thQeV4Date" type="date" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                        </label>
                        <label style="display:block;font-weight:900;color:#111;">Technician
                            <select id="thQeV4Tech" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;background:#fff;"></select>
                        </label>
                    </div>

                    <div style="margin:8px 0 18px;">
                        <div style="display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:8px;">
                            <strong style="font-size:1rem;color:#111;">Available Time Slots</strong>
                            <span id="thQeV4SlotHint" style="font-size:.84rem;color:#777;">Choose date, technician and duration.</span>
                        </div>
                        <input id="thQeV4Time" type="hidden">
                        <div id="thQeV4Slots" style="border:1px dashed #ddd4c3;border-radius:18px;padding:14px;min-height:62px;background:#fffdf8;"></div>
                    </div>

                    <div style="border:1px solid #e8e0d1;border-radius:22px;padding:18px 18px;margin-bottom:18px;background:#fff;">
                        <div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-end;flex-wrap:wrap;margin-bottom:12px;">
                            <label style="display:block;font-weight:900;color:#111;flex:1;min-width:260px;">Add Service / Add-on from Menu_Settings_V2
                                <select id="thQeV4Service" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;background:#fff;"></select>
                            </label>
                            <label style="display:block;font-weight:900;color:#111;width:110px;">Qty
                                <input id="thQeV4Qty" type="number" min="1" step="1" value="1" style="display:block;width:100%;margin-top:8px;padding:14px 12px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                            </label>
                            <button type="button" id="thQeV4Add" class="btn" style="width:auto;padding:13px 22px;border-radius:999px;background:#111;color:#fff;">Add to Booking</button>
                        </div>
                        <small style="display:block;color:#777;font-weight:700;line-height:1.45;">Use this for extra polish, art, repairs, massage, upgrades or another service. Existing appointment details remain editable below.</small>
                    </div>

                    <div style="margin-bottom:18px;">
                        <div style="display:flex;justify-content:space-between;gap:12px;align-items:center;margin-bottom:8px;">
                            <strong style="font-size:1rem;color:#111;">Booking Services</strong>
                            <span style="font-size:.82rem;color:#777;font-weight:800;">Remove wrong items before saving.</span>
                        </div>
                        <div id="thQeV4Items" style="border:1px solid #e8e0d1;border-radius:18px;padding:12px;background:#fffdf8;min-height:76px;"></div>
                    </div>

                    <label style="display:block;font-weight:900;color:#111;margin-bottom:18px;">Manual Service Text / Fallback
                        <textarea id="thQeV4ServicesText" rows="3" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;resize:vertical;"></textarea>
                        <small style="display:block;margin-top:8px;color:#777;font-weight:700;">This text is what reports and check-in will show. It auto-updates from the service list, but can be corrected manually.</small>
                    </label>

                    <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px;margin-bottom:18px;">
                        <label style="display:block;font-weight:900;color:#111;">Duration / mins
                            <input id="thQeV4Duration" type="number" min="0" step="5" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                        </label>
                        <label style="display:block;font-weight:900;color:#111;">Amount / GHC
                            <input id="thQeV4Amount" type="number" min="0" step="0.01" style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;">
                        </label>
                    </div>

                    <label style="display:block;font-weight:900;color:#111;margin-bottom:20px;">Internal Edit Note
                        <textarea id="thQeV4Note" rows="3" placeholder="Optional reason for this same-day edit..." style="display:block;width:100%;margin-top:8px;padding:14px 16px;border:1px solid #d9d9d9;border-radius:10px;font-size:1rem;resize:vertical;"></textarea>
                    </label>

                    <div id="thQeV4Msg" style="display:none;margin-bottom:16px;padding:12px 14px;border-radius:12px;font-weight:800;"></div>
                    <div style="border-top:1px solid #eee3d4;padding-top:22px;display:flex;justify-content:flex-end;gap:14px;flex-wrap:wrap;">
                        <button type="button" id="thQeV4Cancel" class="btn btn-secondary" style="width:auto;padding:12px 28px;border-radius:999px;">Cancel</button>
                        <button type="button" id="thQeV4Save" class="btn" style="width:auto;padding:12px 30px;border-radius:999px;background:#111;color:#fff;">Save Quick Edit V4</button>
                    </div>
                </div>
            </div>`;
        document.body.appendChild(modal);
        q('thQeV4Cancel').addEventListener('click', closeModal);
        q('thQeV4Save').addEventListener('click', saveEdit);
        q('thQeV4Add').addEventListener('click', addSelectedService);
        q('thQeV4Date').addEventListener('change', renderSlots);
        q('thQeV4Tech').addEventListener('change', renderSlots);
        q('thQeV4Duration').addEventListener('input', () => { clearSelectedTime(); renderSlots(); });
        q('thQeV4Amount').addEventListener('input', () => {});
        q('thQeV4ServicesText').addEventListener('input', () => {});
        modal.addEventListener('click', e => { if (e.target === modal) closeModal(); });
        return modal;
    }

    function setMsg(text, type){
        const box = q('thQeV4Msg'); if (!box) return;
        if (!text) { box.style.display='none'; box.textContent=''; return; }
        box.textContent = text;
        box.style.display = 'block';
        box.style.color = type === 'error' ? '#8a1f1f' : '#1f5f2b';
        box.style.background = type === 'error' ? '#fff0f0' : '#effaf0';
        box.style.border = type === 'error' ? '1px solid #f0c1c1' : '1px solid #bee3c2';
    }

    function closeModal(){
        const modal = q('thExpectedQuickEditModalV4');
        if (modal) modal.style.display = 'none';
        activeAppointmentId = null;
        activeAppointmentData = null;
        selectedItems = [];
        saving = false;
    }

    function renderContext(appt){
        const box = q('thQeV4Context'); if (!box) return;
        box.innerHTML = `
            <div>
                <div style="letter-spacing:.18em;text-transform:uppercase;color:#81772f;font-weight:900;font-size:.82rem;margin-bottom:10px;">Client</div>
                <div style="font-weight:1000;font-size:1.25rem;color:#111;">${esc(appt.clientName || 'Unknown Client')}</div>
                <div style="color:#666;margin-top:8px;">${esc(appt.clientPhone || '')}</div>
            </div>
            <div style="text-align:right;color:#555;">
                <div style="letter-spacing:.18em;text-transform:uppercase;color:#81772f;font-weight:900;font-size:.82rem;margin-bottom:10px;">Booking Context</div>
                <div>${appt.groupId ? `Group ID: <strong>${esc(appt.groupId)}</strong> · ` : ''}${appt.isGroupBooking ? `Group Size: <strong>${esc(appt.groupSize || 1)}</strong>` : 'Individual booking'}</div>
                <div style="margin-top:8px;">Status: <strong>${esc(appt.status || 'Scheduled')}</strong></div>
            </div>`;
    }

    function populateTechs(appt){
        const sel = q('thQeV4Tech'); if (!sel) return;
        const list = techList();
        const existingEmail = appt.assignedTechEmail || '';
        const existingName = appt.assignedTechName || 'Current technician';
        sel.innerHTML = '<option value="">Select technician...</option>';
        if (existingEmail && !list.some(t => String(t.email).toLowerCase() === String(existingEmail).toLowerCase())) {
            sel.innerHTML += `<option value="${esc(existingEmail)}">${esc(existingName)}</option>`;
        }
        list.forEach(t => sel.innerHTML += `<option value="${esc(t.email)}">${esc(t.name)}</option>`);
        sel.value = existingEmail;
    }

    async function populateServices(){
        const sel = q('thQeV4Service'); if (!sel) return;
        const list = await loadV2Services();
        sel.innerHTML = '<option value="">Select service/add-on...</option>';
        list.forEach(s => sel.innerHTML += `<option value="${esc(s.id)}">${esc(svcLabel(s))}</option>`);
    }

    function buildInitialItems(appt){
        const existingText = String(appt.bookedService || '').trim();
        const existingDuration = parseInt(appt.bookedDuration || '0', 10) || 0;
        const existingAmount = num(appt.grandTotal || appt.bookedPrice, 0);
        selectedItems = [];
        if (existingText) {
            selectedItems.push({
                key: 'existing_' + Date.now(),
                id: '',
                name: existingText,
                duration: existingDuration,
                price: existingAmount,
                qty: 1,
                manual: true
            });
        }
        syncTotalsFromItems(false);
        renderItems();
    }

    function addSelectedService(){
        const id = q('thQeV4Service')?.value || '';
        const qty = Math.max(1, parseInt(q('thQeV4Qty')?.value || '1', 10) || 1);
        if (!id) { setMsg('Select a service or add-on before adding.', 'error'); return; }
        const s = serviceCache.find(x => String(x.id) === String(id));
        if (!s) { setMsg('Selected service could not be found in Menu_Settings_V2. Refresh and try again.', 'error'); return; }
        selectedItems.push({
            key: `${id}_${Date.now()}_${Math.random().toString(16).slice(2)}`,
            id,
            name: svcName(s),
            duration: svcDuration(s),
            price: svcPrice(s),
            qty,
            manual: false,
            pricingModel: s.pricingModel || s.pricingType || '',
            department: s.department || s.appliesTo || '',
            serviceType: s.serviceType || ''
        });
        if (q('thQeV4Service')) q('thQeV4Service').value = '';
        if (q('thQeV4Qty')) q('thQeV4Qty').value = '1';
        setMsg('', '');
        syncTotalsFromItems(true);
        renderItems();
        clearSelectedTime();
        renderSlots();
    }

    window.thQeV4RemoveItem = function(key){
        selectedItems = selectedItems.filter(item => item.key !== key);
        syncTotalsFromItems(true);
        renderItems();
        clearSelectedTime();
        renderSlots();
    };

    window.thQeV4ChangeQty = function(key, value){
        const qty = Math.max(1, parseInt(value || '1', 10) || 1);
        selectedItems = selectedItems.map(item => item.key === key ? { ...item, qty } : item);
        syncTotalsFromItems(true);
        renderItems();
        clearSelectedTime();
        renderSlots();
    };

    function renderItems(){
        const box = q('thQeV4Items'); if (!box) return;
        if (!selectedItems.length) {
            box.innerHTML = '<div style="color:#8a1f1f;font-weight:900;padding:12px;">No services selected. Add at least one service/add-on before saving.</div>';
            return;
        }
        box.innerHTML = selectedItems.map(item => {
            const lineDur = (parseInt(item.duration || 0, 10) || 0) * (parseInt(item.qty || 1, 10) || 1);
            const linePrice = (num(item.price, 0)) * (parseInt(item.qty || 1, 10) || 1);
            return `
                <div style="display:grid;grid-template-columns:1fr 90px 120px 42px;gap:10px;align-items:center;background:#fff;border:1px solid #e6dece;border-radius:14px;padding:12px 14px;margin-bottom:8px;">
                    <div style="min-width:0;">
                        <div style="font-weight:1000;color:#111;white-space:normal;line-height:1.35;">${esc(item.name)}</div>
                        <div style="margin-top:3px;color:#777;font-size:.78rem;font-weight:800;text-transform:uppercase;letter-spacing:.08em;">${item.manual ? 'Current booking text' : esc([item.department, item.serviceType].filter(Boolean).join(' · ') || 'Menu_Settings_V2')}</div>
                    </div>
                    <input type="number" min="1" step="1" value="${esc(item.qty || 1)}" onchange="thQeV4ChangeQty('${esc(item.key)}', this.value)" style="width:100%;padding:10px;border:1px solid #ddd;border-radius:10px;font-weight:900;text-align:center;">
                    <div style="text-align:right;color:#111;font-weight:900;white-space:nowrap;">${lineDur} mins<br><span style="color:#1f5f2b;">${linePrice.toFixed(2)} GHC</span></div>
                    <button type="button" onclick="thQeV4RemoveItem('${esc(item.key)}')" title="Remove" style="border:1px solid #d9d2c3;background:#fff;color:#111;border-radius:999px;width:34px;height:34px;font-size:1.05rem;font-weight:1000;cursor:pointer;">×</button>
                </div>`;
        }).join('');
    }

    function syncTotalsFromItems(updateText){
        const totalDur = selectedItems.reduce((sum,item) => sum + ((parseInt(item.duration || 0, 10) || 0) * (parseInt(item.qty || 1, 10) || 1)), 0);
        const totalPrice = selectedItems.reduce((sum,item) => sum + (num(item.price,0) * (parseInt(item.qty || 1, 10) || 1)), 0);
        const serviceText = selectedItems.map(item => {
            const qty = parseInt(item.qty || 1, 10) || 1;
            return qty > 1 ? `${item.name} (x${qty})` : item.name;
        }).join(', ');
        if (updateText && q('thQeV4ServicesText')) q('thQeV4ServicesText').value = serviceText;
        if (q('thQeV4Duration')) q('thQeV4Duration').value = totalDur || '';
        if (q('thQeV4Amount')) q('thQeV4Amount').value = totalPrice.toFixed(2);
    }

    function clearSelectedTime(){ const t = q('thQeV4Time'); if (t) t.value = ''; }

    async function busyMap(date){
        if (window.thurayaBuildAvailabilityBusyMap) {
            return window.thurayaBuildAvailabilityBusyMap(date, { ignoreAppointmentId: activeAppointmentId });
        }
        const busy = new Map();
        const add = (email, start, duration) => {
            if (!email || !start) return;
            const s = mins(start); const d = Math.max(15, parseInt(duration || '0',10) || 60);
            if (!busy.has(email)) busy.set(email, []);
            busy.get(email).push([s, s + d]);
        };
        try {
            const snap = await db.collection('Appointments').where('dateString','==',date).get();
            snap.forEach(doc => {
                if (doc.id === activeAppointmentId) return;
                const a = doc.data() || {};
                if (!['Scheduled','Arrived','In Progress','Action Required'].includes(a.status || 'Scheduled')) return;
                add(a.assignedTechEmail, a.timeString, a.bookedDuration);
            });
        } catch(e) { console.warn('Quick Edit V4 appointment availability skipped:', e); }
        try {
            const snap = await db.collection('Active_Jobs').where('dateString','==',date).get();
            snap.forEach(doc => {
                const j = doc.data() || {};
                if (!['Waiting','In Progress'].includes(j.status)) return;
                add(j.assignedTechEmail, j.timeString || j.startTime || OPEN, j.bookedDuration);
            });
        } catch(e) { console.warn('Quick Edit V4 floor availability skipped:', e); }
        return busy;
    }

    function isFree(email,start,duration,busy){
        const end = start + duration;
        return !(busy.get(email) || []).some(([s,e]) => start < e && end > s);
    }

    async function renderSlots(){
        const box = q('thQeV4Slots');
        const hint = q('thQeV4SlotHint');
        if (!box) return;
        clearSelectedTime();
        const date = q('thQeV4Date')?.value || '';
        const techEmail = q('thQeV4Tech')?.value || '';
        const duration = Math.max(15, parseInt(q('thQeV4Duration')?.value || '0',10) || parseInt(activeAppointmentData?.bookedDuration || '60',10) || 60);
        if (hint) hint.textContent = `${duration} mins service window`;
        if (!date || !techEmail) { box.innerHTML = '<div style="color:#777;font-weight:800;">Choose date and technician to see available slots.</div>'; return; }
        if (date < today()) { box.innerHTML = '<div style="color:#9a2222;font-weight:900;">Past dates are not available for same-day edit.</div>'; return; }
        box.innerHTML = '<div style="color:#777;font-weight:800;">Checking availability…</div>';
        const busy = await busyMap(date);
        const rows = [];
        const current = new Date();
        const nowMins = current.getHours() * 60 + current.getMinutes();
        const currentTime = String(activeAppointmentData?.timeString || '');
        for (let t = mins(OPEN); t + duration <= mins(CLOSE); t += STEP) {
            if (date === today() && t <= nowMins + 5 && fmtMins(t) !== currentTime) continue;
            if (!isFree(techEmail, t, duration, busy)) continue;
            const time = fmtMins(t);
            const selected = time === currentTime ? 'selected' : '';
            rows.push(`<button type="button" class="th-qe-v4-slot ${selected}" data-time="${esc(time)}" style="border:1px solid ${selected ? '#111' : '#d7d1c6'};background:${selected ? '#111' : '#fff'};color:${selected ? '#fff' : '#111'};border-radius:999px;padding:10px 14px;font-weight:900;cursor:pointer;">${esc(fmt12(time))}</button>`);
        }
        if (!rows.length) { box.innerHTML = '<div style="color:#9a2222;font-weight:900;">No free slots found for this technician. Try another time, date, or technician.</div>'; return; }
        box.innerHTML = `<div style="display:flex;flex-wrap:wrap;gap:10px;">${rows.join('')}</div>`;
        const match = box.querySelector('.th-qe-v4-slot.selected') || null;
        if (match && q('thQeV4Time')) q('thQeV4Time').value = match.getAttribute('data-time') || '';
        box.querySelectorAll('.th-qe-v4-slot').forEach(btn => btn.addEventListener('click', function(){
            box.querySelectorAll('.th-qe-v4-slot').forEach(b => { b.classList.remove('selected'); b.style.background='#fff'; b.style.color='#111'; b.style.borderColor='#d7d1c6'; });
            this.classList.add('selected'); this.style.background='#111'; this.style.color='#fff'; this.style.borderColor='#111';
            if (q('thQeV4Time')) q('thQeV4Time').value = this.getAttribute('data-time') || '';
        }));
    }

    async function openQuickEditV4(id){
        try {
            activeAppointmentId = id;
            setMsg('', '');
            const doc = await db.collection('Appointments').doc(id).get();
            if (!doc.exists) { alert('Appointment not found.'); return; }
            const appt = { id: doc.id, ...(doc.data() || {}) };
            const status = String(appt.status || 'Scheduled').toLowerCase();
            if (status !== 'scheduled' && status !== 'action required') {
                alert('This appointment has already moved beyond pre-check-in. Manage changes through Consultation / Active Job / Checkout.');
                return;
            }
            activeAppointmentData = appt;
            const modal = ensureModal();
            renderContext(appt);
            populateTechs(appt);
            if (q('thQeV4Date')) q('thQeV4Date').value = appt.dateString || today();
            if (q('thQeV4Time')) q('thQeV4Time').value = appt.timeString || '';
            if (q('thQeV4ServicesText')) q('thQeV4ServicesText').value = appt.bookedService || '';
            if (q('thQeV4Duration')) q('thQeV4Duration').value = parseInt(appt.bookedDuration || '0',10) || '';
            if (q('thQeV4Amount')) q('thQeV4Amount').value = num(appt.grandTotal || appt.bookedPrice, 0).toFixed(2);
            if (q('thQeV4Note')) q('thQeV4Note').value = '';
            await populateServices();
            buildInitialItems(appt);
            modal.style.display = 'flex';
            await renderSlots();
        } catch(e) {
            console.error(e);
            alert('Error opening quick edit V4: ' + e.message);
        }
    }

    async function saveEdit(){
        if (saving || !activeAppointmentId || !activeAppointmentData) return;
        const date = q('thQeV4Date')?.value || '';
        const time = q('thQeV4Time')?.value || '';
        const techEmail = q('thQeV4Tech')?.value || '';
        const techName = selectedTechName(techEmail);
        const services = (q('thQeV4ServicesText')?.value || '').trim();
        const duration = parseInt(q('thQeV4Duration')?.value || '0',10) || 0;
        const amount = num(q('thQeV4Amount')?.value, NaN);
        const note = (q('thQeV4Note')?.value || '').trim();
        if (!date || !time || !techEmail || !services || !duration || !Number.isFinite(amount)) {
            setMsg('Please select date, available slot, technician, service, duration and amount before saving.', 'error');
            return;
        }
        if (date < today()) {
            setMsg('Past dates are not available for quick edit.', 'error');
            return;
        }
        saving = true;
        const btn = q('thQeV4Save'); if (btn) { btn.disabled = true; btn.textContent = 'Saving...'; }
        try {
            await db.collection('Appointments').doc(activeAppointmentId).set({
                dateString: date,
                timeString: time,
                assignedTechEmail: techEmail,
                assignedTechName: techName,
                bookedService: services,
                bookedDuration: String(duration),
                bookedPrice: amount,
                grandTotal: amount,
                quickEditV4Items: selectedItems.map(item => ({
                    id: item.id || '',
                    name: item.name || '',
                    duration: parseInt(item.duration || 0, 10) || 0,
                    price: num(item.price, 0),
                    qty: parseInt(item.qty || 1, 10) || 1,
                    manual: item.manual === true,
                    source: item.manual ? 'existing/manual' : MENU_COLLECTION
                })),
                sameDayEditVersion: 'V4',
                sameDayEditNote: note,
                sameDayEditedAt: firebase.firestore.FieldValue.serverTimestamp(),
                sameDayEditedBy: (typeof currentUserEmail !== 'undefined' ? currentUserEmail : ''),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge: true });
            setMsg('Appointment updated successfully.', 'success');
            setTimeout(closeModal, 500);
        } catch(e) {
            console.error(e);
            setMsg('Save failed: ' + e.message, 'error');
        } finally {
            saving = false;
            if (btn) { btn.disabled = false; btn.textContent = 'Save Quick Edit V4'; }
        }
    }

    window.editAppointment = function(id){ openQuickEditV4(id); };
    window.thOpenExpectedTodayQuickEdit = openQuickEditV4;
    window.thOpenExpectedTodayQuickEditV4 = openQuickEditV4;
})();
/* === END THURAYA STAFF — GO-LIVE HOTFIX 10 === */

/* ============================================================
   THURAYA STAFF — GO-LIVE HOTFIX 11
   Quick Edit V4 Stabilizer / Group Member Safe Routing
   Purpose: force every appointment Edit CTA to the V4 quick-edit modal,
   including group/subgroup members, so staff never falls back into the
   full booking wizard during check-in. This layer does not modify
   Check-In, Active_Jobs, Consultation, Reports, Billing or checkout.
   ============================================================ */
(function(){
    if (window.__TH_EXPECTED_TODAY_QUICK_EDIT_V4_STABILIZER__) return;
    window.__TH_EXPECTED_TODAY_QUICK_EDIT_V4_STABILIZER__ = true;

    function openV4(id){
        if (!id) return false;
        if (typeof window.thOpenExpectedTodayQuickEditV4 === 'function') {
            window.thOpenExpectedTodayQuickEditV4(id);
            return true;
        }
        if (typeof window.thOpenExpectedTodayQuickEdit === 'function') {
            window.thOpenExpectedTodayQuickEdit(id);
            return true;
        }
        console.warn('Quick Edit V4 is not available yet for appointment:', id);
        return false;
    }

    // Keep the public editAppointment API stable for all existing cards.
    window.editAppointment = function(id){
        return openV4(id);
    };

    // Capture any old inline Edit CTA before it can trigger the legacy wizard.
    document.addEventListener('click', function(e){
        const target = e.target && e.target.closest ? e.target.closest('button,a,[onclick]') : null;
        if (!target) return;

        const raw = target.getAttribute('onclick') || '';
        if (!raw) return;

        const match = raw.match(/(?:editAppointment|thOpenExpectedTodayQuickEdit|thOpenExpectedTodayQuickEditV4)\(['"]([^'"]+)['"]\)/);
        if (!match || !match[1]) return;

        e.preventDefault();
        e.stopPropagation();
        e.stopImmediatePropagation();
        openV4(match[1]);
        return false;
    }, true);

    // Safety alias for future buttons generated by other modules.
    window.thStaffQuickEditAppointment = function(id){
        return openV4(id);
    };

    console.log('THURAYA Staff Quick Edit V4 Stabilizer loaded. All appointment edit CTAs route to V4.');
})();
/* === END THURAYA STAFF — GO-LIVE HOTFIX 11 === */

/* ============================================================
   THURAYA STAFF — GO-LIVE AVAILABILITY RELEASE HOTFIX 12
   Purpose: release technician availability immediately when a job
   is completed early, checked out, cancelled, no-showed, or moved
   to Ready for Payment. Staff App only. Does not change reports,
   commission, consultation, group booking, menu, or Client App code.
   ============================================================ */
(function(){
    if (window.__TH_AVAILABILITY_RELEASE_HF12__) return;
    window.__TH_AVAILABILITY_RELEASE_HF12__ = true;

    const ANY = '__ANY_AVAILABLE_TECH__';
    const OPEN = '08:00';
    const CLOSE = '21:00';
    const STEP = 15;
    const DEFAULT_DURATION = 60;
    const BLOCKING_APPOINTMENT_STATUSES = new Set(['Scheduled','Arrived','In Progress','Action Required']);
    const BLOCKING_ACTIVE_JOB_STATUSES = new Set(['Waiting','In Progress']);
    const RELEASED_ACTIVE_JOB_STATUSES = new Set(['Ready for Payment','Closed','Completed','Cancelled','No Show']);

    function q(id){ return document.getElementById(id); }
    function esc(v){ return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
    function today(){
        try { if (typeof getLocalDateString === 'function') return getLocalDateString(); } catch(e) {}
        try { if (typeof todayDateStr !== 'undefined' && todayDateStr) return todayDateStr; } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    }
    function mins(t){
        const parts = String(t || '00:00').split(':').map(Number);
        return (parts[0] || 0) * 60 + (parts[1] || 0);
    }
    function fmt(m){ return `${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`; }
    function fmt12(t){
        const p = String(t || '00:00').split(':').map(Number);
        const h = p[0] || 0, mm = String(p[1] || 0).padStart(2,'0');
        return `${h % 12 || 12}:${mm} ${h >= 12 ? 'PM' : 'AM'}`;
    }
    function num(v, fallback){ const n = Number(v); return Number.isFinite(n) ? n : fallback; }
    function norm(v){ return String(v || '').trim().toLowerCase(); }
    function serviceKey(obj){
        return [norm(obj.clientPhone), norm(obj.dateString), norm(obj.assignedTechEmail)].join('|');
    }
    function activeTechs(){
        const source = Array.isArray(window.allTechs) ? window.allTechs : (typeof allTechs !== 'undefined' && Array.isArray(allTechs) ? allTechs : []);
        return source.filter(t => t && t.email && t.name);
    }
    function selectedDuration(){
        try { if (typeof window.calculateScheduleTotals === 'function') window.calculateScheduleTotals(); } catch(e) {}
        const total = parseInt(q('sched_totalDuration')?.innerText || '0', 10) || 0;
        return total > 0 ? total : DEFAULT_DURATION;
    }
    function selectedServicesCount(){
        const checks = document.querySelectorAll('#sched_serviceMenu .sched-service-item:checked').length;
        const counters = Array.from(document.querySelectorAll('#sched_serviceMenu .sched-service-counter')).filter(i => (parseInt(i.value || i.dataset.qty || '0', 10) || 0) > 0).length;
        return checks + counters;
    }
    function ensureAnyOption(){
        const select = q('sched_techSelect');
        if (!select) return;
        let opt = Array.from(select.options).find(o => o.value === ANY);
        if (!opt) {
            opt = document.createElement('option');
            opt.value = ANY;
            opt.textContent = 'Any available technician';
            const firstReal = Array.from(select.options).find(o => o.value && !o.disabled);
            if (firstReal) select.insertBefore(opt, firstReal); else select.appendChild(opt);
        }
    }
    function setSlots(html){ const box = q('sched_timeSlots'); if (box) box.innerHTML = html; }
    function clearSelectedTime(){ const t = q('sched_time'); if (t) t.value = ''; document.querySelectorAll('.th-avail-slot').forEach(b => b.classList.remove('selected')); }

    async function buildAvailabilityBusyMap(date, options = {}){
        const busy = new Map();
        const ignoreAppointmentId = options.ignoreAppointmentId || '';
        const releasedKeys = new Set();
        const add = (email, start, duration, source) => {
            if (!email || !start) return;
            const s = mins(start);
            const d = Math.max(15, parseInt(duration || '0', 10) || DEFAULT_DURATION);
            if (!busy.has(email)) busy.set(email, []);
            busy.get(email).push([s, s + d, source || '']); 
        };

        // First read Active_Jobs. Waiting/In Progress blocks the tech. Ready/Closed/Completed releases the matching scheduled appointment.
        try {
            const activeSnap = await db.collection('Active_Jobs').where('dateString','==',date).get();
            activeSnap.forEach(doc => {
                const j = doc.data() || {};
                const status = String(j.status || '').trim();
                const key = serviceKey(j);
                if (RELEASED_ACTIVE_JOB_STATUSES.has(status)) releasedKeys.add(key);
                if (BLOCKING_ACTIVE_JOB_STATUSES.has(status)) {
                    add(j.assignedTechEmail, j.timeString || j.startTime || OPEN, j.bookedDuration, 'active_job:' + doc.id);
                }
            });
        } catch(e) {
            console.warn('HF12 Active_Jobs availability read skipped:', e);
        }

        try {
            const apptSnap = await db.collection('Appointments').where('dateString','==',date).get();
            apptSnap.forEach(doc => {
                if (doc.id === ignoreAppointmentId) return;
                const a = doc.data() || {};
                const status = String(a.status || 'Scheduled').trim();
                if (!BLOCKING_APPOINTMENT_STATUSES.has(status)) return;
                // If the same client/date/tech has reached Ready for Payment or Closed, release the remaining scheduled block.
                if (releasedKeys.has(serviceKey(a))) return;
                add(a.assignedTechEmail, a.timeString, a.bookedDuration, 'appointment:' + doc.id);
            });
        } catch(e) {
            console.warn('HF12 Appointments availability read skipped:', e);
        }
        return busy;
    }

    window.thurayaBuildAvailabilityBusyMap = buildAvailabilityBusyMap;

    function isFree(email,start,duration,busy){
        const end = start + duration;
        return !(busy.get(email) || []).some(([s,e]) => start < e && end > s);
    }
    function renderSlot(time, tech){
        return `<button type="button" class="th-avail-slot" data-time="${esc(time)}" data-tech-email="${esc(tech.email)}" data-tech-name="${esc(tech.name)}"><strong>${esc(fmt12(time))}</strong><span>${esc(tech.name)}</span></button>`;
    }
    function renderTechShortcuts(available){
        const select = q('sched_techSelect'); if (!select) return;
        let host = q('thAvailableTechCards');
        if (!host) { host = document.createElement('div'); host.id = 'thAvailableTechCards'; host.className = 'th-available-tech-cards'; select.closest('.form-group')?.appendChild(host); }
        const list = activeTechs();
        if (!list.length) { host.innerHTML = '<div class="th-avail-note">No technicians loaded yet. Check Staff Matrix.</div>'; return; }
        host.innerHTML = `<div class="th-avail-tech-title">Available technician shortcut</div><div class="th-avail-tech-grid">${list.map(t => {
            const ok = available ? available.has(t.email) : true;
            const active = select.value === t.email;
            return `<button type="button" class="th-avail-tech-card ${active?'active':''} ${ok?'':'muted'}" data-tech-email="${esc(t.email)}"><span>${ok?'✓':'•'}</span><strong>${esc(t.name)}</strong><small>${ok?'Available':'May be busy'}</small></button>`;
        }).join('')}</div>`;
    }

    window.generateTimeSlots = async function(){
        ensureAnyOption();
        clearSelectedTime();
        const date = q('sched_date')?.value || '';
        const selectedTech = q('sched_techSelect')?.value || '';
        const duration = selectedDuration();
        const serviceCount = selectedServicesCount();
        if (!serviceCount) { setSlots('<p class="th-avail-empty">Select at least one service first, then choose date and technician.</p>'); renderTechShortcuts(null); return; }
        if (!date) { setSlots('<p class="th-avail-empty">Choose a booking date to see available time slots.</p>'); renderTechShortcuts(null); return; }
        if (!selectedTech) { setSlots('<p class="th-avail-empty">Choose a technician, or select <strong>Any available technician</strong>.</p>'); renderTechShortcuts(null); return; }
        if (date < today()) { setSlots('<p class="th-avail-empty th-avail-error">Past dates are not available for new bookings.</p>'); return; }

        setSlots('<p class="th-avail-empty">Checking live availability…</p>');
        const busy = await buildAvailabilityBusyMap(date);
        const pool = selectedTech === ANY ? activeTechs() : activeTechs().filter(t => norm(t.email) === norm(selectedTech));
        if (!pool.length) { setSlots('<p class="th-avail-empty th-avail-error">No technician profile is available. Check Staff Matrix.</p>'); renderTechShortcuts(null); return; }

        const rows=[]; const available = new Set();
        const now = new Date(); const current = now.getHours()*60 + now.getMinutes();
        for (let t=mins(OPEN); t + duration <= mins(CLOSE); t += STEP) {
            if (date === today() && t <= current + 10) continue;
            const free = pool.filter(tech => isFree(tech.email, t, duration, busy));
            free.forEach(tech => available.add(tech.email));
            if (!free.length) continue;
            if (selectedTech === ANY) free.forEach(tech => rows.push(renderSlot(fmt(t), tech)));
            else rows.push(renderSlot(fmt(t), free[0]));
        }
        renderTechShortcuts(available);
        if (!rows.length) { setSlots('<p class="th-avail-empty th-avail-error">No available slots found. Try another technician, Any available technician, or another date.</p>'); return; }
        setSlots(`<div class="th-avail-head"><strong>${selectedTech === ANY ? 'Available slots by technician' : 'Available slots'}</strong><span>${duration} mins service window · live release enabled</span></div><div class="th-avail-grid">${rows.join('')}</div>`);
    };

    const oldCancel = window.cancelAppointment;
    window.cancelAppointment = async function(id){
        if(!confirm('Are you sure you want to cancel this appointment? The technician slot will be released immediately.')) return;
        try {
            const ref = db.collection('Appointments').doc(id);
            await ref.set({
                status: 'Cancelled',
                cancelledAt: firebase.firestore.FieldValue.serverTimestamp(),
                cancelledBy: (typeof currentUserEmail !== 'undefined' ? currentUserEmail : ''),
                availabilityReleasedAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge:true });
            setTimeout(() => { try { window.generateTimeSlots?.(); } catch(e){} }, 250);
        } catch(e) { alert('Error cancelling appointment: ' + e.message); }
    };

    const oldNoShow = window.markNoShow;
    window.markNoShow = async function(id){
        if(!confirm('Mark this client as a No Show? The technician slot will be released immediately.')) return;
        try {
            await db.collection('Appointments').doc(id).set({
                status: 'No Show',
                noShowAt: firebase.firestore.FieldValue.serverTimestamp(),
                noShowBy: (typeof currentUserEmail !== 'undefined' ? currentUserEmail : ''),
                availabilityReleasedAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge:true });
            setTimeout(() => { try { window.generateTimeSlots?.(); } catch(e){} }, 250);
        } catch(e) { alert('Error marking no show: ' + e.message); }
    };

    const oldAaMarkReady = window.aa_markReady;
    window.aa_markReady = async function(jobId){
        if (!confirm('Mark this job as Ready for Payment? The technician will be released for availability immediately.')) return;
        try {
            await db.collection('Active_Jobs').doc(jobId).set({
                status: 'Ready for Payment',
                serviceCompletedAt: firebase.firestore.FieldValue.serverTimestamp(),
                availabilityReleasedAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            }, { merge:true });
            setTimeout(() => { try { window.generateTimeSlots?.(); } catch(e){} }, 250);
        } catch(e) { alert('Error: ' + e.message); }
    };

    // Tech queue complete button uses a direct inline listener in the original renderer. Capture it after click as a safety refresh.
    document.addEventListener('click', function(e){
        const btn = e.target && e.target.closest && e.target.closest('button');
        if (!btn) return;
        const txt = String(btn.textContent || '').trim().toLowerCase();
        if (txt.includes('complete job') || txt.includes('ready for payment') || txt.includes('cancel') || txt.includes('no show')) {
            setTimeout(() => { try { window.generateTimeSlots?.(); } catch(err){} }, 900);
        }
    }, true);

    function boot(){ ensureAnyOption(); renderTechShortcuts(null); }
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot); else boot();
    console.log('THURAYA availability release hotfix 12 loaded');
})();
/* === END THURAYA STAFF — GO-LIVE AVAILABILITY RELEASE HOTFIX 12 === */



/* ============================================================
   THURAYA STAFF — GO-LIVE HOTFIX 13
   Today Operations > Upcoming Bookings Enterprise Calendar
   Purpose: add a Staff App-only operational calendar/list view for
   upcoming appointments. Reuses Quick Edit V4, Cancel and No Show
   actions. Does not touch Client App, menu source, Active_Jobs,
   consultation, reports, billing or commission logic.
   ============================================================ */
(function(){
    if (window.__TH_UPCOMING_ENTERPRISE_CALENDAR_HF13__) return;
    window.__TH_UPCOMING_ENTERPRISE_CALENDAR_HF13__ = true;

    let _listener = null;
    let _lastAppointments = [];

    function q(id){ return document.getElementById(id); }
    function esc(v){ return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
    function today(){
        try { if (typeof getLocalDateString === 'function') return getLocalDateString(); } catch(e) {}
        try { if (typeof todayDateStr !== 'undefined' && todayDateStr) return todayDateStr; } catch(e) {}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    }
    function addDays(dateStr, days){
        const d = new Date(String(dateStr || today()) + 'T12:00:00');
        d.setDate(d.getDate() + days);
        return d.toISOString().slice(0,10);
    }
    function fmtDate(d){
        try { return new Date(d + 'T12:00:00').toLocaleDateString('en-GB', { weekday:'short', day:'numeric', month:'short' }); }
        catch(e){ return d || '—'; }
    }
    function fmt12(t){
        if (!t) return '—';
        const [hh, mm] = String(t).split(':').map(Number);
        const h = hh || 0;
        return `${h % 12 || 12}:${String(Number.isFinite(mm) ? mm : 0).padStart(2,'0')} ${h >= 12 ? 'PM' : 'AM'}`;
    }
    function money(v){ const n = Number(v); return (Number.isFinite(n) ? n : 0).toFixed(2) + ' GHC'; }
    function activeTechs(){
        const src = Array.isArray(window.allTechs) ? window.allTechs : (typeof allTechs !== 'undefined' && Array.isArray(allTechs) ? allTechs : []);
        return src.filter(t => t && t.email).map(t => ({ email:t.email, name:t.name || t.email }));
    }
    function statusAllowed(a, filter){
        const st = String(a.status || 'Scheduled');
        if (['Cancelled','No Show','Closed','Completed'].includes(st)) return false;
        if (!filter || filter === 'active') return ['Scheduled','Action Required','Arrived','In Progress'].includes(st);
        if (filter === 'all') return true;
        return st === filter;
    }
    function selectedRange(){
        const start = q('thUpcomingDate')?.value || today();
        const range = q('thUpcomingRange')?.value || 'week';
        if (range === 'day') return { start, end:start, days:1 };
        if (range === '14') return { start, end:addDays(start,13), days:14 };
        if (range === '30') return { start, end:addDays(start,29), days:30 };
        return { start, end:addDays(start,6), days:7 };
    }
    function populateTechFilter(){
        const sel = q('thUpcomingTechFilter');
        if (!sel || sel.dataset.loaded === '1') return;
        const prev = sel.value || 'all';
        sel.innerHTML = '<option value="all">All Technicians</option>' + activeTechs().map(t => `<option value="${esc(t.email)}">${esc(t.name)}</option>`).join('');
        sel.value = prev;
        sel.dataset.loaded = '1';
    }
    function kpi(value, label, color){
        return `<div class="th-upcoming-kpi" style="border-left-color:${color || '#111'};"><span>${esc(label)}</span><strong>${esc(value)}</strong></div>`;
    }
    function actionButtons(a){
        const id = esc(a.id);
        const canNoShow = String(a.dateString || '') <= today() && String(a.status || '') === 'Scheduled';
        return `<div class="th-upcoming-card-actions">
            <button type="button" class="btn btn-secondary" onclick="thStaffQuickEditAppointment('${id}')">Quick Edit</button>
            <button type="button" class="btn btn-secondary" style="color:var(--error);border-color:var(--error);" onclick="cancelAppointment('${id}')">Cancel</button>
            ${canNoShow ? `<button type="button" class="btn btn-secondary" style="color:#777;border-color:#888;" onclick="markNoShow('${id}')">No Show</button>` : ''}
        </div>`;
    }
    function card(a){
        const group = a.isGroupBooking || a.groupId;
        const border = a.status === 'Action Required' ? 'var(--error)' : (a.status === 'Arrived' ? 'var(--accent)' : 'var(--primary)');
        return `<div class="th-upcoming-card" style="border-left-color:${border};">
            <div class="th-upcoming-card-top"><div class="th-upcoming-client">${esc(a.clientName || 'Unknown Client')}</div><div class="th-upcoming-time">${esc(fmt12(a.timeString))}</div></div>
            <div class="th-upcoming-service">${esc(a.bookedService || 'N/A')}</div>
            <div class="th-upcoming-meta">
                <span class="th-upcoming-pill status">${esc(a.status || 'Scheduled')}</span>
                <span class="th-upcoming-pill">${esc(a.bookedDuration || '0')} mins</span>
                <span class="th-upcoming-pill">${esc(money(a.grandTotal || a.bookedPrice || 0))}</span>
                ${group ? `<span class="th-upcoming-pill group">GROUP ${esc(a.groupId || '')}</span>` : ''}
            </div>
            ${actionButtons(a)}
        </div>`;
    }
    function render(appts){
        const summary = q('thUpcomingSummary');
        const board = q('thUpcomingCalendarBoard');
        const list = q('thUpcomingList');
        const countEl = q('thUpcomingListCount');
        if (!board || !list) return;
        const techFilter = q('thUpcomingTechFilter')?.value || 'all';
        const statusFilter = q('thUpcomingStatusFilter')?.value || 'active';
        const { start, end, days } = selectedRange();
        let rows = appts.filter(a => String(a.dateString || '') >= start && String(a.dateString || '') <= end && statusAllowed(a, statusFilter));
        if (techFilter !== 'all') rows = rows.filter(a => a.assignedTechEmail === techFilter);
        rows.sort((a,b) => String((a.dateString||'') + (a.timeString||'')).localeCompare(String((b.dateString||'') + (b.timeString||''))));
        const total = rows.reduce((s,a) => s + Number(a.grandTotal || a.bookedPrice || 0), 0);
        const groupCount = rows.filter(a => a.isGroupBooking || a.groupId).length;
        const actionReq = rows.filter(a => a.status === 'Action Required').length;
        if (summary) summary.innerHTML = kpi(rows.length, 'Upcoming Bookings') + kpi(money(total), 'Expected Revenue', 'var(--success)') + kpi(groupCount, 'Group Bookings', 'var(--primary)') + kpi(actionReq, 'Action Required', actionReq ? 'var(--error)' : '#111');
        if (countEl) countEl.textContent = `${rows.length} booking${rows.length === 1 ? '' : 's'}`;
        if (!rows.length) {
            board.innerHTML = '<p style="color:#999; font-style:italic; text-align:center; padding:28px 0;">No upcoming bookings found for the selected filters.</p>';
            list.innerHTML = '<p style="color:#999; font-style:italic;">No bookings to display.</p>';
            return;
        }
        const techs = techFilter === 'all'
            ? activeTechs().filter(t => rows.some(a => a.assignedTechEmail === t.email)).concat(rows.some(a => !a.assignedTechEmail) ? [{email:'__unassigned__', name:'Unassigned'}] : [])
            : activeTechs().filter(t => t.email === techFilter);
        const allTechLanes = techs.length ? techs : [{ email:'__all__', name:'Bookings' }];
        let grid = '<div class="th-upcoming-board-grid">';
        for (let i=0; i<days; i++) {
            const d = addDays(start, i);
            const dayRows = rows.filter(a => a.dateString === d);
            if (days > 7 && !dayRows.length) continue;
            grid += `<div class="th-upcoming-day"><div class="th-upcoming-day-head"><strong>${esc(fmtDate(d))}</strong><span>${dayRows.length} booking${dayRows.length===1?'':'s'}</span></div><div class="th-upcoming-lanes">`;
            if (!dayRows.length) {
                grid += '<div style="color:#999; font-size:.82rem; font-style:italic; padding:10px;">No bookings.</div>';
            } else {
                allTechLanes.forEach(t => {
                    const laneRows = t.email === '__all__' ? dayRows : dayRows.filter(a => (t.email === '__unassigned__' ? !a.assignedTechEmail : a.assignedTechEmail === t.email));
                    if (!laneRows.length && techFilter === 'all') return;
                    grid += `<div class="th-upcoming-lane"><div class="th-upcoming-lane-title"><span>${esc(t.name)}</span><span>${laneRows.length}</span></div>${laneRows.map(card).join('') || '<div style="color:#aaa;font-size:.78rem;">Free</div>'}</div>`;
                });
            }
            grid += '</div></div>';
        }
        grid += '</div>';
        board.innerHTML = grid;
        list.innerHTML = rows.map(a => `<div class="th-upcoming-row">
            <div class="th-upcoming-row-date">${esc(fmtDate(a.dateString))}<br><span style="color:var(--accent);">${esc(fmt12(a.timeString))}</span></div>
            <div class="th-upcoming-row-main"><strong>${esc(a.clientName || 'Unknown')}</strong> ${a.isGroupBooking || a.groupId ? `<span class="th-upcoming-pill group">GROUP ${esc(a.groupId || '')}</span>` : ''}<p>${esc(a.bookedService || 'N/A')} · ${esc(a.assignedTechName || 'Unassigned')} · ${esc(a.status || 'Scheduled')} · ${esc(money(a.grandTotal || a.bookedPrice || 0))}</p></div>
            <div class="th-upcoming-row-actions"><button type="button" class="btn btn-secondary" onclick="thStaffQuickEditAppointment('${esc(a.id)}')">Quick Edit</button><button type="button" class="btn btn-secondary" style="color:var(--error);border-color:var(--error);" onclick="cancelAppointment('${esc(a.id)}')">Cancel</button></div>
        </div>`).join('');
    }

    window.thUpcomingSetToday = function(){
        const el = q('thUpcomingDate');
        if (el) el.value = today();
        window.thLoadUpcomingEnterpriseCalendar();
    };

    window.thLoadUpcomingEnterpriseCalendar = function(){
        const dateEl = q('thUpcomingDate');
        if (dateEl && !dateEl.value) dateEl.value = today();
        populateTechFilter();
        const { start, end } = selectedRange();
        const board = q('thUpcomingCalendarBoard');
        if (board) board.innerHTML = '<p style="color:#777; font-weight:800; text-align:center; padding:24px 0;">Loading enterprise calendar…</p>';
        if (_listener) { try { _listener(); } catch(e){} _listener = null; }
        try {
            _listener = db.collection('Appointments')
                .where('dateString', '>=', start)
                .where('dateString', '<=', end)
                .onSnapshot(snap => {
                    _lastAppointments = [];
                    snap.forEach(doc => _lastAppointments.push({ id: doc.id, ...doc.data() }));
                    render(_lastAppointments);
                }, err => {
                    console.error('Upcoming calendar failed:', err);
                    if (board) board.innerHTML = `<p style="color:var(--error); text-align:center; padding:20px;">Error loading upcoming bookings: ${esc(err.message)}</p>`;
                });
        } catch(e) {
            console.error(e);
            if (board) board.innerHTML = `<p style="color:var(--error); text-align:center; padding:20px;">Error loading upcoming bookings: ${esc(e.message)}</p>`;
        }
    };

    // Extend Today Operations subview switcher without changing the original function body.
    const oldToggle = window.toggleClientsSubView;
    window.toggleClientsSubView = function(){
        const selected = document.querySelector('input[name="clients_view_toggle"]:checked')?.value || 'checkin';
        ['Checkin','Schedule','Upcoming','Billing','Ops'].forEach(x => {
            const target = q('subView_' + x);
            if (target) target.style.display = (selected.toLowerCase() === x.toLowerCase()) ? 'block' : 'none';
        });
        if (selected.toLowerCase() === 'upcoming') setTimeout(window.thLoadUpcomingEnterpriseCalendar, 0);
        if (typeof oldToggle === 'function' && !q('subView_Upcoming')) return oldToggle.apply(this, arguments);
    };

    // Keep board live after cancel/no-show without requiring full page refresh.
    const oldCancel = window.cancelAppointment;
    if (typeof oldCancel === 'function') {
        window.cancelAppointment = async function(){
            const r = await oldCancel.apply(this, arguments);
            setTimeout(() => { try { if (q('subView_Upcoming')?.style.display !== 'none') window.thLoadUpcomingEnterpriseCalendar(); } catch(e){} }, 500);
            return r;
        };
    }
    const oldNoShow = window.markNoShow;
    if (typeof oldNoShow === 'function') {
        window.markNoShow = async function(){
            const r = await oldNoShow.apply(this, arguments);
            setTimeout(() => { try { if (q('subView_Upcoming')?.style.display !== 'none') window.thLoadUpcomingEnterpriseCalendar(); } catch(e){} }, 500);
            return r;
        };
    }

    function boot(){ const el = q('thUpcomingDate'); if (el && !el.value) el.value = today(); populateTechFilter(); }
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot); else boot();
    console.log('THURAYA Upcoming Bookings Enterprise Calendar HF13 loaded');
})();
/* === END THURAYA STAFF — GO-LIVE HOTFIX 13 === */

/* ============================================================
   THURAYA STAFF — GO-LIVE HOTFIX 14
   Today Operations Upcoming Tab Runtime Mount
   Purpose: guarantee Upcoming Bookings appears for Admin/Manager/FOH
   even if the cached/live index.html did not receive the HF13 tab.
   Staff App only. Does not touch Client App, reports, check-in, billing,
   consultation, menu, or Active_Jobs logic.
   ============================================================ */
(function(){
    if (window.__TH_TODAY_UPCOMING_TAB_HF14__) return;
    window.__TH_TODAY_UPCOMING_TAB_HF14__ = true;

    function q(id){ return document.getElementById(id); }
    function today(){
        try { if (typeof getLocalDateString === 'function') return getLocalDateString(); } catch(e){}
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    }

    function ensureUpcomingTab(){
        const clientsView = q('clientsView');
        if (!clientsView) return false;
        const tabs = clientsView.querySelector('.category-tabs');
        if (!tabs) return false;

        if (!q('tab_toggle_upcoming')) {
            const label = document.createElement('label');
            label.id = 'thUpcomingTabLabel';
            label.innerHTML = '<input type="radio" name="clients_view_toggle" value="upcoming" id="tab_toggle_upcoming" onchange="toggleClientsSubView(); if(window.thLoadUpcomingEnterpriseCalendar){ window.thLoadUpcomingEnterpriseCalendar(); }"> 📅 Upcoming Bookings';
            const billing = q('tab_toggle_billing') || Array.from(tabs.querySelectorAll('input[name="clients_view_toggle"]')).find(i => String(i.value||'').toLowerCase()==='billing');
            if (billing && billing.closest('label')) tabs.insertBefore(label, billing.closest('label'));
            else tabs.appendChild(label);
        }

        if (!q('subView_Upcoming')) {
            const pane = document.createElement('div');
            pane.id = 'subView_Upcoming';
            pane.style.display = 'none';
            pane.innerHTML = `
                <div class="module-box th-upcoming-enterprise" style="border-top:4px solid #111;">
                    <div class="th-upcoming-head" style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap;margin-bottom:14px;">
                        <div>
                            <h3 style="color:#111;border-bottom:none;padding-bottom:0;margin-bottom:4px;">📅 Upcoming Bookings</h3>
                            <p style="font-size:.86rem;color:#666;margin:0;">Enterprise calendar view for FOH, Manager and Admin. Click Quick Edit to adjust a booking safely.</p>
                        </div>
                        <div style="display:flex;gap:8px;flex-wrap:wrap;">
                            <button type="button" class="btn btn-secondary" style="width:auto;padding:8px 14px;font-size:.78rem;" onclick="thUpcomingSetToday()">Today</button>
                            <button type="button" class="btn" style="width:auto;padding:8px 14px;font-size:.78rem;" onclick="thLoadUpcomingEnterpriseCalendar()">Refresh</button>
                        </div>
                    </div>
                    <div class="grid-4" style="gap:10px;margin-bottom:14px;">
                        <div class="form-group"><label>View Date</label><input type="date" id="thUpcomingDate" onchange="thLoadUpcomingEnterpriseCalendar()"></div>
                        <div class="form-group"><label>Range</label><select id="thUpcomingRange" onchange="thLoadUpcomingEnterpriseCalendar()"><option value="day">Day</option><option value="week" selected>Week</option><option value="14">Next 14 Days</option><option value="30">Next 30 Days</option></select></div>
                        <div class="form-group"><label>Technician</label><select id="thUpcomingTechFilter" onchange="thLoadUpcomingEnterpriseCalendar()"><option value="all">All Technicians</option></select></div>
                        <div class="form-group"><label>Status</label><select id="thUpcomingStatusFilter" onchange="thLoadUpcomingEnterpriseCalendar()"><option value="active">Active Bookings</option><option value="Scheduled">Scheduled</option><option value="Action Required">Action Required</option><option value="Arrived">Arrived</option><option value="all">All Non-cancelled</option></select></div>
                    </div>
                    <div id="thUpcomingSummary" class="th-upcoming-summary" style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin-bottom:14px;"></div>
                    <div id="thUpcomingCalendarBoard" class="th-upcoming-board"><p style="color:#999;font-style:italic;text-align:center;padding:25px 0;">Loading upcoming bookings...</p></div>
                    <div class="th-upcoming-list-head" style="display:flex;justify-content:space-between;align-items:center;margin:18px 0 8px;"><h4 style="margin:0;color:#111;">Booking List</h4><span id="thUpcomingListCount" style="font-size:.78rem;color:#777;font-weight:800;"></span></div>
                    <div id="thUpcomingList" class="th-upcoming-list"><p style="color:#999;font-style:italic;">Loading...</p></div>
                </div>`;
            const billingPane = q('subView_Billing');
            if (billingPane && billingPane.parentNode) billingPane.parentNode.insertBefore(pane, billingPane);
            else clientsView.appendChild(pane);
        }

        const dateEl = q('thUpcomingDate');
        if (dateEl && !dateEl.value) dateEl.value = today();
        if (typeof populateTechFilter === 'function') {
            try { populateTechFilter(); } catch(e){}
        } else {
            const sel = q('thUpcomingTechFilter');
            if (sel && sel.options.length <= 1 && Array.isArray(window.allTechs || allTechs)) {
                (window.allTechs || allTechs || []).forEach(t => {
                    if (!t || !t.email) return;
                    const opt = document.createElement('option');
                    opt.value = t.email;
                    opt.textContent = t.name || t.email;
                    sel.appendChild(opt);
                });
            }
        }
        return true;
    }

    const previousToggle = window.toggleClientsSubView;
    window.toggleClientsSubView = function(){
        ensureUpcomingTab();
        const selected = document.querySelector('input[name="clients_view_toggle"]:checked')?.value || 'checkin';
        ['Checkin','Schedule','Upcoming','Billing','Ops'].forEach(x => {
            const target = q('subView_' + x);
            if (target) target.style.display = (selected.toLowerCase() === x.toLowerCase()) ? 'block' : 'none';
        });
        if (selected.toLowerCase() === 'upcoming' && typeof window.thLoadUpcomingEnterpriseCalendar === 'function') {
            setTimeout(window.thLoadUpcomingEnterpriseCalendar, 0);
        }
        if (!q('subView_Upcoming') && typeof previousToggle === 'function') return previousToggle.apply(this, arguments);
    };

    function boot(){
        const ok = ensureUpcomingTab();
        if (ok) {
            const checked = document.querySelector('input[name="clients_view_toggle"]:checked');
            if (checked && String(checked.value||'').toLowerCase() === 'upcoming' && typeof window.thLoadUpcomingEnterpriseCalendar === 'function') {
                window.thLoadUpcomingEnterpriseCalendar();
            }
        }
        return ok;
    }

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
    else boot();
    let attempts = 0;
    const timer = setInterval(() => {
        attempts += 1;
        if (boot() || attempts > 20) clearInterval(timer);
    }, 350);

    console.log('THURAYA Today Operations Upcoming Tab HF14 mounted');
})();
