        if (!window.db || !window.firebase || !firebase.firestore) {
            alert('Firebase is not ready. Refresh and try again.');
            return;
        }
        const ok = confirm('Install the approved THURAYA Hand + Foot menu cards now?\n\nThis will ARCHIVE current active Menu_Settings_V2 services and write a clean approved menu from the PDF cards. Existing records are not deleted.');
