(function(){
    if (window.__TH_FINAL_CLEAN_MENU_PIPELINE_20260511__) return;
    window.__TH_FINAL_CLEAN_MENU_PIPELINE_20260511__ = true;

    const COLLECTION = 'Menu_Settings_V2';
    const HAND_ORDER = ['Hand Therapies','Finishing Indulgences','Nail Architecture','Polish & Finish','The Pleiades Studio','Editorial Nail Art','Couture Nail Art','Embellishment Drawers'];
    const FOOT_ORDER = ['Foundation Rituals','Urban Express Rituals','The Medi-Cleanse Series','Finishing Indulgences','Polish & Finish','Editorial Nail Art'];
    const HAND_CATEGORY_ORDER = {
        'Hand Therapies':['Core Hand Rituals','Hand Therapies'],
        'Finishing Indulgences':['Finishing Indulgences'],
        'Nail Architecture':['Acrylic','Sculpt Acrylic','Gel-X','Gel X','BIAB','DuraGel','Nail Repairs & Stick-ons','Repairs'],
        'Polish & Finish':['Polish & Finish'],
        'The Pleiades Studio':['Editorial Nail Art','Couture Nail Art','Embellishment Drawers'],
        'Editorial Nail Art':['Editorial Nail Art'],
        'Couture Nail Art':['Couture Nail Art'],
        'Embellishment Drawers':['Embellishment Drawers']
    };
    const FOOT_CATEGORY_ORDER = {
        'Foundation Rituals':['Foundation Rituals'],
        'Urban Express Rituals':['Urban Express Rituals'],
        'The Medi-Cleanse Series':['The Medi-Cleanse Series'],
        'Finishing Indulgences':['Finishing Indulgences'],
        'Polish & Finish':['Polish & Finish'],
        'Editorial Nail Art':['Editorial Nail Art']
    };
    const RITUAL_DESC = {
        Hand:{
            'Hand Therapies':'The ritual-led hand care suite: restorative, corrective, and aesthetic hand therapies designed to improve skin condition, nail health, and overall hand appearance through structured, intentional care.',
            'Finishing Indulgences':'Targeted enhancements designed to extend the benefits of your hand ritual.',
            'Nail Architecture':'Structure, strength, and shape services that prepare the nail for aesthetic refinement.',
            'Polish & Finish':'Enhancement finishes applied after nail structure or grooming to elevate the final aesthetic.',
            'The Pleiades Studio':'Advanced nail artistry and embellishment for expressive, editorial, and couture-level finishes.',
            'Editorial Nail Art':'Refined artistic detailing that enhances the nail without overwhelming it.',
            'Couture Nail Art':'Highly detailed, custom-designed nail creations incorporating advanced techniques and layered artistry.',
            'Embellishment Drawers':'Dimensional and decorative embellishments that add texture, sparkle, and couture detail.'
        },
        Foot:{
            'Foundation Rituals':'Bare, clean, essential care.',
            'Urban Express Rituals':'Dry, efficient, precision care.',
            'The Medi-Cleanse Series':'Targeted treatment and repair.',
            'Finishing Indulgences':'Luxury add-on rituals available as enhancements to any pedicure ritual.',
            'Polish & Finish':'Finishing options that elevate the final aesthetic after a foot ritual.',
            'Editorial Nail Art':'Atelier customisation nail art available following consultation.'
        }
    };
    const CATEGORY_DESC = {
        'Core Hand Rituals':'Hand therapies focused on restoration, grooming, and visible refinement.',
        'Hand Therapies':'Hand therapies focused on restoration, grooming, and visible refinement.',
        'Finishing Indulgences':'Luxury add-on rituals available as enhancements.',
        'Acrylic':'Durable acrylic enhancement system designed to build strength, length, and defined shape.',
        'Sculpt Acrylic':'Precision-built sculpting technique for seamless, natural-looking extension with refined structure.',
        'Gel-X':'Flexible and natural-looking extension system offering strength with a lighter, adaptable finish.',
        'Gel X':'Flexible and natural-looking extension system offering strength with a lighter, adaptable finish.',
        'BIAB':'Builder gel system focused on strength, overlays, and natural nail reinforcement.',
        'DuraGel':'Durable gel system for long-lasting structure, strength, and clean finish.',
        'Nail Repairs & Stick-ons':'Corrective and temporary enhancement solutions for damaged nails or quick aesthetic alternatives.',
        'Polish & Finish':'Finishing options that elevate the final aesthetic.',
        'Editorial Nail Art':'Artistic and consultation-led nail art.',
        'Couture Nail Art':'Custom-designed nail creations with advanced techniques and layered artistry.',
        'Embellishment Drawers':'Dimensional and decorative embellishments that add texture, sparkle, and couture detail.',
        'Foundation Rituals':'Bare, clean, essential foot care rituals.',
        'Urban Express Rituals':'Dry, efficient, precision-care foot rituals.',
        'The Medi-Cleanse Series':'Targeted treatment and repair foot rituals.'
    };

    function q(id){ return document.getElementById(id); }
    function esc(v){
        if (typeof _thEscapeHtml === 'function') return _thEscapeHtml(v);
        return String(v ?? '').replace(/[&<>'"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[ch]));
    }
    function attr(v){
        if (typeof _thEscapeJsAttr === 'function') return _thEscapeJsAttr(v);
        return String(v ?? '').replace(/\\/g,'\\\\').replace(/'/g,"\\'").replace(/\n/g,' ');
    }
    function loose(v){
        if (typeof _thLooseKey === 'function') return _thLooseKey(v);
        return String(v||'').trim().toLowerCase().replace(/&/g,'and').replace(/[^a-z0-9]+/g,' ').replace(/\s+/g,' ').trim();
    }
    function slug(v){ return loose(v).replace(/\s+/g,'_').slice(0,100) || 'item'; }
    function num(v, fb=9999){ const n=Number(String(v??'').replace(/[^0-9.\-]/g,'')); return Number.isFinite(n) ? n : fb; }
    function status(v){ const t=String(v||'active').toLowerCase(); if (t.includes('delete')) return 'deleted'; if (t.includes('inactive')||t==='off'||t==='disabled') return 'inactive'; return 'active'; }
    function dept(v){ const t=String(v||'').toLowerCase(); return t.includes('foot') ? 'Foot' : 'Hand'; }
    function inputType(v){ const t=String(v||'radio').toLowerCase(); if (/counter|qty|quantity|per[_\s-]*nail|unit/.test(t)) return 'counter'; if (/check|add|multi|finish|repair|optional/.test(t)) return 'checkbox'; return 'radio'; }
    function priceModel(v, it){ const t=String(v||'').toLowerCase(); if (t.includes('consult')) return 'consultation'; if (it==='counter'||t.includes('unit')||t.includes('nail')) return 'per_nail'; return 'fixed'; }
    function orderIndex(arr, name){ const k=loose(name); const i=arr.findIndex(x => loose(x)===k); return i >= 0 ? (i+1)*1000 : 999000; }
    function ritualOrder(department, ritual){ return orderIndex(department==='Foot' ? FOOT_ORDER : HAND_ORDER, ritual); }
    function categoryOrder(department, ritual, category){
        const map = department==='Foot' ? FOOT_CATEGORY_ORDER : HAND_CATEGORY_ORDER;
        const arr = map[ritual] || [];
        return orderIndex(arr, category);
    }
    function serviceName(raw){ return String(raw.serviceName || raw.name || raw.displayName || '').trim(); }

    function inferRitualAndCategory(raw, department){
        const name = serviceName(raw);
        let ritual = String(raw.ritualGroup || '').trim();
        let category = String(raw.category || '').trim();
        const k = loose([name, raw.serviceDescription, raw.description, raw.desc, ritual, category, raw.serviceType].join(' '));

        if (department === 'Foot') {
            if (/foundation|silk skin|refinement|rituel jeunesse/.test(k)) { ritual='Foundation Rituals'; category=category||'Foundation Rituals'; }
            else if (/urban|rapid reboot|essential foot reset/.test(k)) { ritual='Urban Express Rituals'; category=category||'Urban Express Rituals'; }
            else if (/medi cleanse|heel|callus|corrective/.test(k)) { ritual='The Medi-Cleanse Series'; category=category||'The Medi-Cleanse Series'; }
            else if (/finishing|paraffin|hot stone/.test(k)) { ritual='Finishing Indulgences'; category=category||'Finishing Indulgences'; }
            else if (/polish|lacquer|gel couture|french|chrome|ombre|ombré/.test(k)) { ritual='Polish & Finish'; category=category||'Polish & Finish'; }
            else if (/art|atelier|custom/.test(k)) { ritual='Editorial Nail Art'; category=category||'Editorial Nail Art'; }
            else { ritual = ritual || 'Foundation Rituals'; category = category || ritual; }
        } else {
            if (/youthful|silken|precision groom|hand therap|hand renewal|hand balance/.test(k)) { ritual='Hand Therapies'; category=category||'Core Hand Rituals'; }
            else if (/finishing|lush arm|paraffin|hot stone arm/.test(k)) { ritual='Finishing Indulgences'; category=category||'Finishing Indulgences'; }
            else if (/acrylic|gel\s*x|gel-x|biab|duragel|sculpt|repair|stick/.test(k)) { ritual='Nail Architecture';
                if (!category || loose(category)===loose(ritual)) {
                    if (/sculpt/.test(k)) category='Sculpt Acrylic'; else if (/gel\s*x|gel-x/.test(k)) category='Gel-X'; else if (/biab/.test(k)) category='BIAB'; else if (/duragel|dura gel/.test(k)) category='DuraGel'; else if (/repair|stick/.test(k)) category='Nail Repairs & Stick-ons'; else category='Acrylic';
                }
            }
            else if (/polish|french|chrome|ombre|ombré|manicure/.test(k)) { ritual='Polish & Finish'; category=category||'Polish & Finish'; }
            else if (/couture/.test(k)) { ritual='The Pleiades Studio'; category=category||'Couture Nail Art'; }
            else if (/embellish|stone|crystal|pearl|metal|3d/.test(k)) { ritual='The Pleiades Studio'; category=category||'Embellishment Drawers'; }
            else if (/art|editorial|custom/.test(k)) { ritual='The Pleiades Studio'; category=category||'Editorial Nail Art'; }
            else { ritual = ritual || 'Hand Therapies'; category = category || 'Core Hand Rituals'; }
        }
        if (!category) category = ritual;
        return {ritualGroup: ritual, category};
    }

    function normalizeRecord(id, raw={}){
        const explicitDept = dept(raw.department || raw.appliesTo || raw.dept);
        let department = explicitDept;
        const inferredFoot = /\bfoot\b|feet|pedicure|heel|callus|sole|toe|medi[-\s]?cleanse|rapid reboot|essential foot reset|silk skin|refinement indulgence/i.test([raw.serviceName, raw.serviceDescription, raw.ritualGroup, raw.category].join(' '));
        const inferredHand = /\bhand\b|manicure|arm|acrylic|gel\s*x|biab|duragel|sculpt/i.test([raw.serviceName, raw.serviceDescription, raw.ritualGroup, raw.category].join(' '));
        if (inferredFoot && !inferredHand) department='Foot';
        if (inferredHand && !inferredFoot) department='Hand';
        const rc = inferRitualAndCategory(raw, department);
        const it = inputType(raw.inputType || raw.selection || raw.serviceType);
        const st = status(raw.status);
        const sname = serviceName(raw) || 'Unnamed Service';
        const sortOrder = num(raw.sortOrder ?? raw.priority ?? raw.serviceSortOrder, 9999);
        return {
            id, department,
            ritualGroup: rc.ritualGroup,
            ritualGroupDescription: String(raw.ritualGroupDescription || RITUAL_DESC[department]?.[rc.ritualGroup] || '').trim(),
            category: rc.category,
            categoryDescription: String(raw.categoryDescription || CATEGORY_DESC[rc.category] || RITUAL_DESC[department]?.[rc.ritualGroup] || '').trim(),
            serviceName: sname,
            name: sname,
            serviceDescription: String(raw.serviceDescription || raw.description || raw.desc || '').trim(),
            price: parseFloat(raw.price || raw.priceGHC || raw.amount || 0) || 0,
            duration: parseInt(raw.duration || raw.durationMins || 0, 10) || 0,
            inputType: it,
            pricingModel: priceModel(raw.pricingModel || raw.pricingType, it),
            sortOrder,
            status: st,
            isActive: st === 'active' && raw.isActive !== false,
            updatedAt: raw.updatedAt || null,
            tag: raw.tag || 'None'
        };
    }

    function dedup(items){
        const map = new Map();
        items.forEach(s => {
            if (s.status === 'deleted') return;
            const key = [s.department,s.ritualGroup,s.category,s.serviceName].map(loose).join('|');
            const cur = map.get(key);
            if (!cur || (String(s.serviceDescription||'').length > String(cur.serviceDescription||'').length) || (s.isActive && !cur.isActive)) map.set(key,s);
        });
        return Array.from(map.values());
    }

    function buildTree(items){
        const tree = {Hand:{}, Foot:{}};
        items.forEach(s => {
            const d = s.department === 'Foot' ? 'Foot' : 'Hand';
            const r = s.ritualGroup || (d==='Foot'?'Foundation Rituals':'Hand Therapies');
            const c = s.category || r;
            tree[d][r] ||= {name:r, desc:s.ritualGroupDescription || RITUAL_DESC[d]?.[r] || '', categories:{}, order:ritualOrder(d,r)};
            if (!tree[d][r].desc && s.ritualGroupDescription) tree[d][r].desc = s.ritualGroupDescription;
            tree[d][r].categories[c] ||= {name:c, desc:s.categoryDescription || CATEGORY_DESC[c] || '', services:[], order:categoryOrder(d,r,c)};
            if (!tree[d][r].categories[c].desc && s.categoryDescription) tree[d][r].categories[c].desc = s.categoryDescription;
            tree[d][r].categories[c].services.push(s);
        });
        return tree;
    }

    function sortedRituals(tree, d){ return Object.values(tree[d]||{}).sort((a,b)=>a.order-b.order || a.name.localeCompare(b.name,undefined,{numeric:true,sensitivity:'base'})); }
    function sortedCategories(node, d){ return Object.values(node.categories||{}).sort((a,b)=>a.order-b.order || a.name.localeCompare(b.name,undefined,{numeric:true,sensitivity:'base'})); }
    function sortedServices(cat){ return (cat.services||[]).sort((a,b)=>num(a.sortOrder,9999)-num(b.sortOrder,9999) || a.serviceName.localeCompare(b.serviceName,undefined,{numeric:true,sensitivity:'base'})); }

    function money(v){ const n=Number(v); return n>0 ? 'GHC' + (Number.isInteger(n)?String(n):n.toFixed(2)) : 'Consultation'; }
    function serviceCard(s, groupPrefix){
        if (!s.isActive) return '';
        const it = inputType(s.inputType);
        const priceSuffix = s.pricingModel === 'per_nail' ? ' / nail' : '';
        const safeDur = parseInt(s.duration||0,10)||0;
        const safePrc = parseFloat(s.price||0)||0;
        if (it === 'counter') {
            return `<div class="th-ritual-service th-ritual-counter is-simple" data-service-id="${esc(s.id)}"><div class="th-ritual-row"><div><div class="th-ritual-name">${esc(s.serviceName)}</div>${s.serviceDescription?`<div class="th-ritual-desc">${esc(s.serviceDescription)}</div>`:''}</div><div class="th-ritual-price">${esc(money(safePrc)+priceSuffix)}</div></div><div class="counter-box th-ritual-counter-box"><button type="button" class="btn btn-secondary" style="padding:2px 10px;width:auto;" onclick="event.preventDefault();event.stopPropagation();updateCounter('${attr(s.id)}',-1);return false;">-</button><input type="number" id="sched_qty_${esc(s.id)}" class="sched-service-counter" data-name="${esc(s.serviceName)}" data-duration="${safeDur}" data-price="${safePrc}" value="0" min="0" readonly><button type="button" class="btn btn-secondary" style="padding:2px 10px;width:auto;" onclick="event.preventDefault();event.stopPropagation();updateCounter('${attr(s.id)}',1);return false;">+</button></div></div>`;
        }
        const groupName = it === 'radio' ? `sched_base_${slug(groupPrefix)}` : `sched_cb_${slug(s.id)}`;
        const input = it === 'radio' ? `<input type="radio" name="${esc(groupName)}" class="sched-service-item" id="sched_cb_${esc(s.id)}" data-name="${esc(s.serviceName)}" data-duration="${safeDur}" data-price="${safePrc}">` : `<input type="checkbox" class="sched-service-item" id="sched_cb_${esc(s.id)}" data-name="${esc(s.serviceName)}" data-duration="${safeDur}" data-price="${safePrc}">`;
        return `<div class="service-card th-ritual-service is-simple" onclick="toggleServiceCard(event,this,'${attr(s.id)}','${it}','${attr(groupName)}')">${input}<label><div class="th-ritual-row"><div><div class="th-ritual-name">${esc(s.serviceName)}</div>${s.serviceDescription?`<div class="th-ritual-desc">${esc(s.serviceDescription)}</div>`:''}</div><div class="th-ritual-price">${esc(money(safePrc)+priceSuffix)}</div></div></label></div>`;
    }

    function renderDept(tree, d, mode, canEdit){
        const rituals = sortedRituals(tree,d);
        if (!rituals.length) return '<div class="th-menu-empty">No services configured for this department yet.</div>';
        let html = `<div class="th-ritual-menu th-client-menu-tree">`;
        rituals.forEach((r, ri)=>{
            html += `<details class="th-ritual-main th-final-ritual" ${ri===0?'open':''}><summary><div class="th-ritual-title-block"><span class="th-menu-kicker">Ritual Group · V2</span><strong>${esc(r.name)}</strong>${r.desc?`<span>${esc(r.desc)}</span>`:''}</div><div class="th-ritual-chev">⌄</div></summary><div class="th-ritual-content">`;
            sortedCategories(r,d).forEach(c=>{
                html += `<section class="th-ritual-submenu th-final-category"><h3>${esc(c.name)}</h3>${c.desc?`<p class="th-ritual-subdesc">${esc(c.desc)}</p>`:''}<div class="th-final-service-list">`;
                sortedServices(c).forEach(s=>{
                    if (mode === 'admin') {
                        const isActive = s.isActive;
                        html += `<div class="th-menu-service-card ${!isActive?'is-inactive':''}"><div class="th-menu-service-top"><div><span class="th-menu-kicker">Service · Sort ${esc(s.sortOrder)}</span><strong>${esc(s.serviceName)}</strong></div><span class="th-menu-status ${isActive?'active':'inactive'}">${isActive?'active':'inactive'}</span></div>${s.serviceDescription?`<p class="th-menu-service-desc">${esc(s.serviceDescription)}</p>`:`<p class="th-menu-missing">Service Description required.</p>`}<div class="th-menu-meta"><span>${esc(d)}</span><span>${esc(r.name)}</span><span>${esc(c.name)}</span><span>${s.duration||0} mins</span><span>${s.price||0} GHC</span><span>${esc(s.inputType)}</span></div>${canEdit?`<div class="th-menu-actions"><button class="btn btn-secondary" onclick="editMenuService('${attr(s.id)}')">Edit</button><button class="btn btn-secondary" onclick="moveMenuServicePriority('${attr(s.id)}',-1)">↑ Sort</button><button class="btn btn-secondary" onclick="moveMenuServicePriority('${attr(s.id)}',1)">↓ Sort</button><button class="btn btn-secondary" onclick="toggleMenuServiceActive('${attr(s.id)}')">${isActive?'Set Inactive':'Set Active'}</button><button class="btn" style="background:var(--error);" onclick="deleteMenuService('${attr(s.id)}')">Delete Service</button></div>`:''}</div>`;
                    } else {
                        html += serviceCard(s, `${d}_${r.name}_${c.name}`);
                    }
                });
                html += `</div></section>`;
            });
            html += `</div></details>`;
        });
        html += `</div>`;
        return html;
    }

    function renderAll(tree, mode, canEdit){
        return `<div id="${mode==='admin'?'admin':'menu'}_dept_Hand" style="display:block;">${renderDept(tree,'Hand',mode,canEdit)}</div><div id="${mode==='admin'?'admin':'menu'}_dept_Foot" style="display:none;">${renderDept(tree,'Foot',mode,canEdit)}</div>`;
    }

    window.fetchLiveMenu = function(hasEditAccess){
        if (window.thurayaMenuV2Listener) { try { window.thurayaMenuV2Listener(); } catch(e){} window.thurayaMenuV2Listener = null; }
        window.thurayaMenuV2Listener = db.collection(COLLECTION).onSnapshot(snap=>{
            let all = [];
            snap.forEach(doc=>all.push(normalizeRecord(doc.id, doc.data()||{})));
            all = dedup(all).filter(s=>s.status !== 'deleted');
            const active = all.filter(s=>s.isActive);
            window.allMenuServicesCache = active;
            allMenuServicesCache = active;
            const treeAll = buildTree(all);
            const treeActive = buildTree(active);
            const adminList=q('menuManagerList'), booking=q('sched_serviceMenu'), readOnly=q('menuViewReadOnly');
            if (adminList) adminList.innerHTML = renderAll(treeAll,'admin',!!hasEditAccess);
            if (booking) booking.innerHTML = renderAll(treeActive,'booking',false);
            if (readOnly) readOnly.innerHTML = renderAll(treeActive,'view',false).replace(/id="menu_dept_/g,'id="menu_view_dept_').replace(/name="sched_base_/g,'name="view_base_');
            const uSel=q('consultUpsellSelect');
            if (uSel) {
                uSel.innerHTML = '<option value="">Select a service or add-on...</option>';
                active.slice().sort((a,b)=>ritualOrder(a.department,a.ritualGroup)-ritualOrder(b.department,b.ritualGroup)||num(a.sortOrder)-num(b.sortOrder)||a.serviceName.localeCompare(b.serviceName)).forEach(s=>{ uSel.innerHTML += `<option value="${esc(s.id)}">${esc(s.department)} · ${esc(s.ritualGroup)} · ${esc(s.category)} · ${esc(s.serviceName)} (${esc(s.price)} GHC)</option>`; });
            }
            mountToolbar();
        }, err=>{
            const msg = `<p style="color:#b91c1c;text-align:center;font-weight:800;">Error loading Menu_Settings_V2: ${esc(err.message)}</p>`;
            ['menuManagerList','sched_serviceMenu','menuViewReadOnly'].forEach(id=>{ if(q(id)) q(id).innerHTML=msg; });
        });
    };

    function taxonomyFor(department){
        const rituals = (department==='Foot'?FOOT_ORDER:HAND_ORDER).map(name=>({value:name,label:name}));
        return rituals;
    }
    function catsFor(department, ritual){
        const map = department==='Foot'?FOOT_CATEGORY_ORDER:HAND_CATEGORY_ORDER;
        const arr = map[ritual] || [ritual];
        return arr.map(name=>({value:name,label:name}));
    }
    function fillSelect(el, items, keep){
        if(!el) return;
        const old = keep ?? el.value;
        el.innerHTML = items.map(i=>`<option value="${esc(i.value)}">${esc(i.label)}</option>`).join('');
        if (old && !items.some(i=>i.value===old)) el.innerHTML += `<option value="${esc(old)}">${esc(old)} (existing)</option>`;
        if (old) el.value = old;
        if (!el.value && el.options.length) el.selectedIndex=0;
    }
    window.thurayaMenuV2ApplyPresetHints = function(){
        const d = q('adv_applies_to')?.value || 'Hand';
        fillSelect(q('adv_main_menu'), taxonomyFor(d), q('adv_main_menu')?.value);
        const r = q('adv_main_menu')?.value || (d==='Foot'?FOOT_ORDER[0]:HAND_ORDER[0]);
        fillSelect(q('adv_sub_menu'), catsFor(d,r), q('adv_sub_menu')?.value);
        if (q('adv_main_desc')) q('adv_main_desc').value = RITUAL_DESC[d]?.[r] || q('adv_main_desc').value || '';
        const c = q('adv_sub_menu')?.value || '';
        if (q('adv_sub_desc')) q('adv_sub_desc').value = CATEGORY_DESC[c] || RITUAL_DESC[d]?.[r] || q('adv_sub_desc').value || '';
        if (q('adv_type') && !q('adv_type').value) q('adv_type').value = 'Main Therapy';
    };
    window.clearAdvForm = function(){
        window._editingServiceId = null;
        _editingServiceId = null;
        ['adv_name','adv_duration','adv_price','adv_desc'].forEach(id=>{ if(q(id)) q(id).value=''; });
        if (q('adv_applies_to')) q('adv_applies_to').value='Hand';
        if (q('adv_selection')) q('adv_selection').value='radio';
        if (q('adv_priority')) q('adv_priority').value='10';
        if (q('adv_status')) q('adv_status').value='active';
        window.thurayaMenuV2ApplyPresetHints();
        const btn=q('btnSaveServiceConfig')||q('btnAddMenuServiceAdv')||q('btnSaveMenuServiceAdv');
        if (btn) btn.innerText='Save Service Configuration';
    };
    window.addNewMenuServiceAdv = async function(){
        const d = q('adv_applies_to')?.value || 'Hand';
        const r = q('adv_main_menu')?.value || '';
        const c = q('adv_sub_menu')?.value || '';
        const serviceName = q('adv_name')?.value.trim() || '';
        const serviceDescription = q('adv_desc')?.value.trim() || '';
        const price = parseFloat(q('adv_price')?.value || '0');
        const duration = parseInt(q('adv_duration')?.value || '0',10);
        const it = inputType(q('adv_selection')?.value || 'radio');
        const sortOrder = parseInt(q('adv_priority')?.value || '999',10);
        const st = status(q('adv_status')?.value || 'active');
        if (!r) { alert('Select a Ritual Group.'); return; }
        if (!c) { alert('Select a Category.'); return; }
        if (!serviceName) { alert('Service Name is required.'); return; }
        if (!serviceDescription) { alert('Service Description is required.'); return; }
        if (!Number.isFinite(price) || price < 0) { alert('Enter a valid price.'); return; }
        if (!Number.isFinite(duration) || duration < 0) { alert('Enter a valid duration.'); return; }
        if (!Number.isFinite(sortOrder) || sortOrder < 1) { alert('Enter a valid Sort Order.'); return; }
        const payload = {department:d, ritualGroup:r, ritualGroupDescription:RITUAL_DESC[d]?.[r] || q('adv_main_desc')?.value.trim() || '', category:c, categoryDescription:CATEGORY_DESC[c] || q('adv_sub_desc')?.value.trim() || '', serviceName, serviceDescription, price, duration, inputType:it, pricingModel:priceModel(q('adv_pricing_type')?.value,it), sortOrder, status:st, isActive:st==='active', schemaVersion:'v2_final_clean_20260511', updatedAt:firebase.firestore.FieldValue.serverTimestamp(), updatedBy:currentUserEmail || ''};
        try {
            if (_editingServiceId) await db.collection(COLLECTION).doc(_editingServiceId).set(payload,{merge:false});
            else await db.collection(COLLECTION).add({...payload, createdAt:firebase.firestore.FieldValue.serverTimestamp(), createdBy:currentUserEmail || ''});
            alert(_editingServiceId ? 'Service updated in final clean V2 structure.' : 'Service saved in final clean V2 structure.');
            window.clearAdvForm();
        } catch(e){ alert('Error saving service: ' + e.message); }
    };
    window.editMenuService = async function(id){
        try {
            const doc = await db.collection(COLLECTION).doc(id).get();
            if (!doc.exists) { alert('Service not found.'); return; }
            const s = normalizeRecord(doc.id, doc.data()||{});
            _editingServiceId = id;
            if (q('adv_applies_to')) q('adv_applies_to').value=s.department;
            window.thurayaMenuV2ApplyPresetHints();
            if (q('adv_main_menu')) q('adv_main_menu').value=s.ritualGroup;
            window.thurayaMenuV2ApplyPresetHints();
            if (q('adv_sub_menu')) q('adv_sub_menu').value=s.category;
            if (q('adv_main_desc')) q('adv_main_desc').value=s.ritualGroupDescription;
            if (q('adv_sub_desc')) q('adv_sub_desc').value=s.categoryDescription;
            if (q('adv_name')) q('adv_name').value=s.serviceName;
            if (q('adv_desc')) q('adv_desc').value=s.serviceDescription;
            if (q('adv_price')) q('adv_price').value=s.price;
            if (q('adv_duration')) q('adv_duration').value=s.duration;
            if (q('adv_selection')) q('adv_selection').value=s.inputType;
            if (q('adv_priority')) q('adv_priority').value=s.sortOrder;
            if (q('adv_status')) q('adv_status').value=s.status;
            const btn=q('btnSaveServiceConfig')||q('btnAddMenuServiceAdv')||q('btnSaveMenuServiceAdv');
            if (btn) btn.innerText='Update V2 Service';
            q('menuSettingsView')?.scrollIntoView({behavior:'smooth',block:'start'});
        } catch(e){ alert('Error loading service: ' + e.message); }
    };
    window.moveMenuServicePriority = async function(id, dir){
        const ref=db.collection(COLLECTION).doc(id); const doc=await ref.get(); if(!doc.exists)return;
        const cur=num(doc.data().sortOrder,100); await ref.set({sortOrder:Math.max(1,cur+(parseInt(dir,10)||0)), updatedAt:firebase.firestore.FieldValue.serverTimestamp(), updatedBy:currentUserEmail||''},{merge:true});
    };
    window.toggleMenuServiceActive = async function(id){
        const ref=db.collection(COLLECTION).doc(id); const doc=await ref.get(); if(!doc.exists)return;
        const next=status(doc.data().status)==='active'?'inactive':'active';
        await ref.set({status:next,isActive:next==='active',updatedAt:firebase.firestore.FieldValue.serverTimestamp(),updatedBy:currentUserEmail||''},{merge:true});
    };
    window.deleteMenuService = async function(id){
        if(!confirm('Delete this service from active menu?')) return;
        await db.collection(COLLECTION).doc(id).set({status:'deleted',isActive:false,deleted:true,deletedAt:firebase.firestore.FieldValue.serverTimestamp(),deletedBy:currentUserEmail||''},{merge:true});
    };

    async function currentMenu(){ const snap=await db.collection(COLLECTION).get(); const all=[]; snap.forEach(d=>all.push(normalizeRecord(d.id,d.data()||{}))); return all.filter(s=>s.status!=='deleted'); }
    window.thurayaAuditCategoryMenu = async function(){
        try { const all = await currentMenu(); const missingCat=all.filter(s=>!s.category || s.category==='General').length; const wrongOrder=all.filter(s=>ritualOrder(s.department,s.ritualGroup)>=999000).length; alert(`Category Menu Audit\n\nRecords checked: ${all.length}\nMissing/General category: ${missingCat}\nUnapproved ritual groups: ${wrongOrder}\n\nUse BACKFILL CATEGORY ORDER to normalize existing records into the approved hierarchy.`); }
        catch(e){ alert('Audit failed: '+e.message); }
    };
    window.thurayaBackfillCategoryOrder = async function(){
        if(!confirm('Backfill Menu_Settings_V2 into the final approved hierarchy and category order now?')) return;
        try { const snap=await db.collection(COLLECTION).get(); let batch=db.batch(), count=0, ops=0; snap.forEach(doc=>{ const clean=normalizeRecord(doc.id,doc.data()||{}); if(clean.status==='deleted') return; batch.set(doc.ref,{department:clean.department,ritualGroup:clean.ritualGroup,ritualGroupDescription:clean.ritualGroupDescription,category:clean.category,categoryDescription:clean.categoryDescription,serviceName:clean.serviceName,serviceDescription:clean.serviceDescription,price:clean.price,duration:clean.duration,inputType:clean.inputType,pricingModel:clean.pricingModel,sortOrder:clean.sortOrder,status:clean.status,isActive:clean.isActive,schemaVersion:'v2_final_clean_20260511',updatedAt:firebase.firestore.FieldValue.serverTimestamp(),updatedBy:currentUserEmail||''},{merge:false}); count++; ops++; if(ops>=430){ /* single batch fallback handled below */ }}); await batch.commit(); alert(`Backfill complete. ${count} service record(s) normalized.`); } catch(e){ alert('Backfill failed: '+e.message); }
    };
    function mountToolbar(){
        const bar=q('seedMenuBtnContainer'); if(!bar) return;
        const desired=[['BACKUP MENU V2','thurayaBackupMenuV2HF63()','secondary'],['AUDIT CATEGORY MENU','thurayaAuditCategoryMenu()','secondary'],['BACKFILL CATEGORY ORDER','thurayaBackfillCategoryOrder()','primary'],['REPAIR V2 DATA','thurayaRepairMenuV2Data && thurayaRepairMenuV2Data()','secondary']];
        bar.innerHTML='';
        desired.forEach(([label,fn,type])=>{ const b=document.createElement('button'); b.type='button'; b.className= type==='primary'?'btn':'btn btn-secondary'; b.style.width='auto'; if(type==='primary'){ b.style.background='#111'; b.style.color='#fff'; } b.textContent=label; b.setAttribute('onclick',fn); bar.appendChild(b); });
    }
    function patchCopy(){
        const hero=q('menuSettingsView')?.querySelector('.th-menu-hero-head p'); if(hero) hero.textContent='Clean menu control for the final approved hierarchy: Department → Ritual Group → Category → Service. Menu_Settings_V2 is the single source of truth for Menu Settings, Service Menu, and Booking.';
        const live=q('menuManagerList')?.closest('.module-box')?.querySelector('.th-menu-hero-head p'); if(live) live.textContent='Accordion tree view using Department → Ritual Group → Category → Service.';
        mountToolbar();
    }
    document.addEventListener('DOMContentLoaded', function(){ setTimeout(()=>{ try{patchCopy(); window.thurayaMenuV2ApplyPresetHints();}catch(e){} }, 800); });
})();

/* ============================================================
   THURAYA HF70 FORCE-MOUNT FINAL CATEGORY PIPELINE UI
   Purpose: prove correct file is loaded and override remaining HF63 toolbar/copy.
   ============================================================ */
(function(){
  'use strict';
  const VERSION = 'HF70 FINAL CATEGORY PIPELINE · 20260511';
  function q(id){ return document.getElementById(id); }
  function makeBtn(label, fn, primary){
    const b = document.createElement('button');
    b.type = 'button';
    b.className = primary ? 'btn' : 'btn btn-secondary';
    b.style.width = 'auto';
    b.textContent = label;
    b.onclick = function(){
      if (typeof fn === 'function') return fn();
      alert(label + ' is not available yet. Refresh and try again.');
    };
    return b;
  }
  function ensureCategoryField(){
    if (q('adv_sub_menu')) return;
    const ritual = q('adv_main_menu');
    if (!ritual) return;
    const ritualGroup = ritual.closest('.form-group');
    if (!ritualGroup || !ritualGroup.parentNode) return;
    const wrap = document.createElement('div');
    wrap.className = 'form-group';
    wrap.innerHTML = '<label>Category</label><select id="adv_sub_menu"><option value="Core Rituals">Core Rituals</option></select><small class="th-menu-field-hint">Required category layer for client-facing menu structure.</small>';
    ritualGroup.insertAdjacentElement('afterend', wrap);
  }
  function forceMenuSettingsUI(){
    const view = q('menuSettingsView');
    if (!view) return;
    view.setAttribute('data-menu-pipeline-version', VERSION);

    const title = view.querySelector('h3');
    if (title && /menu settings/i.test(title.textContent || '')) {
      title.innerHTML = '🛠 MENU SETTINGS <span style="font-size:11px;letter-spacing:.12em;border:1px solid #111;border-radius:999px;padding:4px 8px;margin-left:10px;vertical-align:middle;">' + VERSION + '</span>';
    }
    const heroCopy = view.querySelector('.th-menu-hero-head p, h3 + p');
    if (heroCopy) heroCopy.textContent = 'Clean menu control for the final approved hierarchy: Department → Ritual Group → Category → Service. Menu_Settings_V2 is the single source of truth for Menu Settings, Service Menu, and Booking.';

    ensureCategoryField();

    const bar = q('seedMenuBtnContainer');
    if (bar && bar.getAttribute('data-hf70-mounted') !== '1') {
      bar.innerHTML = '';
      bar.appendChild(makeBtn('BACKUP MENU V2', window.thurayaBackupMenuV2HF63, false));
      bar.appendChild(makeBtn('AUDIT CATEGORY MENU', window.thurayaAuditCategoryMenu, false));
      bar.appendChild(makeBtn('BACKFILL CATEGORY ORDER', window.thurayaBackfillCategoryOrder, true));
      bar.appendChild(makeBtn('REPAIR V2 DATA', window.thurayaRepairMenuV2Data, false));
      bar.setAttribute('data-hf70-mounted','1');
    }

    const liveTitle = Array.from(view.querySelectorAll('h3')).find(h => /live simplified menu/i.test(h.textContent || ''));
    if (liveTitle) {
      liveTitle.textContent = 'LIVE FINAL MENU';
      const p = liveTitle.parentElement && liveTitle.parentElement.querySelector('p');
      if (p) p.textContent = 'Accordion tree view using Department → Ritual Group → Category → Service from Menu_Settings_V2 only.';
    }
  }
  function tick(){ try { forceMenuSettingsUI(); } catch(e){ console.warn('HF70 force UI skipped', e); } }
  document.addEventListener('DOMContentLoaded', function(){ tick(); setTimeout(tick,500); setTimeout(tick,1500); });
  setInterval(tick, 2000);
  window.THURAYA_MENU_PIPELINE_VERSION = VERSION;
})();


/* ============================================================
   THURAYA STAFF — HF72 GUIDED BOOKING RESTORE ON CLEAN MENU PIPELINE
   Stack:
   - Keeps HF70 Menu_Settings_V2 final category pipeline intact.
   - Restores HF66 guided New Booking shell.
   - Reuses existing sched_* booking runtime so HF65 group booking,
     availability, counters, pricing, tax, promo, and tech assignment remain intact.
   - No Firebase schema changes and no legacy menu source reintroduced.
   ============================================================ */
(function(){
    if (window.__THURAYA_HF72_GUIDED_BOOKING_RESTORE__) return;
    window.__THURAYA_HF72_GUIDED_BOOKING_RESTORE__ = true;

    const state = { step: 1, mounted: false };

    function q(id){ return document.getElementById(id); }
    function money(v){ const n = Number(v || 0); return Number.isFinite(n) ? n.toFixed(2) + ' GHC' : '0.00 GHC'; }
    function selectedServices(){
        const list = [];
        document.querySelectorAll('#sched_serviceMenu .sched-service-item:checked').forEach(el => {
            const name = el.getAttribute('data-name') || '';
            if (name) list.push(name);
        });
        document.querySelectorAll('#sched_serviceMenu .sched-service-counter').forEach(el => {
            const qty = parseInt(el.value || '0', 10) || 0;
            const name = el.getAttribute('data-name') || '';
            if (qty > 0 && name) list.push(`${name} x${qty}`);
        });
        return list;
    }
    function hasClient(){ return !!(q('sched_phone')?.value && q('sched_name')?.value); }
    function hasServices(){ return selectedServices().length > 0; }
    function hasTime(){ return !!(q('sched_date')?.value && q('sched_techSelect')?.value && q('sched_time')?.value); }

    function ensureShell(){
        const bookingView = q('bookingWizardView');
        const mount = q('thB11BookingMount');
        const schedule = q('subView_Schedule');
        if (!bookingView || !mount || !schedule) return false;

        const tab = q('tabNewBooking');
        if (tab) tab.style.display = 'flex';

        if (!mount.contains(schedule)) {
            mount.appendChild(schedule);
        }
        schedule.style.display = 'block';
        schedule.classList.add('th-b11-schedule');

        if (!q('thB11HeaderHF72')) {
            const header = document.createElement('div');
            header.id = 'thB11HeaderHF72';
            header.className = 'th-b11-header';
            header.innerHTML = `
                <section class="th-b11-hero">
                    <div>
                        <div class="th-b11-kicker">Assisted Concierge Booking</div>
                        <h2>New Booking</h2>
                        <p>FOH searches the registered client, then follows a calm client-style booking journey.</p>
                    </div>
                    <span id="thB11StatusPill">Step 1 of 4</span>
                </section>
                <nav class="th-b11-stepper" aria-label="Booking steps">
                    <button type="button" data-step="1" onclick="thB11SetStep(1)"><span>1</span> Client</button>
                    <button type="button" data-step="2" onclick="thB11SetStep(2)"><span>2</span> Services</button>
                    <button type="button" data-step="3" onclick="thB11SetStep(3)"><span>3</span> Date & Time</button>
                    <button type="button" data-step="4" onclick="thB11SetStep(4)"><span>4</span> Review</button>
                </nav>`;
            mount.insertBefore(header, schedule);
        }

        const grid = schedule.querySelector('.grid-2');
        const left = grid ? grid.children[0] : null;
        const right = grid ? grid.children[1] : null;
        const boxes = left ? Array.from(left.querySelectorAll(':scope > .module-box')) : Array.from(schedule.querySelectorAll(':scope > .module-box'));

        if (boxes[0]) boxes[0].classList.add('th-b11-pane', 'th-b11-client-pane');
        if (boxes[1]) boxes[1].classList.add('th-b11-pane', 'th-b11-services-pane');
        if (boxes[2]) boxes[2].classList.add('th-b11-pane', 'th-b11-time-pane');

        if (right) right.classList.add('th-b11-side-pane');

        if (!q('thB11ReviewPaneHF72')) {
            const review = document.createElement('div');
            review.id = 'thB11ReviewPaneHF72';
            review.className = 'module-box th-b11-pane th-b11-review-pane';
            review.style.display = 'none';
            review.innerHTML = `
                <h3 style="color:var(--primary); border-bottom-color:var(--accent);">Review Booking</h3>
                <p class="th-b11-muted">Confirm client, services, date, technician, time and total before booking.</p>
                <div id="thB11ReviewBodyHF72" class="th-b11-review-body"></div>
                <div class="th-b11-actions">
                    <button type="button" class="btn btn-secondary" onclick="thB11SetStep(3)">Back</button>
                    <button type="button" class="btn th-b11-primary" onclick="bookAppointment()">Confirm & Book Appointment</button>
                </div>`;
            if (left) left.appendChild(review);
            else schedule.appendChild(review);
        }

        addActionsOnce();
        state.mounted = true;
        return true;
    }

    function addActionsOnce(){
        function add(sel, id, html){
            const pane = document.querySelector(sel);
            if (!pane || q(id)) return;
            const div = document.createElement('div');
            div.id = id;
            div.className = 'th-b11-actions';
            div.innerHTML = html;
            pane.appendChild(div);
        }
        add('.th-b11-client-pane', 'thB11ClientActionsHF72', `
            <button type="button" class="btn th-b11-primary" onclick="thB11GoServices()">Continue to Services</button>
        `);
        add('.th-b11-services-pane', 'thB11ServiceActionsHF72', `
            <button type="button" class="btn btn-secondary" onclick="thB11SetStep(1)">Back</button>
            <button type="button" class="btn th-b11-primary" onclick="thB11GoTime()">Continue to Date & Time</button>
        `);
        add('.th-b11-time-pane', 'thB11TimeActionsHF72', `
            <button type="button" class="btn btn-secondary" onclick="thB11SetStep(2)">Back</button>
            <button type="button" class="btn th-b11-primary" onclick="thB11GoReview()">Review Booking</button>
        `);
    }

    function renderReview(){
        const body = q('thB11ReviewBodyHF72');
        if (!body) return;

        const name = q('sched_name')?.value || 'No client selected';
        const phone = q('sched_phone')?.value || '';
        const services = selectedServices();
        const date = q('sched_date')?.value || '—';
        const techSel = q('sched_techSelect');
        const tech = techSel?.options[techSel.selectedIndex]?.text || '—';
        const time = q('sched_time')?.value || '—';
        const duration = q('sched_totalDuration')?.innerText || '0';
        const total = q('sched_grandTotalVal')?.value || q('sched_totalCost')?.innerText || '0';
        const groupSize = parseInt(q('sched_groupSize')?.value || '1', 10) || 1;
        const groupId = q('sched_groupId')?.value || '';

        body.innerHTML = `
            <div class="th-b11-review-grid">
                <div><span>Client</span><strong>${name}</strong><small>${phone}</small></div>
                <div><span>Visit Type</span><strong>${groupSize > 1 ? `Group Booking · ${groupSize} people` : 'Individual Booking'}</strong><small>${groupId || ''}</small></div>
                <div><span>Date & Time</span><strong>${date} · ${time}</strong><small>${duration} mins</small></div>
                <div><span>Technician</span><strong>${tech}</strong><small>Assigned resource</small></div>
            </div>
            <div class="th-b11-review-services">
                <span>Services</span>
                ${services.length ? services.map(s => `<p>${s}</p>`).join('') : '<p>No services selected.</p>'}
            </div>
            <div class="th-b11-review-total"><span>Grand Total</span><strong>${money(total)}</strong></div>
        `;
    }

    function renderStep(step){
        if (!ensureShell()) return;
        state.step = Math.max(1, Math.min(4, parseInt(step || 1, 10) || 1));

        const panes = [
            document.querySelector('.th-b11-client-pane'),
            document.querySelector('.th-b11-services-pane'),
            document.querySelector('.th-b11-time-pane'),
            q('thB11ReviewPaneHF72')
        ];

        panes.forEach((pane, idx) => {
            if (pane) pane.style.display = (idx + 1 === state.step) ? 'block' : 'none';
        });

        const side = document.querySelector('.th-b11-side-pane');
        if (side) side.style.display = 'none';

        document.querySelectorAll('#thB11HeaderHF72 .th-b11-stepper button').forEach(btn => {
            const n = parseInt(btn.getAttribute('data-step'), 10);
            btn.classList.toggle('active', n === state.step);
            btn.classList.toggle('done', n < state.step);
        });

        const pill = q('thB11StatusPill');
        if (pill) pill.textContent = `Step ${state.step} of 4`;

        if (state.step === 2) {
            try { if (typeof fetchLiveMenu === 'function') fetchLiveMenu(true); } catch(e) {}
        }
        if (state.step === 3) {
            try { if (typeof generateTimeSlots === 'function') generateTimeSlots(); } catch(e) {}
        }
        if (state.step === 4) renderReview();

        const target = q('bookingWizardView');
        if (target) setTimeout(() => target.scrollIntoView({behavior:'smooth', block:'start'}), 30);
    }

    window.thB11SetStep = function(step){ renderStep(step); };

    window.thB11GoServices = function(){
        if (!hasClient()) {
            alert('Search and select a registered client first.');
            return;
        }
        renderStep(2);
    };

    window.thB11GoTime = function(){
        if (!hasServices()) {
            alert('Select at least one service before choosing date and time.');
            return;
        }
        renderStep(3);
    };

    window.thB11GoReview = function(){
        if (!hasTime()) {
            alert('Select date, technician, and available time slot first.');
            return;
        }
        renderStep(4);
    };

    function openGuidedBooking(){
        document.querySelectorAll('.app-module').forEach(mod => mod.style.display = 'none');
        const view = q('bookingWizardView');
        if (view) view.style.display = 'block';

        const clients = q('clientsView');
        if (clients) clients.style.display = 'none';

        ensureShell();
        renderStep(1);

        const nav = q('nav_new_booking');
        if (nav) nav.checked = true;
    }

    function wrapSwitchModule(){
        if (typeof window.switchModule !== 'function') return false;
        if (window.switchModule.__THURAYA_HF72_GUIDED_WRAPPED__) return true;

        const previous = window.switchModule;
        const wrapped = function(moduleId){
            if (moduleId === 'bookingWizardView') {
                openGuidedBooking();
                return;
            }
            return previous.apply(this, arguments);
        };
        wrapped.__THURAYA_HF72_GUIDED_WRAPPED__ = true;
        window.switchModule = wrapped;
        return true;
    }

    document.addEventListener('DOMContentLoaded', function(){
        wrapSwitchModule();
        const tab = q('tabNewBooking');
        if (tab) tab.style.display = 'flex';

        const nav = q('nav_new_booking');
        if (nav && nav.dataset.hf72Wired !== '1') {
            nav.dataset.hf72Wired = '1';
            nav.addEventListener('change', function(){
                if (this.checked) openGuidedBooking();
            });
        }

        const label = document.querySelector('label[for="nav_new_booking"]');
        if (label && label.dataset.hf72Wired !== '1') {
            label.dataset.hf72Wired = '1';
            label.addEventListener('click', function(){
                setTimeout(openGuidedBooking, 50);
            });
        }

        setTimeout(function(){
            if (q('bookingWizardView')?.style.display === 'block' || q('nav_new_booking')?.checked) {
                openGuidedBooking();
            }
        }, 500);
    });

    setTimeout(wrapSwitchModule, 300);
    setTimeout(wrapSwitchModule, 1200);
})();


/* ============================================================
   THURAYA STAFF — HF73 PRODUCTION WIZARD BODY RESTORE
   Purpose:
   - Keeps HF70 Menu_Settings_V2 Category pipeline.
   - Restores the production Step 1 guided body: Just Me / Book for a Group.
   - Hides the old sched_groupSize dropdown visually only.
   - Leaves sched_* booking runtime intact for HF65 availability, pricing,
     counters, tax, promo, and group booking logic.
   ============================================================ */
(function(){
    if (window.__THURAYA_HF73_PRODUCTION_WIZARD_BODY__) return;
    window.__THURAYA_HF73_PRODUCTION_WIZARD_BODY__ = true;

    function q(id){ return document.getElementById(id); }
    function pane(){ return document.querySelector('.th-b11-client-pane'); }
    function esc(v){ return String(v ?? '').replace(/[&<>'"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[ch])); }

    function installStyles(){
        if (q('thHF73WizardBodyStyles')) return;
        const style = document.createElement('style');
        style.id = 'thHF73WizardBodyStyles';
        style.textContent = `
            #thB11HeaderHF72 .th-b11-kicker{letter-spacing:.20em!important;}
            .th-b2-visit-shell{margin-top:18px;border:1px solid rgba(181,158,75,.24);background:#fffdf8;border-radius:20px;padding:16px;}
            .th-b2-visit-kicker{color:#8a7a35;font-size:.72rem;font-weight:900;letter-spacing:.18em;text-transform:uppercase;margin-bottom:8px;}
            .th-b2-visit-title{font-size:1rem;font-weight:900;color:#111;margin:0 0 12px;}
            .th-b2-visit-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
            .th-b2-choice{border:1px solid rgba(0,0,0,.10);border-radius:18px;background:#fff;min-height:88px;padding:16px;display:flex;align-items:center;gap:14px;cursor:pointer;text-align:left;transition:transform .16s ease,box-shadow .16s ease,border-color .16s ease,background .16s ease;}
            .th-b2-choice:hover{border-color:rgba(181,158,75,.55);box-shadow:0 12px 28px rgba(10,10,10,.07);}
            .th-b2-choice.active{background:#111;color:#fff;border-color:#111;box-shadow:0 16px 34px rgba(10,10,10,.16);}
            .th-b2-choice-icon{width:48px;height:48px;border-radius:50%;display:flex;align-items:center;justify-content:center;background:#f3f1ea;font-size:1.15rem;flex:0 0 auto;}
            .th-b2-choice.active .th-b2-choice-icon{background:rgba(255,255,255,.12);}
            .th-b2-choice strong{display:block;font-size:1rem;line-height:1.2;color:inherit;}
            .th-b2-choice span{display:block;font-size:.82rem;line-height:1.35;color:#6f665c;margin-top:4px;}
            .th-b2-choice.active span{color:rgba(255,255,255,.78);}
            .th-b2-group-panel{display:none;margin-top:14px;border:1px dashed rgba(181,158,75,.45);border-radius:18px;padding:14px;background:#fff;}
            .th-b2-group-panel.active{display:block;}
            .th-b2-counter-row{display:flex;align-items:center;justify-content:space-between;gap:16px;flex-wrap:wrap;}
            .th-b2-counter-row p{margin:0;color:#5f5a52;font-size:.86rem;line-height:1.45;}
            .th-b2-counter{display:flex;align-items:center;gap:10px;}
            .th-b2-count-btn{width:42px;height:42px;border-radius:50%;border:1px solid rgba(0,0,0,.14);background:#fff;color:#111;font-size:1.25rem;font-weight:900;cursor:pointer;}
            .th-b2-count-badge{min-width:88px;height:48px;border-radius:999px;border:1px solid rgba(181,158,75,.45);display:flex;align-items:center;justify-content:center;font-weight:900;font-size:1.05rem;color:#111;background:#fffdf8;}
            .th-b2-client-status{margin-top:14px;border-radius:16px;padding:12px 14px;font-size:.86rem;font-weight:800;}
            .th-b2-client-status.warn{background:#fff8e1;border:1px solid rgba(181,158,75,.35);color:#7c5a00;}
            .th-b2-client-status.ready{background:rgba(39,174,96,.10);border:1px solid rgba(39,174,96,.25);color:#047857;}
            .th-b2-primary-disabled{opacity:.45!important;pointer-events:none!important;filter:grayscale(.25);}
            .th-b2-hidden-legacy-group{display:none!important;}
            @media(max-width:780px){.th-b2-visit-grid{grid-template-columns:1fr}.th-b2-counter-row{align-items:flex-start}.th-b2-counter{width:100%;justify-content:center;}}
        `;
        document.head.appendChild(style);
    }

    function getGroupSize(){ return Math.max(1, Math.min(6, parseInt(q('sched_groupSize')?.value || '1', 10) || 1)); }

    function setGroupSize(size){
        const sel = q('sched_groupSize');
        const n = Math.max(1, Math.min(6, parseInt(size, 10) || 1));
        if (sel) {
            const hasOption = Array.from(sel.options || []).some(o => String(o.value) === String(n));
            if (!hasOption) {
                const opt = document.createElement('option');
                opt.value = String(n);
                opt.textContent = n === 1 ? 'No — Individual' : `Yes — ${n} people`;
                sel.appendChild(opt);
            }
            sel.value = String(n);
        }
        try { if (typeof window.onGroupSizeChange === 'function') window.onGroupSizeChange(); } catch(e) { console.warn('HF73 group size sync skipped', e); }
        renderVisitChoiceState();
    }

    function hideLegacyGroupBlock(){
        const sel = q('sched_groupSize');
        if (!sel) return;
        let node = sel.closest('div');
        for (let i = 0; node && i < 5; i++, node = node.parentElement) {
            const txt = (node.textContent || '').toLowerCase();
            if (txt.includes('group booking')) {
                node.classList.add('th-b2-hidden-legacy-group');
                break;
            }
        }
        const note = q('groupSizeNote');
        if (note) note.classList.add('th-b2-hidden-legacy-group');
    }

    function updateClientPaneText(){
        const p = pane();
        if (!p) return;
        const h3 = p.querySelector('h3');
        if (h3) h3.textContent = '1. Client & Visit Type';
        const heroKicker = document.querySelector('#thB11HeaderHF72 .th-b11-kicker');
        if (heroKicker) heroKicker.textContent = 'Assisted Concierge Booking';
        const heroCopy = document.querySelector('#thB11HeaderHF72 .th-b11-hero p');
        if (heroCopy) heroCopy.textContent = 'FOH searches the registered client, then follows a calm client-style booking journey.';
    }

    function ensureVisitChoice(){
        installStyles();
        updateClientPaneText();
        const p = pane();
        if (!p) return false;
        hideLegacyGroupBlock();
        if (q('thB2VisitChoice')) { renderVisitChoiceState(); return true; }

        const host = document.createElement('div');
        host.id = 'thB2VisitChoice';
        host.className = 'th-b2-visit-shell';
        host.innerHTML = `
            <div class="th-b2-visit-kicker">Assisted Client Flow</div>
            <div class="th-b2-visit-title">How is the client visiting?</div>
            <div class="th-b2-visit-grid">
                <button type="button" class="th-b2-choice" id="thB2ChoiceIndividual" onclick="thB2ChooseIndividual()">
                    <div class="th-b2-choice-icon">🪑</div>
                    <div><strong>Just Me</strong><span>Single appointment, standard flow</span></div>
                </button>
                <button type="button" class="th-b2-choice" id="thB2ChoiceGroup" onclick="thB2ChooseGroup()">
                    <div class="th-b2-choice-icon">👥</div>
                    <div><strong>Book for a Group</strong><span>FOH guides each person through service choice</span></div>
                </button>
            </div>
            <div id="thB2GroupPanel" class="th-b2-group-panel">
                <div class="th-b2-counter-row">
                    <p><strong>Group size</strong><br>Choose how many people will be linked under one group booking.</p>
                    <div class="th-b2-counter">
                        <button type="button" class="th-b2-count-btn" onclick="thB2AdjustGroup(-1)">−</button>
                        <div class="th-b2-count-badge"><span id="thB2GroupCount">2</span> people</div>
                        <button type="button" class="th-b2-count-btn" onclick="thB2AdjustGroup(1)">+</button>
                    </div>
                </div>
            </div>
            <div id="thB2ClientStatus" class="th-b2-client-status warn">Search and select a registered client to continue.</div>
        `;

        const actions = q('thB11ClientActionsHF72') || q('thB11ClientActions');
        if (actions && actions.parentElement === p) p.insertBefore(host, actions);
        else p.appendChild(host);
        renderVisitChoiceState();
        return true;
    }

    function renderVisitChoiceState(){
        const size = getGroupSize();
        const isGroup = size > 1;
        const ind = q('thB2ChoiceIndividual');
        const grp = q('thB2ChoiceGroup');
        const panel = q('thB2GroupPanel');
        const count = q('thB2GroupCount');
        if (ind) ind.classList.toggle('active', !isGroup);
        if (grp) grp.classList.toggle('active', isGroup);
        if (panel) panel.classList.toggle('active', isGroup);
        if (count) count.textContent = String(Math.max(2, size));

        const hasClient = !!(q('sched_phone')?.value && q('sched_name')?.value);
        const status = q('thB2ClientStatus');
        if (status) {
            status.className = 'th-b2-client-status ' + (hasClient ? 'ready' : 'warn');
            const name = q('sched_name')?.value || q('sched_displayName')?.textContent || 'Client';
            status.textContent = hasClient
                ? `${name} selected · ${isGroup ? `Group booking for ${size} people` : 'Individual booking'}`
                : 'Search and select a registered client to continue.';
        }
        const continueBtn = (q('thB11ClientActionsHF72') || q('thB11ClientActions'))?.querySelector('button.th-b11-primary, button.btn');
        if (continueBtn) {
            continueBtn.classList.toggle('th-b2-primary-disabled', !hasClient);
            continueBtn.setAttribute('aria-disabled', hasClient ? 'false' : 'true');
        }
    }

    window.thB2ChooseIndividual = function(){ setGroupSize(1); };
    window.thB2ChooseGroup = function(){ if (getGroupSize() < 2) setGroupSize(2); else renderVisitChoiceState(); };
    window.thB2AdjustGroup = function(delta){ setGroupSize(getGroupSize() + (parseInt(delta, 10) || 0)); };

    function wrapClientHooks(){
        if (typeof window.selectClientForSchedule === 'function' && !window.selectClientForSchedule.__hf73Wrapped) {
            const old = window.selectClientForSchedule;
            const wrapped = function(clientData){
                const result = old.apply(this, arguments);
                setTimeout(renderVisitChoiceState, 50);
                setTimeout(renderVisitChoiceState, 250);
                return result;
            };
            wrapped.__hf73Wrapped = true;
            window.selectClientForSchedule = wrapped;
        }
        if (typeof window.clearScheduleClient === 'function' && !window.clearScheduleClient.__hf73Wrapped) {
            const old = window.clearScheduleClient;
            const wrapped = function(){
                const result = old.apply(this, arguments);
                setTimeout(renderVisitChoiceState, 50);
                return result;
            };
            wrapped.__hf73Wrapped = true;
            window.clearScheduleClient = wrapped;
        }
    }

    function boot(){
        wrapClientHooks();
        ensureVisitChoice();
        setTimeout(ensureVisitChoice, 250);
        setTimeout(ensureVisitChoice, 900);
        setTimeout(renderVisitChoiceState, 1200);
    }

    const oldGo = window.thB11GoServices;
    if (typeof oldGo === 'function' && !oldGo.__hf73Guarded) {
        const guarded = function(){
            const hasClient = !!(q('sched_phone')?.value && q('sched_name')?.value);
            if (!hasClient) { alert('Search and select a registered client first.'); return; }
            return oldGo.apply(this, arguments);
        };
        guarded.__hf73Guarded = true;
        window.thB11GoServices = guarded;
    }

    document.addEventListener('DOMContentLoaded', boot);
    if (document.readyState !== 'loading') boot();
    document.addEventListener('change', function(e){ if (e.target && e.target.id === 'sched_groupSize') setTimeout(renderVisitChoiceState, 50); }, true);
    document.addEventListener('input', function(e){ if (e.target && ['sched_phone','sched_name','sched_search'].includes(e.target.id)) setTimeout(renderVisitChoiceState, 50); }, true);

    const obs = new MutationObserver(() => {
        clearTimeout(window.__thHF73WizardTimer);
        window.__thHF73WizardTimer = setTimeout(() => {
            if (q('bookingWizardView')?.style.display === 'block' || q('nav_new_booking')?.checked) boot();
        }, 120);
    });
    try { obs.observe(document.body, {childList:true, subtree:true}); } catch(e) {}
})();

/* ============================================================
   THURAYA STAFF — HF74 BOOKING WIZARD SAFETY + ANY TECH RESTORE
   Purpose:
   - Keep HF73 production wizard body and HF70 clean menu pipeline.
   - Hide legacy direct Confirm button until guided Review step.
   - Restore "Any available technician" in Date & Time.
   - When Any is used, selected time assigns the actual available tech.
   Staff App only. Does not touch Menu Settings, pricing, tax, group booking, or Firestore schema.
   ============================================================ */
(function(){
  if (window.__THURAYA_HF74_ANY_TECH_WIZARD_SAFETY__) return;
  window.__THURAYA_HF74_ANY_TECH_WIZARD_SAFETY__ = true;

  const ANY = '__ANY_AVAILABLE_TECH__';
  const OPEN = '08:00';
  const CLOSE = '20:00';
  const STEP = 15;

  function q(id){ return document.getElementById(id); }
  function norm(v){ return String(v || '').trim().toLowerCase(); }
  function esc(v){ return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
  function mins(t){ const p = String(t || '00:00').split(':').map(Number); return (p[0] || 0) * 60 + (p[1] || 0); }
  function fmt(m){ return `${String(Math.floor(m/60)).padStart(2,'0')}:${String(m%60).padStart(2,'0')}`; }
  function fmt12(t){ const p = String(t || '00:00').split(':').map(Number); const h = p[0] || 0; const mm = String(p[1] || 0).padStart(2,'0'); return `${h % 12 || 12}:${mm} ${h >= 12 ? 'PM' : 'AM'}`; }
  function today(){ try { if (typeof getLocalDateString === 'function') return getLocalDateString(); } catch(e){} const d = new Date(); return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`; }
  function techs(){
    const arr = Array.isArray(window.allTechs) ? window.allTechs : (typeof allTechs !== 'undefined' && Array.isArray(allTechs) ? allTechs : []);
    return arr.filter(t => t && t.email && t.name);
  }
  function selectedDuration(){
    try { window.calculateScheduleTotals?.(); } catch(e){}
    const total = parseInt(q('sched_totalDuration')?.innerText || '0', 10) || 0;
    return Math.max(15, total || 60);
  }
  function selectedServiceCount(){
    const checks = document.querySelectorAll('#sched_serviceMenu .sched-service-item:checked').length;
    const counters = Array.from(document.querySelectorAll('#sched_serviceMenu .sched-service-counter')).filter(i => (parseInt(i.value || '0',10)||0) > 0).length;
    return checks + counters;
  }
  function setSlots(html){ const box = q('sched_timeSlots'); if (box) box.innerHTML = html; }
  function clearTime(){ const t = q('sched_time'); if (t) t.value = ''; document.querySelectorAll('.th-avail-slot').forEach(b=>b.classList.remove('selected')); }
  function isFree(email, start, duration, busy){
    const key = norm(email);
    const end = start + duration;
    const list = (busy && (busy.get(key) || busy.get(email))) || [];
    return !list.some(([s,e]) => start < e && end > s);
  }
  function ensureAnyOption(){
    const sel = q('sched_techSelect');
    if (!sel) return;
    let opt = Array.from(sel.options).find(o => o.value === ANY);
    if (!opt) {
      opt = document.createElement('option');
      opt.value = ANY;
      opt.textContent = 'Any available technician';
      const firstReal = Array.from(sel.options).find(o => o.value && !o.disabled && o.value !== ANY);
      if (firstReal) sel.insertBefore(opt, firstReal);
      else sel.appendChild(opt);
    }
  }
  function renderSlot(time, tech){
    return `<button type="button" class="th-avail-slot" data-time="${esc(time)}" data-tech-email="${esc(tech.email)}" data-tech-name="${esc(tech.name)}"><strong>${esc(fmt12(time))}</strong><span>${esc(tech.name)}</span></button>`;
  }
  function renderTechShortcuts(available){
    const sel = q('sched_techSelect');
    if (!sel) return;
    let host = q('thAvailableTechCards');
    if (!host) {
      host = document.createElement('div');
      host.id = 'thAvailableTechCards';
      host.className = 'th-available-tech-cards';
      sel.closest('.form-group')?.appendChild(host);
    }
    const list = techs();
    if (!list.length) { host.innerHTML = '<div class="th-avail-note">No technicians loaded yet. Check Staff Matrix.</div>'; return; }
    host.innerHTML = `<div class="th-avail-tech-title">Available technician shortcut</div><div class="th-avail-tech-grid">${list.map(t => {
      const ok = available ? available.has(norm(t.email)) : true;
      const active = norm(sel.value) === norm(t.email);
      return `<button type="button" class="th-avail-tech-card ${active?'active':''} ${ok?'':'muted'}" data-tech-email="${esc(t.email)}"><span>${ok?'✓':'•'}</span><strong>${esc(t.name)}</strong><small>${ok?'Available':'May be busy'}</small></button>`;
    }).join('')}</div>`;
  }

  const oldFetchAllTechs = window.fetchAllTechs || (typeof fetchAllTechs === 'function' ? fetchAllTechs : null);
  if (oldFetchAllTechs && !oldFetchAllTechs.__hf74Wrapped) {
    const wrapped = async function(){
      const result = await oldFetchAllTechs.apply(this, arguments);
      setTimeout(ensureAnyOption, 50);
      setTimeout(ensureAnyOption, 500);
      return result;
    };
    wrapped.__hf74Wrapped = true;
    window.fetchAllTechs = wrapped;
    try { fetchAllTechs = wrapped; } catch(e) {}
  }

  window.generateTimeSlots = async function(){
    ensureAnyOption();
    clearTime();
    const date = q('sched_date')?.value || '';
    const selectedTech = q('sched_techSelect')?.value || '';
    const duration = selectedDuration();
    if (!selectedServiceCount()) { setSlots('<p class="th-avail-empty">Select at least one service first, then choose date and technician.</p>'); renderTechShortcuts(null); return; }
    if (!date) { setSlots('<p class="th-avail-empty">Choose a booking date to see available time slots.</p>'); renderTechShortcuts(null); return; }
    if (!selectedTech) { setSlots('<p class="th-avail-empty">Choose a technician, or select <strong>Any available technician</strong>.</p>'); renderTechShortcuts(null); return; }
    if (date < today()) { setSlots('<p class="th-avail-empty th-avail-error">Past dates are not available for new bookings.</p>'); return; }

    setSlots('<p class="th-avail-empty">Checking unified Staff App availability…</p>');
    const build = window.thurayaBuildAvailabilityBusyMap || window.thurayaBuildAvailabilityBusyMapHF22 || window.thurayaBuildAvailabilityBusyMapHF17;
    const busy = build ? await build(date, { ignoreAppointmentId: window.editingApptId || '' }) : new Map();
    const pool = selectedTech === ANY ? techs() : techs().filter(t => norm(t.email) === norm(selectedTech));
    if (!pool.length) { setSlots('<p class="th-avail-empty th-avail-error">No technician profile is available. Check Staff Matrix.</p>'); renderTechShortcuts(null); return; }

    const rows = [];
    const available = new Set();
    const now = new Date();
    const current = now.getHours()*60 + now.getMinutes();
    for (let t = mins(OPEN); t + duration <= mins(CLOSE); t += STEP) {
      if (date === today() && t <= current + 10) continue;
      const free = pool.filter(tech => isFree(tech.email, t, duration, busy));
      free.forEach(tech => available.add(norm(tech.email)));
      if (!free.length) continue;
      if (selectedTech === ANY) free.forEach(tech => rows.push(renderSlot(fmt(t), tech)));
      else rows.push(renderSlot(fmt(t), free[0]));
    }
    renderTechShortcuts(available);
    if (!rows.length) { setSlots('<p class="th-avail-empty th-avail-error">No available slots found. Try another technician, Any available technician, or another date.</p>'); return; }
    setSlots(`<div class="th-avail-head"><strong>${selectedTech === ANY ? 'Available slots by technician' : 'Available slots'}</strong><span>${duration} mins service window</span></div><div class="th-avail-grid">${rows.join('')}</div>`);
  };

  document.addEventListener('click', function(e){
    const slot = e.target && e.target.closest && e.target.closest('.th-avail-slot');
    if (slot) {
      const time = slot.getAttribute('data-time') || '';
      const email = slot.getAttribute('data-tech-email') || '';
      const input = q('sched_time');
      if (input) input.value = time;
      const sel = q('sched_techSelect');
      if (sel && sel.value === ANY && email) sel.value = email;
      document.querySelectorAll('.th-avail-slot').forEach(b => b.classList.remove('selected'));
      slot.classList.add('selected');
      try { if (typeof window.thB11RefreshState === 'function') window.thB11RefreshState(); } catch(_){ }
    }
    const techCard = e.target && e.target.closest && e.target.closest('.th-avail-tech-card');
    if (techCard) {
      const sel = q('sched_techSelect');
      if (sel) { sel.value = techCard.getAttribute('data-tech-email') || ''; window.generateTimeSlots(); }
    }
  }, true);

  function boot(){
    ensureAnyOption();
    const view = q('bookingWizardView');
    if (view) view.classList.add('th-hf74-wizard-safe');
  }
  document.addEventListener('DOMContentLoaded', boot);
  if (document.readyState !== 'loading') boot();
  setInterval(ensureAnyOption, 1500);
})();
/* === END THURAYA STAFF — HF74 BOOKING WIZARD SAFETY + ANY TECH RESTORE === */

/* ============================================================
   THURAYA STAFF — HF75 LEGACY BOOKING UI RETIREMENT
   Purpose:
   - The old sched_* form remains only as a hidden runtime engine.
   - The guided wizard is the only visible booking experience.
   - Removes the legacy group dropdown and direct confirm CTA from the visible flow.
   - Preserves availability, pricing, counters, tax, promo, group booking, and bookAppointment().
   ============================================================ */
(function(){
  if (window.__THURAYA_HF75_LEGACY_BOOKING_UI_RETIRED__) return;
  window.__THURAYA_HF75_LEGACY_BOOKING_UI_RETIRED__ = true;

  const ANY = '__ANY_AVAILABLE_TECH__';
  function q(id){ return document.getElementById(id); }
  function esc(v){ return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
  function size(){ return Math.max(1, Math.min(6, parseInt(q('sched_groupSize')?.value || '1', 10) || 1)); }
  function hasClient(){ return !!(q('sched_phone')?.value && q('sched_name')?.value); }

  function addBadge(){
    const header = q('thB11HeaderHF72');
    if (!header || q('thHF75EngineBadge')) return;
    const badge = document.createElement('div');
    badge.id = 'thHF75EngineBadge';
    badge.className = 'th-hf75-engine-note';
    badge.textContent = 'HF75 · Guided wizard active · Legacy UI retired';
    header.insertAdjacentElement('afterend', badge);
  }

  function ensureAnyOption(){
    const sel = q('sched_techSelect');
    if (!sel) return;
    let opt = Array.from(sel.options || []).find(o => o.value === ANY);
    if (!opt) {
      opt = document.createElement('option');
      opt.value = ANY;
      opt.textContent = 'Any available technician';
      const firstReal = Array.from(sel.options || []).find(o => o.value && !o.disabled);
      if (firstReal) sel.insertBefore(opt, firstReal); else sel.appendChild(opt);
    } else {
      opt.textContent = 'Any available technician';
    }
  }

  function setGroupSize(n){
    const sel = q('sched_groupSize');
    const safe = Math.max(1, Math.min(6, parseInt(n, 10) || 1));
    if (sel) {
      if (!Array.from(sel.options || []).some(o => String(o.value) === String(safe))) {
        const opt = document.createElement('option');
        opt.value = String(safe);
        opt.textContent = safe === 1 ? 'No — Individual' : `Yes — ${safe} people`;
        sel.appendChild(opt);
      }
      sel.value = String(safe);
      sel.dispatchEvent(new Event('change', {bubbles:true}));
    }
    try { window.onGroupSizeChange?.(); } catch(e) {}
    updateVisitState();
  }

  function aggressivelyHideLegacyControls(){
    document.body.classList.add('th-hf75-booking-retired');

    const confirm = q('btnConfirmBooking');
    if (confirm) {
      confirm.classList.add('th-hf75-hidden-legacy');
      confirm.style.display = 'none';
      confirm.setAttribute('aria-hidden', 'true');
      confirm.tabIndex = -1;
    }

    const group = q('sched_groupSize');
    if (group) {
      group.classList.add('th-hf75-hidden-legacy');
      group.setAttribute('aria-hidden', 'true');
      let node = group.closest('div');
      for (let i = 0; node && i < 7; i++, node = node.parentElement) {
        const text = String(node.textContent || '').toLowerCase();
        if (text.includes('group booking') && node.querySelector('#sched_groupSize')) {
          node.classList.add('th-hf75-hidden-legacy');
          node.style.display = 'none';
          break;
        }
      }
    }
    const note = q('groupSizeNote');
    if (note) { note.classList.add('th-hf75-hidden-legacy'); note.style.display = 'none'; }

    const side = document.querySelector('#bookingWizardView .th-b11-side-pane');
    if (side) side.style.display = 'none';
  }

  function ensureVisitCards(){
    const pane = document.querySelector('#bookingWizardView .th-b11-client-pane');
    if (!pane) return;
    const h3 = pane.querySelector('h3');
    if (h3) h3.textContent = '1. Client & Visit Type';

    const heroKicker = document.querySelector('#thB11HeaderHF72 .th-b11-kicker');
    if (heroKicker) heroKicker.textContent = 'Assisted Concierge Booking';
    const heroCopy = document.querySelector('#thB11HeaderHF72 .th-b11-hero p');
    if (heroCopy) heroCopy.textContent = 'FOH searches the registered client, then follows a calm client-style booking journey.';

    if (q('thHF75VisitChoice')) { updateVisitState(); return; }
    const host = document.createElement('div');
    host.id = 'thHF75VisitChoice';
    host.className = 'th-hf75-visit-shell';
    host.innerHTML = `
      <div class="th-hf75-visit-kicker">Assisted Client Flow</div>
      <div class="th-hf75-visit-title">How is the client visiting?</div>
      <div class="th-hf75-visit-grid">
        <button type="button" id="thHF75Individual" class="th-hf75-choice" onclick="thHF75ChooseIndividual()">
          <div class="th-hf75-choice-icon">🪑</div>
          <div><strong>Just Me</strong><span>Single appointment, standard flow</span></div>
        </button>
        <button type="button" id="thHF75Group" class="th-hf75-choice" onclick="thHF75ChooseGroup()">
          <div class="th-hf75-choice-icon">👥</div>
          <div><strong>Book for a Group</strong><span>FOH guides each person through service choice</span></div>
        </button>
      </div>
      <div id="thHF75GroupPanel" class="th-hf75-group-panel">
        <div class="th-hf75-counter-row">
          <p><strong>Group size</strong><br>Choose how many people will be linked under one group booking.</p>
          <div class="th-hf75-counter">
            <button type="button" class="th-hf75-count-btn" onclick="thHF75AdjustGroup(-1)">−</button>
            <div class="th-hf75-count-badge"><span id="thHF75GroupCount">2</span> people</div>
            <button type="button" class="th-hf75-count-btn" onclick="thHF75AdjustGroup(1)">+</button>
          </div>
        </div>
      </div>
      <div id="thHF75ClientStatus" class="th-hf75-client-status">Search and select a registered client to continue.</div>`;

    const actions = q('thB11ClientActionsHF72') || q('thB11ClientActions');
    if (actions && actions.parentElement === pane) pane.insertBefore(host, actions); else pane.appendChild(host);
    updateVisitState();
  }

  function updateVisitState(){
    const n = size();
    const isGroup = n > 1;
    const ind = q('thHF75Individual') || q('thB2ChoiceIndividual');
    const grp = q('thHF75Group') || q('thB2ChoiceGroup');
    const panel = q('thHF75GroupPanel') || q('thB2GroupPanel');
    const count = q('thHF75GroupCount') || q('thB2GroupCount');
    if (ind) ind.classList.toggle('active', !isGroup);
    if (grp) grp.classList.toggle('active', isGroup);
    if (panel) panel.classList.toggle('active', isGroup);
    if (count) count.textContent = String(Math.max(2, n));

    const status = q('thHF75ClientStatus') || q('thB2ClientStatus');
    if (status) {
      const ready = hasClient();
      status.classList.toggle('ready', ready);
      const name = q('sched_name')?.value || q('sched_displayName')?.textContent || 'Client';
      status.textContent = ready ? `${name} selected · ${isGroup ? `Group booking for ${n} people` : 'Individual booking'}` : 'Search and select a registered client to continue.';
    }
    const continueBtn = (q('thB11ClientActionsHF72') || q('thB11ClientActions'))?.querySelector('button.th-b11-primary, button.btn');
    if (continueBtn) {
      continueBtn.classList.toggle('th-hf75-disabled', !hasClient());
      continueBtn.setAttribute('aria-disabled', hasClient() ? 'false' : 'true');
    }
  }

  window.thHF75ChooseIndividual = function(){ setGroupSize(1); };
  window.thHF75ChooseGroup = function(){ setGroupSize(size() < 2 ? 2 : size()); };
  window.thHF75AdjustGroup = function(delta){ setGroupSize(size() + (parseInt(delta, 10) || 0)); };

  function wrapClientSelection(){
    if (typeof window.selectClientForSchedule === 'function' && !window.selectClientForSchedule.__hf75Wrapped) {
      const old = window.selectClientForSchedule;
      window.selectClientForSchedule = function(){
        const result = old.apply(this, arguments);
        setTimeout(updateVisitState, 50);
        setTimeout(updateVisitState, 250);
        return result;
      };
      window.selectClientForSchedule.__hf75Wrapped = true;
    }
    if (typeof window.clearScheduleClient === 'function' && !window.clearScheduleClient.__hf75Wrapped) {
      const old = window.clearScheduleClient;
      window.clearScheduleClient = function(){
        const result = old.apply(this, arguments);
        setTimeout(updateVisitState, 50);
        return result;
      };
      window.clearScheduleClient.__hf75Wrapped = true;
    }
  }

  const oldSetStep = window.thB11SetStep;
  if (typeof oldSetStep === 'function' && !oldSetStep.__hf75Wrapped) {
    window.thB11SetStep = function(step){
      const result = oldSetStep.apply(this, arguments);
      setTimeout(boot, 40);
      setTimeout(updateVisitState, 90);
      return result;
    };
    window.thB11SetStep.__hf75Wrapped = true;
  }

  const oldGoServices = window.thB11GoServices;
  if (typeof oldGoServices === 'function' && !oldGoServices.__hf75Guarded) {
    window.thB11GoServices = function(){
      if (!hasClient()) { alert('Search and select a registered client first.'); return; }
      return oldGoServices.apply(this, arguments);
    };
    window.thB11GoServices.__hf75Guarded = true;
  }

  function boot(){
    aggressivelyHideLegacyControls();
    ensureAnyOption();
    wrapClientSelection();
    addBadge();
    ensureVisitCards();
    updateVisitState();
  }

  document.addEventListener('DOMContentLoaded', boot);
  if (document.readyState !== 'loading') boot();
  ['input','change','click'].forEach(evt => document.addEventListener(evt, function(e){
    if (!e.target) return;
    if (['sched_phone','sched_name','sched_search','sched_groupSize','sched_techSelect','sched_date','sched_time'].includes(e.target.id)) setTimeout(boot, 50);
  }, true));
  setInterval(boot, 1600);
  try { new MutationObserver(() => { clearTimeout(window.__thHF75BootTimer); window.__thHF75BootTimer = setTimeout(boot, 120); }).observe(document.body, {childList:true, subtree:true}); } catch(e) {}
})();
/* === END THURAYA STAFF — HF75 LEGACY BOOKING UI RETIREMENT === */

/* ============================================================
   THURAYA STAFF — HF76 SINGLE WIZARD MOUNT GUARD
   Purpose:
   - Remove the duplicate HF73 visit-type body from the guided wizard.
   - Keep HF75 as the only visible New Booking wizard body.
   - Preserve hidden sched_* runtime engine, Any Available Tech, pricing,
     availability, counters, group booking, and HF70 Menu Settings.
   ============================================================ */
(function(){
  if (window.__THURAYA_HF76_SINGLE_WIZARD_MOUNT_GUARD__) return;
  window.__THURAYA_HF76_SINGLE_WIZARD_MOUNT_GUARD__ = true;

  function q(id){ return document.getElementById(id); }

  function installStyles(){
    if (q('thHF76SingleMountStyles')) return;
    const style = document.createElement('style');
    style.id = 'thHF76SingleMountStyles';
    style.textContent = `
      /* HF73 injected a second visit-type block. HF75 is now canonical. */
      #thB2VisitChoice,
      .th-b2-visit-shell{
        display:none!important;
        visibility:hidden!important;
        height:0!important;
        min-height:0!important;
        max-height:0!important;
        margin:0!important;
        padding:0!important;
        border:0!important;
        overflow:hidden!important;
      }
      #thHF75VisitChoice{display:block!important;visibility:visible!important;}
      #thHF76SingleMountBadge{
        display:inline-flex;align-items:center;justify-content:center;
        border:1px solid rgba(181,158,75,.38);border-radius:999px;
        padding:8px 12px;margin:10px 0 0;color:#8a7a35;background:#fffdf8;
        font-size:.72rem;font-weight:900;letter-spacing:.16em;text-transform:uppercase;
      }
    `;
    document.head.appendChild(style);
  }

  function removeDuplicateVisitBlocks(){
    // Remove any HF73 duplicate blocks. HF75 remains the single visible wizard body.
    document.querySelectorAll('#thB2VisitChoice, .th-b2-visit-shell').forEach(el => {
      try { el.remove(); } catch(_) { el.style.display = 'none'; }
    });

    // If more than one HF75 block ever appears, keep the first only.
    const hf75Blocks = Array.from(document.querySelectorAll('#thHF75VisitChoice'));
    hf75Blocks.slice(1).forEach(el => { try { el.remove(); } catch(_) { el.style.display = 'none'; } });
  }

  function addBadge(){
    const header = q('thB11HeaderHF72');
    if (!header || q('thHF76SingleMountBadge')) return;
    const badge = document.createElement('div');
    badge.id = 'thHF76SingleMountBadge';
    badge.textContent = 'HF76 · Single wizard mount active';
    header.insertAdjacentElement('afterend', badge);
  }

  function sync(){
    installStyles();
    removeDuplicateVisitBlocks();
    addBadge();
    try { if (typeof window.thB11RefreshState === 'function') window.thB11RefreshState(); } catch(_) {}
  }

  function boot(){
    sync();
    setTimeout(sync, 120);
    setTimeout(sync, 500);
    setTimeout(sync, 1200);
  }

  const oldSetStep = window.thB11SetStep;
  if (typeof oldSetStep === 'function' && !oldSetStep.__hf76SingleMountWrapped) {
    window.thB11SetStep = function(){
      const result = oldSetStep.apply(this, arguments);
      setTimeout(sync, 40);
      setTimeout(sync, 180);
      return result;
    };
    window.thB11SetStep.__hf76SingleMountWrapped = true;
  }

  document.addEventListener('DOMContentLoaded', boot);
  if (document.readyState !== 'loading') boot();
  try { new MutationObserver(() => { clearTimeout(window.__thHF76SingleMountTimer); window.__thHF76SingleMountTimer = setTimeout(sync, 80); }).observe(document.body, {childList:true, subtree:true}); } catch(_) {}
})();
/* === END THURAYA STAFF — HF76 SINGLE WIZARD MOUNT GUARD === */

/* ============================================================
   THURAYA STAFF — HF77 BOOKING SUBMIT RUNTIME SHIM
   Purpose:
   - Restore missing clearScheduleClient() dependency used by the preserved
     sched_* booking engine after legacy UI retirement.
   - Keep guided wizard visible and reset safely after successful booking.
   - Does not touch Menu_Settings_V2, availability, pricing, counters, tax,
     promo, or group booking logic.
   ============================================================ */
(function(){
  if (window.__THURAYA_HF77_BOOKING_SUBMIT_SHIM__) return;
  window.__THURAYA_HF77_BOOKING_SUBMIT_SHIM__ = true;

  function q(id){ return document.getElementById(id); }

  function setValue(id, value){
    const el = q(id);
    if (!el) return;
    el.value = value;
    try { el.dispatchEvent(new Event('input', { bubbles:true })); } catch(_) {}
    try { el.dispatchEvent(new Event('change', { bubbles:true })); } catch(_) {}
  }

  function ensureClearScheduleClient(){
    if (typeof window.clearScheduleClient === 'function' && window.clearScheduleClient.__hf77Safe) return;

    const previous = (typeof window.clearScheduleClient === 'function') ? window.clearScheduleClient : null;
    window.clearScheduleClient = function(){
      try {
        if (previous && previous !== window.clearScheduleClient) {
          try { previous.apply(this, arguments); } catch(e) { console.warn('Previous clearScheduleClient failed, using HF77 fallback', e); }
        }

        setValue('sched_phone', '');
        setValue('sched_name', '');
        setValue('sched_search', '');

        const display = q('sched_selectedClientDisplay');
        if (display) display.style.display = 'none';
        const name = q('sched_displayName');
        if (name) name.textContent = '';
        const phone = q('sched_displayPhone');
        if (phone) phone.textContent = '';
        const results = q('sched_searchResults');
        if (results) { results.innerHTML = ''; results.style.display = 'none'; }
      } catch(e) {
        console.warn('HF77 clearScheduleClient fallback error', e);
      }
      return false;
    };
    window.clearScheduleClient.__hf77Safe = true;
  }

  function refreshWizardAfterReset(){
    try { if (typeof window.thB11SetStep === 'function') window.thB11SetStep(1); } catch(_) {}
    try { if (typeof window.thB11RefreshState === 'function') window.thB11RefreshState(); } catch(_) {}
    try { if (typeof window.thHF75ChooseIndividual === 'function') window.thHF75ChooseIndividual(); } catch(_) {}
  }

  function wrapBookAppointment(){
    if (typeof window.bookAppointment !== 'function' || window.bookAppointment.__hf77Wrapped) return;
    const original = window.bookAppointment;
    window.bookAppointment = async function(){
      ensureClearScheduleClient();
      try {
        const result = await original.apply(this, arguments);
        setTimeout(refreshWizardAfterReset, 250);
        setTimeout(refreshWizardAfterReset, 900);
        return result;
      } catch(e) {
        const msg = String(e && e.message ? e.message : e || '');
        if (/clearScheduleClient is not a function/i.test(msg)) {
          console.warn('HF77 intercepted missing clearScheduleClient during booking; retrying once.');
          ensureClearScheduleClient();
          const retry = await original.apply(this, arguments);
          setTimeout(refreshWizardAfterReset, 250);
          return retry;
        }
        throw e;
      }
    };
    window.bookAppointment.__hf77Wrapped = true;
  }

  function addBadge(){
    if (q('thHF77SubmitShimBadge')) return;
    const anchor = q('thHF76SingleMountBadge') || q('thHF75RetiredBadge') || q('thB11HeaderHF72');
    if (!anchor) return;
    const badge = document.createElement('div');
    badge.id = 'thHF77SubmitShimBadge';
    badge.style.cssText = 'display:inline-flex;align-items:center;justify-content:center;border:1px solid rgba(181,158,75,.38);border-radius:999px;padding:8px 12px;margin:10px 0 0 8px;color:#8a7a35;background:#fffdf8;font-size:.72rem;font-weight:900;letter-spacing:.16em;text-transform:uppercase;';
    badge.textContent = 'HF77 · Booking submit shim active';
    anchor.insertAdjacentElement('afterend', badge);
  }

  function boot(){
    ensureClearScheduleClient();
    wrapBookAppointment();
    addBadge();
  }

  document.addEventListener('DOMContentLoaded', boot);
  if (document.readyState !== 'loading') boot();
  setTimeout(boot, 500);
  setTimeout(boot, 1500);
  try { new MutationObserver(() => { clearTimeout(window.__thHF77Timer); window.__thHF77Timer = setTimeout(boot, 120); }).observe(document.body, {childList:true, subtree:true}); } catch(_) {}
})();
/* === END THURAYA STAFF — HF77 BOOKING SUBMIT RUNTIME SHIM === */

/* ============================================================
   THURAYA STAFF — HF78 BOOKING CLEANUP SHIM
   Purpose: restore missing clearAllSelections() dependency used by
   the preserved hidden sched_* booking runtime after legacy UI retirement.
   Scope: booking runtime helper only. Does not alter Menu Settings,
   Menu_Settings_V2, availability, pricing, group booking, or client sync.
   ============================================================ */
(function(){
  if (window.__THURAYA_HF78_CLEAR_ALL_SELECTIONS_SHIM__) return;
  window.__THURAYA_HF78_CLEAR_ALL_SELECTIONS_SHIM__ = true;

  const previous = (typeof window.clearAllSelections === 'function') ? window.clearAllSelections : null;

  window.clearAllSelections = function(){
    try {
      if (previous && previous !== window.clearAllSelections) {
        try { previous.apply(this, arguments); } catch(e) { console.warn('Previous clearAllSelections failed, using HF78 fallback', e); }
      }

      document.querySelectorAll('.sched-service-item').forEach(input => {
        input.checked = false;
        try { input.removeAttribute('checked'); } catch(_) {}
      });

      document.querySelectorAll('.sched-service-counter').forEach(input => {
        input.value = '0';
        input.setAttribute('value', '0');
      });

      document.querySelectorAll('.service-card.selected, .th-ritual-service.selected, .th-b11-service-card.selected').forEach(card => {
        card.classList.remove('selected');
      });

      const totalDuration = document.getElementById('sched_totalDuration');
      if (totalDuration) totalDuration.innerText = '0';
      const totalCost = document.getElementById('sched_totalCost');
      if (totalCost) totalCost.innerText = '0.00';
      const subtotal = document.getElementById('sched_subtotalVal');
      if (subtotal) subtotal.value = '0';
      const taxData = document.getElementById('sched_taxData');
      if (taxData) taxData.value = '[]';
      const grand = document.getElementById('sched_grandTotalVal');
      if (grand) grand.value = '0';

      if (typeof window.calculateScheduleTotals === 'function') {
        try { window.calculateScheduleTotals(); } catch(e) { console.warn('HF78 calculateScheduleTotals skipped', e); }
      }
      return true;
    } catch(e) {
      console.warn('HF78 clearAllSelections fallback error', e);
      return false;
    }
  };
  window.clearAllSelections.__hf78Safe = true;

  window.addEventListener('error', function(ev){
    const msg = String(ev && (ev.message || ev.error?.message) || '');
    if (/clearAllSelections is not defined|clearAllSelections is not a function/i.test(msg)) {
      console.warn('HF78 intercepted missing clearAllSelections during booking.');
      window.clearAllSelections();
    }
  });

  console.log('THURAYA HF78 clearAllSelections booking cleanup shim loaded');
})();
/* === END THURAYA STAFF — HF78 BOOKING CLEANUP SHIM === */


/* ============================================================
   THURAYA STAFF — HF83 STABILITY ROLLBACK PATCH
   Purpose:
   - Remove the unstable HF79/HF80/HF81/HF82 group-member builder stack.
   - Keep Menu_Settings_V2 / HF70 clean menu pipeline untouched.
   - Keep the guided booking wizard and hidden sched_* booking runtime.
   - Restore a simple, production-safe group booking model:
     lead client + group size + shared services/time + linked groupId.
   - Preserve individual booking, pricing, counters, taxes, commissions,
     availability, and Any Available Technician behavior.
   ============================================================ */
(function(){
  if (window.__THURAYA_HF83_STABILITY_ROLLBACK__) return;
  window.__THURAYA_HF83_STABILITY_ROLLBACK__ = true;

  const VERSION = 'HF83 Stability Rollback';
  const ANY = '__ANY_AVAILABLE_TECH__';

  function q(id){ return document.getElementById(id); }
  function safeInt(v, fallback){
    const n = parseInt(v, 10);
    return Number.isFinite(n) ? n : fallback;
  }
  function groupSize(){
    return Math.max(1, Math.min(12, safeInt(q('sched_groupSize')?.value || '1', 1)));
  }
  function makeGroupId(){
    const existing = String(q('sched_groupId')?.value || '').trim();
    if (existing) return existing;
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let out = 'GRP-';
    if (window.crypto && crypto.getRandomValues) {
      const arr = new Uint8Array(6);
      crypto.getRandomValues(arr);
      for (let i = 0; i < arr.length; i++) out += chars[arr[i] % chars.length];
    } else {
      for (let i = 0; i < 6; i++) out += chars[Math.floor(Math.random() * chars.length)];
    }
    const el = q('sched_groupId');
    if (el) el.value = out;
    return out;
  }

  function removeHF79UI(){
    [
      'thHF79GroupBuilder',
      'thHF79PaymentBox',
      'thHF80EditGuard',
      'thHF81NameGuard',
      'thHF82NameGuard'
    ].forEach(id => { const el = q(id); if (el) el.remove(); });

    document.querySelectorAll('[id^="thHF79MemberName_"], .th-hf79-member, .th-hf79-member-tab, .th-hf79-active-note, .th-hf79-summary, .th-hf79-payment-box, .th-hf79-group-builder')
      .forEach(el => { try { el.remove(); } catch(_) {} });
  }

  function ensureAnyOption(){
    const sel = q('sched_techSelect');
    if (!sel) return;
    let opt = Array.from(sel.options || []).find(o => o.value === ANY);
    if (!opt) {
      opt = document.createElement('option');
      opt.value = ANY;
      opt.textContent = 'Any available technician';
      const firstReal = Array.from(sel.options || []).find(o => o.value && !o.disabled);
      if (firstReal) sel.insertBefore(opt, firstReal);
      else sel.appendChild(opt);
    } else {
      opt.textContent = 'Any available technician';
    }
  }

  function renderStableGroupNotice(){
    removeHF79UI();
    const size = groupSize();
    const pane = document.querySelector('#bookingWizardView .th-b11-services-pane') || q('sched_serviceMenu')?.parentElement;
    if (!pane) return;

    let notice = q('thHF83StableGroupNotice');
    if (size <= 1) {
      if (notice) notice.remove();
      return;
    }

    const gid = makeGroupId();
    if (!notice) {
      notice = document.createElement('div');
      notice.id = 'thHF83StableGroupNotice';
      notice.className = 'th-hf83-stable-group-note';
      notice.style.cssText = 'margin:12px 0;padding:14px 16px;border:1px solid #111;border-radius:16px;background:#fff;color:#111;box-shadow:0 8px 24px rgba(0,0,0,.05);font-size:.88rem;line-height:1.45;';
      const menu = q('sched_serviceMenu');
      if (menu && menu.parentElement === pane) pane.insertBefore(notice, menu);
      else pane.insertBefore(notice, pane.firstChild);
    }

    notice.innerHTML = `
      <strong style="display:block;font-size:.92rem;letter-spacing:.04em;text-transform:uppercase;margin-bottom:4px;">${VERSION}</strong>
      <div>Simple group booking is active: lead client + ${size} people + shared services/time.</div>
      <div style="margin-top:4px;color:#555;">Group ID: <strong>${gid}</strong>. Member-by-member editing is temporarily disabled to protect live booking stability.</div>
    `;
  }

  function syncSimpleGroupRuntime(){
    const size = groupSize();
    const groupIdEl = q('sched_groupId');
    const note = q('groupSizeNote');
    const noteCount = q('groupSizeNoteCount');

    if (size > 1) {
      if (groupIdEl && !groupIdEl.value) groupIdEl.value = makeGroupId();
      if (note) note.style.display = 'block';
      if (noteCount) noteCount.textContent = String(size);
    } else {
      if (groupIdEl) groupIdEl.value = '';
      if (note) note.style.display = 'none';
    }

    renderStableGroupNotice();
  }

  // Disable the HF79 public surface so any remaining inline handlers become safe no-ops.
  window.THURAYA_HF79_GROUP = {
    disabledBy: VERSION,
    activeIndex: 0,
    members: [],
    billingMode: 'lead_pays_all_after_last'
  };
  window.thHF79SwitchMember = function(){ syncSimpleGroupRuntime(); return false; };
  window.thHF79UpdateMemberName = function(){ return false; };
  window.thHF79SetBillingMode = function(){ return false; };
  window.thHF79SaveActive = function(){ return false; };
  window.thHF79ValidateMembers = function(){ return true; };

  const previousOnGroupSizeChange = typeof window.onGroupSizeChange === 'function' ? window.onGroupSizeChange : null;
  window.onGroupSizeChange = function(){
    syncSimpleGroupRuntime();
    if (previousOnGroupSizeChange && previousOnGroupSizeChange !== window.onGroupSizeChange) {
      try { previousOnGroupSizeChange.apply(this, arguments); } catch(e) { console.warn('HF83 preserved group-size handler skipped:', e); }
    }
    syncSimpleGroupRuntime();
    try { if (typeof window.generateTimeSlots === 'function') window.generateTimeSlots(); } catch(e) { console.warn('HF83 time slot refresh skipped:', e); }
    try { if (typeof window.thB11RefreshState === 'function') window.thB11RefreshState(); } catch(_) {}
    return true;
  };

  const originalBookAppointment = typeof window.bookAppointment === 'function' ? window.bookAppointment : null;
  if (originalBookAppointment && !originalBookAppointment.__hf83SimpleGroupWrapped) {
    window.bookAppointment = async function(){
      removeHF79UI();
      syncSimpleGroupRuntime();
      const size = groupSize();
      if (size > 1) makeGroupId();
      return originalBookAppointment.apply(this, arguments);
    };
    window.bookAppointment.__hf83SimpleGroupWrapped = true;
  }

  function boot(){
    ensureAnyOption();
    removeHF79UI();
    syncSimpleGroupRuntime();
    const view = q('bookingWizardView');
    if (view) {
      view.classList.add('th-hf83-stable-booking');
      view.setAttribute('data-booking-stability-version', VERSION);
    }
  }

  document.addEventListener('change', function(e){
    if (e.target && e.target.id === 'sched_groupSize') boot();
  }, true);

  document.addEventListener('click', function(e){
    if (e.target && e.target.closest && e.target.closest('#thHF79GroupBuilder, #thHF79PaymentBox, .th-hf79-member, .th-hf79-member-tab')) {
      e.preventDefault();
      e.stopPropagation();
      removeHF79UI();
      syncSimpleGroupRuntime();
    }
  }, true);

  document.addEventListener('DOMContentLoaded', boot);
  if (document.readyState !== 'loading') boot();
  setTimeout(boot, 300);
  setTimeout(boot, 1200);

  console.log('THURAYA STAFF HF83 stability rollback loaded: HF79-HF82 member builder disabled; simple group booking restored.');
})();
/* === END THURAYA STAFF — HF83 STABILITY ROLLBACK PATCH === */
